-- Poems batch 302
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('05d61693-72f0-4760-a0cb-defbc77c9c7b','衰老','劉攽','宋','宋诗','song-poetry','','[]','蒼耳嬰末疾，浴蘭殊未解。',104,'全唐诗/poet.song.34000.json','["蒼耳嬰末疾，浴蘭殊未解。", "枲耳傳愈風，及秋始堪采。", "惟昔沙塞陰，偶從羊負來。", "葡萄安石榴，安可同語哉。", "雞雍與豨苓，適用即爲貴。", "何必黄金盤，磊落薦滋味。", "老人學道破諸妄，猶有塵緣爲疾恙。", "安得澡身并澡心，使我有意煙霞上。"]'),
('dd6bd47f-d9b4-4c9a-ba3f-eeef3df5574a','次韵孔常父','劉攽','宋','宋诗','song-poetry','','[]','老翁衰遲爲日久，自知不是文章手。',88,'全唐诗/poet.song.34000.json','["老翁衰遲爲日久，自知不是文章手。", "紫微熒煌十二星，青閣彤庭掖垣右。", "誰令孤翼此飛棲，正似枯槎犯牛斗。", "諸公可親復可望，黄鍾渾宏秋水光。", "但論四海矧故鄉，清詩翻翻鴻鵠翔，願言與子同升堂。"]'),
('da4f43b9-fc6e-4859-ae79-e3af5adbfa5c','太液池','劉攽','宋','宋诗','song-poetry','','[]','建章宮中太液池，水象星漢波漣漪。',64,'全唐诗/poet.song.34000.json','["建章宮中太液池，水象星漢波漣漪。", "鳬雛雁子相群嬉，黄鵠來翔金爲衣。", "主人勿惜稻粱恩，主人勿矜羅網繁。", "暫來可見不可親，乘風一舉超崑崙。"]'),
('5d42bff6-3514-44b3-8675-ea6ed42f7eaa','送原甫帥永興','劉攽','宋','宋诗','song-poetry','','[]','讀書當爲王者師，論兵要作萬人將。',160,'全唐诗/poet.song.34000.json','["讀書當爲王者師，論兵要作萬人將。", "古來志士希兩遂，白首儒生彼無望。", "騏驎一出凡馬空，豫章蟠根歲逾壯。", "金華事業爛然新，徂西謀謨誰與讓。", "旌旗蔽日紅半天，笳鼓隘塗車萬兩。", "中軍令出聽無譁，秦山渭水皆東向。", "荒夷憺威霜雪明，屬城陽和春日亮。", "趙張成事不足論，方虎遺詩猶可尚。", "龍文金鉉待調飪，鉉樞斡中付群當。", "西人歡歌公肯留，公車雙鹿畫轓上。"]'),
('437a6ef6-6ce4-4790-aa2f-8010380e918c','晚起','劉攽','宋','宋诗','song-poetry','','[]','黄昏就枕日午眠，入春夜短常獨然。',64,'全唐诗/poet.song.34000.json','["黄昏就枕日午眠，入春夜短常獨然。", "不嫌時世欲無覺，每爲身謀私自憐。", "夢爲嘉魚潛九淵，夢爲飛鳥翔高天。", "喜來寢覺了不辨，安知此興非神仙。"]'),
('b5dde8c6-73c9-4e9d-85a1-16124adcf308','漁翁','劉攽','宋','宋诗','song-poetry','','[]','老翁年侵耕作苦，官田稅多不敢住。',64,'全唐诗/poet.song.34000.json','["老翁年侵耕作苦，官田稅多不敢住。", "身携兒孫事漁釣，編竹爲家寄江浦。", "朝尋菱芡逗煙水，暮飯魚蝦宿風雨。", "人生如此亦自由，何用車馬稱公侯。"]'),
('a4c9279c-987a-45e6-b2e6-5b20b2294c11','和羅著作漁翁','劉攽','宋','宋诗','song-poetry','','[]','漁翁結網求魚子，得魚滿船心始喜。',112,'全唐诗/poet.song.34000.json','["漁翁結網求魚子，得魚滿船心始喜。", "豈知陂池水不深，但有鯤鮞少魴鯉。", "漁翁結網安得疏，漁翁用力常有餘。", "心疑他人得厚味，滿眼看來池無魚。", "古來任公不如此，期年得魚雄浙水。", "龍伯國人連六鰲，二山漂流不能止。", "由來萬事不同調，說似漁翁翁必笑。"]'),
('344faf77-d300-4bb5-b3fa-691c28211e2c','大風','劉攽','宋','宋诗','song-poetry','','[]','朝風吹沙天宇窄，暮風吹沙地載薄。',80,'全唐诗/poet.song.34000.json','["朝風吹沙天宇窄，暮風吹沙地載薄。", "視天昏冥畏其壓，視地震蕩憂其坼。", "一春三月風不息，跼天蹐地勞筋力。", "波濤翻空礔礰怒，行路之難行不得。", "安得重雲十日雨，洗眼去瞇分白黑。"]'),
('0b887acc-9a0c-4e06-bd0b-8917ba68fef3','初調江陰主簿','劉攽','宋','宋诗','song-poetry','','[]','小來讀書非爲名，約身不肯遊公卿。',64,'全唐诗/poet.song.34000.json','["小來讀書非爲名，約身不肯遊公卿。", "祇憐狂簡真吾黨，謾有文章慚老成。", "漢廷好武臣尚少，郎官十年不見調。", "青衫黄綬赤詔除，落拓敢辭流俗笑。"]'),
('ce884c4a-c27b-421e-96cd-d20d298ad27a','送直史館孫兵部知陝府','劉攽','宋','宋诗','song-poetry','','[]','侍臣數厭承明廬，太守何妨太史書。',64,'全唐诗/poet.song.34000.json','["侍臣數厭承明廬，太守何妨太史書。", "十里九坂二殽道，駟馬高蓋朱輪車。", "分陝已信召南貴，補郡詎比平原疏。", "諫垣風彩東觀筆，不待上計看回輿。"]'),
('497584c1-8ca2-483c-9359-8d6e9405c53f','湘中阻風','劉攽','宋','宋诗','song-poetry','','[]','十月北風不肯回，湘中白浪高成堆。',96,'全唐诗/poet.song.34000.json','["十月北風不肯回，湘中白浪高成堆。", "小如飛鷗大奔馬，一輩纔去群復來。", "一旬陰雲色死灰，劃劙掀簸初全開。", "晨陽照空幸澄澈，蜚廉暴怒猶喧豗。", "繫舟沙渚依曲隈，歲晏永路真悠哉。", "棹夫卷縮亦何恨，時乎寧有材不材。"]'),
('9318308b-cfdd-4a68-97ff-66af223d4a2c','欲雨寄張壁','劉攽','宋','宋诗','song-poetry','','[]','北山雲起南山雨，返照却見南山樹。',64,'全唐诗/poet.song.34000.json','["北山雲起南山雨，返照却見南山樹。", "逆風燕子能疾飛，隔葉黄鸝猶獨語。", "憶君池上波悠悠，憶君翠竹聲颼颼。", "興來冒雨故相視，薄暮雷電歸何憂。"]'),
('3d294b59-3873-41f2-a8a2-b2952b80eeb2','寄楊十七','劉攽','宋','宋诗','song-poetry','','[]','楊侯論詩銷我憂，昔歲相逢偕旅游。',112,'全唐诗/poet.song.34000.json','["楊侯論詩銷我憂，昔歲相逢偕旅游。", "梁多長者不虛語，傾蓋結交子所求。", "三年契闊意不展，嘆彼栖栖爲藪幽。", "窮愁著書亦自足，有策肯說東諸侯。", "長安富貴易反掌，末路功名猶捶鈎。", "天公於予豈愛惜，由來萬事非人謀。", "陰風朔雪五湖凍，歲窮高卧思同裘。"]'),
('285251c6-6237-4cef-99c2-551046af56c3','春寒  其一','劉攽','宋','宋诗','song-poetry','','[]','越羅裁衫春服新，寒爐委灰無復溫。',112,'全唐诗/poet.song.34000.json','["越羅裁衫春服新，寒爐委灰無復溫。", "夭桃著花紅滿檻，弱柳吹線青映門。", "豈知天事有反覆，假借專物矜餘恩。", "平明雪片白似玉，敗裘死灰仍紛紛。", "女桑吐葉蠶欲生，東郊草綠方趣耕。", "玄冥欺人人弗信，百蟲奮蟄雷已驚。", "沈陰驅除坐可待，白日隠隠浮雲外。"]'),
('59ecfca7-69c3-4aec-b92b-c085adb61936','春寒  其二','劉攽','宋','宋诗','song-poetry','','[]','清明東風零雨頻，曉來料峭寒著人。',96,'全唐诗/poet.song.34000.json','["清明東風零雨頻，曉來料峭寒著人。", "人言天事不可測，欲回暮春成早春。", "花紅柳綠皆自若，一氣變化宜有神。", "漆園老人惜光景，求術却老無聲影。", "忽聞春有再韶時，亦覺身當還壯境。", "花前一酌心熏然，敢道朱顔非少年。"]'),
('1f46a822-ea30-4f1a-90ce-f9b02b431b92','戲謝師直買伊陽田','劉攽','宋','宋诗','song-poetry','','[]','雒陽東周蘇子賢，兄弟馳說雄當年。',64,'全唐诗/poet.song.34000.json','["雒陽東周蘇子賢，兄弟馳說雄當年。", "一身曾兼六國印，舉世皆羞二頃田。", "君才十倍鬼谷子，期年已出揣摩篇。", "公侯將相可自致，何竟高蹈伊陽川。"]'),
('e76d1966-d53a-4d06-97d8-03cc375d98a9','陽翟賈人歌','劉攽','宋','宋诗','song-poetry','','[]','潁川陽翟趙邯鄲，大衢如砥車班班。',96,'全唐诗/poet.song.34000.json','["潁川陽翟趙邯鄲，大衢如砥車班班。", "重裝富貴名游間，輕紈寶玉高若山。", "關西王孫龍虎驅，此中奇貨奇可居。", "千金入秦藉短策，立談須臾分王符。", "華陽松柏成高丘，壽陵蔓草令人愁。", "沈沈相府士如市，山東供事河南侯。"]'),
('1b7c684f-f9bb-460b-810f-d9a8e65cb4be','和王平甫韓幹畫馬行','劉攽','宋','宋诗','song-poetry','','[]','韓幹畫馬出曹霸，得名不在陳栩下。',272,'全唐诗/poet.song.34000.json','["韓幹畫馬出曹霸，得名不在陳栩下。", "詔令師栩辭不可，苑中萬馬師在我。", "王侯讀書愛此言，由來能事須天然。", "看圖作詩寄慷慨，錦文織字珠聯聯。", "乘黄騕褭久埋沒，安西大宛路超忽。", "丹青能令千萬年，不比燕人空市骨。", "霜蹄踣鐵精權奇，耳截筒竹稍垂絲。", "超然抉後三十尺，一日千里御者誰。", "舐筆和鉛人所同，爾今獨成第一工。", "神凝意會不可料，天駟降精來此中。", "少陵作詩譏畫肉，惋惜驊騮氣凋縮。", "未知良工嘗苦心，空使時人爭賤目。", "九皋相馬觀天機，神雋不辨黄與驪。", "君知畫手貴自我，何若相法非有師。", "拙工俗子紛紛是，畏避權豪如畏死。", "生棟濕塗多覆屋，巧書掣肘真難使。", "吾知公詩正如此，丈夫特立嗟已矣。"]'),
('3f943649-53b3-43c0-b321-c2955d963afb','次韵蘇子瞻韓幹馬贈李伯時','劉攽','宋','宋诗','song-poetry','','[]','韓幹畫馬名獨垂，冰紈數幅橫素絲。',160,'全唐诗/poet.song.34000.json','["韓幹畫馬名獨垂，冰紈數幅橫素絲。", "諸公賦詩邀我和，我如鈍椎逢利錐。", "區中纔容三萬里，正可騕褭一日馳。", "朝燕暮吳亦其亞，幸得夷路無縶羈。", "此間三馬皆國馬，瑰資逸態成崛奇。", "有如秋空見霜鶻，下睨衆禽俱伏雌。", "良工苦心爲遠到，天機要眇潛得之。", "區區駑駘浪自負，豈可醜骨包妍皮。", "李侯洒筆定超詣，尚有天驥君未知。", "宛王母寡今授首，汗血不敢藏貳師。"]'),
('187bd3cf-0bc5-49a2-9628-796d12039900','送程少卿','劉攽','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','使君船舸如浮宮，蕩蕩帆影垂白虹。',192,'全唐诗/poet.song.34000.json','["使君船舸如浮宮，蕩蕩帆影垂白虹。", "苦無三江五湖水，安見一日千里風。", "長蛟巨魚遠避去，水府泉室深玲瓏。", "使君按俗不異此，意氣自覺凌虛空。", "滕王閣前流水白，西山落日銜微紅。", "城頭臺榭眺望極，玉壺置酒光融融。", "勝遊重臨不隔歲，塗歌巷祝歡南公。", "作官得此亦是少，况復章綬彌尊崇。", "南金折鈎富九鼎，荆揚塗泥多歲豐。", "會令利術析毫末，萬古江流常向東。", "故鄉秀水三百里，送遠遊子情無窮。", "遥知躧履待高士，安得羽翼隨飛鴻。"]'),
('e9fe4768-840d-4136-b7fd-405d89ef2ae1','懷信驛亭晚望題其楹','劉攽','宋','宋诗','song-poetry','','[]','吳檣東風曉來入，楚客齊橈暮去急。',40,'全唐诗/poet.song.34000.json','["吳檣東風曉來入，楚客齊橈暮去急。", "行人西，行人東。", "逢迎送歸景不同，夕日春煙一望中。"]'),
('bde69143-a3f3-49ce-919b-88d08a767104','戲題西湖中魚','劉攽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','重明水深波洗空，嘉魚萬族連西東。',64,'全唐诗/poet.song.34000.json','["重明水深波洗空，嘉魚萬族連西東。", "鯤鮞細碎長者惜，赤鯉成就隨飛龍。", "南風吹雨中宵雷，衆鱗不去真常才。", "魴魚如玉鱠第一，安得大網相隨來。"]'),
('8b24b1ec-69f5-4528-a26d-a9ab2f85b2b8','盆山','劉攽','宋','宋诗','song-poetry','','[]','青泉盈池底白石，中有高山高不極。',64,'全唐诗/poet.song.34000.json','["青泉盈池底白石，中有高山高不極。", "連峰絕壑知幾許，朝霏暝煙無定色。", "山下清波清淺流，魚龍浩蕩芥爲舟。", "今君欲渡何由得，縱有神仙君不識。"]'),
('3ac93551-e7d5-43ba-9adf-3f2ed9e54c40','出門無馬行','劉攽','宋','宋诗','song-poetry','','[]','市兒暮歸錢滿把，田翁秋收禾滿野。',160,'全唐诗/poet.song.34000.json','["市兒暮歸錢滿把，田翁秋收禾滿野。", "人生勤苦必有獲，天事豈常遺拙者。", "鄙夫能言知讀書，十五著論驚群儒。", "文章不作少壯用，白髮垂領皮肉粗。", "作官不如閒日多，得祿無若饑寒何。", "百年陳人誰比數，滿眼貴士難經過。", "欲爲揣摩心智短，欲學造請顔色赧。", "黄金難成丹砂貴，紫芝將秀白日晚。", "退居長安百不爲，出門無馬還步歸。", "高天報施固有待，可得不如翁與兒。"]'),
('7fd8d0c7-fffd-45fe-a271-68c7c06e9df2','次韵子瞻贈喬道人','劉攽','宋','宋诗','song-poetry','','[]','昔有仙公項曼都，去家十年若斯須。',152,'全唐诗/poet.song.35000.json','["昔有仙公項曼都，去家十年若斯須。", "還歸壯語驚妻孥，月邊朝拜雖勞軀。", "流霞一杯真味腴，世人但怪醫多盧。", "不知列仙山澤臞，陰陽變化隨指呼。", "日新無窮非故吾，喬公築居近濰都。", "交遊洞賓儕爾朱，又言其師奇丈夫。", "璞玉粹美名不沽，郎官仕晉更五胡。", "我今老病須人扶，衰顔白鬢日已渝。", "捐書絕學休守儒，去不爲少猶雙鳬，公能濟我良藥無。"]'),
('8bb62d99-1640-45e0-a5db-0e2de9972f1b','俠少行戲王子直','劉攽','宋','宋诗','song-poetry','','[]','長安少年俠自任，一生意氣過人甚。',147,'全唐诗/poet.song.35000.json','["長安少年俠自任，一生意氣過人甚。", "許身直以豪取名，快意那知武犯禁。", "寶刀强弓千里馬，風馳電射無敵者。", "有時獨醉倡樓春，一身歌舞兼百人。", "休來著書吐胸臆，脫落章句嗤丘墳。", "王侯願交不可得，貴者雖貴猶埃塵。", "君不見漢家雲臺畫良將，高冠長劍森相向。", "由來落拓塵土中，不妨論議巖廊上。", "乃知功名爲世賢，安知輕欺惡少年。"]'),
('d7429c12-5d93-4785-96b5-a4b2e50d8f35','王家酒樓','劉攽','宋','宋诗','song-poetry','','[]','君不見天漢橋下東流河，渾渾瀚瀚無停波。',207,'全唐诗/poet.song.35000.json','["君不見天漢橋下東流河，渾渾瀚瀚無停波。", "遊人閱水看白日，駭浪瞥遠紅影蹉。", "感嘆世事亦如此，振頓兩足行吟哦。", "提錢買酒聊取醉，道傍高樓正嵯峨。", "白銀角盆大如艑，臛雞煮蟹隨紛羅。", "黄花滿把照眼麗，紅裙女兒前艷歌。", "樂酣興極事反覆，舊歡脫落新愁多。", "夷門城東門，南對屠兒墓。", "信陵今安在，賓客散如霧。", "竊符事可鄙，袖椎復何慕。", "猶令主人成大功，千歲英名若可遇。", "笑殺平原君，恥從毛薛遊。", "選士十九人，毛遂晚見收。", "丈夫一身貴特達，因人成事良足羞。"]'),
('3af5b113-ea2a-4e84-8b5b-31e7fdf35960','和章都官洞庭詩','劉攽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','閱水須閱秋水時，洞庭八月爲最宜。',320,'全唐诗/poet.song.35000.json','["閱水須閱秋水時，洞庭八月爲最宜。", "百川湧溢注平曠，倒卷溟海翻天池。", "瀟湘沅澧紺碧色，千里一片清瑠璃。", "蜀江亦濁遠不雜，正若黄組縈鑑匜。", "長風簸軒一何壯，雪浪成山相蹙移。", "奔霆擊電恣轟磕，素車白馬交橫馳。", "朱垠騁望更無地，翼軫落影光參差。", "南極老人坐盤石，赤足皤鬢濯項頤。", "修鱗巨鬣出萬族，窟穴鱣鮪泥蛟螭。", "身軀長大竟無益，機械利器潛相隨。", "但令漁師賈餘勇，冒突死地常安之。", "巴蛇斷骨不自免，此曹幺麽何能辭。", "秦皇屬車八十一，赭衣伐山豪不羈。", "九疑不到二妃泣，聖賢失勢令人悲。", "憶登洛陽值摇落，暮霞新月含風漪。", "古今光景共一瞬，獨繞四壁觀題詩。", "神官威巖鬢似戟，樓船持節森畫旗。", "湘靈奔走伺顔色，鼓瑟獻巧招馮夷。", "新篇秀句遠爲寄，清風白芷叢余思。", "呼兒疊紙作報語，衰老撫事情孳孳。"]'),
('0fe07816-60ee-463d-b109-1678dd08c900','新灘行','劉攽','宋','宋诗','song-poetry','','[]','巴江之水西南來，峽束川壅聲若雷。',115,'全唐诗/poet.song.35000.json','["巴江之水西南來，峽束川壅聲若雷。", "瞿唐五月不敢下，灧澦中流大如馬。", "風波雖惡石不去，太古以來怨行者。", "君不見前日巴山復摧裂，萬仞臬兀江中絕。", "孟冬水涸石角見，上流下流盡精鐵。", "當時長年皆有語，後來艱危從此數。", "上天設險知爲誰，但恐妨人如灧澦。"]'),
('1fa815c2-0720-4b3a-a4c7-a5ceb4af5f6e','和楊十七傷蘇子美','劉攽','宋','宋诗','song-poetry','','[]','蘇君在朝素機警，氣排青雲力扛鼎。',224,'全唐诗/poet.song.35000.json','["蘇君在朝素機警，氣排青雲力扛鼎。", "鵷鴻遇風鄙巢栖，騏驥得塗嗤坎井。", "千金置酒宴長夜，錦繡照爛絲篁靜。", "明珠盈車謗隨起，白巾還家酒未醒。", "翟公署門賓客改，魏牟去闕江湖永。", "濯纓漁父唱滄浪，結廬陶令依人境。", "時浮扁舟就什一，出從數騎非造請。", "窮途詩語尤慨慷，暮年筆法加豪逞。", "霜凋蘭蕙不待老，一世歡悲竟俄頃。", "遺書猶缺茂陵求，卜宅乍許要離並。", "生平相望不相接，凜凜氣概吾能省。", "川流既逝安可回，駿骨雖買何由騁。", "知君金石嘗定交，末路人琴俱不幸。", "大招無復修門期，懷舊邈與山陽等。"]'),
('d1ef86df-ed33-49d4-9de2-a94b0eeedbf1','城東觀魚','劉攽','宋','宋诗','song-poetry','','[]','東城水深色如黛，居人來過不知愛。',189,'全唐诗/poet.song.35000.json','["東城水深色如黛，居人來過不知愛。", "我浮扁舟轉城曲，蒼煙古樹寒相對。", "忽如身在松江游，况有漁子前操舟。", "霜天黯黯始下雁，雪浪杳杳頻驚鷗。", "萬魚挂網同時急，赤鯉長大猶人立。", "舊疑古潭有神物，倏見金鱗却騰入。", "檝師獻功喜相顧，岸傍歡聲仍坌集。", "主人置酒樂未央，艇子行{炙火=肉}輕相及。", "吳酸縷鱠白玉盤，四座相喻同加餐。", "人生萬事豈有難，我能爲公成此歡，興極意移令我嘆。", "落日藹藹沈雲端，岸草露白天風寒。"]'),
('ba64239b-516e-4749-a346-fe2283769236','觀魚','劉攽','宋','宋诗','song-poetry','','[]','清濠環城四十里，蒹葭蒼蒼天接水。',128,'全唐诗/poet.song.35000.json','["清濠環城四十里，蒹葭蒼蒼天接水。", "使君褰帷乘大舸，觀魚今從北闕起。", "開門漁師百舟入，大罟密罾雲霧集。", "小魚一舉以千數，赤鯉强梁猶百十。", "濁醪賞功傾瓦壺，公言錫爵爭歡呼。", "餘人不及色沮喪，數奇天幸相賢愚。", "濃雲吹雨寒蕭散，置酒移船泊前岸。", "暴殄天物古所矜，誰道於今爲壯觀。"]'),
('bce0fcc4-8ea6-421e-bb8b-e897b4113aba','送張太保知冀州','劉攽','宋','宋诗','song-poetry','','[]','使君使敵前歲中，手爲單于畫吉凶。',176,'全唐诗/poet.song.35000.json','["使君使敵前歲中，手爲單于畫吉凶。", "敵人破膽不敢迕，即日歸報明光宮。", "漢家牧師三十六，水甘草豐馬數足。", "問誰虎臣司苑門，極望離宮皆苜蓿。", "長河東來橫冀州，雄雄大府森戈矛。", "紅旗照天軍令肅，紫髯昂藏居上頭。", "將軍威名動殊俗，天子今無北顧憂。", "舊傳冀土多良馬，歲看北客輸旃裘。", "廟謀將新赤岸澤，强鄰猶知博望侯。", "使君家聲仍世傳，慷慨功名方壯年。", "黄金如斗組丈二，富貴光華真謂賢。"]'),
('20166de3-c5d4-46fb-8c87-ccf1c26d4269','送裴如晦知潤州','劉攽','宋','宋诗','song-poetry','','[]','柳陰深碧黄鸝語，川水平堤鷗鳥舞。',144,'全唐诗/poet.song.35000.json','["柳陰深碧黄鸝語，川水平堤鷗鳥舞。", "送君臨流眼暫明，愛此虛凉少塵土。", "何况連檣一月行，吳山楚水相逢迎。", "稻花吹雨香不絕，蘆葉摇風聲正清。", "北固樓臺似圖畫，廣陵欲渡聞潮生。", "縹壺盈前京口酒，紅旆相隨北府兵。", "少年投栗常爲樂，晚歲甘棠空涕零。", "望君鴻飛不可攀，白頭方出玉門關。", "獨向天涯共明月，猶應夢裏借千山。"]'),
('45bb3dd3-4d50-470f-8f31-9fed3e3cb72f','送章學士知湖州','劉攽','宋','宋诗','song-poetry','','[]','昔賢爲親屈小官，使君專城情更歡。',64,'全唐诗/poet.song.35000.json','["昔賢爲親屈小官，使君專城情更歡。", "連山大湖水凝碧，高蓋駟馬車塗丹。", "綵衣兒戲養顔色，箬酒賓宴羅杯盤。", "吳興釣碣亦可羨，悵望從事空南冠。"]'),
('5223b382-0bff-47de-85c7-00b920e4f7ee','陳和叔賀蘭溪所居近有信來言水竹事戲贈','劉攽','宋','宋诗','song-poetry','','[]','北山移文那爾爲，淮陽招隠殊未歸。',64,'全唐诗/poet.song.35000.json','["北山移文那爾爲，淮陽招隠殊未歸。", "流泉漲溪可厲渡，修竹飽雨添舊圍。", "鳴禽作巢皆有託，白雲抱石初無機。", "主人已知戰勝樂，溪童未老情庶幾。"]'),
('8c308088-c344-4053-9dea-941e8fb5d7b7','柿紅','劉攽','宋','宋诗','song-poetry','','[]','柿紅梨紫漫山熟，冷雨蕭蕭落喬木。',96,'全唐诗/poet.song.35000.json','["柿紅梨紫漫山熟，冷雨蕭蕭落喬木。", "東田收穀畝數斛，築場斂積高如屋。", "柴車斑斑黄犢健，丁男肩磵兒指禿。", "烹豬漉酒樂社神，急鼓悲笳斷仍續。", "田家此樂何所憂，閭里至老還相收。", "道傍滯穗如山邱，何處老翁寧有求。"]'),
('f0f8b12d-3f10-435c-97d6-8792cf790eb9','寄題岳陽酒務水樓','劉攽','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','洞庭蒼蒼水拍天，巴陵居人無斗泉。',96,'全唐诗/poet.song.35000.json','["洞庭蒼蒼水拍天，巴陵居人無斗泉。", "天生地勢正如此，抱罋臂飲真堪憐。", "架樓窾木出百尺，剖竹接筒如筆直。", "驚雷發地山鬼憂，白波統霤湘君惜。", "吾侯智與神鬼侔，古來能事皆悠悠。", "會令太湖變春酒，更使騷客忘離憂。"]'),
('4fc7befe-8e76-4239-a1f4-5c96dc9f3816','關西行','劉攽','宋','宋诗','song-poetry','','[]','關西居人多閉屋，屋底老翁相向哭。',128,'全唐诗/poet.song.35000.json','["關西居人多閉屋，屋底老翁相向哭。", "縣官禁錢錢益輕，百姓無錢食不足。", "平時斗粟錢百數，今者千錢人不顧。", "大家蕭條無十金，小家流離半逵路。", "憶初鑄錢爲强國，盜賊無端皆得職。", "邇來救弊因寬民，盜賊自苦民逾貧。", "安得萬物皆爲銅，陰陽熾炭造化工。", "鑄錢萬萬大似尺，官定足用民家豐。"]'),
('5a9921eb-3edb-4fd3-ab6c-51a26f52340c','移舟城東','劉攽','宋','宋诗','song-poetry','','[]','厭聞九衢車馬喧，泛舟初出城東門。',96,'全唐诗/poet.song.35000.json','["厭聞九衢車馬喧，泛舟初出城東門。", "陰虹吐雨水勢怒，河聲浩浩如雷奔。", "棹工歡呼事拳捷，童稚變色愁驚魂。", "濟危經險正當爾，安得拱默爲希言。", "雖無清泠可澣滌，喜見黄濁來原原。", "便風催櫓兩快意，千里萬里何足論。"]'),
('a497343d-823a-4f36-bf3b-6280ff4ba1b2','游濟堤傅家園亭','劉攽','宋','宋诗','song-poetry','','[]','濟水與河俱至海，陶邱之北川原改。',192,'全唐诗/poet.song.35000.json','["濟水與河俱至海，陶邱之北川原改。", "由來天事不可料，黄濁長存清晦在。", "猶餘平堤十里長，逶迤東注如高岡。", "水泉味甘土脉膩，固知餘潤宜群芳。", "君家園籞臨濟堤，荆扉茅屋隨高低。", "當軒古木密如蓋，無數雜花行有蹊。", "谷虛遥聞樵斧應，晝靜便有幽禽啼。", "穿栽卜築事未已，上爲層臺深鑿溪。", "東鄰可買莫惜費，臘月課種當令齊。", "柳綠正如陶令宅，桃紅應似晉人迷。", "城中老守厭窘束，行樂得至城東西。", "此家園亭可屢往，薄酒自足充提携。"]'),
('801d6954-f9f3-4dab-bc8a-172369729f17','和楊彥文嵩山詩','劉攽','宋','宋诗','song-poetry','','[]','楊侯作邑山水中，縣南百里維青嵩。',288,'全唐诗/poet.song.35000.json','["楊侯作邑山水中，縣南百里維青嵩。", "官閒身老詩筆健，樂與邱壑研豪雄。", "是時新凉背炎夏，草木秀麗全天功。", "重青疊碧百萬狀，有如耋老携兒童。", "懸泉落崖瀉萬丈，震雷發地聲隆隆。", "陰風巖洞忽悽愴，寒生六月如凝冬。", "祠官祀典有常秩，掃除給復何其恭。", "孕靈産異遠不極，面周負鄭人殊風。", "生雲觸石始膚寸，倏忽澍雨成冥濛。", "群山相望不足算，禮若小國來朝宗。", "幽人羽客此獨往，深處時與神仙通。", "念君吏職有章綬，池鴻籠鶴思長空。", "暫留靈境寄心賞，仰止萬古希遐蹤。", "梯高徑側目力短，涉歷庳下非穹崇。", "山中居人亦富逸，翠竹寒松名素封。", "願言携家事卜築，採薇飲水欣長終。", "巖田種芝地高下，茅屋遡水溪西東。", "君能挂冠共此約，何必綺季東園公。"]'),
('81b7c1ff-cf28-4ac2-add0-71a62293cc96','送徐君章','劉攽','宋','宋诗','song-poetry','','[]','每秋送客常羨人，今秋送君尤惜別。',112,'全唐诗/poet.song.35000.json','["每秋送客常羨人，今秋送君尤惜別。", "白髮相知無幾何，明日扁舟成楚越。", "忘形誰復到爾汝，末路轉憂欺老拙。", "西風落葉密如雨，信宿長淮見清月。", "紫蟹出籪加二螯，白魚掛網色勝雪。", "人生功名何由致，適意勿羞徒餔啜。", "何時亦得東南征，赤脚吳溪嘲釣碣。"]'),
('262e7957-6dc3-4449-8e97-98134d7b6ca9','送楊康功知安豐縣','劉攽','宋','宋诗','song-poetry','','[]','楊郎作文殊勇爲，辯如濤波捷刺蜚。',196,'全唐诗/poet.song.35000.json','["楊郎作文殊勇爲，辯如濤波捷刺蜚。", "相逢喜吾故人子，門風宛存令我悲。", "艾蘭驅車最先入，百箭穿楊誰可及。", "擢第勝人十改官，作官不辭萬家邑。", "勸耕課桑力有餘，吏事不受崇空虛。", "後生才資動出衆，何至苦心城旦書。", "清泉百里環芍陂，楚人千年長不饑。", "叔敖子孫負薪苦，念爲廉吏何可爲。", "忽憶雲臺故侯司空公，五郡士馬河西東。", "功名亦有際會數，退讓自是雄雋風。", "誰謂鄙夫老昏忘，屈指古事猶初終。", "作詩寫此豈有意，正若指點山水書魚蟲。"]'),
('d9dc3b6a-f833-42c8-81a4-e825a4a3ac91','天馬行','劉攽','宋','宋诗','song-poetry','','[]','漢家天馬來宛西，天子愛之藏貳師。',144,'全唐诗/poet.song.35000.json','["漢家天馬來宛西，天子愛之藏貳師。", "甘泉貴人寵第一，昆弟封侯真謂宜。", "軍書插羽廟選將，一朝百萬皆熊羆。", "大射盧山亦快意，死人亂麻非所悲。", "論功廟堂誰與敵，外廄皆是麒麟兒。", "白茅金印結紫綬，老將流落多瑕疵。", "天生富貴實有命，寧復憶君貧賤時。", "勢高累愚計慮遠，大志落落嗟徒爲。", "渭橋祖道一語泄，身釁邊鼓家流離。"]'),
('9de05b04-86ef-4d1b-a2f4-7ba4104011b7','和梅聖俞食鱠歌','劉攽','宋','宋诗','song-poetry','','[]','黄河赤鯉非龍材，欲化不化煩風雷。',165,'全唐诗/poet.song.35000.json','["黄河赤鯉非龍材，欲化不化煩風雷。", "隨波浮沉偷自得，網羅失身成暴腮。", "火鬐錦鬣鱗雪霜，紅眼照耀珠夜光。", "若無鯤鮞與蝦蚪，安見品格非尋常。", "主人愛客不計錢，少婦縷鱠情可憐。", "蜀薑吳橘正相益，炊菰絮羹還慊然。", "燕人寸腴不足貴，專諸全{炙火=肉}非珍味。", "屬饜默懷一飯報，欲令主人千萬歲。", "白玉換米桂作薪，主人家居長不貧。", "賣魚一值任公子，厭鱠與遍長安人。"]'),
('d69f1f21-ff5f-4b70-90d9-1425779bc465','兖州古檜','劉攽','宋','宋诗','song-poetry','','[]','兖州宅西有古檜，十尋度高百圍大。',96,'全唐诗/poet.song.35000.json','["兖州宅西有古檜，十尋度高百圍大。", "生理成全不增長，半枯半榮常常在。", "游人相與疑汝年，檜不能言聊臆宣。", "百番桃李香撲地，一輩蒲柳長參天。", "束薪尋斧不旋踵，種子著花還比肩。", "老身寂寞無顔色，猶有黄鵠來枝側。"]'),
('a2b27d91-8ab0-4315-8495-62301e1e5b3e','早行','劉攽','宋','宋诗','song-poetry','','[]','東方未明天紫色，凉風吹空聲惻惻。',99,'全唐诗/poet.song.35000.json','["東方未明天紫色，凉風吹空聲惻惻。", "船人起語鳥奮翼，兼葭茫茫江水白。", "石潭轉旋蛟龍窟，巖壁冥蒙虎豹迹。", "生存古木數十圍，老死懸藤百餘尺。", "民生有爲俱事役，豈獨羈人不遑息。", "商歌濁酒聊慰懷，君不見仲尼旅人常接淅。"]'),
('915e1c70-67d6-4d81-ae41-fe5c35fe69dd','夜携賈十五過巨源作','劉攽','宋','宋诗','song-poetry','','[]','鄙夫開年便四十，白髮垂頤眼眵澀。',320,'全唐诗/poet.song.35000.json','["鄙夫開年便四十，白髮垂頤眼眵澀。", "不甘老態日見侵，自計多憂諸病集。", "待詔侏儒飽欲死，囊空有時都絕粒。", "丈夫立氣須激昂，豈能中夜牛衣泣。", "朱門貴人那易見，後生美仕尤難挹。", "敝裘敗屨欲安往，蹭蹬通衢還獨立。", "賈侯游從久不厭，孫君風誼今相入。", "由來大瓠矜濩落，尚喜靈珀勤收拾。", "暮通水火並鄰居，巷無牛羊時屢及。", "泛愛已許金石堅，覺我衰遲情汲汲。", "清霜著屋萬瓦明，白月當空北風急。", "排門上堂童孺歡，青燈照書簡編緝。", "縱談自爾外形骸，虛舟不值呼張翕。", "赤桐燒酒傾玉杯，念君屢空此遄給。", "葡萄紫熟梨甘津，寒葅盈盤更啜汁。", "酒腸雖狹底能足，邂逅歡娛論串習。", "百牢九鼎亦盡空，金带玉符誰等級。", "三更還家燈火斷，浩氣凝虛榮都邑。", "斗杓落北草木死，層冰凝水魚龍蟄。", "何時春雷起霖雨，宿雲溫媚天衢濕。"]'),
('284a4b57-c3f6-4816-a454-afde71e7adc6','次韵裴庫部二月二日遊傅園','劉攽','宋','宋诗','song-poetry','','[]','二月二日春意動，東風生物來無垠。',64,'全唐诗/poet.song.35000.json','["二月二日春意動，東風生物來無垠。", "苦憐清濟不如古，却愛小園方及辰。", "谷鳥出聲已脫俗，林花一枝疑占新。", "銀壺擔酒馬馱妓，莫辜乘興寧傷頻。"]'),
('acb6aaa9-217c-4800-b2b6-8b8bb1b5b7c3','桃源','劉攽','宋','宋诗','song-poetry','','[]','武陵溪深山合沓，巖谷掩映秦人家。',64,'全唐诗/poet.song.35000.json','["武陵溪深山合沓，巖谷掩映秦人家。", "仙俗迷塗不可到，春風流水空桃花。", "山中道人多百歲，翠髮蕭條神骨異。", "漁舟往往傍林麓，相逢亦問人間世。"]'),
('11e9df9a-2d3d-43ee-a24f-834f909efa1e','黄金','劉攽','宋','宋诗','song-poetry','','[]','黄金能成不願鑄，封侯可得差有求。',64,'全唐诗/poet.song.35000.json','["黄金能成不願鑄，封侯可得差有求。", "小來一意今白首，世事萬變都無謀。", "詩書已廢徒博弈，交友益落空沈浮。", "江湖漁釣足自給，拂衣歸去營扁舟。"]'),
('80c2faa3-d078-4729-97a2-8a3d905438f3','瑞荷','劉攽','宋','宋诗','song-poetry','','[]','西濠本連金水河，天潢之下分餘波。',149,'全唐诗/poet.song.35000.json','["西濠本連金水河，天潢之下分餘波。", "波深水靜生物秀，十步百步皆圓荷。", "五月浮舟人不見，瑞荷亭亭尤可羨。", "連二雕成白玉盤，合歡裁作青油扇。", "浣紗女子紅蓮房，背面照鏡勻鮮粧。", "斜陽弄影並高蓋，下有戢翼雙鴛鴦。", "人情貴少瑞云美，亦自天和獨鍾此。", "周王嘉禾獻同穎，漢皇奇木誇連理。", "君不見今年大田所收十萬倉，上客爲子歌吉祥。"]'),
('ff6e1bac-806a-40fd-8144-4733f18dd241','鑿井','劉攽','宋','宋诗','song-poetry','','[]','旱天雨少官鑿井，鑿深源長水泉冷。',64,'全唐诗/poet.song.35000.json','["旱天雨少官鑿井，鑿深源長水泉冷。", "塗人無復觸熱憂，居人况有操瓢幸。", "前王扇暍力已勞，後王舞雩功不省。", "此功一成千萬年，却願炎日長當天。"]'),
('410dcb81-bc9f-4dc0-ba80-4805b013e5e4','次韵和羅著作風琴詩送畢長官','劉攽','宋','宋诗','song-poetry','','[]','君不見長風翏翏起山林，大木怒呺喧萬竅。',163,'全唐诗/poet.song.35000.json','["君不見長風翏翏起山林，大木怒呺喧萬竅。", "是爲天籟來無方，中有知音全衆妙。", "洛陽琴工誇死桐，齊魯諸儒頌清廟。", "刻商變羽不得騁，擊手高張空改調。", "豈如風琴得自然，但令雕虎長清嘯。", "鏗鏘闡緩連晝夜，已斷復續誰能料。", "不論九奏金石諧，那辨五絃宮徵少。", "世間俚耳何足聽，幸有楊荂嗑然笑。", "高堂置酒月如霜，金盤照筵紅蠟燒。", "淵明子賤皆有琴，兩君叵惜清樽醮。"]'),
('5eff5df9-60e3-4acf-a659-f801d488681e','保州亂','劉攽','宋','宋诗','song-poetry','','[]','緣邊戍兵精絕倫，腹飽官粟思食人。',64,'全唐诗/poet.song.35000.json','["緣邊戍兵精絕倫，腹飽官粟思食人。", "健兒睚眥殺刺史，可憐百口同埃塵。", "燕雲蒼蒼日色紫，帳前血流守尉死。", "亂兵相歡肯畏天，保州去邊無百里。"]'),
('c384e01f-f99c-40c7-a13b-0e6b8ab94d1b','耳病','劉攽','宋','宋诗','song-poetry','','[]','風林幾處颼颼葉，石磵無時浩浩泉。',48,'全唐诗/poet.song.35000.json','["風林幾處颼颼葉，石磵無時浩浩泉。", "正欲登山驚雨過，未經烹鼎怪湯煎。", "病身老態何由避，耳疾行當耳順年。"]'),
('aff392ff-5b4c-4b29-8da3-74ad3993995c','竹間亭作','劉攽','宋','宋诗','song-poetry','','[]','溪東雜花亂如谷，溪西老樹交篁竹。',64,'全唐诗/poet.song.35000.json','["溪東雜花亂如谷，溪西老樹交篁竹。", "橫槎波水纔一葦，繚徑出林凡幾曲。", "半旬霖雨泉脈動，四岸春風柳芽綠。", "眼前景物向人好，心事幽憂傷局促。"]'),
('031923e6-0918-48ed-8d2c-bb46ee317d6c','城南行','劉攽','宋','宋诗','song-poetry','','[]','八月江湖秋水高，大堤夜坼聲嘈嘈。',64,'全唐诗/poet.song.35000.json','["八月江湖秋水高，大堤夜坼聲嘈嘈。", "前村農家失幾戶，近郭扁舟屯百艘。", "蛟龍蜿蜒水禽白，渡頭老翁須雇直。", "城南百姓多爲魚，買魚欲烹輒悽惻。"]'),
('9d0f8b78-a9e0-46fd-b596-9f137dda6acc','鄧聖求往爲武昌令刻石元次山漥尊及蘇子瞻謫官黄州遊武昌見前刻後同在翰林因有詩示余余爲次韵和之','劉攽','宋','宋诗','song-poetry','','[]','側江小屋香酒醅，出林繚徑藂花栽。',224,'全唐诗/poet.song.35000.json','["側江小屋香酒醅，出林繚徑藂花栽。", "溪風暫過響修竹，嶺雪未盡兼寒梅。", "往遊武昌值佳境，白雲漫漫縈崔嵬。", "孫家舊事頗可見，樊山杳靄臨釣臺。", "赤壁樓船不餘燼，屬車豹尾空塵埃。", "埋名腐骨彼誰子，正見邱墟黄土堆。", "三分割據亦徒話，今人尚爲羞瓶罍。", "謝公伏令首佳句，遊衍相與期江隈。", "次山孟宰繼有作，漥尊取飲摩蒼苔。", "兩公雄才又超拔，明珠照人眸瞼開。", "騰龍始知爪牙壯，掣鷹無復毛羽摧。", "腰金佩魚見官秩，不似遷客談象雷。", "朝廷一入不得出，邱壑何事煩公來。", "南人歌聲易慷慨，公詩感激成嘆哀。"]'),
('9db31a86-f068-4798-9468-858649ff2026','蔡河漁叟','劉攽','宋','宋诗','song-poetry','','[]','河冰始消春沮洳，老翁求魚日來去。',64,'全唐诗/poet.song.35000.json','["河冰始消春沮洳，老翁求魚日來去。", "川流容船網罟繁，上流下流密如霧。", "跳蝦潛斗不自惜，時復鯤鮞聊可識。", "吁嗟勞心能幾何，信道相看猶羨他。"]'),
('8322ca23-2be5-48ba-8ca5-89727ae10ab2','高樓','劉攽','宋','宋诗','song-poetry','','[]','青樓高高危九衢，朱欄畫栱相傾扶。',128,'全唐诗/poet.song.35000.json','["青樓高高危九衢，朱欄畫栱相傾扶。", "佳人當軒玉不如，紅簾翠幕深沉居。", "危絃促柱鳴笙竽，哀音感耳心意舒。", "浮雲不行飛鳥徐，游人駐車馬踟躕。", "嘉肴桂酒白玉壺，浩唱爛醉何所居。", "樂極哀多盈必虛，世故萬變誰能圖。", "飛鳶墮鼠殘諸虞，里閭豪傑何時無。", "茂陵老儒空嘆息，曲突徙薪纔賜帛。"]'),
('a0234145-f21c-49fc-a44b-093deb9f8c79','古詩咏歐陽永叔家白兔','劉攽','宋','宋诗','song-poetry','','[]','飛若白鷺，衆不足珍。',162,'全唐诗/poet.song.35000.json','["飛若白鷺，衆不足珍。", "走若白馬，近而易馴。", "古來希世絕遠始爲寶，白玉之白無緇磷。", "乃知白兔與玉比，道與之貌天與神。", "瑩然月魄照霜雪，紅眼顧眄珠璘㻞。", "山農提携越千里，主人得之誇衆賓。", "網羅脫死鷹犬避，一以潔素能超群。", "清江愴神龜，大野傷麒麟。", "刳腸折足不免患，智若三穴方全身。", "主人好奇意不倦，有來往往蒙金銀。", "老翁守株更有待，勿使珍物遺今晨。"]'),
('daa2868e-5718-4070-9d0c-3e02bed4208d','始凉夜坐','劉攽','宋','宋诗','song-poetry','','[]','八月秋風高，凉風動天地。',60,'全唐诗/poet.song.35000.json','["八月秋風高，凉風動天地。", "漸疑晝短少閒暇，况復宵長減眠睡。", "空林露下物色清，閒堂明燈門不扃。", "四隅寂寞群動息，我與蟋蟀皆宵征。"]'),
('00b8b629-9e38-4a93-a08e-341e958bcbeb','劉五草蟲扇子','劉攽','宋','宋诗','song-poetry','','[]','吾宗白團扇，畫作草蟲樣。',192,'全唐诗/poet.song.35000.json','["吾宗白團扇，畫作草蟲樣。", "天時變炎凉，棄置幾惆悵。", "網蟲蒼蒼顔色晦，畫工筆法依然在。", "剪裁帖綴復生光，白月團團仍可愛。", "蒼蠅輕巧蝴蝶狂，怒螳斮斧誰能當。", "老蠶作繭意自了，露蟬孤嘒殊清凉。", "其餘百品隨變化，天機所動俱閒暇。", "座人咨嗟用筆精，不知猶是今人畫。", "畫工侯生今白頭，有時看畫還淚流。", "壯年名聲却自惜，老去心神無處求。", "始知能事須當年，盛時一過殊可憐。", "即今拙工各自喜，豈知此家先日前，落筆輒得千萬錢。"]'),
('d95c7123-457f-4680-80f4-ddc33ef8f791','題歐公廳前兩鶴','劉攽','宋','宋诗','song-poetry','','[]','明公真愛鶴，相鶴選仙骨。',74,'全唐诗/poet.song.35000.json','["明公真愛鶴，相鶴選仙骨。", "遂令千金姿，爲君軒墀物。", "啄腥豈復辭雞群，鎩翼欲比鳬鷖馴。", "聆音發舞似矜客，避寒孤警將依人。", "吾聞芝田逸翮不如此，世上悠悠誰識真。"]'),
('f22f6854-04ee-446c-b64b-c075bdea2ffc','苦熱','劉攽','宋','宋诗','song-poetry','','[]','南方炎德非尋常，六月高下俱探湯。',64,'全唐诗/poet.song.35000.json','["南方炎德非尋常，六月高下俱探湯。", "羲和未息不可避，寒門安在徒相望。", "苦憐萬物暍且死，反顧一身困在床。", "願呼快雨洗六合，徑馭微風周八荒。"]'),
('6a964502-0a5f-4cb0-82e3-cf0c0bfd434e','和永叔春雪','劉攽','宋','宋诗','song-poetry','','[]','陬筒吹灰變冥朔，生氣萌泉天不覺。',224,'全唐诗/poet.song.35000.json','["陬筒吹灰變冥朔，生氣萌泉天不覺。", "凝陰忽升氣橫厲，重雲大同勢綿邈。", "通衢漫漫走流沙，近甸稍稍堆喬岳。", "焚爐姹女姿飛揚，匝野神奸誰彫琢。", "刀圭不惜透牆隙，捷業俄然垂屋角。", "戶斜尺劍未及收，窗缺連環如可握。", "鮮粧宮女喜深印，紅手庠童鬥堅搦。", "暝雞誤曉屢咿咿，饑雀衝人猶啄啄。", "雖憐林篁有摧折，却喜隴苗就優渥。", "貧廬敗褐憎破牖，富屋珍裘轉深幄。", "使君高義仍泛愛，潁士多文方力學。", "獵師得雋鮮棄薧，厨釀薦甘清間濁。", "氣隨陽春破凝烈，巧奪鈞工畏名貌。", "吾知郢人不復歌，古聲比今爲拙朴。"]'),
('b1e07c65-45fa-45c7-87b1-54c1a1c501a9','次韵和裴庫部喜雪歌','劉攽','宋','宋诗','song-poetry','','[]','四時平分氣升降，當冬宜藏反宣暢。',320,'全唐诗/poet.song.35000.json','["四時平分氣升降，當冬宜藏反宣暢。", "玄冥羸孱失其職，驟弛威權避威仰。", "由來萬事可盡料，一夕同雲迷下上。", "始疑群靈久猜阻，勿爾覺悟歡相訪。", "周宣商湯號明主，圭璧垂盡虛卣鬯。", "豈如聖神備參兩，精意潛發天垂貺。", "朔風蕭條嚴莫犯，四野皜白光彌望。", "乾施無方意必均，陰殺夸多力尤壯。", "松篁得意忍枯槁，鷹隼乘時戾寬曠。", "層樓眺遠復褰簾，密室就煖仍施幛。", "舞投牆隙到中堂，響拂紙疏喧北向。", "樵林無聲自斤斧，野渡爭趨急船舫。", "富觴屢舉極歡呼，貧屨踐行赧嘲讓。", "誰令小邑盡華屋，不覺南山失青嶂。", "月臨靜夜絕氛埃，濤起風江冞蕩漾。", "豫期晴和當勸耕，徑入園林稍挾杖。", "宿酲未解雞三號，照梁輝煥晨光亮。", "裴侯清通思豪絕，郢曲不比巴人唱。", "老均茵憑遊益歡，閒藉杯酒神俱王。", "明年三農飽牟麥，病民自可逃無狀。"]'),
('b54f112f-03c1-4484-ac2e-06e77d8c4f3f','地震戲王深父','劉攽','宋','宋诗','song-poetry','','[]','員方肇開坼，積塊成坤輿。',108,'全唐诗/poet.song.35000.json','["員方肇開坼，積塊成坤輿。", "漂浮大波不自止，幸有萬里之鼇魚。", "抃首戴炎州，尾直崑崙墟。", "億載不墜陷，始知力有餘。", "揚鬐播四岳，鼓鬣摇五湖。", "豈知古今士，竟以地震書。", "自是世俗聞見拘，潢汙蛙黽相隨居。", "我從龍伯借鈎餌，釣鼇惟子知非誣。"]'),
('48cce61c-6cdf-464f-bcf8-c4e607536285','戲作賣雪人歌','劉攽','宋','宋诗','song-poetry','','[]','北風沍寒紅日短，火爐燃薪不知暖。',96,'全唐诗/poet.song.35000.json','["北風沍寒紅日短，火爐燃薪不知暖。", "南山闌干雪塞滿，連玉疊瓊何足算。", "時移事異不可言，眼看星火垂南天。", "道傍暍死常比肩，市兒相與贏金錢。", "徹功有時難久全，物生豈有金石堅。", "煎湯沸騰在眼前，可得意氣長矜權。"]'),
('be600dca-2687-4316-a6de-7d6316df44aa','刁景純得假還丹陽','劉攽','宋','宋诗','song-poetry','','[]','晨霜落川水，行子自相趣。',120,'全唐诗/poet.song.35000.json','["晨霜落川水，行子自相趣。", "帝城桂爲薪，斗米勝白玉。", "丈人乘老猶愛書，十年厭直承明廬。", "漢廷三最得予告，此行亦是思鱸魚。", "沙頭打鼓朝發船，捩柂已見江湖天。", "落帆京口望北固，此溪此山如宛然。", "壯年封侯豈不好，金朱祇令夸者道。", "聞公東岡長萬杉，采芝何似商山老。"]'),
('36a17630-702b-4112-989c-b8486efa5ebf','櫻桃','劉攽','宋','宋诗','song-poetry','','[]','中庭兩櫻桃，枝葉密相對。',90,'全唐诗/poet.song.35000.json','["中庭兩櫻桃，枝葉密相對。", "蟠根不十年，不能開花如繡蓋。", "前人費力後人賞，曩日春風今日在。", "世間萬事或如此，富貴功名豈無待。", "共知韶光過眼疾，霞紅雪白不足頼。", "繁華及時數快飲，鳥散蜂飛無所悔。"]'),
('5656a7a2-f275-4297-b1ae-8f859b4d6c5b','上書行','劉攽','宋','宋诗','song-poetry','','[]','仕不至二千石，賈不至五百萬。',163,'全唐诗/poet.song.35000.json','["仕不至二千石，賈不至五百萬。", "此事夸者憂，而非志士嘆。", "君不見下邳少年授書起，幄中運籌制千里。", "功成不受三萬戶，拂衣歸從赤松子。", "君不見計倪半策誅强吳，鴟夷扁舟浮五湖。", "三致千金不自擅，至今籍籍宗陶朱。", "大賢富貴不爲己，心事邈與常人殊。", "逢時致身如反手，雲蒸龍變無時無。", "君勿愛上書獻賦稱賢豪，刺繡倚市相矜高。", "丈夫昔曾笑徒勞，商賈旦旦爭錐刀。"]'),
('2ba061e4-d0aa-4218-8ae4-628450707c92','題合肥縣效裕堂詩','劉攽','宋','宋诗','song-poetry','','[]','九月霜降公堂成，江侯寄詩求所名。',128,'全唐诗/poet.song.35000.json','["九月霜降公堂成，江侯寄詩求所名。", "定名揣稱事不易，以予樸直言必誠。", "百詞號呶片語决，十役漫汗一教行。", "令乎於此有餘裕，堂以效實非無形。", "庭羅芳草寒轉碧，池有魚鳥閒不驚。", "左經右律給嘯咏，雨軒風檻含秋聲。", "今我不樂歲云暮，蟋蟀在堂鴻雁鳴。", "主人愛客豈有極，助爾美酒長河傾。"]'),
('2e9ee211-e7a0-4d2e-99b7-b2feb0b3a924','傷孫曼叔尚書','劉攽','宋','宋诗','song-poetry','','[]','金聲擲賦惟興公，西河智略稱會宗。',64,'全唐诗/poet.song.35000.json','["金聲擲賦惟興公，西河智略稱會宗。", "曳裾置醴初奮發，聽履題劍方從容。", "上倚壺遂以爲相，衆恨王駿不得封。", "韞吾良臣九京地，此意自昔悲重重。"]'),
('f292931f-7a33-494a-b864-867673f44fdd','茂陵徐生歌','劉攽','宋','宋诗','song-poetry','','[]','茂陵徐生老且迂，一心區區長信書。',96,'全唐诗/poet.song.35000.json','["茂陵徐生老且迂，一心區區長信書。", "拜章北闕三待報，意欲霍氏安無虞。", "那知世主心不同，積惡未極難爲功。", "徙薪曲突事不爾，壯侯幾人能受封。", "高岸爲谷邱淵移，魯酒之薄邯鄲爲。", "人生决己各以時，舊意望君君不思。"]'),
('c31210e0-278b-4160-9adb-64a603103f78','幽谷泉','劉攽','宋','宋诗','song-poetry','','[]','幼卿初鑿琅琊溪，憶當大歷六年時。',160,'全唐诗/poet.song.35000.json','["幼卿初鑿琅琊溪，憶當大歷六年時。", "歐陽今疏幽谷泉，復在慶歷之六年。", "兩公相望幾百載，中間游客常比肩。", "山神愛惜第一境，邂逅知者方流傳。", "乃知勝事未有盡，可憐歲月猶依然。", "穿雲斸苔色澄澈，寶鏡霜刃光蜎蜒。", "巖前濫觴如可鑒，山下積石還成川。", "如公好事誠難得，推公此心人莫識。", "且如泉源在污泥，誰道汲引非人力。", "作詩刻石歌泉池，欲問何似陽冰題。"]'),
('ff787a77-b986-4419-864e-42dd7383b769','熙州行','劉攽','宋','宋诗','song-poetry','','[]','自胡請盟供貢職，關西二紀剽兵革。',272,'全唐诗/poet.song.35000.json','["自胡請盟供貢職，關西二紀剽兵革。", "胡人歲來受金帛，地雖國本常不惜。", "帝家將軍勇無敵，謀如轉圜心匪席。", "精神動天天不隔，鑿空借籌皆碩畫。", "賈生屬國試五餌，買臣朔方發十策。", "偏師倏然盡西海，一月三捷猶餘力。", "百蠻解辮慕冠带，五郡掃地開城壁。", "葱嶺陂陀蒲類深，回笑秦并與禹績。", "尚書論功易等差，御史行封自明白。", "武功貤爵十萬金，徹侯印組丈二尺。", "奮行過望理自爾，少從進熟來無極。", "憶昔漢武開西域，天下騷然苦征役。", "哀痛輪臺置肥美，割棄造陽損斗僻。", "豈知洮河宜種稻，此去凉州皆白麥。", "女桑被野水泉甘，吳兒力耕秦婦織。", "行子雖爲萬里程，居人坐盈九年食。", "熙州歡娛軍事息，天王聖明丞相直。"]'),
('e0186227-12bf-4fdd-b6a6-95cf1aabe9f8','庵嶺漁叟詩','劉攽','宋','宋诗','song-poetry','','[]','溪叟厭塵網，移家臨水居。',48,'全唐诗/poet.song.35000.json','["溪叟厭塵網，移家臨水居。", "開扉對山色，堰水活嘉魚。", "蓬棹自相得，笑歌還自如。", "猶嫌子陵傲，老更就蒲車。"]'),
('38a0f616-1c5a-4b71-8e3d-61d407abf044','道人申演','劉攽','宋','宋诗','song-poetry','','[]','先生隠君子，暮齒寄山林。',48,'全唐诗/poet.song.35000.json','["先生隠君子，暮齒寄山林。", "蒼鶴齊筋力，清泉漱語音。", "衣冠猶似俗，心事獨非今。", "歸去峨嵋路，千峰何處尋。"]'),
('d9d68bb4-d8d6-4d72-9f9b-572d46f482dc','幽居','劉攽','宋','宋诗','song-poetry','','[]','住處必松竹，經年長自閒。',48,'全唐诗/poet.song.35000.json','["住處必松竹，經年長自閒。", "青苔仍有徑，亂石更成山。", "飲水却餘樂，荷鋤誰愧顔。", "悠然謝車馬，聽客到門還。"]'),
('6f479a78-62f5-4304-a23f-f741a63c8ef1','小雨  其一','劉攽','宋','宋诗','song-poetry','','[]','微雲興縹緲，疏雨過森陰。',48,'全唐诗/poet.song.35000.json','["微雲興縹緲，疏雨過森陰。", "潤積衣裳膩，凉生戶牖深。", "塵埃聊洗眼，宇宙快開襟。", "寂寞城闉暮，歸飛見水禽。"]'),
('a77ea53e-0c13-4a24-8e5e-a2ca48b5d772','小雨  其二','劉攽','宋','宋诗','song-poetry','','[]','好風隨細雨，蕭颯過吾廬。',48,'全唐诗/poet.song.35000.json','["好風隨細雨，蕭颯過吾廬。", "野興鋤瓜後，衡門隠几初。", "積陰生綠縟，清氣襲空虛。", "耳目遺塵土，還當讀我書。"]'),
('f2705d23-cfee-4049-b72f-70c17727188a','小雨  其三','劉攽','宋','宋诗','song-poetry','','[]','宿雲留暝色，細雨逼殘春。',48,'全唐诗/poet.song.35000.json','["宿雲留暝色，細雨逼殘春。", "芳樹看紅濕，垂楊亦翠顰。", "高風吹燕翼，定水漲魚鱗。", "漸恐年華改，桃源憶晉人。"]'),
('91d2359e-8f23-4c54-bafa-f237688f73c0','立春','劉攽','宋','宋诗','song-poetry','','[]','得新矜白鬢，數九喜和風。',48,'全唐诗/poet.song.35000.json','["得新矜白鬢，數九喜和風。", "菜甲成春事，郊園付野翁。", "天開池水碧，雪盡樹梢紅。", "頗復尋樵隠，柴門步武通。"]'),
('368f030b-f79d-4c69-ba9e-87d6f31ce1dc','挽故相國尚書令忠獻公  其一','劉攽','宋','宋诗','song-poetry','','[]','四轉更注意，兩朝公受遺。',48,'全唐诗/poet.song.35000.json','["四轉更注意，兩朝公受遺。", "大明開日月，全德冠皋夔。", "已悟騎箕事，猶餘罷市悲。", "太常難紀績，天語詔豐碑。"]'),
('e263be8d-6a99-4604-bb1e-800d86cd2fbb','挽故相國尚書令忠獻公  其二','劉攽','宋','宋诗','song-poetry','','[]','意氣萬夫望，衣冠八尺身。',48,'全唐诗/poet.song.35000.json','["意氣萬夫望，衣冠八尺身。", "有爲悲鳳鳥，不作畫麒麟。", "餘烈周宗近，英威漢相真。", "召棠終勿剪，晝錦仰鄉人。"]'),
('1a7534cf-9902-4801-83fc-45613ebb14ab','挽故相國尚書令忠獻公  其三','劉攽','宋','宋诗','song-poetry','','[]','殄瘁虛人望，哀榮備寵章。',48,'全唐诗/poet.song.35000.json','["殄瘁虛人望，哀榮備寵章。", "疇功蕭相國，異數郭汾陽。", "鼎實宵無味，階星晝隕光。", "惟應文考廟，萬歲共丞嘗。"]'),
('1be54f41-38d1-45b1-970a-0bb320230c21','曾魯公挽詩  其一','劉攽','宋','宋诗','song-poetry','','[]','扶陽詩禮樂，丞相始安車。',48,'全唐诗/poet.song.35000.json','["扶陽詩禮樂，丞相始安車。", "世祚公之魯，門風行在書。", "三朝推帝賫，九敘見民餘。", "古有騎箕事，今知定不虛。"]'),
('73ab558e-c3b4-47d2-92ac-e3464e0f38f9','曾魯公挽詩  其二','劉攽','宋','宋诗','song-poetry','','[]','雲臺存畫像，畢陌想遺風。',48,'全唐诗/poet.song.35000.json','["雲臺存畫像，畢陌想遺風。", "文彩階符在，儀型嶽鎮空。", "考終方備福，言念始爲忠。", "今日緇衣美，能明善善功。"]'),
('d731ae61-b1d8-43d4-bdc2-3af0738012a8','曾魯公挽詩  其三','劉攽','宋','宋诗','song-poetry','','[]','南公工說讖，故老筆通靈。',48,'全唐诗/poet.song.35000.json','["南公工說讖，故老筆通靈。", "本自符千運，宜然享百齡。", "嵩高雄作鎮，河潤溢爲滎。", "考卜佳城處，無須石槨銘。"]'),
('f19a5e19-8acd-41e4-9658-686f218c9e81','齊國公主挽詩','劉攽','宋','宋诗','song-poetry','','[]','湯沐侯家貴，山林主第開。',48,'全唐诗/poet.song.35000.json','["湯沐侯家貴，山林主第開。", "天孫烏鵲水，蕭史鳳凰臺。", "遇事悲風燭，新阡愴劫灰。", "清秋降北渚，不奈楚聲哀。"]'),
('61e5192a-e8ca-43d1-86a7-231e71d850d0','秋園晚步  其一','劉攽','宋','宋诗','song-poetry','','[]','慘慘高秋興，蕭蕭欲暮天。',48,'全唐诗/poet.song.35000.json','["慘慘高秋興，蕭蕭欲暮天。", "地荒逢敗葉，日下聽殘蟬。", "感物偏無頼，悲秋私自憐。", "如今已如此，何待二毛年。"]'),
('15ce560e-4263-47b2-9680-f29e67f0faf6','秋園晚步  其二','劉攽','宋','宋诗','song-poetry','','[]','摇落西風早，蒼茫晚日斜。',48,'全唐诗/poet.song.35000.json','["摇落西風早，蒼茫晚日斜。", "木蘭休紫艷，籬菊委黄花。", "興似陶潛賦，愁如庾信家。", "向來吟思苦，直恐鬢霜華。"]'),
('31ddf767-94af-4dbf-ac13-86200e8b6090','晚步','劉攽','宋','宋诗','song-poetry','','[]','日沒城陰合，人歸草露凉。',48,'全唐诗/poet.song.35000.json','["日沒城陰合，人歸草露凉。", "淺池宜短艇，高樹倚胡床。", "清嘯激秋氣，孤吟留月光。", "敢言吾獨善，魚鳥正相忘。"]'),
('315a6da1-8023-4c2d-9432-b5ae1ba10889','城西晚歸南山馬上口占','劉攽','宋','宋诗','song-poetry','','[]','塵土辜雙眼，驅馳損壯顔。',48,'全唐诗/poet.song.35000.json','["塵土辜雙眼，驅馳損壯顔。", "夕陽銜遠樹，馬首看南山。", "應接都忘倦，神明自覺還。", "無心非自强，最識白雲閒。"]'),
('49d633c4-2291-4a47-9938-ae1ba60a5824','便風掛帆欣然有作','劉攽','宋','宋诗','song-poetry','','[]','泛梗江流疾，轉蓬風力强。',48,'全唐诗/poet.song.35000.json','["泛梗江流疾，轉蓬風力强。", "天時周必復，吾道不終藏。", "白鶴先余路，飛烏送客檣。", "掛帆資隠几，北走萬山蒼。"]'),
('f7bba2d3-6207-4382-8755-721bfde6e0aa','巢湖','劉攽','宋','宋诗','song-poetry','','[]','天與水相通，舟行去不窮。',48,'全唐诗/poet.song.35000.json','["天與水相通，舟行去不窮。", "無人能縮地，何術可分風。", "宿霧凝深黑，朝曦浴嫩紅。", "四山千里遠，晴晦已難同。"]'),
('080a0c18-3f94-49e5-a54b-8d28e4746f3b','晨至後園','劉攽','宋','宋诗','song-poetry','','[]','白露晨已重，晚花秋正繁。',48,'全唐诗/poet.song.35000.json','["白露晨已重，晚花秋正繁。", "城陰到少息，林下寂無喧。", "圃老能呼鶴，樵奴競戲猿。", "山林何異此，機事復誰存。"]'),
('a81add1e-c09b-4be8-86df-5852f6623f87','寄范佑之','劉攽','宋','宋诗','song-poetry','','[]','徽宗隨武後，相與亦通家。',48,'全唐诗/poet.song.35000.json','["徽宗隨武後，相與亦通家。", "望氣如豐劍，聞名省渥洼。", "將門嚴棨戟，王略盡流沙。", "好取封侯印，誰能讀五車。"]'),
('774f7b3c-1783-4976-8474-4d3d46224596','寄和父','劉攽','宋','宋诗','song-poetry','','[]','行李資章甫，秋期看海濤。',48,'全唐诗/poet.song.35000.json','["行李資章甫，秋期看海濤。", "埃塵乍振袂，淮泗幸容舠。", "颺舄雙鳬健，飛烏五兩高。", "須君菊花酒，慰此寸心勞。"]'),
('7cd7c312-0f88-4f65-a22c-9ff65abea82c','寄楊十七','劉攽','宋','宋诗','song-poetry','','[]','宰邑成三異，吾兄復妙年。',48,'全唐诗/poet.song.35000.json','["宰邑成三異，吾兄復妙年。", "長愁越聲短，不似古詩傳。", "高唱今獨步，知音深謂然。", "還疑剡溪上，紙貴幾多錢。"]'),
('ddc83026-c537-40e8-83f2-7f9f09cf7044','寄梅聖俞','劉攽','宋','宋诗','song-poetry','','[]','獨騎駑馬出，强逐衆人行。',48,'全唐诗/poet.song.35000.json','["獨騎駑馬出，强逐衆人行。", "貧始怨寡與，老仍畏後生。", "吾子忘年友，新詩獨步名。", "秋風夢無限，時過許昌城。"]'),
('130ae45a-62e7-462d-b666-49b58ebf1dea','寄王深甫','劉攽','宋','宋诗','song-poetry','','[]','箕潁多奇士，他年洗耳翁。',48,'全唐诗/poet.song.35000.json','["箕潁多奇士，他年洗耳翁。", "古人皆直道，吾子嗣高風。", "解榻迎徐孺，名鄉禮鄭公。", "正憐賢太守，心賞與人同。"]'),
('7e7e55dc-0c75-4c6b-8975-46747ae01c08','寄隠直','劉攽','宋','宋诗','song-poetry','','[]','遠身嗟道敝，築室笑勞生。',48,'全唐诗/poet.song.35000.json','["遠身嗟道敝，築室笑勞生。", "應接知儕俗，浮沈得避名。", "陳家星不昧，灌氏水長清。", "往事今閭里，悠悠旅客情。"]'),
('88056ea2-2ccd-4d2e-90bd-7d25c92a5579','洞庭寄張四','劉攽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','壤俗三苗舊，湖波八月寒。',48,'全唐诗/poet.song.35000.json','["壤俗三苗舊，湖波八月寒。", "天形漸水近，秋氣逼楓丹。", "漠漠萍號雨，瀟瀟澧有蘭。", "東流無限水，一洗故人冠。"]'),
('70f37970-3632-47ec-8836-0ac7fb7d0239','滑州罷爲白馬縣舍弟司法省歸寄此詩','劉攽','宋','宋诗','song-poetry','','[]','散軍收棨戟，改邑壯三畿。',48,'全唐诗/poet.song.35000.json','["散軍收棨戟，改邑壯三畿。", "太守朝行在，諸曹自免歸。", "大河終北注，旅雁獨南飛。", "遲爾寬相憶，他時信息稀。"]'),
('79cca0cc-53fa-4b58-8da5-9aa97b3ae547','送韓太祝罷官歸許昌覲','劉攽','宋','宋诗','song-poetry','','[]','吏課三年最，歸裝五日糧。',48,'全唐诗/poet.song.35000.json','["吏課三年最，歸裝五日糧。", "朋情惜分散，子舍想輝光。", "泉潔湖波白，春融柳带黄。", "因君老萊戲，遥奉使君觴。"]'),
('0a3e0093-5eb3-4d4b-82fb-7feef0a444f4','自江南將歸先寄和甫  其一','劉攽','宋','宋诗','song-poetry','','[]','五湖休作客，八月去乘槎。',48,'全唐诗/poet.song.35000.json','["五湖休作客，八月去乘槎。", "天地凝秋日，山川照落霞。", "寄聲西道主，好在嗣宗家。", "盛醖重陽酒，登高飲菊花。"]'),
('900f351f-2f45-4f43-84c7-d272be51b3eb','自江南將歸先寄和甫  其二','劉攽','宋','宋诗','song-poetry','','[]','狂直非儕俗，文章念及門。',48,'全唐诗/poet.song.35000.json','["狂直非儕俗，文章念及門。", "無成似馮衍，失路比虞翻。", "抱罋機先息，書空事不言。", "江南香草地，一一賦荃蓀。"]'),
('a2370cf3-3b34-4b39-9aa4-4078198d3492','風雨寄張野人','劉攽','宋','宋诗','song-poetry','','[]','宿雨萍號苦，凄風虎嘯頻。',48,'全唐诗/poet.song.35000.json','["宿雨萍號苦，凄風虎嘯頻。", "喜開蟲豸蟄，悵阻物華春。", "雞叫思君子，鶑遷憶故人。", "泥塗塞車轍，相過獨無因。"]'),
('c000c92c-3cca-4fab-aaad-50b7f22e08bf','寄張六','劉攽','宋','宋诗','song-poetry','','[]','十里一反顧，去君垂五千。',48,'全唐诗/poet.song.35000.json','["十里一反顧，去君垂五千。", "遠身卑濕地，歸意泬寥天。", "南極多來雁，秋陰減跕鳶。", "寄書江漢水，好送北歸船。"]'),
('eba2c216-735b-414a-8f01-3869dd0c6334','寄張宜','劉攽','宋','宋诗','song-poetry','','[]','屈指張生老，無人事隠淪。',48,'全唐诗/poet.song.35000.json','["屈指張生老，無人事隠淪。", "鯨魚空自飽，章甫向誰親。", "丹荔充庭實，明珠逐賈人。", "如何滄海上，甔石一生貧。"]'),
('c7616c05-1772-4085-9c6b-e57e30f0a439','寄張六','劉攽','宋','宋诗','song-poetry','','[]','君爲棄官去，豪氣故風流。',48,'全唐诗/poet.song.35000.json','["君爲棄官去，豪氣故風流。", "無復池中物，真能方外遊。", "浮生都物變，衰俗使人愁。", "聞有桃源路，歸來試力求。"]'),
('1aa7966a-6d82-4a46-9cc2-ab7ad03de728','省中寄王平甫','劉攽','宋','宋诗','song-poetry','','[]','簿領禿千兔，禺中强一餐。',48,'全唐诗/poet.song.35000.json','["簿領禿千兔，禺中强一餐。", "未爲勤事吏，空負寫書官。", "奇獸名天祿，層樓近井幹。", "林花今正盛，夢想月邊寒。"]'),
('4f2d72ae-d539-453b-94e3-dc7986325457','重寄蘇子瞻','劉攽','宋','宋诗','song-poetry','','[]','空胸迷舊學，華髮悵頹齡。',48,'全唐诗/poet.song.35000.json','["空胸迷舊學，華髮悵頹齡。", "江海容孤翼，雲霄寄客星。", "未堪循吏傳，默守太玄經。", "正恐聲聞酒，令人醉不醒。"]'),
('cf630b78-7de9-4d7b-890d-4a527e72d200','寄仲馮','劉攽','宋','宋诗','song-poetry','','[]','府掾西曹貴，星華使節雄。',48,'全唐诗/poet.song.35000.json','["府掾西曹貴，星華使節雄。", "我行千里鎬，即敘百餘戎。", "王略持籌內，邊山聚米中。", "因成率然勢，不陳取奇功。"]'),
('df1ac764-a91c-43ae-917d-1881137892e7','夏木聞禽','劉攽','宋','宋诗','song-poetry','','[]','愛此南軒木，親聞好鳥聲。',48,'全唐诗/poet.song.35000.json','["愛此南軒木，親聞好鳥聲。", "夏陰雙綠縟，幽韵獨凄清。", "带霧知天曉，因風覺晚晴。", "忘機是幽客，相見不相驚。"]'),
('41e10dc2-f761-4a1f-bb8a-211df7d80f3b','挽盧通議  其一','劉攽','宋','宋诗','song-poetry','','[]','射策蘭成歲，歸全韋相年。',48,'全唐诗/poet.song.35000.json','["射策蘭成歲，歸全韋相年。", "聰明百齡事，冠带五朝賢。", "賜几元知止，臨雍尚缺然。", "秋風正摇落，哀挽向新阡。"]'),
('e40f917a-512d-45e3-84b2-81cb68d8a7a5','挽盧通議  其二','劉攽','宋','宋诗','song-poetry','','[]','山東推望族，泉室閟歸真。',48,'全唐诗/poet.song.35000.json','["山東推望族，泉室閟歸真。", "善政餘談舌，清風在縉紳。", "薤晞無復露，草弱漫棲塵。", "頼有傳家慶，光華列世臣。"]'),
('46c8ea16-fec4-4189-93d6-6fb4ddcbd732','唐參政挽詩  其一','劉攽','宋','宋诗','song-poetry','','[]','天奪悲楊綰，人亡愴魏公。',48,'全唐诗/poet.song.35000.json','["天奪悲楊綰，人亡愴魏公。", "終疑仁者壽，尚想直臣風。", "聽履餘榮在，牽裾舊事空。", "惟應司隸姓，更使世知忠。"]'),
('9ac64823-bc1f-4837-8995-8d436bf1082a','唐參政挽詩  其二','劉攽','宋','宋诗','song-poetry','','[]','倜儻先言路，經綸重鼎司。',48,'全唐诗/poet.song.35000.json','["倜儻先言路，經綸重鼎司。", "武文兼二允，愛直見雙遺。", "無復靈臺論，空傷薤露詩。", "邢山向鄭國，千古意同悲。"]'),
('2cf992b9-ec16-460c-9ea0-14559c4ae4de','挽馮當世母朱太君  其一','劉攽','宋','宋诗','song-poetry','','[]','郡封家邑盛，羹遺主恩頻。',48,'全唐诗/poet.song.35000.json','["郡封家邑盛，羹遺主恩頻。", "所以令勤貴，由來得孟鄰。", "文軒空舊事，弔鶴怪來嬪。", "摇落千山暮，陔蘭不復春。"]'),
('583ad80c-2464-4021-bbd0-671eb737a1bb','挽馮當世母朱太君  其二','劉攽','宋','宋诗','song-poetry','','[]','躬績維公父，平反在不疑。',48,'全唐诗/poet.song.35000.json','["躬績維公父，平反在不疑。", "榮兼綵衣養，孝著白華詩。", "黄髮全天壽，遺風盛女師。", "畫輀丹旐遠，寧記鹿車時。"]'),
('5e3aa11f-c118-4ab1-90f4-cd6d348e7b59','挽王正仲母永壽太君  其一','劉攽','宋','宋诗','song-poetry','','[]','天錫期頤壽，恩疏石窌封。',48,'全唐诗/poet.song.35000.json','["天錫期頤壽，恩疏石窌封。", "母儀兼事事，子貴亦重重。", "歸旐滄江水，新阡翠嶺松。", "曾參無所係，不待祿千鍾。"]'),
('da209340-42c7-4068-8ac0-97312def67b0','挽王正仲母永壽太君  其二','劉攽','宋','宋诗','song-poetry','','[]','平日南陔養，諸公爲美談。',48,'全唐诗/poet.song.35000.json','["平日南陔養，諸公爲美談。", "兒啼因戲綵，羹遺復調甘。", "盛事一知十，修齡百與三。", "青烏傳吉卜，喬木藹相參。"]'),
('858cc85c-9c7f-450a-9f49-5c2727da560f','濮王任夫人挽詞','劉攽','宋','宋诗','song-poetry','','[]','思齊疏慶族，聖善積慈恩。',48,'全唐诗/poet.song.35000.json','["思齊疏慶族，聖善積慈恩。", "子貴哀榮在，舟移謦欬存。", "紼謳悲薤露，象服照魚軒。", "惟有秦原望，東西見寢園。"]'),
('6df186bc-fe86-4e49-a122-63db49da9459','挽韓侍郎夫人范郡君  其一','劉攽','宋','宋诗','song-poetry','','[]','名卿俱令族，慶善集清門。',48,'全唐诗/poet.song.35000.json','["名卿俱令族，慶善集清門。", "珮玉師柔訓，稱詩得婦言。", "已嗟封馬鬣，不待歸魚軒。", "從此公侯事，凄凉屬采蘩。"]'),
('d884862c-d73f-4cbe-bdbd-972862d8766c','挽韓侍郎夫人范郡君  其二','劉攽','宋','宋诗','song-poetry','','[]','夫尊因受郡，子貴亦通朝。',48,'全唐诗/poet.song.35000.json','["夫尊因受郡，子貴亦通朝。", "象服違偕老，幽宮不復朝。", "長川空滾滾，落葉自飄飄。", "哀挽青郊道，悲風送大招。"]'),
('c77f8044-4cc9-49bf-ba52-564503574869','西戎','劉攽','宋','宋诗','song-poetry','','[]','旄頭占虜候，鳴鏑射單于。',48,'全唐诗/poet.song.35000.json','["旄頭占虜候，鳴鏑射單于。", "哀死知明主，和親愧腐儒。", "邊鋒少南牧，天馬自東趨。", "看撤山西戍，無勞議遠圖。"]'),
('adda900b-d814-42e9-b540-f7bb102803c1','晚過西湖','劉攽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','落日微雨好，浮雲近水多。',48,'全唐诗/poet.song.35000.json','["落日微雨好，浮雲近水多。", "空濛亂林樹，涵泳著星河。", "賞極興不盡，跡歸心更過。", "猶須明月夜，濯足弄金波。"]'),
('f7b2cefb-137c-4146-83a5-45902193dd14','泛舟西湖  其一','劉攽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','靡亹蘋萍合，夤緣島嶼深。',48,'全唐诗/poet.song.35000.json','["靡亹蘋萍合，夤緣島嶼深。", "操舟非有術，鑒水會清心。", "老樹成重蓋，初荷散萬簪。", "名園皆有主，費日試幽尋。"]'),
('b42e133b-992f-4601-8390-000892f218bd','泛舟西湖  其二','劉攽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','懶意適自强，舊游疑觸新。',48,'全唐诗/poet.song.35000.json','["懶意適自强，舊游疑觸新。", "如從剡溪客，忽晤武陵人。", "鐘磬高低寺，漁樵來去津。", "凉風水雲合，天半是魚鱗。"]'),
('d5204766-bc4a-47d6-a814-33adf4f768aa','鄭侍郎挽詞  其一','劉攽','宋','宋诗','song-poetry','','[]','置驛無留客，名卿擬上公。',48,'全唐诗/poet.song.35000.json','["置驛無留客，名卿擬上公。", "應惟泣遺愛，競欲頌寬中。", "賜履靈臺隔，開阡夢澤空。", "秋音送歸旐，依約認樵風。"]'),
('7ba442a3-69b5-447f-b543-0ee331410219','鄭侍郎挽詞  其二','劉攽','宋','宋诗','song-poetry','','[]','治獄餘陰德，哀矜出片言。',48,'全唐诗/poet.song.35000.json','["治獄餘陰德，哀矜出片言。", "千金無重比，駟馬見高門。", "星落林烏暝，愁悲薤露喧。", "江風傷遠目，楚些一招魂。"]'),
('1cd19635-aa7a-446f-9597-d7c85a033a12','送張六入浙東','劉攽','宋','宋诗','song-poetry','','[]','君侯曾一仕，已作棄官歸。',48,'全唐诗/poet.song.35000.json','["君侯曾一仕，已作棄官歸。", "又欲過吳市，還愁脫賜衣。", "春風解冰雪，澤國盡芳菲。", "相望不可及，孤雲天外飛。"]'),
('ae77b0aa-7042-4a62-9b30-d9e2745b0e27','上清宮花木自夏及秋相續','劉攽','宋','宋诗','song-poetry','','[]','信此神仙地，經時玩物華。',48,'全唐诗/poet.song.35000.json','["信此神仙地，經時玩物華。", "殘紅未零落，暗紫續矜夸。", "掃石分文繡，開林碎晚霞。", "秋風蘭菊茂，此去有黄花。"]'),
('453708b7-cc0c-4cf6-9d10-561eb98c3a78','將去上清宮題梧桐','劉攽','宋','宋诗','song-poetry','','[]','舊日見春華，圓陰羽蓋斜。',48,'全唐诗/poet.song.35000.json','["舊日見春華，圓陰羽蓋斜。", "野軒何必掃，小徑故從遮。", "秋氣先摧葉，春風別有花。", "野夫心好靜，異日到山家。"]'),
('1935d6ba-b933-45bd-9be1-5755adf77417','九日','劉攽','宋','宋诗','song-poetry','','[]','九日秋蕭瑟，登高亦少歡。',48,'全唐诗/poet.song.35000.json','["九日秋蕭瑟，登高亦少歡。", "黄花宜澹泊，碧樹早凋殘。", "醉舞烏紗落，彈歌短劍寒。", "可憐西北望，白日遠長安。"]'),
('4f4af2c3-20b7-4b37-85da-bc16c65c2e21','九日寄江北兄弟','劉攽','宋','宋诗','song-poetry','','[]','登高雖有興，羈旅亦消魂。',48,'全唐诗/poet.song.35000.json','["登高雖有興，羈旅亦消魂。", "插鬢茱萸細，題詩蟋蟀喧。", "黄花一樽酒，斜日最高原。", "回首江天迥，翩翩塞雁翻。"]'),
('0e3bf1fa-88ec-43ca-b7d5-9b56f2da7248','張比部景真挽詩  其一','劉攽','宋','宋诗','song-poetry','','[]','埋輪負壯志，持節向炎墟。',48,'全唐诗/poet.song.35000.json','["埋輪負壯志，持節向炎墟。", "反戶驚殊俗，彤襜豈定居。", "跕鳶愁瘴霧，斷雁哭來書。", "天理真冥漠，誰能問太虛。"]'),
('6bdc9d93-fabc-44cc-bf48-363f30344582','張比部景真挽詩  其二','劉攽','宋','宋诗','song-poetry','','[]','五嶺瘴癘地，宦遊前事存。',48,'全唐诗/poet.song.35000.json','["五嶺瘴癘地，宦遊前事存。", "求爲勾漏令，卧念少游言。", "夫子獨不返，壯心誰復論。", "凄凉大招賦，不見入修門。"]'),
('8163fd8a-7cca-409f-aa9c-4762fd934fbf','蘇度支挽詩  其一','劉攽','宋','宋诗','song-poetry','','[]','翰墨兼能事，功名自壯圖。',48,'全唐诗/poet.song.35000.json','["翰墨兼能事，功名自壯圖。", "雲霄曾幾許，意氣即通衢。", "埋玉情何已，修文理不誣。", "敢忘徐穉禮，絮酒望江湖。"]'),
('db5c0a82-0dd3-4b11-8360-67691e40c905','蘇度支挽詩  其二','劉攽','宋','宋诗','song-poetry','','[]','前年伯鸞死，卜葬近要離。',48,'全唐诗/poet.song.35000.json','["前年伯鸞死，卜葬近要離。", "今日延陵墓，仍書季子碑。", "人琴俱已矣，林壑助悽其。", "心許千金劍，終當挂樹枝。"]'),
('b00e953c-c27b-4364-86d7-5e3006b62639','建公挽詩','劉攽','宋','宋诗','song-poetry','','[]','燕祺歡受福，陽祿痛離災。',48,'全唐诗/poet.song.35000.json','["燕祺歡受福，陽祿痛離災。", "胙土乘初載，賓天遽不回。", "弄璋迷夢幻，壯髮變塵埃。", "唯有華封祝，能寬上聖哀。"]'),
('64f7f4c8-9e37-420b-ad8c-24d9e873260b','題魯氏老檜堂','劉攽','宋','宋诗','song-poetry','','[]','當日山林客，移根近小軒。',48,'全唐诗/poet.song.35000.json','["當日山林客，移根近小軒。", "樹陰今百尺，人世亦曾孫。", "堅節寒逾甚，清風老更存。", "猶餘雙白鶴，終戀主人恩。"]'),
('01ec9217-ac32-4eef-b580-1c604aa06ab1','柏悅堂  其一','劉攽','宋','宋诗','song-poetry','','[]','往說齊侯寢，此堂申甫餘。',48,'全唐诗/poet.song.35000.json','["往說齊侯寢，此堂申甫餘。", "千齡長秀聳，衆木既消除。", "杖履每多興，冰霜冞自如。", "凉風破蒸暑，真賞復誰須。"]'),
('8421de82-4db4-46f2-8248-34400ffcf2eb','柏悅堂  其二','劉攽','宋','宋诗','song-poetry','','[]','華堂柏兩株，清景喜多餘。',48,'全唐诗/poet.song.35000.json','["華堂柏兩株，清景喜多餘。", "密影隨步武，凉風自掃除。", "蒼顔師尚父，勁節藺相如。", "寄謝繁華子，榮枯可立須。"]'),
('cc6df035-74ac-4e68-95b6-f027e12ec244','夜凉','劉攽','宋','宋诗','song-poetry','','[]','稀星映斜漢，孤月靜前軒。',48,'全唐诗/poet.song.35000.json','["稀星映斜漢，孤月靜前軒。", "意喜凉風過，遥看碧樹翻。", "勞生共裘葛，辭秩愧田園。", "高枕息群動，吟蛬依草根。"]'),
('1ec36945-d697-4086-81eb-707753319c90','自蔡河之陳州','劉攽','宋','宋诗','song-poetry','','[]','扁舟去鳬雁，川路正龍蛇。',48,'全唐诗/poet.song.35000.json','["扁舟去鳬雁，川路正龍蛇。", "日色暝如午，風鳥端復斜。", "漸漸過隴麥，短短被堤花。", "涕淚元無極，那堪視物華。"]'),
('a199c38b-ca5c-48bd-8932-cbcdcdb8ba4c','重傷胡二','劉攽','宋','宋诗','song-poetry','','[]','逝水竟不復，死生嗟可憐。',51,'全唐诗/poet.song.35000.json','["逝水竟不復，死生嗟可憐。", "所思今已矣，歸使一悽然。", "尚想飛鳬{罒与}，終辜憶戴船。", "神交如有驗，會付廣陵絃。"]'),
('efb68320-d48f-4bcf-ab2b-80a118e59078','五龍井禱雨','劉攽','宋','宋诗','song-poetry','','[]','湯年不過此，丘禱亦何頻。',48,'全唐诗/poet.song.35000.json','["湯年不過此，丘禱亦何頻。", "石井無多水，泥蟠詎有神。", "舞雩聲寂寞，剪爪事酸辛。", "萬古爲霖意，長嗟傅野人。"]'),
('0a894fdf-d944-4d00-82a1-47f6f5db1c16','苦寒','劉攽','宋','宋诗','song-poetry','','[]','苦寒殊不意，衰老若爲謀。',48,'全唐诗/poet.song.35000.json','["苦寒殊不意，衰老若爲謀。", "賜隔青綾被，貧餘白罽裘。", "蟄龍才自脫，過雁可深憂。", "靳靳西頹日，牆陰肯爲留。"]'),
('9abc7083-a79c-4577-aaf8-c1914934541a','秋過薦福院竹亭  其一','劉攽','宋','宋诗','song-poetry','','[]','入秋纔一到，風物已凄凉。',48,'全唐诗/poet.song.35000.json','["入秋纔一到，風物已凄凉。", "舊篠全侵席，新梢亂出牆。", "蕭蕭吹葉雨，稍稍墜枝霜。", "爲有留人意，嘉遊不可忘。"]'),
('5ee5d41a-902c-42a4-a077-d397bd92e7c4','秋過薦福院竹亭  其二','劉攽','宋','宋诗','song-poetry','','[]','開門金鎖碎，繞徑碧檀欒。',48,'全唐诗/poet.song.35000.json','["開門金鎖碎，繞徑碧檀欒。", "鐘唄風餘韵，房櫳日暮寒。", "老僧長入定，好鳥故相看。", "何事扁舟客，殷勤覓釣竿。"]'),
('758c12d9-f7e0-4a5a-8290-4f3d8b02b8d4','濟川亭  其一','劉攽','宋','宋诗','song-poetry','','[]','誰謂此池小，遠將天漢通。',48,'全唐诗/poet.song.35000.json','["誰謂此池小，遠將天漢通。", "分明涵列宿，迢遞引來風。", "松竹凌虛碧，軒窗倒影紅。", "高明推李杜，不負傅巖功。"]'),
('9abf33ef-a297-4c4e-b42b-085053965c52','濟川亭  其二','劉攽','宋','宋诗','song-poetry','','[]','自倚杖九節，時携書一通。',48,'全唐诗/poet.song.35000.json','["自倚杖九節，時携書一通。", "石橋照影水，竹檻納凉風。", "高柳參天碧，新蓮映日紅。", "由來帝何力，况數濟川功。"]'),
('3bbc906c-c421-4e5c-bb2b-056dc52ba737','曬書','劉攽','宋','宋诗','song-poetry','','[]','幽事隨時有，移書曬日華。',48,'全唐诗/poet.song.35000.json','["幽事隨時有，移書曬日華。", "囊開魚蠹字，眼暈石榴花。", "病忘多三篋，勞心愧五車。", "賜書仍有品，前輩羨吾家。"]'),
('fe8b8437-d197-4469-85d8-e3fb1f232c83','夜過曾孚先','劉攽','宋','宋诗','song-poetry','','[]','索我形骸內，從君里巷居。',48,'全唐诗/poet.song.35000.json','["索我形骸內，從君里巷居。", "度阡仍越陌，酌醴更焚魚。", "殘雪春泥熟，青燈缺月初。", "誰能憚乘興，嘆息歲將除。"]'),
('82f82caf-8cfb-4a30-82c6-b557f97f8ef4','將赴官廬州寄張四隠直二首  其一','劉攽','宋','宋诗','song-poetry','','[]','一爲彈冠仕，遂廢東皋田。',48,'全唐诗/poet.song.35000.json','["一爲彈冠仕，遂廢東皋田。", "不至二千石，行登四十年。", "羈遊無定許，鬢髮欲蒼然。", "萬里南江路，春風棹客船。"]'),
('5c645c2e-6c54-4038-8d30-921b88440750','將赴官廬州寄張四隠直二首  其二','劉攽','宋','宋诗','song-poetry','','[]','江路西南永，風波歲月淹。',48,'全唐诗/poet.song.35000.json','["江路西南永，風波歲月淹。", "頼君同此役，久客復誰嫌。", "榜叟誇忠信，津童識孝廉。", "雲山仍在眼，詩興力能兼。"]'),
('0eecfc5d-f6ce-4cb3-afd3-f133b2e0e7f4','賀隠直','劉攽','宋','宋诗','song-poetry','','[]','舉國皆儒服，吾人智有餘。',48,'全唐诗/poet.song.35000.json','["舉國皆儒服，吾人智有餘。", "焚舟濟河後，埋劍發硎初。", "天路騫黄鵠，雲濤縱巨魚。", "殷勤故人意，青眼看鄉書。"]'),
('58318970-0979-4c61-b192-03ee1ec737aa','送隠直歸扶離','劉攽','宋','宋诗','song-poetry','','[]','羈旅自無友，非因七不堪。',48,'全唐诗/poet.song.35000.json','["羈旅自無友，非因七不堪。", "逃空見人喜，失學向君慚。", "貧病意不展，滯留情未甘。", "相從欲有問，空法本傳南。"]'),
('f385a2e7-afc5-4d96-94bd-7e4cf9b68a6c','雪中憶隠直','劉攽','宋','宋诗','song-poetry','','[]','北風吹朔雪，遥想度關西。',48,'全唐诗/poet.song.35000.json','["北風吹朔雪，遥想度關西。", "覆閣眼初熟，登樓望獨迷。", "巧妝梅意密，偏壓柳條低。", "竟日思君飲，空憐駿馬蹄。"]'),
('00fc4ea9-8151-4dea-93ea-5b18270b1459','哭張隠直  其一','劉攽','宋','宋诗','song-poetry','','[]','結友兒童歲，對門兄弟辭。',48,'全唐诗/poet.song.35000.json','["結友兒童歲，對門兄弟辭。", "存亡殊不意，晚暮可勝悲。", "宰木歸吳遠，輀車出劍遲。", "善人鮮百福，神理儻吾欺。"]'),
('4605f3f3-3daf-44d6-92d3-29a94a41c6c3','哭張隠直  其二','劉攽','宋','宋诗','song-poetry','','[]','二星占使者，九折見忠臣。',48,'全唐诗/poet.song.35000.json','["二星占使者，九折見忠臣。", "白髮猶强力，青雲早致身。", "勞生真夢寐，過事悉埃塵。", "已矣寢門淚，石交兼懿親。"]'),
('8d9e8526-f726-4be5-ab42-a8fe41e44630','占晴  其一','劉攽','宋','宋诗','song-poetry','','[]','南國無全臘，江天可喜晴。',48,'全唐诗/poet.song.35000.json','["南國無全臘，江天可喜晴。", "山林開雪色，鳬雁與風聲。", "春物催群動，年華强旅情。", "無人同此酒，嘆息滯蠻荆。"]'),
('c20f5f89-e028-4824-b1fa-90f56ef7a8ed','占晴  其二','劉攽','宋','宋诗','song-poetry','','[]','蒸濕何由解，暄和自不禁。',48,'全唐诗/poet.song.35000.json','["蒸濕何由解，暄和自不禁。", "片雲常蔽日，小雨不成霖。", "蚊蟆晴明地，蛟龍老病心。", "雄風不易得，無處可披襟。"]'),
('c6972eeb-1e12-412b-85a6-f32312c78593','雪晴','劉攽','宋','宋诗','song-poetry','','[]','山雪喜初霽，意行因肆觀。',48,'全唐诗/poet.song.35000.json','["山雪喜初霽，意行因肆觀。", "巖光花半散，峰勢玉新攢。", "鳥去樹冰落，水來溪舍寒。", "還愁向融散，立到夕陽看。"]'),
('77b0d6ac-9ea3-4128-8da1-3f8c53dcd5a8','還郡寄洛中諸賢','劉攽','宋','宋诗','song-poetry','','[]','雖勤車馬役，而與故人同。',48,'全唐诗/poet.song.35000.json','["雖勤車馬役，而與故人同。", "濯熱宜清洛，忘饑爲碧松。", "御風思禦寇，縮地憶壺公。", "待我成仙術，相過豈有窮。"]'),
('9c0e8481-5538-4db0-b7f1-3f9a05dec788','送江淑寺丞棄官歸江州','劉攽','宋','宋诗','song-poetry','','[]','時事不可願，還家方自由。',48,'全唐诗/poet.song.35000.json','["時事不可願，還家方自由。", "看山一長嘯，飲水亦消憂。", "林竹通鄰里，陔蘭潔膳羞。", "還將計然策，江上倚扁舟。"]'),
('c83515ed-0dc7-4a20-a8be-5af9599a93c6','霍邱謝令寺丞','劉攽','宋','宋诗','song-poetry','','[]','明府雙飛鳬，南歸鴻鵠俱。',48,'全唐诗/poet.song.35000.json','["明府雙飛鳬，南歸鴻鵠俱。", "東風解冰雪，春水渡江湖。", "光祿詩爲樂，淵明酒自娛。", "公田皆種秫，三徑更何須。"]'),
('13fafa6d-a92d-4290-bcdb-1e20dc25a57e','送王肅侍禁新安監酒','劉攽','宋','宋诗','song-poetry','','[]','丹穴鳳皆好，藍田玉自溫。',48,'全唐诗/poet.song.35000.json','["丹穴鳳皆好，藍田玉自溫。", "流傳洛生咏，嘆賞貴公孫。", "好事欲成癖，著書經閉門。", "看君桂枝擢，祿仕復誰論。"]'),
('c595f932-406f-440f-9f74-a2164fd5b34d','山寺','劉攽','宋','宋诗','song-poetry','','[]','疊嶂橫秋水，招提隠半峰。',48,'全唐诗/poet.song.35000.json','["疊嶂橫秋水，招提隠半峰。", "白雲迷到路，曉日自鳴鐘。", "法會樵漁熟，齋時鳥雀慵。", "試尋方外士，繫馬就長松。"]'),
('4105fa73-477f-41ab-8acf-77016d5f8d66','畫雪扇子','劉攽','宋','宋诗','song-poetry','','[]','灑落瑶花薄，蒼茫殺氣深。',48,'全唐诗/poet.song.35000.json','["灑落瑶花薄，蒼茫殺氣深。", "因風驚拂面，濯熱幸開襟。", "夜色非關月，朝雲不待陰。", "秋風來應起，好在郢中吟。"]'),
('e89f270f-dd8f-4e2c-9e6f-41adff452cc1','曉起東園','劉攽','宋','宋诗','song-poetry','','[]','禽鳴知欲曙，野客自晨興。',48,'全唐诗/poet.song.35000.json','["禽鳴知欲曙，野客自晨興。", "春草生三徑，朝光下九層。", "園林問圃老，笋蕨待巖僧。", "即此甘幽屏，趨時要未能。"]'),
('3b94967e-e70a-4593-a0df-6bb2d4b2c2f7','古檜亭  其一','劉攽','宋','宋诗','song-poetry','','[]','散櫟厭爲社，枯梧非有神。',48,'全唐诗/poet.song.35000.json','["散櫟厭爲社，枯梧非有神。", "一身具松柏，千歲作秋春。", "風影日亭午，露香宵向晨。", "唯應仙鹿迹，不悔白頭新。"]'),
('6730b5d4-2474-470c-bf08-e5fed1a5c80b','古檜亭  其二','劉攽','宋','宋诗','song-poetry','','[]','昔聞上昇檜，傳作亳宮神。',48,'全唐诗/poet.song.35000.json','["昔聞上昇檜，傳作亳宮神。", "念此亦千載，玩之經一春。", "凉蟬號永晝，獨鶴起清晨。", "誰與畫屏幛，長令水墨新。"]'),
('25ee443d-a38f-4390-8005-03548bdae29c','上櫰','劉攽','宋','宋诗','song-poetry','','[]','人世南柯夢，看君葺舊居。',48,'全唐诗/poet.song.35000.json','["人世南柯夢，看君葺舊居。", "小庭長汛掃，暇日省文書。", "黑葉生煙外，黄花過雨餘。", "那知山谷興，不向市朝疏。"]'),
('a40a108a-d5e3-4ca5-b8ac-90be66c3c6ff','登樓','劉攽','宋','宋诗','song-poetry','','[]','溪谷含冰雪，川原見草芽。',48,'全唐诗/poet.song.35000.json','["溪谷含冰雪，川原見草芽。", "春生三峽水，日照萬人家。", "時節長如此，風光會有涯。", "唯應多美酒，厭看海棠花。"]'),
('d428705a-8196-4616-8aef-b35f1a6ad5ea','雨中過汜水關入鞏縣','劉攽','宋','宋诗','song-poetry','','[]','泥塗出關惡，風雨過雲寒。',48,'全唐诗/poet.song.35000.json','["泥塗出關惡，風雨過雲寒。", "懸水餘百仞，層峰知幾盤。", "攀躋頭目眩，揭厲衣裳單。", "稍出萬山外，始知人世寬。"]'),
('03ca9bbe-1859-4837-922c-8c36e0e94103','次韵謝三利涉寺見寄','劉攽','宋','宋诗','song-poetry','','[]','衆水會蒼山，僧房積翠間。',48,'全唐诗/poet.song.35000.json','["衆水會蒼山，僧房積翠間。", "夕陰留到客，清暑獨開關。", "月出亂峰白，天明遊子還。", "他時望君意，餘恨不同攀。"]'),
('51adb814-599e-468f-bd4f-6dfec6dcf53c','題利涉寺','劉攽','宋','宋诗','song-poetry','','[]','雲水上方居，迢迢百尺餘。',48,'全唐诗/poet.song.35000.json','["雲水上方居，迢迢百尺餘。", "水光摇几席，嵐翠徹窗疏。", "鶴樹追前佛，隆中問結廬。", "已知禪寂意，仍得揣摩書。"]'),
('b63d0f74-d194-491e-8448-c2179a2e6eca','哭王子直  其一','劉攽','宋','宋诗','song-poetry','','[]','積水忽變濁，聚星無復光。',48,'全唐诗/poet.song.35000.json','["積水忽變濁，聚星無復光。", "風流都滅盡，天理竟冥茫。", "過事皆陳迹，餘哀祇淚行。", "遥憐轉麈柄，顧影夜燈旁。"]'),
('60ca2578-d725-4272-856d-052b0705264a','哭王子直  其二','劉攽','宋','宋诗','song-poetry','','[]','衰老惜年歲，羈孤慕友生。',48,'全唐诗/poet.song.35000.json','["衰老惜年歲，羈孤慕友生。", "一哀誰爲慟，百志爾無成。", "弓劍輕前敵，詩書足自名。", "人皆期不朽，持此傲公卿。"]'),
('a6d5189a-84eb-489d-8413-aa34f222b257','荷花','劉攽','宋','宋诗','song-poetry','','[]','白水滿方塘，荷花五月芳。',48,'全唐诗/poet.song.35000.json','["白水滿方塘，荷花五月芳。", "弄珠圓不定，濯錦冷逾光。", "香憶風醒酒，聲宜雨送凉。", "扁舟學騷客，葺室近滄浪。"]'),
('9b6053ee-c488-49d2-9a77-950d8e66a7ee','黄州臨皋亭','劉攽','宋','宋诗','song-poetry','','[]','遠國江千里，荒城水一涯。',48,'全唐诗/poet.song.35000.json','["遠國江千里，荒城水一涯。", "居人愁避虎，過客競乘槎。", "秋雨吹天暮，寒濤浸日車。", "從來遷謫地，卑濕是長沙。"]'),
('ded5d41e-3378-4191-9e84-701236d7a13b','野竹亭','劉攽','宋','宋诗','song-poetry','','[]','勁節四時好，此君常眼青。',48,'全唐诗/poet.song.35000.json','["勁節四時好，此君常眼青。", "影摇金破碎，聲動玉瓏玲。", "方丈塵埃絕，高齋醉夢醒。", "由來謀野意，不異在林坰。"]'),
('addeae28-56ba-4881-8f53-7629db172292','聞西戎乞降','劉攽','宋','宋诗','song-poetry','','[]','玉關依斥堠，荒服祀春秋。',48,'全唐诗/poet.song.35000.json','["玉關依斥堠，荒服祀春秋。", "干羽由來事，桑榆尚可收。", "發書迎寶馬，錫貢入貂裘。", "高枕興王世，吾生免外憂。"]'),
('35fa7e2b-c875-4617-938f-83a246540cb1','冬夜賞月','劉攽','宋','宋诗','song-poetry','','[]','暈逐陰風起，光隨凜氣多。',48,'全唐诗/poet.song.35000.json','["暈逐陰風起，光隨凜氣多。", "霜應摧桂樹，冰恐徹天河。", "池鏡初容鑑，窗櫺亦戲磨。", "關山千里雪，此夕共金波。"]'),
('f8678573-7610-4596-bb25-fcca85a922ed','雪夜月中','劉攽','宋','宋诗','song-poetry','','[]','雪霽流雲盡，天虛片月升。',48,'全唐诗/poet.song.35000.json','["雪霽流雲盡，天虛片月升。", "氣清群玉府，光徹滿壺冰。", "過雁明可數，啼鳥寒不勝。", "山陰自此去，野興豈難乘。"]'),
('7cb1c3de-ad3e-4e68-9dd2-3b1bcf71ddd0','玩芳亭','劉攽','宋','宋诗','song-poetry','','[]','誰與玩芳草，慨然思古人。',48,'全唐诗/poet.song.35000.json','["誰與玩芳草，慨然思古人。", "東風千里目，紅蕊一城春。", "賀燕自高下，浮雲無舊新。", "南山際滄海，更覺爾爲鄰。"]'),
('78a27be1-9c80-4fb7-a807-e53a28d4039d','留別諸兄弟','劉攽','宋','宋诗','song-poetry','','[]','羈遊路萬里，物色共悽然。',48,'全唐诗/poet.song.35000.json','["羈遊路萬里，物色共悽然。", "霖雨傷秋意，西南接漏天。", "壺公縮地遠，列子御風旋。", "信有神仙術，諸公一見憐。"]'),
('2d574d5f-9c20-4144-bcb5-74b7799aa12a','暫之霅上留別一二兄弟','劉攽','宋','宋诗','song-poetry','','[]','回首嗟行役，吟詩愴物華。',48,'全唐诗/poet.song.35000.json','["回首嗟行役，吟詩愴物華。", "西風凋木葉，客子去天涯。", "日暮看邊雁，江秋見海槎。", "重陽誰對酒，野菊自開花。"]'),
('1f1c2516-a688-4f18-ac9c-e4438749b7d2','春日登樓  其一','劉攽','宋','宋诗','song-poetry','','[]','水國春歸晚，晴樓旅望賒。',48,'全唐诗/poet.song.35000.json','["水國春歸晚，晴樓旅望賒。", "青絲垂地柳，白朵出牆花。", "聽鳥參人語，看雲任帽斜。", "滄浪殊不極，春色故無涯。"]'),
('770b2c85-803d-47ff-bdf4-dbe5556da783','春日登樓  其二','劉攽','宋','宋诗','song-poetry','','[]','野性耽章句，春容看旅愁。',48,'全唐诗/poet.song.35000.json','["野性耽章句，春容看旅愁。", "眼前都俗物，天外倚高樓。", "芳草茫茫綠，清淮𣺻𣺻流。", "片雲還欲雨，悵望恐花休。"]'),
('3b8d856c-4c07-459d-9081-67c2672e2ee4','綠野亭偶題  其一','劉攽','宋','宋诗','song-poetry','','[]','記得春晚句，緣情因謝公。',48,'全唐诗/poet.song.35000.json','["記得春晚句，緣情因謝公。", "名賢共標準，清境定無窮。", "樂矣登臨際，悠然坐嘯中。", "壺觴聊發興，隨儉亦隨豐。"]'),
('25e00c4a-532c-4c59-826c-4b5dc79a83ab','綠野亭偶題  其二','劉攽','宋','宋诗','song-poetry','','[]','倚郭遍禾黍，安知私與公。',48,'全唐诗/poet.song.35000.json','["倚郭遍禾黍，安知私與公。", "爲農亦可樂，遇歲不終窮。", "累榭白雲外，壤歌明月中。", "誰言魯酒薄，自覺勝新豐。"]'),
('15900d48-8a31-4467-bf92-e1dc727079b5','日晚步過孫監丞','劉攽','宋','宋诗','song-poetry','','[]','夕陽喧鳥雀，幽徑入蓬蒿。',48,'全唐诗/poet.song.35000.json','["夕陽喧鳥雀，幽徑入蓬蒿。", "於此興不淺，行吟殊未勞。", "市朝移俗態，麋鹿共吾曹。", "稍稍鐘聲暝，林梢白月高。"]'),
('3e1cde64-ea43-47e6-a42f-4b0500b17d7f','望華山','劉攽','宋','宋诗','song-poetry','','[]','荆山連太華，青翠望難分。',48,'全唐诗/poet.song.35000.json','["荆山連太華，青翠望難分。", "嶺首明新旭，山腰暝白雲。", "玉攢光自照，波蕩勢成文。", "應接寧知倦，清輝遠送君。"]'),
('05fd8f99-6b22-4bb5-90d9-03e87bcfbb2c','鳳翔官宅園亭','劉攽','宋','宋诗','song-poetry','','[]','退食自閒暇，空堂仍集虛。',48,'全唐诗/poet.song.35000.json','["退食自閒暇，空堂仍集虛。", "秋林長費掃，寒草不教鋤。", "移石改迂徑，拂牆看舊書。", "枝棲亦云穩，何用憶吾廬。"]'),
('50ba18b7-e8e6-4003-addd-295a663ac68e','馬當山','劉攽','宋','宋诗','song-poetry','','[]','雲壑斷無土，江流橫倒山。',48,'全唐诗/poet.song.35000.json','["雲壑斷無土，江流橫倒山。", "蛟涎晴出沒，鳥羽倦飛還。", "神禹遺疏鑿，天機藉險艱。", "長風且破浪，帆席慰愁顔。"]'),
('872401fb-66e9-43de-8866-f40c80935d43','送畢長官','劉攽','宋','宋诗','song-poetry','','[]','銅墨非君志，仙鳬爲我來。',48,'全唐诗/poet.song.35000.json','["銅墨非君志，仙鳬爲我來。", "三年話傾蓋，十日算銜杯。", "許與羞垂白，飛騰指上台。", "倚門方有待，未覺厭京埃。"]'),
('09604c65-45a3-4d86-97ff-146e23d4da14','送鄭推官','劉攽','宋','宋诗','song-poetry','','[]','此邦人事少，離恨不關心。',48,'全唐诗/poet.song.35000.json','["此邦人事少，離恨不關心。", "頓與吾子別，如何旅思深。", "暖風隨躍馬，永路變鳴禽。", "蓬鬢添衰白，知予厭滯淫。"]'),
('b1ceb15f-6312-4b3f-9656-ab9262cfbd68','咏雪','劉攽','宋','宋诗','song-poetry','','[]','北風吹朔雪，楚塞亦凝寒。',48,'全唐诗/poet.song.35000.json','["北風吹朔雪，楚塞亦凝寒。", "天地浮雲滿，江湖行路難。", "醉宜乘馬出，高愛倚樓看。", "會是豐年候，居人意似寬。"]'),
('8bd2aec7-5ce1-4776-a75f-7f8838e96aa5','書堂對雪','劉攽','宋','宋诗','song-poetry','','[]','天寒不成寐，看雪坐清晨。',48,'全唐诗/poet.song.35000.json','["天寒不成寐，看雪坐清晨。", "默怪人聲絕，都迷物態真。", "璇宮寒爍目，琪樹靜無塵。", "信有崑崙圃，神游屬此身。"]'),
('75bd7943-652e-4fd5-9853-58c37a0fdfb0','和裴庫部諸家雪 侯家','劉攽','宋','宋诗','song-poetry','','[]','裘馬寒逾壯，歌鐘暝未閒。',48,'全唐诗/poet.song.35000.json','["裘馬寒逾壯，歌鐘暝未閒。", "排雲朝象闕，踏凍獵黄山。", "上客珠裝履，妖姬玉綴鬟。", "園林通夜賞，洞戶不須關。"]'),
('e09ecdf2-8278-4ef3-845e-d90a76c5deba','和裴庫部諸家雪 山家','劉攽','宋','宋诗','song-poetry','','[]','雲暗峰疑斷，林長路稍迷。',48,'全唐诗/poet.song.35000.json','["雲暗峰疑斷，林長路稍迷。", "庭隅時卧鹿，旁舍遠聽鷄。", "隠几添樵火，應門倚杖藜。", "兒童別村至，薄酒自提携。"]'),
('78fe9633-8070-4203-9c40-eb16e208a367','和裴庫部諸家雪 酒家','劉攽','宋','宋诗','song-poetry','','[]','繚徑集瓶罌，江樓倚上層。',48,'全唐诗/poet.song.35000.json','["繚徑集瓶罌，江樓倚上層。", "青帘吹淡墨，翠幕映飄燈。", "勸客寒威壯，歌時歲事登。", "十千賒可得，不恨價仍增。"]'),
('9670e456-b422-4560-a40f-8cb8d608617b','和裴庫部諸家雪 獵家','劉攽','宋','宋诗','song-poetry','','[]','寒事輕杯酒，晨裝急製衣。',48,'全唐诗/poet.song.35000.json','["寒事輕杯酒，晨裝急製衣。", "狐麋尋去迹，鷹隼競橫飛。", "沙路濃隨馬，風毛盛合圍。", "興酣生鼻火，狂發會忘歸。"]'),
('aa15c48c-b4ae-4986-a603-ffb55fc622bb','和裴庫部諸家雪 樵家','劉攽','宋','宋诗','song-poetry','','[]','山木瓊瑶合，溪風虎豹哀。',48,'全唐诗/poet.song.35000.json','["山木瓊瑶合，溪風虎豹哀。", "舊林迷處所，破斧獨歸來。", "世路深泥滓，生涯半死灰。", "誰憐廊廟語，正復此遺材。"]'),
('57e84b85-5334-4dc6-8ac6-f809e4a9fa36','和裴庫部諸家雪 船家','劉攽','宋','宋诗','song-poetry','','[]','雲白連沙渚，風高雜浪花。',48,'全唐诗/poet.song.35000.json','["雲白連沙渚，風高雜浪花。", "解帆依下雁，沽酒看棲鴉。", "篷響投珠亂，門欹墮劍斜。", "山陰路不遠，去問戴逵家。"]'),
('98d6bf29-dbf2-4def-8e0b-b04c9ec35617','雪後  其一','劉攽','宋','宋诗','song-poetry','','[]','高城催戍鼓，病枕聽哀鴻。',48,'全唐诗/poet.song.35000.json','["高城催戍鼓，病枕聽哀鴻。", "灑竹蕭蕭雪，開門峭峭風。", "消憂樽酒綠，久雨燭花紅。", "旅夢還知路，孤舟向剡中。"]'),
('3c98e274-9cbd-4fbc-ab32-cbb893d86a2b','雪後  其二','劉攽','宋','宋诗','song-poetry','','[]','朔雪凍乾坤，黄雲晝景昏。',48,'全唐诗/poet.song.35000.json','["朔雪凍乾坤，黄雲晝景昏。", "宿酲猶戀酒，靜卧亦開門。", "烏鵲時時語，松篁處處翻。", "問知淮水凍，不復渡頭喧。"]'),
('f164809b-4c20-4a39-a1da-7a833b0eba6b','陸子履有詩贈行次韵留別','劉攽','宋','宋诗','song-poetry','','[]','尚白不自悟，愧君稱絕倫。',48,'全唐诗/poet.song.35000.json','["尚白不自悟，愧君稱絕倫。", "高秋獨去國，下水不留人。", "菊秀鴻初過，魚肥稻已新。", "淮山見明月，千里最情親。"]'),
('245849d2-f6e1-4766-a7a6-294e07c9a75f','留別傅欽之','劉攽','宋','宋诗','song-poetry','','[]','驅車長值險，投足正臨深。',48,'全唐诗/poet.song.35000.json','["驅車長值險，投足正臨深。", "白首抱壹意，故人知此心。", "巢禽歡避弋，轍鮒偶爲霖。", "去矣江湖興，淒然東武吟。"]'),
('d7c44f41-9028-4147-816c-f7cfbda2d0c4','苦熱  其一','劉攽','宋','宋诗','song-poetry','','[]','炎暉不可避，鬰鬰度朝晡。',48,'全唐诗/poet.song.35000.json','["炎暉不可避，鬰鬰度朝晡。", "飛鳥有時墮，高林無事枯。", "形骸等外物，橐籥任洪爐。", "正有捐塵濁，東浮萬里桴。"]'),
('2c5790a4-e002-4239-bb13-f468257066b0','苦熱  其二','劉攽','宋','宋诗','song-poetry','','[]','炎暉共茲世，南紀獨何偏。',48,'全唐诗/poet.song.35000.json','["炎暉共茲世，南紀獨何偏。", "天地大爐耳，江湖沸鼎然。", "魚龍危失所，黍稷恐無年。", "浩蕩思雷雨，長吟雲漢篇。"]'),
('8e9dd9e9-093a-4f9a-b6e0-b27c6c2d0af8','畫鶴','劉攽','宋','宋诗','song-poetry','','[]','置此憐神駿，三年故不飛。',48,'全唐诗/poet.song.35000.json','["置此憐神駿，三年故不飛。", "軒車寧假寵，野客會忘機。", "燕雀那相笑，鳬鷖直自肥。", "蓬萊千萬里，正想玉爲衣。"]'),
('5c164b58-5e23-46df-ab9e-01d88eb711b9','得楊十七書見報所居近種花木詩','劉攽','宋','宋诗','song-poetry','','[]','堪憂雖陋巷，寓興即名園。',48,'全唐诗/poet.song.35000.json','["堪憂雖陋巷，寓興即名園。", "似得壺公樂，如吹黍谷暄。", "艷花爭獻笑，芳草共忘言。", "近種南軒竹，春來亦有孫。"]'),
('09379971-c1d3-4d53-bf97-93489a062e8a','眼昏','劉攽','宋','宋诗','song-poetry','','[]','因循衰便至，邂逅眼成昏。',48,'全唐诗/poet.song.35000.json','["因循衰便至，邂逅眼成昏。", "稍與詩書隔，初慚長老言。", "談空迷起滅，蠅翼競飛翻。", "懶卧稱長策，深居欲杜門。"]'),
('b57dd545-3e50-47fb-8501-4e2725d2ed35','登浴室院閣  其一','劉攽','宋','宋诗','song-poetry','','[]','秋霽登臨好，危欄百尺梯。',48,'全唐诗/poet.song.35000.json','["秋霽登臨好，危欄百尺梯。", "層城斜照裏，雙闕五雲西。", "雜樹黄映綠，生煙高復低。", "章臺少年子，走馬錦障泥。"]'),
('a24401a8-5f26-49df-baf8-5c3ed81e5711','登浴室院閣  其二','劉攽','宋','宋诗','song-poetry','','[]','稍出紅塵外，方知萬象虛。',48,'全唐诗/poet.song.35000.json','["稍出紅塵外，方知萬象虛。", "林端辨遠水，樓角怪行車。", "燈續黄金像，香餘貝葉書。", "誰能捐世事，即地亦山居。"]'),
('06514958-ea39-41d8-ab79-71c096b4a2da','中夜見月','劉攽','宋','宋诗','song-poetry','','[]','月午四鄰靜，高齋人寂然。',48,'全唐诗/poet.song.35000.json','["月午四鄰靜，高齋人寂然。", "虛空時有警，影響善驚眠。", "宿羽移深樹，商胡慣夜船。", "無雲更可恨，珍重此嬋娟。"]'),
('f2cbea5f-bf99-4eaa-a1d1-b840bdbec187','新月','劉攽','宋','宋诗','song-poetry','','[]','稍見桑榆上，還沈河漢西。',48,'全唐诗/poet.song.35000.json','["稍見桑榆上，還沈河漢西。", "氣凉知露白，天闊見星低。", "靜色餘簾額，回光射鳥棲。", "城烏偏可恨，到曉不休啼。"]'),
('eef3d849-9f57-468f-b972-ecdac8f55eab','次韵和黄朝議  其一','劉攽','宋','宋诗','song-poetry','','[]','下武新周烈，謳歌屬禹謨。',48,'全唐诗/poet.song.35000.json','["下武新周烈，謳歌屬禹謨。", "恭聞始元詔，遠紹帝軒圖。", "山海無加賦，戎胡遂息徒。", "英風逾草偃，俯仰逮樵蘇。"]'),
('190e3c70-00a3-40e0-bea9-c5059e1f6117','次韵和黄朝議  其二','劉攽','宋','宋诗','song-poetry','','[]','已作華顛老，欣聞紫詔新。',48,'全唐诗/poet.song.35000.json','["已作華顛老，欣聞紫詔新。", "經綸兼事事，哀痛及人人。", "願輟須臾死，求觀富壽民。", "短歌隨擊壤，感動不無神。"]'),
('d3faf85c-96c9-4e86-b533-3a78016655be','傷丁元珍學士','劉攽','宋','宋诗','song-poetry','','[]','休沐非連騎，投沙迫去身。',48,'全唐诗/poet.song.35000.json','["休沐非連騎，投沙迫去身。", "似鴞憂鵩鳥，比鶴望鄉人。", "夢與江湖隔，情存翰墨新。", "定交相得晚，撫事亦酸辛。"]'),
('b03d72d9-f9dc-4763-8d9e-2215d881d536','喜雨','劉攽','宋','宋诗','song-poetry','','[]','山雨來何暮，高天始震雷。',48,'全唐诗/poet.song.35000.json','["山雨來何暮，高天始震雷。", "江聲翻灧澦，水氣逼昭回。", "灑落芳年晚，空凉醉眼開。", "蛟龍定神宅，蝸角更誰猜。"]'),
('6a4ee233-4cac-4830-9f1b-16a66f6f808f','漫成','劉攽','宋','宋诗','song-poetry','','[]','經旬柳已綠，過雨草齊生。',48,'全唐诗/poet.song.35000.json','["經旬柳已綠，過雨草齊生。", "無事觀兒戲，閒遊識鳥情。", "看花低帽立，弄水棹舟行。", "宦學都如夢，浮生底自名。"]'),
('6b5e6b79-03de-42d5-800f-f5ecfd482a99','次韵和司法掾陳郛','劉攽','宋','宋诗','song-poetry','','[]','晚得詩人賦，長謠長者言。',48,'全唐诗/poet.song.35000.json','["晚得詩人賦，長謠長者言。", "坐曹凉雨過，歸舍暮禽喧。", "交態傷貧富，時情任輊軒。", "懷歸空有夢，郢路屬營魂。"]'),
('c45f8164-ee10-402b-a5d7-d42bde6d9d2e','送慧思歸吳','劉攽','宋','宋诗','song-poetry','','[]','塵埃十年夢，江海一身歸。',48,'全唐诗/poet.song.35000.json','["塵埃十年夢，江海一身歸。", "境與夙心會，事容前日非。", "連山橫遠勢，定水湛明輝。", "別後相望處，雲孤雁自飛。"]'),
('d470c110-6b10-47af-89f7-0e62f5192f52','奠昭禪師','劉攽','宋','宋诗','song-poetry','','[]','昭公不住世，岑寂白蓮宮。',48,'全唐诗/poet.song.35000.json','["昭公不住世，岑寂白蓮宮。", "煮水終還冷，浮雲本自空。", "諸天方丈室，萬事百年翁。", "俯仰成今昔，蕭蕭鶴樹風。"]'),
('fafd8351-f459-463c-9e21-92fec1405276','送僧子南','劉攽','宋','宋诗','song-poetry','','[]','脫身游萬里，空手出長安。',48,'全唐诗/poet.song.35000.json','["脫身游萬里，空手出長安。", "猶以抱琴樂，不知行路難。", "春歸吳國遠，水滿紫溪寒。", "越俗今章甫，疑師不著冠。"]'),
('3c92c03d-8ba9-4ed0-b566-937a45a3c728','宋門城下新居','劉攽','宋','宋诗','song-poetry','','[]','頗習田野事，偶居朝市間。',48,'全唐诗/poet.song.35000.json','["頗習田野事，偶居朝市間。", "前塵應妄想，舊觀輒來還。", "甘井如汲澗，高城疑望山。", "更憐車馬絕，日在掩柴關。"]'),
('ccdf6e05-6b00-41ad-ade0-00ea3c0bf88d','新居','劉攽','宋','宋诗','song-poetry','','[]','舉世同逆旅，此身那拙謀。',48,'全唐诗/poet.song.35000.json','["舉世同逆旅，此身那拙謀。", "趣營容膝地，適似種瓜侯。", "藥餌扶多病，躬耕强隠憂。", "彈冠仍應客，車馬肯淹留。"]'),
('3e40bf4d-9fab-4214-9389-78c4bec02443','雪後行小園','劉攽','宋','宋诗','song-poetry','','[]','晚照開霽色，閉園幽事增。',48,'全唐诗/poet.song.35000.json','["晚照開霽色，閉園幽事增。", "樹摇風落雪，池漲水浮冰。", "鵲亂聲已變，鳶飛誰爲矜。", "風光看滿眼，取醉此吾能。"]'),
('5e5a1d18-1f8b-4c64-87cf-eebf625ac4eb','過丁晉公舊園','劉攽','宋','宋诗','song-poetry','','[]','寧知陵谷變，遂見曲池平。',48,'全唐诗/poet.song.35000.json','["寧知陵谷變，遂見曲池平。", "喬木祇益老，儲胥空復情。", "廢墀盈疊蘚，頹榭迹微行。", "桑霍爲厚戒，千秋餘嘆聲。"]'),
('4555a595-b00c-445c-952d-b6ad0fa2133f','雪夜酌酒','劉攽','宋','宋诗','song-poetry','','[]','雨雪寒休市，春泥早閉門。',48,'全唐诗/poet.song.35000.json','["雨雪寒休市，春泥早閉門。", "嚴城深窈窕，孤月靜黄昏。", "棲翼此中樹，高舂何處村。", "物容煩應接，乘興即開樽。"]'),
('8bf51ef8-d8ee-4236-8003-c35fb0c73cff','送雍元直使浙右','劉攽','宋','宋诗','song-poetry','','[]','詔給四封傳，自乘千里船。',48,'全唐诗/poet.song.35000.json','["詔給四封傳，自乘千里船。", "雲山深發興，秋物正蕭然。", "零雨隨持節，驚濤避執鞭。", "鱸肥稻米白，勝事奈君偏。"]'),
('f5c7620c-3e94-424c-a8b4-08b84d0ab5d8','引泉','劉攽','宋','宋诗','song-poetry','','[]','春池凍已消，泉落白魚跳。',48,'全唐诗/poet.song.35000.json','["春池凍已消，泉落白魚跳。", "石淺喧鳴玉，沙虛沒暗潮。", "晚寒妨濯足，竟日欲平橋。", "最愛臨波柳，東風萬萬條。"]'),
('797433bc-de8a-48e9-baf3-2f1650b496ac','金鳳花','劉攽','宋','宋诗','song-poetry','','[]','妖嬈如自媚，紅白競爲娛。',48,'全唐诗/poet.song.35000.json','["妖嬈如自媚，紅白競爲娛。", "共笑翔千仞，猶疑將九雛。", "軒墀蒙𥈅睞，風雨易泥塗。", "靜掃蒼苔地，還令近酒壺。"]'),
('2dd79157-cfda-4e6d-9eb5-f8451891dd7d','景潮亭','劉攽','宋','宋诗','song-poetry','','[]','澤國水遥遠，歸舟亭短長。',48,'全唐诗/poet.song.35000.json','["澤國水遥遠，歸舟亭短長。", "他方向夕景，此地正朝陽。", "物色桑榆上，風波鳬雁行。", "臨流問漁父，好在濯滄浪。"]'),
('4e37c4e3-0268-4cb6-8191-0c3d15d50c76','退朝觀御溝上雜花贈陸四','劉攽','宋','宋诗','song-poetry','','[]','溝水去無窮，宮花映日紅。',48,'全唐诗/poet.song.35000.json','["溝水去無窮，宮花映日紅。", "惜陰猶宿露，照影獨衰翁。", "燕語晴明外，風香錦繡中。", "爲非溫室問，心賞幸君同。"]'),
('c5ee7978-b75b-425c-9174-fcb6e53d8ffa','上三山磯','劉攽','宋','宋诗','song-poetry','','[]','江湍趨絕壁，山木映雲濤。',48,'全唐诗/poet.song.35000.json','["江湍趨絕壁，山木映雲濤。", "野路青冥近，孤舟應接勞。", "魚龍防碎首，鳥獸幾亡曹。", "生事垂堂戒，愁心欲二毛。"]'),
('aac27b24-8e92-4aee-8874-cca90f186c22','過龍眼磯','劉攽','宋','宋诗','song-poetry','','[]','洪波浮一葉，弱髮引千鈞。',48,'全唐诗/poet.song.35000.json','["洪波浮一葉，弱髮引千鈞。", "虎豹公橫道，蛟龍喜得人。", "强顔猶失色，乘險屢傷神。", "回首雙鳬翼，隨波愧此身。"]'),
('0649dd09-3349-434e-8075-366e6ee9c7e5','送鄭五下第西歸','劉攽','宋','宋诗','song-poetry','','[]','萬里河西路，憐君徒步歸。',48,'全唐诗/poet.song.35000.json','["萬里河西路，憐君徒步歸。", "遊人並塞少，落葉待霜飛。", "相得不恨晚，知音深謂稀。", "壯心須慷慨，勿學淚沾衣。"]'),
('59186b80-bf83-4574-bba6-7f8ab4efc0fd','送人之官嶺南','劉攽','宋','宋诗','song-poetry','','[]','過嶺幾千里，孤城近海涯。',48,'全唐诗/poet.song.35000.json','["過嶺幾千里，孤城近海涯。", "地溫饒瘴毒，民惡半蠻家。", "并日初開市，非春亦有花。", "知君望星斗，西北認京華。"]'),
('75fb09cf-d4ba-458a-a69d-e894a7dc5aff','和孫少述中秋  其一','劉攽','宋','宋诗','song-poetry','','[]','月出東山表，遥思澤國秋。',48,'全唐诗/poet.song.35000.json','["月出東山表，遥思澤國秋。", "綠雲孤鏡上，透水大珠浮。", "重露梧桐落，微寒蟋蟀愁。", "我時携客飲，浮白最高樓。"]'),
('3295d756-b383-48c8-9638-4bd6c8f2048c','和孫少述中秋  其二','劉攽','宋','宋诗','song-poetry','','[]','竟夕雲四斂，始知天意偏。',48,'全唐诗/poet.song.35000.json','["竟夕雲四斂，始知天意偏。", "西風不勝冷，亭午更添圓。", "老髮緣詩苦，秋懷得酒便。", "君居江浦上，望我想依然。"]'),
('8ed89da1-94e9-4ddc-ad42-c9875b4dfceb','春日野次','劉攽','宋','宋诗','song-poetry','','[]','溪雲晴漠漠，野日晝陰陰。',48,'全唐诗/poet.song.35000.json','["溪雲晴漠漠，野日晝陰陰。", "燕翼飛高下，花房亂淺深。", "和風快吹面，浄水喜清心。", "極目傷千里，曾無楓樹林。"]'),
('4a105e70-abc8-4954-b4c4-325839b0a3cb','南原','劉攽','宋','宋诗','song-poetry','','[]','南原殊可望，桑柘百家村。',48,'全唐诗/poet.song.35000.json','["南原殊可望，桑柘百家村。", "紫赤春晴氣，青葱舊燒痕。", "遠川飛雁鶩，平壤牧鷄豚。", "更待花如織，臨高置一樽。"]'),
('c93340b0-b5b2-468a-9689-a9596bb55b02','遠信','劉攽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','清秋萬里夢，久客一封書。',48,'全唐诗/poet.song.35000.json','["清秋萬里夢，久客一封書。", "長日看鴻雁，呼兒問鯉魚。", "凉風郢路遠，落葉洞庭初。", "無限歸鳬翼，南飛最跂予。"]'),
('0d1879b7-d529-45c3-b452-67ea3687065c','金沙花','劉攽','宋','宋诗','song-poetry','','[]','苒弱金沙樹，花奇名字珍。',48,'全唐诗/poet.song.35000.json','["苒弱金沙樹，花奇名字珍。", "移從今日晚，恨失去年春。", "嫩綠藤垂架，深紅棘刺人。", "東風會入手，照眼萬枝新。"]'),
('184e067a-d699-4518-83d5-a19620572f20','贈鄰翁','劉攽','宋','宋诗','song-poetry','','[]','與彼茅茨接，看渠卜築初。',48,'全唐诗/poet.song.35000.json','["與彼茅茨接，看渠卜築初。", "丈人真耄矣，孺子復何如。", "翁且勤杯酒，兒教讀道書。", "衡門來往近，時爲過吾廬。"]'),
('4430bcf8-135f-4774-aa8f-9fdaefd8b74e','初晴贈某翁','劉攽','宋','宋诗','song-poetry','','[]','雲隨夜色改，日與曙光升。',48,'全唐诗/poet.song.35000.json','["雲隨夜色改，日與曙光升。", "已變前除雪，猶餘北戶冰。", "鴻飛知適意，鶴語若矜能。", "天事寬羈旅，幽人亦有朋。"]'),
('ef67619d-0e43-425c-8d1a-a59fcc829abc','晨起','劉攽','宋','宋诗','song-poetry','','[]','斷角續鳴鐘，惜時春已空。',48,'全唐诗/poet.song.35000.json','["斷角續鳴鐘，惜時春已空。", "曉星猶伴月，早雨不禁風。", "眠食須頤老，衣冠强自公。", "庭陰全綠色，無復見殘紅。"]'),
('cac979b0-f934-444c-9c32-ade78d6d9e98','挽胡元夫母壽安縣太君二首  其一','劉攽','宋','宋诗','song-poetry','','[]','應嫗金琛社，桓釐邑致膰。',48,'全唐诗/poet.song.35000.json','["應嫗金琛社，桓釐邑致膰。", "母儀真盛德，祿養現興門。", "尚想君羹遺，那悲口澤存。", "蒼山松梓暮，弔鶴去翩翻。"]'),
('8b853395-f269-4ff8-ba75-faa3a32edc0b','挽胡元夫母壽安縣太君二首  其二','劉攽','宋','宋诗','song-poetry','','[]','清德畏人知，傳家頼母慈。',48,'全唐诗/poet.song.35000.json','["清德畏人知，傳家頼母慈。", "何時丹桂擢，相戒白華詩。", "戲綵歡無極，藏舟事密移。", "千鍾已不暨，後日可勝悲。"]'),
('df733e03-5fc3-49c2-b497-f8b8a08cf75b','孟冬','劉攽','宋','宋诗','song-poetry','','[]','十月江南暑，居人尚葛衣。',48,'全唐诗/poet.song.35000.json','["十月江南暑，居人尚葛衣。", "秋花看不絕，沙鳥聽忘歸。", "氣鬰愁成瘴，霜輕嘆失威。", "異方羈旅思，歲事每多違。"]'),
('0ec46315-050e-42e9-95fe-4dba5a865b0e','午睡','劉攽','宋','宋诗','song-poetry','','[]','浮雲蔽白日，風雨近秋天。',48,'全唐诗/poet.song.35000.json','["浮雲蔽白日，風雨近秋天。", "車馬欲安適，戶庭方閴然。", "世塗高枕外，身事曲肱前。", "似覺松生腹，迢遥不記年。"]'),
('5e20a5b3-e356-4efd-8b6c-3421ad6061b4','古槐二首  其一','劉攽','宋','宋诗','song-poetry','','[]','地有藏丹井，人傳不死鄉。',48,'全唐诗/poet.song.35000.json','["地有藏丹井，人傳不死鄉。", "南柯經腊李，黑葉勝枯楊。", "甲錯龍鱗斷，花明鼠耳黄。", "離宮緣望幸，仙檜儼相望。"]'),
('7ec4282c-eefc-4f22-b2b1-ffa4c76fa862','古槐二首  其二','劉攽','宋','宋诗','song-poetry','','[]','仙人鍊形骨，枯槁不知年。',48,'全唐诗/poet.song.35000.json','["仙人鍊形骨，枯槁不知年。", "秀色倏還觀，陽和仍宛然。", "今古山川異，乾坤雨露偏。", "東陽無歇息，生意會綿綿。"]'),
('3e9bfa33-7669-4e17-b90e-2c64ae367640','復和前韵二首  其一','劉攽','宋','宋诗','song-poetry','','[]','遺履事悠遠，白雲飛帝鄉。',48,'全唐诗/poet.song.35000.json','["遺履事悠遠，白雲飛帝鄉。", "潛真社寄櫟，觀化肘生楊。", "秀葉髮垂綠，雜英牙變黄。", "犧尊與溝斷，俗骨爾何望。"]'),
('389eff57-3b72-4756-9ed0-d8f86f712979','復和前韵二首  其二','劉攽','宋','宋诗','song-poetry','','[]','父老見枯朽，皆從童稚年。',48,'全唐诗/poet.song.35000.json','["父老見枯朽，皆從童稚年。", "孫枝復秀色，仙事故依然。", "巢鶴千齡異，源泉一溉偏。", "頗笑海棕陋，崎嶇留在綿。"]'),
('68077302-8d07-4ab9-9ae0-82690e9e9f71','秋暑呈馮守','劉攽','宋','宋诗','song-poetry','','[]','秋律何時效，炎雲莫肯陰。',48,'全唐诗/poet.song.35000.json','["秋律何時效，炎雲莫肯陰。", "烈風長鼓鞴，去水亦流金。", "藿食無求飽，單絺不自任。", "開懷幸寬政，事省得清心。"]'),
('54391393-4111-4579-82e6-37820c126175','宿荆門','劉攽','宋','宋诗','song-poetry','','[]','山行厭曲折，小邑正歡譁。',48,'全唐诗/poet.song.35000.json','["山行厭曲折，小邑正歡譁。", "流水纔一带，居人聚兩涯。", "池偏饒草木，山晚聚雲霞。", "郢路定未遠，夢魂還到家。"]'),
('80ded71f-117d-4ea1-8902-9e1f8a9c6335','西湖水决','劉攽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平原出大水，蟻壤潰長汀。',48,'全唐诗/poet.song.35000.json','["平原出大水，蟻壤潰長汀。", "舟檝疑藏壑，波濤駭建瓴。", "蛟龍隨過雨，魚鼈問滄溟。", "聞道蓬萊水，桑田亦屢經。"]'),
('34d27de6-2b6f-4560-9baa-02c7735b2469','素屏','劉攽','宋','宋诗','song-poetry','','[]','陋室避塵雜，深居惟此屏。',48,'全唐诗/poet.song.35000.json','["陋室避塵雜，深居惟此屏。", "虛空自生白，樸素擬忘形。", "畫手山林迹，先生几杖銘。", "長來師絕學，未肯事丹青。"]'),
('d6f68e77-c899-4348-a258-6143c6592f07','燒殘樹','劉攽','宋','宋诗','song-poetry','','[]','異時龍起蟄，一夕鳥焚巢。',48,'全唐诗/poet.song.35000.json','["異時龍起蟄，一夕鳥焚巢。", "摧落殘孤幹，荒凉委近郊。", "莓苔深蟻穴，風雨詫神交。", "尚想知音遇，空心或遠庖。"]'),
('c1b0352b-5f98-41d2-8976-8dff0293d4f6','避風','劉攽','宋','宋诗','song-poetry','','[]','南風多疊浪，逆水暫回船。',48,'全唐诗/poet.song.35000.json','["南風多疊浪，逆水暫回船。", "畫鷁秋相對，沙鷗靜獨眠。", "微明見雲樹，孤絕問人煙。", "吾道常如此，聽歌枉渚邅。"]'),
('b03ecee8-7e63-4fe3-bb2e-bfe4c7158adc','同原甫咏秘閣詔藏古器圖','劉攽','宋','宋诗','song-poetry','','[]','昔占金寶氣，天瑞告成功。',48,'全唐诗/poet.song.35000.json','["昔占金寶氣，天瑞告成功。", "繪事今時絕，書文自古同。", "剖鈎記巫錦，按刻異桓公。", "塵世無由睹，崑山策府中。"]'),
('0bd15d1c-02c9-476a-85cc-bde236627184','王廣淵郎中挽詩','劉攽','宋','宋诗','song-poetry','','[]','家本秦川貴，舊傳淮水占。',48,'全唐诗/poet.song.35000.json','["家本秦川貴，舊傳淮水占。", "省郎時望在，公族主恩兼。", "轉燭風何急，棲塵草正纖。", "襄陽今罷市，涕淚萬人霑。"]'),
('724e30e6-0281-4808-a0b9-d857cb83b432','劉彝學士挽詩','劉攽','宋','宋诗','song-poetry','','[]','傳聞四君子，同是五經師。',48,'全唐诗/poet.song.35000.json','["傳聞四君子，同是五經師。", "獨以功名誤，空思俎豆爲。", "不成宣室召，長負雁門期。", "頼有銘泉室，千秋無愧詞。"]'),
('73914f14-b079-4ad0-84fd-e7e90786ded9','重過觀音精舍舊讀書房','劉攽','宋','宋诗','song-poetry','','[]','往作關東客，來携一束書。',48,'全唐诗/poet.song.35000.json','["往作關東客，來携一束書。", "旅人觀所主，野性樂玄虛。", "過事都如夢，精廬宛若初。", "空憐兩蓬鬢，蕭颯十年餘。"]'),
('46146276-a3da-403e-8988-8df6ebc578be','過雍熙院興師房','劉攽','宋','宋诗','song-poetry','','[]','習靜未離解，悟空猶著禪。',48,'全唐诗/poet.song.35000.json','["習靜未離解，悟空猶著禪。", "齋居性所近，古寺境蕭然。", "瓶水寒生凍，爐香暝裊煙。", "老僧眉雪白，晏坐已忘年。"]'),
('1cf99c55-0229-4cc3-b43b-4e33049276d8','夜雨','劉攽','宋','宋诗','song-poetry','','[]','天暝龍蛇化，風高鳥獸呼。',48,'全唐诗/poet.song.35000.json','["天暝龍蛇化，風高鳥獸呼。", "塵囂一洒盡，暑病暫時蘇。", "電火將焚野，雷車若隘塗。", "坐疑陵谷變，明發蹈江湖。"]'),
('5f926b3a-7868-48db-8f52-5dd13324e74a','江上夜雨','劉攽','宋','宋诗','song-poetry','','[]','江黑暮潮生，雲深驟雨傾。',48,'全唐诗/poet.song.35000.json','["江黑暮潮生，雲深驟雨傾。", "風波兩舟語，燈火一川明。", "短夜苦難曙，羈懷方未平。", "空憐夢中路，依約盡歸程。"]'),
('bd8ab5f4-105e-4c86-b908-9891a794c270','慶壽挽詩二首  其一','劉攽','宋','宋诗','song-poetry','','[]','史占書五鹿，世德活千人。',48,'全唐诗/poet.song.35000.json','["史占書五鹿，世德活千人。", "孝養東朝盛，徽音赤管新。", "濯龍虛望幸，繭館不知春。", "歷數姜任事，寧如復辟辰。"]'),
('2a9e5608-ca80-4e55-94fa-fe0fb35f5d6d','慶壽挽詩二首  其二','劉攽','宋','宋诗','song-poetry','','[]','鹵簿嚴仙仗，笳簫去掖門。',48,'全唐诗/poet.song.35000.json','["鹵簿嚴仙仗，笳簫去掖門。", "晝閒長樂衛，春寂灞陵園。", "壹德詒謀地，群生顧復恩。", "神遊餘仿像，日入際崑崙。"]'),
('480b7c29-a606-4495-a16f-8bace9bed1cb','營冬二首  其一','劉攽','宋','宋诗','song-poetry','','[]','羈旅殊多事，崩騰欲老身。',48,'全唐诗/poet.song.35000.json','["羈旅殊多事，崩騰欲老身。", "連年俱異邑，幾地愧鄰人。", "板屋秦詩舊，衡門泌水新。", "何時仲長子，卜築離風塵。"]'),
('016ccd3f-aff6-4784-a68d-00f23ea799c0','營冬二首  其二','劉攽','宋','宋诗','song-poetry','','[]','薙草元留徑，開窗祇近檐。',48,'全唐诗/poet.song.35000.json','["薙草元留徑，開窗祇近檐。", "成冬須少有，爲客未嘗淹。", "朋舊看都絕，詩書剩欲嫌。", "自知疏懶劇，决意老幽潛。"]'),
('d13f68ed-4aeb-466c-b611-35c9c017feb5','思歸','劉攽','宋','宋诗','song-poetry','','[]','扁舟到北郭，屣履向東門。',48,'全唐诗/poet.song.35000.json','["扁舟到北郭，屣履向東門。", "不改蓬蒿陋，猶憐松菊存。", "因秋動歸興，值物愴離魂。", "早晚城頭月，呼兒坐小軒。"]'),
('26579f03-7df2-4396-9a17-1678231acad7','楊花','劉攽','宋','宋诗','song-poetry','','[]','不分春色晚，楊花意氣驕。',48,'全唐诗/poet.song.35000.json','["不分春色晚，楊花意氣驕。", "吹噓輕一羽，容易點層霄。", "細細穿檐隙，姍姍學舞腰。", "暫來幽僻地，還復去人遥。"]'),
('2687be43-e12a-4fcc-b5f5-71a075388477','移居觀音寺','劉攽','宋','宋诗','song-poetry','','[]','棲息避城市，塵埃將浼人。',48,'全唐诗/poet.song.35000.json','["棲息避城市，塵埃將浼人。", "虛空見佛性，簡傲得吾真。", "霜過草木改，齋餘鳥雀馴。", "席門常晝閉，誰與駐車輪。"]'),
('231a2f53-b8ef-48ed-8eb8-111243b355e1','題陝西圖三首  其一','劉攽','宋','宋诗','song-poetry','','[]','干戈今日事，關塞此圖看。',48,'全唐诗/poet.song.35000.json','["干戈今日事，關塞此圖看。", "白日長安近，蒼山壠坂寒。", "由來名百二，自古有艱難。", "指以安西道，凝情意據鞍。"]'),
('95542e18-cd20-4636-8213-4186f93fe899','題陝西圖三首  其二','劉攽','宋','宋诗','song-poetry','','[]','萬里靈州地，他年漢朔方。',48,'全唐诗/poet.song.35000.json','["萬里靈州地，他年漢朔方。", "山河從割棄，關輔急堤防。", "轉益豺狼窟，堪嗟禮義鄉。", "拔胡須壯士，看畫意蒼茫。"]'),
('6e984d81-ab68-440e-a942-d0e35f3571ac','題陝西圖三首  其三','劉攽','宋','宋诗','song-poetry','','[]','河源來積石，天馬涉流沙。',48,'全唐诗/poet.song.35000.json','["河源來積石，天馬涉流沙。", "耳目成千古，丹青在一涯。", "荒凉都護府，斷絕使臣槎。", "安得山河將，收功似漢家。"]'),
('c6c2d782-c6f8-401b-96c3-41126ea3c495','五月二首  其一','劉攽','宋','宋诗','song-poetry','','[]','五月黄梅熟，江邊晝雨初。',48,'全唐诗/poet.song.35000.json','["五月黄梅熟，江邊晝雨初。", "鏽痕侵匣劍，潤氣蠹囊書。", "亂恐翻銀漢，喧愁洩尾閭。", "時時雙水鳥，往往上吾廬。"]'),
('5d89e19e-6a24-446d-95cd-600e639b5257','五月二首  其二','劉攽','宋','宋诗','song-poetry','','[]','榻移隨樹影，杯側見山岑。',48,'全唐诗/poet.song.35000.json','["榻移隨樹影，杯側見山岑。", "白鳥渴求水，玄蟬清噪林。", "道書無近語，天籟有遺音。", "向北新開徑，行苔過竹陰。"]'),
('49d6429c-0d4c-4170-b442-fac69870dd13','江上雨中','劉攽','宋','宋诗','song-poetry','','[]','江雲似無信，山雨易翻盆。',48,'全唐诗/poet.song.35000.json','["江雲似無信，山雨易翻盆。", "鵬起天形黑，龍驤水面渾。", "大舟纔弱纜，孤樹小前村。", "濯熱吾知慰，風波勿重論。"]'),
('915b319c-212e-45c4-8e8b-5c886a3b1e7c','和王待制湘東王故苑','劉攽','宋','宋诗','song-poetry','','[]','故園悲帝子，高興復清秋。',48,'全唐诗/poet.song.35000.json','["故園悲帝子，高興復清秋。", "密竹娟娟靜，通波細細流。", "干戈餘魯殿，池沼似滄洲。", "魚鳥應無恨，山公肯醉遊。"]'),
('23f8e572-c875-411e-b7a5-f90a3061ae3f','冬暖','劉攽','宋','宋诗','song-poetry','','[]','南瘴無消息，玄冥爲失威。',48,'全唐诗/poet.song.35000.json','["南瘴無消息，玄冥爲失威。", "水深鴻雁宿，霜薄鷓鴣飛。", "處處憐喬木，人人慣袷衣。", "生涯卑濕地，日飲自知機。"]'),
('762bab85-1d10-448a-bfd1-f7eec98e0d20','忝官','劉攽','宋','宋诗','song-poetry','','[]','忝官東北藩，老拙復何言。',48,'全唐诗/poet.song.35000.json','["忝官東北藩，老拙復何言。", "曹事輒付外，客車稀到門。", "臨池看魚樂，倚杖聽禽喧。", "莫恨三年最，從今長子孫。"]'),
('bd81b059-7b93-46a1-851c-7f7038f09b00','雨中','劉攽','宋','宋诗','song-poetry','','[]','沈陰連日雨，六月似高秋。',48,'全唐诗/poet.song.35000.json','["沈陰連日雨，六月似高秋。", "凉冷宵眠穩，泥塗晝事休。", "塵昏舊銅鏡，朽蠹敝貂裘。", "頼有盈樽酒，能爲懶病謀。"]'),
('6ff27d99-09fb-4e49-89dd-eb660489e113','雨後','劉攽','宋','宋诗','song-poetry','','[]','積雨黄梅後，多風夕景天。',48,'全唐诗/poet.song.35000.json','["積雨黄梅後，多風夕景天。", "少陰回玉燭，秋氣變薰弦。", "孤鳥爰居外，殘雲螮蝀邊。", "羽陵書蠹盡，數怪絕韋編。"]'),
('69e78441-ae09-4e16-8ac2-5f31c36aee97','欲雨','劉攽','宋','宋诗','song-poetry','','[]','久晴驚礎潤，信宿候風回。',48,'全唐诗/poet.song.35000.json','["久晴驚礎潤，信宿候風回。", "仰月光如瓦，燒雲色變灰。", "歡蛙疑自得，青鷁競飛來。", "正想江南地，清凉接過梅。"]'),
('aed1d196-4954-4a97-a368-83e966a479d0','北窗聞雨','劉攽','宋','宋诗','song-poetry','','[]','庭梧不隠響，秋入意蕭條。',48,'全唐诗/poet.song.35000.json','["庭梧不隠響，秋入意蕭條。", "過雨喧天籟，高風會海潮。", "寒侵知洒近，氣豁想雲遥。", "歲晚看摇落，無衣恥敝貂。"]'),
('48966012-5b6d-4ab3-b192-c6700cdac6f3','雨','劉攽','宋','宋诗','song-poetry','','[]','繁陰晝漠漠，日雨暝紛紛。',48,'全唐诗/poet.song.35000.json','["繁陰晝漠漠，日雨暝紛紛。", "鬥蟻仍移市，乖龍亦過雲。", "泥塗休不出，鐘鼓遣相聞。", "願得辭昏墊，長風破宿氛。"]'),
('3baae325-dfee-44d7-a204-723c23706fb2','酴醿軒雨中二首  其一','劉攽','宋','宋诗','song-poetry','','[]','小雨疏陰響，高風綠幕斜。',48,'全唐诗/poet.song.35000.json','["小雨疏陰響，高風綠幕斜。", "冷吹能却暑，細滴不妨花。", "輕濕苔痕滑，連陰草色加。", "路長車馬少，暫喜息飛沙。"]'),
('113763f6-f09c-4945-84a7-1b4a9dec8437','酴醿軒雨中二首  其二','劉攽','宋','宋诗','song-poetry','','[]','病身常自力，杖屨及比鄰。',48,'全唐诗/poet.song.35000.json','["病身常自力，杖屨及比鄰。", "繼日傷霖雨，深居若避人。", "陰苔無數綠，秋草一番新。", "入夜添凉冷，書燈頓可親。"]'),
('9284f609-85fd-4d28-8b10-6d8f8d651dd8','巢湖阻風二首  其一','劉攽','宋','宋诗','song-poetry','','[]','重雲迷日月，異縣失西東。',48,'全唐诗/poet.song.35000.json','["重雲迷日月，異縣失西東。", "苦畏連天水，何須竟夕風。", "微明分白鳥，摇落望青楓。", "久客嗟留滯，吾生事事同。"]'),
('d7f5e623-ad17-40cd-948d-4b2d85aa0578','巢湖阻風二首  其二','劉攽','宋','宋诗','song-poetry','','[]','四月風猶北，湖邊氣似秋。',48,'全唐诗/poet.song.35000.json','["四月風猶北，湖邊氣似秋。", "天時如反置，吾道信淹留。", "望遠還吹帽，憎寒更擁裘。", "無由開白日，晦暝使人愁。"]'),
('b4adf1d5-87d2-4b2b-a4a4-c84131acf9f7','安河阻風','劉攽','宋','宋诗','song-poetry','','[]','隨湖寄漁浦，村戍起孤烟。',48,'全唐诗/poet.song.35000.json','["隨湖寄漁浦，村戍起孤烟。", "水色連天黑，沙禽亦晝眠。", "柘田春種麥，客渡晚爭船。", "盡日無他事，尋村聽野泉。"]'),
('4d52bc75-3a9a-4bec-aa1f-55c84575470a','凝翠堂','劉攽','宋','宋诗','song-poetry','','[]','聳聳排修竹，蕭蕭拂蠹檐。',48,'全唐诗/poet.song.35000.json','["聳聳排修竹，蕭蕭拂蠹檐。", "秋聲送凉雨，晚影碎寒蟾。", "居處貧非病，生涯智養恬。", "著書聊自守，非欲效幽潛。"]'),
('7a756dad-3f91-4bc9-8061-d07ab49a5aa1','留張十二宿','劉攽','宋','宋诗','song-poetry','','[]','靜外塵土息，故人從我遊。',48,'全唐诗/poet.song.35000.json','["靜外塵土息，故人從我遊。", "襟懷已瀟洒，杯酒聊勸酬。", "大笑呼五白，浩歌遣四愁。", "勞生如此少，嘆息爲君留。"]'),
('10def642-d312-41f2-963c-fb5546d25159','王太傅河北閱馬','劉攽','宋','宋诗','song-poetry','','[]','豐草河壖地，平沙冀北區。',48,'全唐诗/poet.song.35000.json','["豐草河壖地，平沙冀北區。", "離宮連苜蓿，舊苑半騊駼。", "夫子深詩者，無邪頒使乎。", "寧令漢馬少，不議擊匈奴。"]'),
('3a167bd2-e019-42e0-9ca5-9ca60d0adc33','庶幾堂','劉攽','宋','宋诗','song-poetry','','[]','碧草衡門裏，凉天過雨初。',48,'全唐诗/poet.song.35000.json','["碧草衡門裏，凉天過雨初。", "驚秋數甲子，隠几讀殘書。", "近郭多鳴鶴，坳堂可釣魚。", "異方無到客，非是故人疏。"]'),
('bc804a6f-8185-4b88-9e22-ad0eb0b33acf','歲除立春乾祐縣獻梅','劉攽','宋','宋诗','song-poetry','','[]','除日應無歲，新春不待年。',48,'全唐诗/poet.song.35000.json','["除日應無歲，新春不待年。", "風光生意裏，梅信客情邊。", "冷艷來冰谷，疏風映雪天。", "不逢江上使，相與競芳妍。"]'),
('0787807f-0598-4377-a60e-f0409bf3901b','挽胡太傅二首  其一','劉攽','宋','宋诗','song-poetry','','[]','州來推博物，伯始貴中庸。',48,'全唐诗/poet.song.35000.json','["州來推博物，伯始貴中庸。", "論道宜黄髮，銘功遍景鐘。", "龍門餘舊客，馬鬣悵新封。", "後世瞻遺德，南山萬丈峰。"]'),
('a6f8eebc-67e0-42bc-97c8-dcb65c6b182d','挽胡太傅二首  其二','劉攽','宋','宋诗','song-poetry','','[]','路車申伯去，白馬庾公歸。',48,'全唐诗/poet.song.35000.json','["路車申伯去，白馬庾公歸。", "殄瘁人相弔，哀歌露易晞。", "石麟森立木，蜜印鎖泉扉。", "絮酒慚徐孺，回看旅雁飛。"]'),
('71cf12d9-7a26-4d84-971c-620726406499','挽西京左藏使石太保二首  其一','劉攽','宋','宋诗','song-poetry','','[]','勇擲諸生筆，終乘使者車。',48,'全唐诗/poet.song.35000.json','["勇擲諸生筆，終乘使者車。", "家聲唯孝謹，將略亦詩書。", "鶴髮遺榮始，瀧岡卜兆初。", "謬承公叔薦，曾未撇衣裾。"]'),
('f44b14ab-84a7-4cb8-8be8-df97156fe2f2','挽西京左藏使石太保二首  其二','劉攽','宋','宋诗','song-poetry','','[]','青綬股肱守，毳衣方伯監。',48,'全唐诗/poet.song.35000.json','["青綬股肱守，毳衣方伯監。", "威名真落落，碩望自巖巖。", "道遠年如待，才長志尚緘。", "家多二千石，會見集門凡。"]'),
('a783441d-62b6-4e73-b6eb-e90140016789','挽宋司空丞相二首  其一','劉攽','宋','宋诗','song-poetry','','[]','斗樞齊七政，鼎鉉象三公。',48,'全唐诗/poet.song.35000.json','["斗樞齊七政，鼎鉉象三公。", "文武兼人際，安危注意同。", "規隨餘故事，止足暢高風。", "他日雲臺畫，依然想竇融。"]'),
('8e372b3c-f320-4857-b885-afc5850e4bda','挽宋司空丞相二首  其二','劉攽','宋','宋诗','song-poetry','','[]','蜜印加泉室，哀簫去國門。',48,'全唐诗/poet.song.35000.json','["蜜印加泉室，哀簫去國門。", "降龍嚴冕服，畫鹿並車轓。", "山甫中興業，臧孫既歿言。", "定應天壤內，長與日星存。"]'),
('8d012cc7-cf08-4f29-8a8f-ca89d2f7bfdb','月夜吹簫','劉攽','宋','宋诗','song-poetry','','[]','長路見秋月，空江連夜明。',48,'全唐诗/poet.song.35000.json','["長路見秋月，空江連夜明。", "吹簫不能寐，舉酒遞相傾。", "賈客或垂淚，羈人多失聲。", "湘絃苦沉絕，曲盡一含情。"]'),
('9f545a7f-b24e-44c0-ba45-8880cfa4f9f7','秦國公主挽詩','劉攽','宋','宋诗','song-poetry','','[]','渭陽追舅氏，婺女嫁天孫。',48,'全唐诗/poet.song.35000.json','["渭陽追舅氏，婺女嫁天孫。", "平日諸姑問，當時赤綬尊。", "烟波空北渚，荻竹自長門。", "後夜秦樓月，哀簫閟九原。"]'),
('5ac68783-7020-44ec-bc3f-07d59ddbaab0','宿峴山寺二首  其一','劉攽','宋','宋诗','song-poetry','','[]','睠予倦羈旅，坎壈林壑間。',48,'全唐诗/poet.song.35000.json','["睠予倦羈旅，坎壈林壑間。", "落日投古寺，秋蟲吟亂山。", "月明露已白，風定雲方還。", "王事殊未暇，悵茲清夜閒。"]'),
('34c5f750-d434-404d-a6f8-879f39881297','宿峴山寺二首  其二','劉攽','宋','宋诗','song-poetry','','[]','蒼山若無路，落日聽鳴鐘。',48,'全唐诗/poet.song.35000.json','["蒼山若無路，落日聽鳴鐘。", "旁舍適眠虎，古潭微見龍。", "空窗向雲月，高枕聽風松。", "幽境昔未遘，仙游如可逢。"]'),
('934cab51-7e3b-47f2-94b3-5233e55d0314','觀虎翼士戍宜州','劉攽','宋','宋诗','song-poetry','','[]','虎賁王爪士，銅柱國南門。',48,'全唐诗/poet.song.35000.json','["虎賁王爪士，銅柱國南門。", "魑魅非人境，蠻夷盡鳥言。", "瘴烟旗纛黑，霧雨劍鋩昏。", "即路皆無色，何時見北轅。"]'),
('d2051533-2285-4fe3-a2e5-93985df031ea','再見士卒戍桂陽','劉攽','宋','宋诗','song-poetry','','[]','驛書頻插羽，漢士遠征蠻。',48,'全唐诗/poet.song.35000.json','["驛書頻插羽，漢士遠征蠻。", "四月天將暑，三苗舊阻艱。", "悲笳背城邑，苦霧濕關山。", "後夜東南望，妖氛翼軫間。"]'),
('189900bb-b407-479c-ae30-409b765ccd78','悼楊公緼二首  其一','劉攽','宋','宋诗','song-poetry','','[]','得君雖恨晚，白髮幸前期。',48,'全唐诗/poet.song.35000.json','["得君雖恨晚，白髮幸前期。", "分手遂陳迹，晤言成獨悲。", "隙駒得未久，風燭不勝危。", "詎有修文選，高天可易知。"]'),
('b7fad5b7-dc4e-4c0d-a301-12e9eeabc1aa','悼楊公緼二首  其二','劉攽','宋','宋诗','song-poetry','','[]','寄書曾未報，題墨宛如新。',48,'全唐诗/poet.song.35000.json','["寄書曾未報，題墨宛如新。", "長路歸丹旐，孤兒泣畫輴。", "江湖餘氣槩，星月聚精神。", "冥漠九原上，空將萬鬼鄰。"]'),
('e4c87194-6732-468d-9246-b41f314e585f','秋懷二首  其一','劉攽','宋','宋诗','song-poetry','','[]','摇落看秋色，淹留倦郢城。',48,'全唐诗/poet.song.35000.json','["摇落看秋色，淹留倦郢城。", "登臨想自昔，風土最含情。", "白露黄橙熟，清風綠桂生。", "異鄉隨衆醉，須爾析朝酲。"]'),
('41d0d43d-7117-4a6c-b12b-f10d33bc6710','秋懷二首  其二','劉攽','宋','宋诗','song-poetry','','[]','蒹葭晚已變，天宇向來高。',48,'全唐诗/poet.song.35000.json','["蒹葭晚已變，天宇向來高。", "風露一瀟洒，江湖久鬰陶。", "鱸魚越人膾，白露廣陵濤。", "歸興憑三鳥，悲秋嘆二毛。"]'),
('8974b5b9-4859-4fc0-acb5-c9c1345d8d3d','夕霧','劉攽','宋','宋诗','song-poetry','','[]','日落山氣改，汀洲寒霧生。',48,'全唐诗/poet.song.35000.json','["日落山氣改，汀洲寒霧生。", "深沈轉墟落，迢遞失重城。", "樹裏迷人語，沙頭見火明。", "商帆宿何處，彷彿棹歌聲。"]'),
('1eb63db1-fe85-4ab4-a62a-e96154985c53','簽判承議携官酒并具殽炙晚飲檜下二首  其一','劉攽','宋','宋诗','song-poetry','','[]','煩携光祿酒，愧舉使君觴。',48,'全唐诗/poet.song.35000.json','["煩携光祿酒，愧舉使君觴。", "伏盡轉秋熱，月明纔夜凉。", "暗蛩聲蕊蕊，古檜影蒼蒼。", "衰老淡薄味，殽蔬猶遍嘗。"]'),
('a443cd9f-4c95-40db-8e12-869cabbbb747','簽判承議携官酒并具殽炙晚飲檜下二首  其二','劉攽','宋','宋诗','song-poetry','','[]','風月近秋好，君來蒙十觴。',48,'全唐诗/poet.song.35000.json','["風月近秋好，君來蒙十觴。", "塵勞我休息，炎暑此清凉。", "玉露衣襟爽，金波鬢髮蒼。", "知心一爲足，何必似原嘗。"]'),
('13f261cc-90c6-4395-a3e1-e987c09d8816','送儀父清溪縣丞','劉攽','宋','宋诗','song-poetry','','[]','雖方六七十，皆有萬千家。',48,'全唐诗/poet.song.35000.json','["雖方六七十，皆有萬千家。", "贊府亦製錦，到官殊及瓜。", "山苗甘笋蕨，溪飯飽魚蝦。", "爲爾傳清白，遺黎每嘆嗟。"]'),
('0fcc438b-f8de-4553-b2ed-ad8301f03265','次韵和周承議登仙源宮樓','劉攽','宋','宋诗','song-poetry','','[]','屏星駐真境，喬木盡蕭森。',48,'全唐诗/poet.song.35000.json','["屏星駐真境，喬木盡蕭森。", "野曠日偏永，山寒雲更深。", "九皇容盡信，萬事盛來今。", "回首靈光殿，飛鴉起暮林。"]'),
('a710b112-3186-4218-ae9b-e3811db0adc5','送從兄思甫尉富陽','劉攽','宋','宋诗','song-poetry','','[]','南州吏數千，尉事獨神仙。',48,'全唐诗/poet.song.35000.json','["南州吏數千，尉事獨神仙。", "平日稀桴鼓，端居數醉眠。", "潮聲雷出海，山色劍橫天。", "會盡登臨興，淹留肯計年。"]'),
('95862398-fc14-4527-b250-b3dc050a8ebf','送劉誼先輩尉涇縣','劉攽','宋','宋诗','song-poetry','','[]','詔除芸閣吏，名屬太常書。',48,'全唐诗/poet.song.35000.json','["詔除芸閣吏，名屬太常書。", "高第余無愧，同宗誰不如。", "鄉情歡賜服，壽酒慶安輿。", "正復秋風起，滄江厭膾魚。"]'),
('02b7f76d-fe79-43f1-bbf1-ae80377627b7','周節推移曹州','劉攽','宋','宋诗','song-poetry','','[]','珠履幕中客，行行亦倦游。',48,'全唐诗/poet.song.35000.json','["珠履幕中客，行行亦倦游。", "勞歌一長鋏，歷聘五諸侯。", "捧檄爲親喜，問程輕旅愁。", "遥憐在陳士，無友重悲秋。"]'),
('1331036a-3bda-42be-be8e-316d3feaf507','送張益宣州法曹','劉攽','宋','宋诗','song-poetry','','[]','謝守宣城句，偏矜呂法曹。',48,'全唐诗/poet.song.35000.json','["謝守宣城句，偏矜呂法曹。", "郡齋應似舊，廷掾不徒勞。", "東北歸流駛，空虛去棹高。", "木瓜因贈客，并擇兔千毫。"]'),
('48fae5fd-9e40-4cc2-9ae3-fa3a7f691e32','韓康公挽詞三首  其一','劉攽','宋','宋诗','song-poetry','','[]','初還丞相印，併授上公封。',48,'全唐诗/poet.song.35000.json','["初還丞相印，併授上公封。", "門戟交行馬，衣章雜繡龍。", "策書休命畢，拜老未臨雍。", "遺愛無時息，淒凉在輟舂。"]'),
('5be8e27c-907d-43cd-9904-7fe54ffbd323','韓康公挽詞三首  其二','劉攽','宋','宋诗','song-poetry','','[]','八龍歸濟美，四輔號無官。',48,'全唐诗/poet.song.35000.json','["八龍歸濟美，四輔號無官。", "魯衛聯三壽，韋平屬二難。", "大勳流竹帛，盛事絕衣冠。", "今日哀榮禮，賢豪共永嘆。"]'),
('909252ed-558e-4f51-9278-b2cb4208200f','韓康公挽詞三首  其三','劉攽','宋','宋诗','song-poetry','','[]','乘輿錫臨弔，朝士盛班辭。',48,'全唐诗/poet.song.35000.json','["乘輿錫臨弔，朝士盛班辭。", "笳鼓千人仗，輼輬數仞旗。", "壞梁蕭畫在，藏壑說舟移。", "無復龍淵劍，空傳禹甸詩。"]'),
('d445d8e2-07f4-400d-bf81-1d9b8eb29723','傷王都官正卿','劉攽','宋','宋诗','song-poetry','','[]','巍然積德門，識此貴公孫。',48,'全唐诗/poet.song.35000.json','["巍然積德門，識此貴公孫。", "譬彼芝蘭秀，行看鴻鵠軒。", "誰令武子死，無復孟嘗言。", "寂寞繐帷暝，流塵空酒樽。"]'),
('0d5be7e7-650d-4932-926e-42f275a64bbb','傷胥平叔都官','劉攽','宋','宋诗','song-poetry','','[]','欲爲大招賦，期子入修門。',48,'全唐诗/poet.song.35000.json','["欲爲大招賦，期子入修門。", "昔爾南宗學，慚予莊叟言。", "清樽湛凝綠，丹旐杳飛翻。", "晨夕高堂念，此情難重論。"]'),
('5d34929d-e611-4921-87f8-c7df5ce2d503','傷楊元明都官','劉攽','宋','宋诗','song-poetry','','[]','傳家推德祖，似舅識劉牢。',48,'全唐诗/poet.song.35000.json','["傳家推德祖，似舅識劉牢。", "刻意鴻都學，精心常侍曹。", "萬金酬六體，一字禿千豪。", "詎有修文事，蒼蒼空自高。"]'),
('65d1223a-2455-4d9b-bc71-62ebe54782b2','歸雁','劉攽','宋','宋诗','song-poetry','','[]','楚水幾時綠，歸鴻前後聞。',48,'全唐诗/poet.song.35000.json','["楚水幾時綠，歸鴻前後聞。", "江湖久漂泊，南北忍辛勤。", "意氣融融日，聲音漠漠雲。", "青冥易凌厲，况復未離群。"]'),
('8799fbdd-8dfc-4d8c-87be-90de7e44b9b7','雪中聞雁','劉攽','宋','宋诗','song-poetry','','[]','四海困橫絕，經年長往來。',48,'全唐诗/poet.song.35000.json','["四海困橫絕，經年長往來。", "雪霜空盡力，道路有餘哀。", "水宿稻梁薄，雲深羅網猜。", "北方有殺氣，緩緩及春迴。"]'),
('aa839193-f7fd-4973-aa24-4ace4e599b3b','新雁','劉攽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南飛洞庭雁，稍復過衡陽。',48,'全唐诗/poet.song.35000.json','["南飛洞庭雁，稍復過衡陽。", "宇宙同爲客，春秋各異方。", "邊塵猶處處，殺氣苦蒼蒼。", "恐有傷弓翮，哀鳴少稻粱。"]'),
('ecc1850e-b226-4599-8b26-e7d62de4a6a2','觀南戍士','劉攽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','膂力三軍士，由來百戰經。',48,'全唐诗/poet.song.35000.json','["膂力三軍士，由來百戰經。", "舞旗翻鳥隼，疊鼓會風霆。", "殺氣過銅柱，歡聲塞洞庭。", "九州防盜賊，儒服愧青萍。"]'),
('4e4cc18c-cab4-40ec-b58e-db607a0033a8','平山堂','劉攽','宋','宋诗','song-poetry','','[]','吳山不過楚，江水限中間。',48,'全唐诗/poet.song.35000.json','["吳山不過楚，江水限中間。", "此地一回首，衆峰如可攀。", "俯看孤鳥沒，平視白雲還。", "行子厭長路，秋風聊解顔。"]'),
('291ac0dc-6ad5-4737-877d-00036e840695','伯父挽詩二首  其一','劉攽','宋','宋诗','song-poetry','','[]','遂有終焉志，纔成智者居。',48,'全唐诗/poet.song.35000.json','["遂有終焉志，纔成智者居。", "戶庭連水竹，几杖接舟輿。", "愛客樽中酒，傳家篋裏書。", "疏公知足計，不益舊田廬。"]'),
('75f330f2-8f20-40d7-acb9-8b77a485f4e8','伯父挽詩二首  其二','劉攽','宋','宋诗','song-poetry','','[]','民思常在去，令德久猶存。',48,'全唐诗/poet.song.35000.json','["民思常在去，令德久猶存。", "慟哭新阡樹，遲疑舊里門。", "大招聲斷絕，丹旐影翩翻。", "後日談隨會，人知嘆九原。"]'),
('3f8cc7ae-a332-4b82-a960-1cd62f348347','挽刁景純二首  其一','劉攽','宋','宋诗','song-poetry','','[]','承明通佚老，仁智遠歸居。',48,'全唐诗/poet.song.35000.json','["承明通佚老，仁智遠歸居。", "門下無留客，燈前不廢書。", "舞筵交履舄，倚杖及田廬。", "以此爲家事，忘年八十餘。"]'),
('2220e514-782e-424c-b303-9680557b13c8','挽刁景純二首  其二','劉攽','宋','宋诗','song-poetry','','[]','延陵君子墓，南極老人星。',48,'全唐诗/poet.song.35000.json','["延陵君子墓，南極老人星。", "自古稱遺愛，斯文重典刑。", "一生隆許與，五福最康寧。", "逝矣俱陳迹，臨風祇涕零。"]'),
('f4b4a95f-6ff1-4abf-9803-1e1b8c51f1cc','挽孔經父二首  其一','劉攽','宋','宋诗','song-poetry','','[]','鄉里東南秀，衣冠伯仲賢。',48,'全唐诗/poet.song.35000.json','["鄉里東南秀，衣冠伯仲賢。", "先鳴俱中雋，競爽故無前。", "朔雪凋華萼，炎風急逝川。", "斗間占紫氣，應復在龍淵。"]'),
('481b78c6-08be-4fb3-95b2-cf008007452b','挽孔經父二首  其二','劉攽','宋','宋诗','song-poetry','','[]','往昔方聞策，中間五諫書。',48,'全唐诗/poet.song.35000.json','["往昔方聞策，中間五諫書。", "直繩無廢墨，利刃必投虛。", "任重生何薄，年長恨有餘。", "悲君雖視草，不及馬相如。"]'),
('915d2eec-f992-45d3-83da-87329fe6e4aa','挽丁元珍','劉攽','宋','宋诗','song-poetry','','[]','顔駟縻三省，君山困六安。',48,'全唐诗/poet.song.35000.json','["顔駟縻三省，君山困六安。", "宦遊俱邂逅，行路正艱難。", "去水爭還壑，凝霜苦敗蘭。", "唯餘青簡在，時爲拂塵看。"]'),
('b76c4f7e-e5c2-44fd-bf63-72f0e6830f85','挽蘇明允二首  其一','劉攽','宋','宋诗','song-poetry','','[]','季子才無敵，桓公義有餘。',48,'全唐诗/poet.song.35000.json','["季子才無敵，桓公義有餘。", "空悲武儋石，猶得茂陵書。", "郢路營魂遠，江源氣象虛。", "康成宜有後，正使大門閭。"]'),
('daed3d17-376a-4083-96bd-9fd04bbcf057','挽蘇明允二首  其二','劉攽','宋','宋诗','song-poetry','','[]','漢儀綿蕝盛，周謚竹書存。',48,'全唐诗/poet.song.35000.json','["漢儀綿蕝盛，周謚竹書存。", "益以春秋法，因知皇帝尊。", "百年當絕筆，諸子謝微言。", "詩禮終誰及，賢良萃一門。"]'),
('72a3bfe6-26a1-4902-b2bb-1f4b413d27b1','聞雷','劉攽','宋','宋诗','song-poetry','','[]','過臘山微雨，開正兩震雷。',48,'全唐诗/poet.song.35000.json','["過臘山微雨，開正兩震雷。", "漸南風土異，傷早歲時催。", "放逐漁翁問，淹留漂母哀。", "餘寒附煙火，尚有復燃灰。"]'),
('efa96055-7406-4ddc-9ad4-4ee11aba7030','和孫宣德中秋不見月','劉攽','宋','宋诗','song-poetry','','[]','便有倚天劍，决雲殊細微。',48,'全唐诗/poet.song.35000.json','["便有倚天劍，决雲殊細微。", "清光自無蔽，絕境轉知稀。", "露重蟬時落，風高雁已飛。", "嫦娥苦幽獨，會載客槎歸。"]'),
('74c95324-e91d-4e2e-af6c-95298ea22314','和中秋對月','劉攽','宋','宋诗','song-poetry','','[]','星稀如有避，雲卷不辭勞。',48,'全唐诗/poet.song.35000.json','["星稀如有避，雲卷不辭勞。", "露已深秋白，天應爲月高。", "幽懷向誰盡，詩興更何逃。", "勿負盈樽酒，須營千兔毫。"]'),
('71e46107-e26b-49af-996d-df15a2e04e1e','十月四日離都歸陳州','劉攽','宋','宋诗','song-poetry','','[]','南浦三篙水，歸人五日糧。',48,'全唐诗/poet.song.35000.json','["南浦三篙水，歸人五日糧。", "寒沙晨起雁，古樹夜經霜。", "久客復去國，有情知望鄉。", "鬢毛渾欲變，鳴笛不須長。"]'),
('f4842cfc-cd8e-456b-8f22-bf191551c2d2','去陳二首  其一','劉攽','宋','宋诗','song-poetry','','[]','近關蘧舍衛，接淅孔違齊。',48,'全唐诗/poet.song.35000.json','["近關蘧舍衛，接淅孔違齊。", "今日思狂簡，儒生自滑稽。", "歸歟那慍見，去矣約輕齎。", "潁水清如鏡，風波定弗迷。"]'),
('9613a086-db03-41c9-9403-742a366e3c72','去陳二首  其二','劉攽','宋','宋诗','song-poetry','','[]','禮賢齊相國，愛客鄭尚書。',48,'全唐诗/poet.song.35000.json','["禮賢齊相國，愛客鄭尚書。", "徐孺曾懸榻，馮公預食魚。", "甘棠勿剪伐，客館遂邱墟。", "長鋏還相語，冥鴻幸起予。"]'),
('af326353-44e0-4f74-a32b-d97c41169378','端午','劉攽','宋','宋诗','song-poetry','','[]','萬里荆州俗，今晨採藥翁。',48,'全唐诗/poet.song.35000.json','["萬里荆州俗，今晨採藥翁。", "浴蘭從忌潔，服艾已同風。", "泛酒菖蒲細，含沙蝘蜓紅。", "沉湘猶可問，角飯畏蛟龍。"]'),
('9c823e9d-3270-4223-b844-44fcbd2a3fbf','嘉祐大行皇帝挽詩十首  其一','劉攽','宋','宋诗','song-poetry','','[]','七月期先遠，三泉異卜征。',48,'全唐诗/poet.song.35000.json','["七月期先遠，三泉異卜征。", "悲憂同軌事，遏密兆人情。", "晚出蒼龍駕，真遊白玉京。", "稱天騰茂實，厚德始能名。"]'),
('917a3b60-db48-45cb-aba5-c2a722a060fc','嘉祐大行皇帝挽詩十首  其二','劉攽','宋','宋诗','song-poetry','','[]','北發聲名遠，西城劍戟銷。',48,'全唐诗/poet.song.35000.json','["北發聲名遠，西城劍戟銷。", "萬靈潛受記，百獸樂聞韶。", "昧谷迷升日，璇霄失建杓。", "仙遊那可問，賦諷已飄飄。"]'),
('8ccb4179-34ae-477d-9d48-5c92ceff4730','嘉祐大行皇帝挽詩十首  其三','劉攽','宋','宋诗','song-poetry','','[]','盛德終無逸，元功熟間然。',48,'全唐诗/poet.song.35000.json','["盛德終無逸，元功熟間然。", "啟疆神禹績，著記帝虞年。", "桑變旋觀海，弓遺杳望天。", "霸陵無石槨，不改故山川。"]'),
('476e8bb0-947c-4353-9aea-5ed0a05a5361','嘉祐大行皇帝挽詩十首  其四','劉攽','宋','宋诗','song-poetry','','[]','盡禮三神事，齋居五日朝。',48,'全唐诗/poet.song.35000.json','["盡禮三神事，齋居五日朝。", "綈衣仍澣濯，禁籞亦芻蕘。", "汾水遊何往，華胥夢轉遥。", "羹藜與環堵，無日不思堯。"]'),
('1b81b0ea-17c5-479b-ba02-a3e97f470c0e','嘉祐大行皇帝挽詩十首  其五','劉攽','宋','宋诗','song-poetry','','[]','屬車全鹵簿，寶玉煥渠眉。',48,'全唐诗/poet.song.35000.json','["屬車全鹵簿，寶玉煥渠眉。", "萬國瞻龍翣，三辰會素旗。", "雪迷帝鄉望，風動海隅悲。", "今日西巡守，仍非八月期。"]'),
('67547fef-04f1-44bb-a27a-07e15f08d397','嘉祐大行皇帝挽詩十首  其六','劉攽','宋','宋诗','song-poetry','','[]','清光非可望，天道亦難聞。',48,'全唐诗/poet.song.35000.json','["清光非可望，天道亦難聞。", "策府開群玉，賡歌續慶雲。", "一經皆賜復，九譯尚同文。", "會盡南山竹，成書紀帝墳。"]'),
('a176f31b-57f5-4cb5-a7fe-bc5f9f675919','嘉祐大行皇帝挽詩十首  其七','劉攽','宋','宋诗','song-poetry','','[]','陵闕儼因山，明中恍下天。',48,'全唐诗/poet.song.35000.json','["陵闕儼因山，明中恍下天。", "燃魚常照夜，耕象自成田。", "鴻洞深投玉，莓苔密瘞錢。", "涕流昭德舞，無復柏梁篇。"]'),
('03a01062-9c79-4d96-8c4e-da59459becf8','嘉祐大行皇帝挽詩十首  其八','劉攽','宋','宋诗','song-poetry','','[]','帝車旋北斗，馳道繞青松。',48,'全唐诗/poet.song.35000.json','["帝車旋北斗，馳道繞青松。", "銀海浮雙闕，虞淵頓六龍。", "深思傾杞國，遺恨泣華封。", "述作無憂事，靈臺與辟雍。"]'),
('90b01255-7b5a-4523-bc5d-565afb4dcccb','嘉祐大行皇帝挽詩十首  其九','劉攽','宋','宋诗','song-poetry','','[]','車書共文軌，律度出聲身。',48,'全唐诗/poet.song.35000.json','["車書共文軌，律度出聲身。", "明白垂中典，優容禮直臣。", "熊羆渭川叟，風雨越裳人。", "更想攀髯士，猶知不犯鱗。"]'),
('3977bd61-4e6b-4dfe-a6db-83d98d4b38ae','嘉祐大行皇帝挽詩十首  其一○','劉攽','宋','宋诗','song-poetry','','[]','哀挽千人唱，崇岡萬歲居。',48,'全唐诗/poet.song.35000.json','["哀挽千人唱，崇岡萬歲居。", "呼關想傳警，羨道法周廬。", "晚日塗車靜，深山灌柏初。", "谷神知有術，猶欲信前書。"]'),
('b3430777-1cb6-4da4-8c7b-5e1cc3de66fe','次韵和麻直講題楊直講所種三樗樹','劉攽','宋','宋诗','song-poetry','','[]','誰能知散木，封植亦無心。',48,'全唐诗/poet.song.35000.json','["誰能知散木，封植亦無心。", "歲月如視蔭，棲遲還息陰。", "宦情移柳在，詩興愛棠深。", "定有歸飛翼，懷音似泮林。"]'),
('d51c54cd-34c8-4326-8f35-b28e5f38f59e','神宗皇帝挽詩四首  其一','劉攽','宋','宋诗','song-poetry','','[]','制作夸三正，規模壯百王。',48,'全唐诗/poet.song.35000.json','["制作夸三正，規模壯百王。", "自然推大略，誰得望清光。", "東樂來蟠木，南琛過越裳。", "白雲那可測，應復向汾陽。"]'),
('67f74046-4d77-4122-b797-2b196df9e8ed','神宗皇帝挽詩四首  其二','劉攽','宋','宋诗','song-poetry','','[]','綿宇正歡心，虞韶驟遏音。',48,'全唐诗/poet.song.35000.json','["綿宇正歡心，虞韶驟遏音。", "戴天憂杞國，就日悵崦岑。", "貫朽三泉府，方輸九牧金。", "斯民已仁壽，至理更難忱。"]'),
('21fabc58-2e3f-4a04-8d87-6cf6f982b4f2','神宗皇帝挽詩四首  其三','劉攽','宋','宋诗','song-poetry','','[]','四塞聯初郡，千官僅代工。',48,'全唐诗/poet.song.35000.json','["四塞聯初郡，千官僅代工。", "舟車逾漢迹，臺省變唐風。", "賢傑程能際，戎夷率服中。", "軒威百年在，何必畫周公。"]'),
('2fff3e7d-7aa1-4d14-b285-ba20eef7f3d7','神宗皇帝挽詩四首  其四','劉攽','宋','宋诗','song-poetry','','[]','晚駕嚴仙御，西巡即舊都。',48,'全唐诗/poet.song.35000.json','["晚駕嚴仙御，西巡即舊都。", "天寒餘鶴語，弓墮脫龍鬚。", "白髮孤臣淚，清湘萬里途。", "無由宣室問，回首叫蒼梧。"]'),
('41cb97f6-f36b-4499-a592-19ce2a146833','大行挽詩二首  其一','劉攽','宋','宋诗','song-poetry','','[]','受名從大行，復土自因山。',48,'全唐诗/poet.song.35000.json','["受名從大行，復土自因山。", "秋草龍髯墮，宮煙淚竹斑。", "不知汲水遠，猶與化人還。", "寂寞崦嵫日，空瞻咫尺顔。"]'),
('de42b5fa-3f6c-45f3-a0b4-4077663c01a9','大行挽詩二首  其二','劉攽','宋','宋诗','song-poetry','','[]','謳歌前授啟，桑穀遂興商。',48,'全唐诗/poet.song.35000.json','["謳歌前授啟，桑穀遂興商。", "恭己朝無事，優賢禮亦莊。", "那驚同軌至，方奏萬年觴。", "西望歸雲白，悠悠指帝鄉。"]'),
('f3c868e7-0478-4b2e-b894-74e7665da9ef','又二首  其一','劉攽','宋','宋诗','song-poetry','','[]','萬國依無外，三登頌太平。',48,'全唐诗/poet.song.35000.json','["萬國依無外，三登頌太平。", "樵夫亦談道，耆舊莫知兵。", "雲去仙鄉遠，龍來寶鼎成。", "西風動閶闔，哀涕不勝情。"]'),
('252fcecc-8f0d-423c-94eb-c0dcf6c3bdcf','又二首  其二','劉攽','宋','宋诗','song-poetry','','[]','供張連三輔，梯航會九圍。',48,'全唐诗/poet.song.35000.json','["供張連三輔，梯航會九圍。", "屬車疑晚駕，清蹕望來歸。", "草露淒金闕，松風颺玉衣。", "舊傳當脫躧，遥見五雲飛。"]'),
('48f0ddb6-be9e-4b2f-9b22-63c36e56cca9','日晚','劉攽','宋','宋诗','song-poetry','','[]','清秋來早晚，落日正蕭然。',48,'全唐诗/poet.song.35000.json','["清秋來早晚，落日正蕭然。", "稍見林外水，獨聽風際蟬。", "牛羊暝知道，墟落遠生烟。", "歲事看禾黍，方知沮溺賢。"]'),
('93f69506-90cd-499e-b627-64c94776bb1f','挽杜祁公太師二首  其一','劉攽','宋','宋诗','song-poetry','','[]','孤童迨耆老，仕郡至三公。',48,'全唐诗/poet.song.35000.json','["孤童迨耆老，仕郡至三公。", "任重仍長道，材全信永終。", "時推子房智，人識伯夷風。", "存歿哀榮禮，千秋誰與同。"]'),
('7608b3d1-5ab5-4e45-ae2f-16bdbf545a75','挽杜祁公太師二首  其二','劉攽','宋','宋诗','song-poetry','','[]','赤舄三師貴，諸公百里封。',48,'全唐诗/poet.song.35000.json','["赤舄三師貴，諸公百里封。", "舊勳兼注意，餘事寄明農。", "哀動襄陽市，悲殘鄭國舂。", "空餘靈壽賜，無復見臨雍。"]'),
('6b4baa05-0736-4301-bf49-935f4056afab','秋雨四首  其一','劉攽','宋','宋诗','song-poetry','','[]','冷雨黄昏暮，秋聲衆葉喧。',48,'全唐诗/poet.song.35000.json','["冷雨黄昏暮，秋聲衆葉喧。", "濯煩天宇闊，流惡楚江渾。", "蛙黽煩當道，魚龍稍在門。", "一樽聊自勸，還欲笑臧孫。"]'),
('abdebb15-185f-4b50-86e2-fffe97504c49','秋雨四首  其二','劉攽','宋','宋诗','song-poetry','','[]','漠漠清秋雨，蕭蕭萬宇寒。',48,'全唐诗/poet.song.35000.json','["漠漠清秋雨，蕭蕭萬宇寒。", "蛟龍移窟宅，江漢急波瀾。", "瘴霧深蠻洞，旌旗濕漢官。", "南征愁失道，后土若爲乾。"]'),
('f68fd496-fd09-40f1-bad7-b38a85465c38','秋雨四首  其三','劉攽','宋','宋诗','song-poetry','','[]','海風吹暮雨，淮上始秋聲。',48,'全唐诗/poet.song.35000.json','["海風吹暮雨，淮上始秋聲。", "點滴潛滋潤，陰沈未放晴。", "林塘雲似密，水鑒鏡來清。", "無事看魚鳥，飛沈體亦輕。"]'),
('851d53d7-95c2-4327-a8bf-7e66d95c512c','秋雨四首  其四','劉攽','宋','宋诗','song-poetry','','[]','炎天常畏酒，秋興憶開觴。',48,'全唐诗/poet.song.35000.json','["炎天常畏酒，秋興憶開觴。", "海面孤雲黑，林端一葉黄。", "島夷歌似楚，村笛語如羌。", "更覺非吾土，登臨思舊鄉。"]'),
('ef729b0e-e750-4e25-9906-a36a62f7c61d','有懷北歸','劉攽','宋','宋诗','song-poetry','','[]','江漢不宜秋，羈人北望愁。',48,'全唐诗/poet.song.35000.json','["江漢不宜秋，羈人北望愁。", "帝鄉從此去，楚水正東流。", "竟日悲鶗鴂，長歌倚蒯緱。", "天邊兩黄鵠，那肯爲人留。"]'),
('36c0ed2b-5dec-4d82-bfc3-3298f0b3d92e','秘閣梅花','劉攽','宋','宋诗','song-poetry','','[]','始知丹禁密，獨見早梅新。',48,'全唐诗/poet.song.35000.json','["始知丹禁密，獨見早梅新。", "天上應常雪，人間未有春。", "亂香交砌草，疏影媚庭筠。", "浪作瀛洲客，催成白髮人。"]'),
('941d99c8-0824-48d6-af9b-802cff46f957','雨中晚凉','劉攽','宋','宋诗','song-poetry','','[]','落日浮雲暝，滄江雨氣來。',48,'全唐诗/poet.song.35000.json','["落日浮雲暝，滄江雨氣來。", "風燈殊未定，洞戶故頻開。", "秋意梧桐急，宵征蟋蟀哀。", "客心聊灑濯，天地久塵埃。"]'),
('27bc243c-2cb1-4d39-820d-e022227e7f75','始凉','劉攽','宋','宋诗','song-poetry','','[]','秋風來幾時，客病不相宜。',48,'全唐诗/poet.song.35000.json','["秋風來幾時，客病不相宜。", "摇落令心苦，虛凉益氣衰。", "生涯貧更拙，交態卧尤知。", "安得千金贈，鴟夷與爾期。"]'),
('f38a313b-d4a4-441c-b614-f7c26eaaf842','送張直溫主簿赴南陽','劉攽','宋','宋诗','song-poetry','','[]','張君年少予，冠歲聚公車。',48,'全唐诗/poet.song.35000.json','["張君年少予，冠歲聚公車。", "留落成强仕，聲名就子虛。", "穰橙千戶富，潭菊萬家居。", "吏隠何爲樂，優游不廢書。"]'),
('7ca34bda-bfe9-48d2-9eee-8d50d1dc4c1d','黄知錄園池','劉攽','宋','宋诗','song-poetry','','[]','劫火無遺者，靈光獨巋然。',48,'全唐诗/poet.song.35000.json','["劫火無遺者，靈光獨巋然。", "寒池清照日，古木碧參天。", "細雨來幽鷺，凉風急亂蟬。", "頗知魚樂意，仍得離鈎筌。"]'),
('f8483142-f1ac-4f43-9665-d2fcf01c5a9c','游李氏園池二首  其一','劉攽','宋','宋诗','song-poetry','','[]','從人問喬木，繫馬得名園。',48,'全唐诗/poet.song.35000.json','["從人問喬木，繫馬得名園。", "柳带晴先綠，禽聲暖更喧。", "臨池照清水，拂石置芳樽。", "不畏歸侵夜，嚴城未掩門。"]'),
('3f1cd0e7-058e-43ce-acf3-849db0527e8d','游李氏園池二首  其二','劉攽','宋','宋诗','song-poetry','','[]','樹密渾成塢，花深更有蹊。',48,'全唐诗/poet.song.35000.json','["樹密渾成塢，花深更有蹊。", "來游春尚淺，重到客應迷。", "已近無人境，深憐快馬蹄。", "風光不負約，樽酒會長携。"]'),
('e8ef048c-57ef-4829-aa57-93628f236564','春陰','劉攽','宋','宋诗','song-poetry','','[]','峽雲春易雨，水國暮多風。',48,'全唐诗/poet.song.35000.json','["峽雲春易雨，水國暮多風。", "原草萋萋綠，林花淡淡紅。", "清江晚寒外，落景半晴空。", "物色憐新燕，歸懷目去鴻。"]'),
('e7572627-64a3-45f6-a6b4-a2c306400617','秋雨','劉攽','宋','宋诗','song-poetry','','[]','南國秋常暑，凉風起自今。',48,'全唐诗/poet.song.35000.json','["南國秋常暑，凉風起自今。", "洩雲無白日，度夕亦層陰。", "摇落梧楸意，蕭條蟋蟀音。", "窮愁抵衰病，坐作老翁心。"]'),
('19f053c9-b36a-47c0-a172-17180c30bbf1','樹陰二首  其一','劉攽','宋','宋诗','song-poetry','','[]','清陰方丈得，暑氣乍來無。',48,'全唐诗/poet.song.35000.json','["清陰方丈得，暑氣乍來無。", "塵榻從箕踞，前賢亦鍛爐。", "晚蟲多黑羽，秋草半青珠。", "安得遺方客，玄談似給孤。"]'),
('3f8f3a82-16d8-47ca-91f2-5debaf95d13f','樹陰二首  其二','劉攽','宋','宋诗','song-poetry','','[]','避世長梧子，居貧五柳生。',48,'全唐诗/poet.song.35000.json','["避世長梧子，居貧五柳生。", "清秋葛衣薄，晚日濁醪傾。", "雨蝶輕猶舞，風蟬凉不鳴。", "淮南摇落早，倚樹不無情。"]'),
('059c347d-bc06-40f0-9293-1b2fbcf38660','夜坐','劉攽','宋','宋诗','song-poetry','','[]','積雨凝凉氣，疏林滴露華。',48,'全唐诗/poet.song.35000.json','["積雨凝凉氣，疏林滴露華。", "流星占使者，斜漢挹浮槎。", "喜近天流火，回看斗轉車。", "秋風下閶闔，消散萬人家。"]'),
('a47e9061-a384-48b6-9a22-d51b05614790','飲酒城南門贈高子中','劉攽','宋','宋诗','song-poetry','','[]','蒼山際碧霄，綠樹及山腰。',48,'全唐诗/poet.song.35000.json','["蒼山際碧霄，綠樹及山腰。", "青靄照殘日，白雲縈麗譙。", "偶然成勝賞，長嘯隔塵囂。", "少駐飛鳬舄，吾無獨酌謠。"]'),
('e2a1a400-f278-465b-8c53-bc992fb9ed1c','酬晁單州二首  其一','劉攽','宋','宋诗','song-poetry','','[]','九載一相逢，侵尋頭已童。',48,'全唐诗/poet.song.35000.json','["九載一相逢，侵尋頭已童。", "喜君真傲吏，老我未成翁。", "簡易文書省，悲歡酒盞空。", "平生懷舊意，盡見醉醒中。"]'),
('1bf24cc0-2e76-4e40-b8cc-e99260ef0bcd','酬晁單州二首  其二','劉攽','宋','宋诗','song-poetry','','[]','彈琴君子邑，賢守智逾多。',48,'全唐诗/poet.song.35000.json','["彈琴君子邑，賢守智逾多。", "不作長沙賦，仍傳白雪歌。", "解酲應用酒，成佛却須魔。", "正買千金骨，何憂驥跋跎。"]'),
('a4dc4083-c4a4-417b-a4c8-ba07660b6748','送呂國博知常州','劉攽','宋','宋诗','song-poetry','','[]','計然餘半策，賈子就新書。',48,'全唐诗/poet.song.35000.json','["計然餘半策，賈子就新書。", "屈意銀青綬，之官鳥隼旟。", "丹楓千里遠，秋興二毛初。", "最可羞晨膳，蓴絲雜膾魚。"]'),
('9e76be9d-205f-4c37-90bb-fd74ee77cf78','李公擇自滑州移知鄂州','劉攽','宋','宋诗','song-poetry','','[]','黄河魴與鯉，不及武昌魚。',48,'全唐诗/poet.song.35000.json','["黄河魴與鯉，不及武昌魚。", "好去連城守，翩然雙隼旟。", "諫官仍重外，天祿不成書。", "可待三年最，歸來侍赤除。"]'),
('61b220c2-82db-4709-8b73-6b05083eb829','朝回','劉攽','宋','宋诗','song-poetry','','[]','朝回還閉戶，講徹復觀書。',48,'全唐诗/poet.song.35000.json','["朝回還閉戶，講徹復觀書。", "重祿爭消得，微軀且自如。", "俗情矜不及，生理付無餘。", "寂嘿懷張摯，淹留苦魏渠。"]'),
('b412802b-d8d8-4fb0-ba7b-a96011b4fe53','同宋次道飲王史館園','劉攽','宋','宋诗','song-poetry','','[]','珍館掃塵埃，賓階餘綠苔。',48,'全唐诗/poet.song.35000.json','["珍館掃塵埃，賓階餘綠苔。", "凉風知廣厦，清唱急行杯。", "修竹端藏日，交流靜殷雷。", "歡窮有餘恨，不及壯年來。"]'),
('89a6af9c-754f-4cb9-a4c1-2f442e8cfb52','同韓持國飲城東俞氏園','劉攽','宋','宋诗','song-poetry','','[]','貧家常汲汲，一飲自難營。',48,'全唐诗/poet.song.35000.json','["貧家常汲汲，一飲自難營。", "不笑烹雞黍，因之同耦耕。", "林花含秀色，谷鳥變新聲。", "歸馬無庸疾，郊扉最近城。"]'),
('217a0d63-c62b-4ae6-8031-2177636632b3','泛舟城南二首  其一','劉攽','宋','宋诗','song-poetry','','[]','清溪亦多曲，窄地頗宜花。',48,'全唐诗/poet.song.35000.json','["清溪亦多曲，窄地頗宜花。", "出水游魚樂，驚人白鷺斜。", "孤城舊郢樹，三戶楚人家。", "歸興仍風雨，蕭然睠物華。"]'),
('652c68a1-e114-403e-a5f3-33e5760775e6','泛舟城南二首  其二','劉攽','宋','宋诗','song-poetry','','[]','風逆湍聲急，雲酣雨氣豪。',48,'全唐诗/poet.song.35000.json','["風逆湍聲急，雲酣雨氣豪。", "川蜺垂飲近，江鶴去飛高。", "洗藕還餘味，操舟未覺勞。", "蒹葭彌極望，秋意晚騷騷。"]'),
('a9f0bee3-a711-4d07-8376-1967ced529e2','早行','劉攽','宋','宋诗','song-poetry','','[]','山鳥相呼曙，檣烏自指南。',48,'全唐诗/poet.song.35000.json','["山鳥相呼曙，檣烏自指南。", "健看帆席滿，坐數舳艫銜。", "水闊蛟龍舞，魚肥鸛鶴貪。", "陣雲濃似墨，送雨向湘潭。"]'),
('7dedad6d-e6b1-4fc3-98c2-ef364b3d05f6','晚行','劉攽','宋','宋诗','song-poetry','','[]','天闊西曛久，風多客語聞。',48,'全唐诗/poet.song.35000.json','["天闊西曛久，風多客語聞。", "九江秋落水，三峽暮歸雲。", "飲啄鷗相並，歸飛鶴不群。", "湘潭早摇落，稍稍悵平分。"]'),
('01e39515-855c-4fb6-85d1-8e230ebbcdf9','次韵酬錢少卿','劉攽','宋','宋诗','song-poetry','','[]','簿書非力學，何事不窺園。',48,'全唐诗/poet.song.35000.json','["簿書非力學，何事不窺園。", "乘興緣心賞，忘懷到酒樽。", "露蟬凉寂寞，風葉靜翩翻。", "少駐東方騎，前盟豈可溫。"]'),
('9631a35c-4df3-423b-bb97-7c037cfadab9','送楚南','劉攽','宋','宋诗','song-poetry','','[]','心寄江湖上，樂聞遊子歸。',48,'全唐诗/poet.song.35000.json','["心寄江湖上，樂聞遊子歸。", "送君從此去，脫葉正秋飛。", "雲水聊破浪，風塵今振衣。", "山僧不善飲，定負蟹螯肥。"]'),
('b4006e4e-2cd7-4b5d-b268-8cf94b119d1a','送袁生','劉攽','宋','宋诗','song-poetry','','[]','巴蜀窮天險，驚君便向西。',48,'全唐诗/poet.song.35000.json','["巴蜀窮天險，驚君便向西。", "長年勞賈勇，懸度約輕齎。", "行止千金子，艱危萬丈梯。", "自憐傾蓋舊，即事復睽携。"]'),
('899fbd59-5efc-4756-b6a3-265eea738f57','送劉四畋二首  其一','劉攽','宋','宋诗','song-poetry','','[]','四海皆兄弟，吾宗加老成。',48,'全唐诗/poet.song.35000.json','["四海皆兄弟，吾宗加老成。", "好書如子政，飲酒勝公榮。", "今日鱸魚膾，羨君乘興行。", "秋風峽中度，快意聽潮聲。"]'),
('7d5f37a9-20ce-42e4-9bac-814e20c7167c','送劉四畋二首  其二','劉攽','宋','宋诗','song-poetry','','[]','肥水不能遠，祇今行子東。',48,'全唐诗/poet.song.35000.json','["肥水不能遠，祇今行子東。", "高秋千里月，暮景一帆風。", "時節迎黄菊，汀洲下早鴻。", "江天多勝事，無術與君同。"]'),
('404ad5a6-84b9-42f8-a815-35f5f0db33a5','山陽送王中甫','劉攽','宋','宋诗','song-poetry','','[]','弱扇避風瀾，卑飛歲復單。',48,'全唐诗/poet.song.35000.json','["弱扇避風瀾，卑飛歲復單。", "君行反閶闔，人望接鵷鸞。", "齋日容臺峻，書籤策府寒。", "誰言今昔異，王貢本彈冠。"]'),
('73fa783b-cf58-4693-951b-18e7a6ae48f9','送某','劉攽','宋','宋诗','song-poetry','','[]','詞曹大府掾，誰謂詔恩輕。',48,'全唐诗/poet.song.35000.json','["詞曹大府掾，誰謂詔恩輕。", "遺愛念諸父，司存從汝兄。", "男兒貴壯志，子弟習家聲。", "努力自勉勵，吾衰觀爾成。"]'),
('a4dedca4-912a-45c3-a926-05e11566cb05','送王同年殿丞知鄞縣','劉攽','宋','宋诗','song-poetry','','[]','結愛愧同年，君先予著鞭。',48,'全唐诗/poet.song.35000.json','["結愛愧同年，君先予著鞭。", "稍遷鈎盾省，歷試武城弦。", "越嶺霞明日，南溟水浸天。", "微官等不遂，欲治子猷船。"]'),
('6fc741dd-1728-48c3-a5b1-ab2f9e50d3f7','江亭後池','劉攽','宋','宋诗','song-poetry','','[]','清江長望極，餘興曲池深。',48,'全唐诗/poet.song.35000.json','["清江長望極，餘興曲池深。", "俯視游魚族，仰嬉喬木陰。", "通津厭離會，勝地有登臨。", "暮雨寒潮急，歸飛聞水禽。"]'),
('85d2bef7-bd2b-4299-9b10-d16245628073','送胡因甫知湘鄉縣','劉攽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雲水長沙國，銅章邑大夫。',48,'全唐诗/poet.song.35000.json','["雲水長沙國，銅章邑大夫。", "俗傳鴞似鵩，仙化舄爲鳬。", "卑濕加餐飯，絃歌豈壯圖。", "洞庭見歸客，書信不宜無。"]'),
('7230b43c-1771-462f-8cf7-275a2ab5795e','季夏雨過小有秋氣','劉攽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雨過猶長夏，秋深從洞庭。',48,'全唐诗/poet.song.35000.json','["雨過猶長夏，秋深從洞庭。", "江涵郭門白，山到戍樓青。", "天意憐卑濕，吾謀有醉醒。", "柴門夜不掩，高枕看流星。"]'),
('dd9fc7eb-81b7-4cd0-ab79-2d482e378eea','觀雲','劉攽','宋','宋诗','song-poetry','','[]','江上秋多雨，山中晝出雲。',48,'全唐诗/poet.song.35000.json','["江上秋多雨，山中晝出雲。", "太虛終日曀，疊嶂不時分。", "半覺蛟龍氣，皆成虎豹群。", "微風動閶闔，暫喜見西曛。"]'),
('1ea7a87d-a841-4b46-a680-200a7ddad502','山行','劉攽','宋','宋诗','song-poetry','','[]','危塗煩側足，積水向吹襟。',48,'全唐诗/poet.song.35000.json','["危塗煩側足，積水向吹襟。", "雲樹參天直，風湍殷地深。", "翠香秋後草，巧語霽來禽。", "信美非人境，無爲久滯淫。"]'),
('128e459c-836e-4cf0-941a-daac3cef8fbb','泛舟','劉攽','宋','宋诗','song-poetry','','[]','野境尋不盡，幽歡良自如。',48,'全唐诗/poet.song.35000.json','["野境尋不盡，幽歡良自如。", "猶疑夢爲鳥，誰謂子非魚。", "岸樹綠已合，渚蒲長且疏。", "逍遥此中意，何減漆園書。"]'),
('03a66e89-1837-4e6b-8b62-cc3572d614c9','初夜','劉攽','宋','宋诗','song-poetry','','[]','海氣三陰早，秋宵一刻長。',48,'全唐诗/poet.song.35000.json','["海氣三陰早，秋宵一刻長。", "凉風吹樹動，疏雨過雲忙。", "寂寂庭槐落，微微徑竹香。", "蛩聲畏人寢，故故近眠床。"]'),
('52b2cf0e-94c9-438b-855d-dad3cf3e5edf','夜三首  其一','劉攽','宋','宋诗','song-poetry','','[]','積水浮南極，流沙聚客亭。',48,'全唐诗/poet.song.35000.json','["積水浮南極，流沙聚客亭。", "暝聞漁父曲，秋揖老人星。", "初月霜華薄，孤山石黛青。", "天高多影響，彷彿見湘靈。"]'),
('13e81573-1652-488b-ba8e-e2431afdafa2','夜三首  其二','劉攽','宋','宋诗','song-poetry','','[]','凉風吹素月，深夜欲眠時。',48,'全唐诗/poet.song.35000.json','["凉風吹素月，深夜欲眠時。", "露自入秋白，漏從前日遲。", "河光如劍直，螢影似星移。", "多少流年感，聞蛩輒易悲。"]'),
('062efdac-1259-4119-9ba4-9c86cd073b6c','夜三首  其三','劉攽','宋','宋诗','song-poetry','','[]','流雲卷殘雨，初月浄中宵。',48,'全唐诗/poet.song.35000.json','["流雲卷殘雨，初月浄中宵。", "秋色河漢白，凉風星斗摇。", "暗螢猶奕奕，高樹獨蕭蕭。", "客鬢非松柏，何時得後凋。"]'),
('9499725e-7a14-445a-a862-9b7137128b40','寄題康州陳氏連理木詩','劉攽','宋','宋诗','song-poetry','','[]','陳家聚德星，累世若同生。',48,'全唐诗/poet.song.35000.json','["陳家聚德星，累世若同生。", "天事知常象，林珍獨應誠。", "相傳殖嘉樹，不復羨名卿。", "坐使炎荒化，何如谷口耕。"]'),
('52305188-e123-4d63-84a6-9caf7cbe5bd6','哭吳道粹學士','劉攽','宋','宋诗','song-poetry','','[]','結束并州騎，雍容使者車。',48,'全唐诗/poet.song.35000.json','["結束并州騎，雍容使者車。", "乃心長象闕，稱旨得金魚。", "熊鳥空遺術，龍蛇有讖書。", "平生一笑樂，回首涕盈裾。"]'),
('ec3483d0-ebbc-4ab1-95b4-4b70877a2c50','次韵酬盛秘丞黑桃二首  其一','劉攽','宋','宋诗','song-poetry','','[]','度索方殊域，崑崙起素封。',48,'全唐诗/poet.song.35000.json','["度索方殊域，崑崙起素封。", "幾人曾白眼，吾子幸先容。", "晦迹煤炱暗，含滋沆瀣濃。", "上林求異木，詔使會尋蹤。"]'),
('b3c626b5-0eb3-4e4e-a29d-32f155ff7036','次韵酬盛秘丞黑桃二首  其二','劉攽','宋','宋诗','song-poetry','','[]','春華各自媚，秋實頓能殊。',48,'全唐诗/poet.song.35000.json','["春華各自媚，秋實頓能殊。", "悴貌從黎黑，丹心固碩膚。", "榴花隨使者，荔子賜匈奴。", "寄語玄都客，相疑失味腴。"]'),
('512ae083-c926-4b06-9442-1a49d399c59c','雨夜三首  其一','劉攽','宋','宋诗','song-poetry','','[]','急雨吹喬木，孤燈瞑小軒。',48,'全唐诗/poet.song.35000.json','["急雨吹喬木，孤燈瞑小軒。", "神傷徒隠几，夢極不招魂。", "老淚悲朝雉，摧腸怯夜猿。", "舊惟眸子亮，一月遂全昏。"]'),
('fe1096fe-269e-40eb-ae1e-e1a6b3f368d2','雨夜三首  其二','劉攽','宋','宋诗','song-poetry','','[]','孟夏樹木長，夜凉風雨時。',48,'全唐诗/poet.song.35000.json','["孟夏樹木長，夜凉風雨時。", "明燈掃塵榻，散帙坐書帷。", "曠野波濤合，中宵虎豹悲。", "形骸吾喪我，隠几向爲誰。"]'),
('dd0c99c0-35ce-45ee-844f-cc161e32a45a','雨夜三首  其三','劉攽','宋','宋诗','song-poetry','','[]','雲闇黄昏雨，風淒九月秋。',48,'全唐诗/poet.song.35000.json','["雲闇黄昏雨，風淒九月秋。", "老便安坐久，用即置書休。", "知命應無念，虛心自不愁。", "三年同此興，中夜一燈留。"]'),
('ebd4b950-5c38-4eb2-955e-26ac6a1690a6','季夏雨夜','劉攽','宋','宋诗','song-poetry','','[]','烈暑殊未艾，更籌初少添。',48,'全唐诗/poet.song.35000.json','["烈暑殊未艾，更籌初少添。", "電光金作屋，雨氣瀑吹簾。", "巢燕密誶語，闇蛩爭出潛。", "何由掃氛翳，試使祝蜚廉。"]'),
('1d7df1e3-cd67-48e5-bf70-26704a612c32','靈壁張氏園亭二首  其一','劉攽','宋','宋诗','song-poetry','','[]','落帆楊柳渚，步屧松竹園。',48,'全唐诗/poet.song.35000.json','["落帆楊柳渚，步屧松竹園。", "叢石千巖秀，凉風萬葉翻。", "主人昔傲吏，燕翼此衡門。", "略看題詩客，空令悲九原。"]'),
('92749a32-2f1b-4272-bd6b-c442b30c5de0','靈壁張氏園亭二首  其二','劉攽','宋','宋诗','song-poetry','','[]','密竹換啼鳥，清池添放魚。',48,'全唐诗/poet.song.35000.json','["密竹換啼鳥，清池添放魚。", "懸藤林下坐，響石洞中居。", "興趣自無盡，傳聞那得虛。", "如何仲長子，刻意但成書。"]'),
('8a0fc310-e5fb-451a-b0bc-4b6b82e5f07e','重到謝氏園亭寄裴博士俊叔王主簿宗傑時裴往淮南王出京師','劉攽','宋','宋诗','song-poetry','','[]','徘徊遠林下，幽草爲誰芳。',48,'全唐诗/poet.song.35000.json','["徘徊遠林下，幽草爲誰芳。", "前日同游客，今朝俱異鄉。", "東風雖淡蕩，陳迹似淒凉。", "何用江千里，春心故易傷。"]'),
('17d143d7-ef32-41f2-8f76-48d8f11cc258','八月十五日秋分是日又社','劉攽','宋','宋诗','song-poetry','','[]','秋分當月半，望魄復宵中。',48,'全唐诗/poet.song.35000.json','["秋分當月半，望魄復宵中。", "難得良辰並，仍將吉戊同。", "高樓連卜夜，濁酒任治聾。", "注想乘槎客，何如擊壤翁。"]'),
('c7894317-0575-42cf-b35f-847fd615d14a','送裴太博','劉攽','宋','宋诗','song-poetry','','[]','萊子頭垂白，斑衣歡過人。',48,'全唐诗/poet.song.35000.json','["萊子頭垂白，斑衣歡過人。", "官知爲親屈，祿足代家貧。", "歸雁江南遠，芳蘭雪後新。", "仙舟興不淺，致意越鄉春。"]'),
('4832ba96-edf9-4234-b448-7200cc45acc4','夕陽','劉攽','宋','宋诗','song-poetry','','[]','驟雨無多潤，殘陽不復遲。',48,'全唐诗/poet.song.35000.json','["驟雨無多潤，殘陽不復遲。", "陰凉庭樹老，點綴石苔滋。", "鬥雀輕投地，懸蟲剩倚絲。", "林櫻供口實，美味及童兒。"]'),
('b3efc3de-07a2-4b3b-9928-e0dd3e8cc8fb','馬氏中隠庵','劉攽','宋','宋诗','song-poetry','','[]','千歲知名士，文淵與少游。',48,'全唐诗/poet.song.35000.json','["千歲知名士，文淵與少游。", "平生款段馬，晚歲伏波侯。", "鄉里足稱善，功名仍可收。", "聞君事中隠，嘆息此孫謀。"]'),
('99188129-7d30-4fec-bace-a9e650e25274','望荆山','劉攽','宋','宋诗','song-poetry','','[]','宿雲收疊嶺，初日上危岑。',48,'全唐诗/poet.song.35000.json','["宿雲收疊嶺，初日上危岑。", "黤黮千重黛，光芒一線金。", "秋高怨摇落，野曠快登臨。", "誰怪欣然樂，山林慰此心。"]'),
('3cfd3bee-44d9-4826-b396-1cc863c1183d','送李太博知梓州郪縣','劉攽','宋','宋诗','song-poetry','','[]','亦有飛鳬舄，那知蜀道難。',48,'全唐诗/poet.song.35000.json','["亦有飛鳬舄，那知蜀道難。", "峽山從劍盡，江水向浯寬。", "近邑輸鹽井，連城接錦官。", "清風足富俗，唯寄七弦彈。"]'),
('c634afda-0998-4dec-8fff-e429c6276aea','送邵中允知華亭縣','劉攽','宋','宋诗','song-poetry','','[]','一登文石陛，立拜紫泥書。',48,'全唐诗/poet.song.35000.json','["一登文石陛，立拜紫泥書。", "省戶方通籍，絃歌想下車。", "飛鳬來不遠，唳鶴聽何如。", "莫作陶彭澤，田園與世疏。"]'),
('307f958f-96b7-4a4b-93af-87bf40a577c8','晦日自薦福泛舟泊女郎臺下又泛東湖','劉攽','宋','宋诗','song-poetry','','[]','雪解寒生水，平湖照眼新。',48,'全唐诗/poet.song.35000.json','["雪解寒生水，平湖照眼新。", "扁舟徐送客，絕境漸無人。", "逕草芳菲淺，沙禽羽翼馴。", "佳辰數携酒，晦日已疑春。"]'),
('dd4f8fdd-c494-4c1d-9b31-46160989d537','晨興','劉攽','宋','宋诗','song-poetry','','[]','宿露寒猶重，升曦旦尚昏。',48,'全唐诗/poet.song.35000.json','["宿露寒猶重，升曦旦尚昏。", "高秋凋衆木，百里見平原。", "水涸看魚族，田收長稻孫。", "冥山不可望，那復更南轅。"]'),
('ad8d623b-04e8-4163-81c1-df24cc172f0c','將遊吳中寄原父','劉攽','宋','宋诗','song-poetry','','[]','久宦減仲産，行歌非五噫。',48,'全唐诗/poet.song.35000.json','["久宦減仲産，行歌非五噫。", "歸來問長鋏，習水看吳兒。", "弱喪殊可恨，儻來今自知。", "江山不我厭，有意卜居之。"]'),
('3733c3fd-9248-43a9-a9b7-0a60d22d733d','次韵和梁郎中咏太一碑','劉攽','宋','宋诗','song-poetry','','[]','翠琰盤螭近玉題，芝書光彩賁雄辭。',64,'全唐诗/poet.song.35000.json','["翠琰盤螭近玉題，芝書光彩賁雄辭。", "方從薄忌真如在，事絕鴻都豈易窺。", "幼婦色絲輝錦組，銀鈎金錯照琉璃。", "暮年無望青藜燭，時就祠官效祝釐。"]'),
('21528942-f473-4a82-b745-3cb70a0eea8d','次韵和郭固太保留別長句','劉攽','宋','宋诗','song-poetry','','[]','關西兵馬盛車鄰，君向吳門望緹群。',64,'全唐诗/poet.song.35000.json','["關西兵馬盛車鄰，君向吳門望緹群。", "聚米山川都掌內，折膠天氣及秋分。", "大將軍令窮青海，三受降城起拂雲。", "壯士不甘文學老，應須一劍取功勳。"]'),
('6ae2f2aa-4a81-455f-ad13-b8ec5677726d','年三十三','劉攽','宋','宋诗','song-poetry','','[]','年光過眼日復日，世事無成三十三。',64,'全唐诗/poet.song.35000.json','["年光過眼日復日，世事無成三十三。", "尚子幾時當畢嫁，倉公殊恨不生男。", "老知尚白書無益，貧作歸田計不堪。", "傳劍由來笑逢掖，簿書何必減清談。"]'),
('8bdf1c98-2c2f-4e92-b956-f2137b1f8ff7','晨起汴上口占寄韓玉汝','劉攽','宋','宋诗','song-poetry','','[]','戍鼓鄰雞催啟關，繁星未墜重愁顔。',64,'全唐诗/poet.song.35000.json','["戍鼓鄰雞催啟關，繁星未墜重愁顔。", "雲含雪意朝寒外，河带冰光曙色間。", "去遠不堪登灞涘，言歸時復念東山。", "梁臺客在文章盛，修竹何當復共攀。"]'),
('bd906d89-03f3-4de8-86a0-79e0cb8ada43','謝霍丘靜樂亭','劉攽','宋','宋诗','song-poetry','','[]','河陽種花春已滋，彭澤釀酒醉無期。',64,'全唐诗/poet.song.35000.json','["河陽種花春已滋，彭澤釀酒醉無期。", "宣城家聲故未泯，單父絃歌方爾爲。", "會知丘壑潛高興，新作池塘出夢思。", "多慚嵇呂相思意，空寄羊何共和詩。"]'),
('4d7384e2-121c-49b1-96e4-50a6defcb9d7','海陵','劉攽','宋','宋诗','song-poetry','','[]','楚江葭葦带青楓，小市魚鹽一水通。',64,'全唐诗/poet.song.35000.json','["楚江葭葦带青楓，小市魚鹽一水通。", "度日冥茫吹凍雨，欲晴撩亂起凉風。", "秋花舞蝶蒼煙裏，古木啼鴉返照中。", "扶杖階除搔白首，可憐卑濕負衰翁。"]'),
('204cc8fe-7a1f-4804-9270-31c6e6108ff3','寄陳和叔內翰','劉攽','宋','宋诗','song-poetry','','[]','六十衰遲祇自寬，讀書無味細書難。',64,'全唐诗/poet.song.35000.json','["六十衰遲祇自寬，讀書無味細書難。", "一麾已愧腰銀印，百選何由及治官。", "潮過石城如雪白，山從鍾嶺似虬蟠。", "元龍豪氣逾堅壯，投舝能同客醉歡。"]'),
('5375471f-734e-4f5e-9294-e865d26b3ca1','寄楊元素內翰','劉攽','宋','宋诗','song-poetry','','[]','四世清名悉上公，看君羽翮勢陵空。',64,'全唐诗/poet.song.35000.json','["四世清名悉上公，看君羽翮勢陵空。", "戲成爐鼎誇方士，妙奪蓍龜執鬼中。", "家有秦聲居自樂，書非尚白智無窮。", "華光講罷承明直，墨客無煩賦射熊。"]'),
('84786f10-3971-4649-a0f0-49e6328e7934','同諸公晚游開寶寺福聖院','劉攽','宋','宋诗','song-poetry','','[]','微雨吹凉晚更清，老人牽强逐君行。',64,'全唐诗/poet.song.35000.json','["微雨吹凉晚更清，老人牽强逐君行。", "縱談灰燼疑燒劫，指顧樓臺似化城。", "盤屈庭槐爲狡獪，扶持山薜喜縱橫。", "偷閒光景易侵夜，十二街頭坊鼓鳴。"]'),
('7e82a33f-5e15-46eb-888c-56a5bf2a3afe','奉詔再任諸掾曹有詩因次其韵','劉攽','宋','宋诗','song-poetry','','[]','天下英雄將相才，自銘重石畫雲臺。',64,'全唐诗/poet.song.35000.json','["天下英雄將相才，自銘重石畫雲臺。", "老夫不薄淮陽守，明詔幸緣黄霸來。", "豈有豹文容霧隠，更慚鵬翼待風培。", "諸卿相與望此府，詩筆縱橫武庫開。"]'),
('fd97f2e2-802c-4363-aac4-86c2fd7e5cf3','感事','劉攽','宋','宋诗','song-poetry','','[]','誤以雄名薦九重，天書待詔未央宮。',64,'全唐诗/poet.song.35000.json','["誤以雄名薦九重，天書待詔未央宮。", "白衣不召崔亭伯，賦筆猶殘亡是公。", "魂驚晚出芙蓉輦，淚墮春生楊柳風。", "衰鬢邇來元自白，可堪回首望遺弓。"]'),
('d50b0dfa-f22f-4ca8-bad1-efd604e5d2d2','建業華藏院此君亭','劉攽','宋','宋诗','song-poetry','','[]','何可幽棲無此君，層軒高下絕囂塵。',64,'全唐诗/poet.song.35000.json','["何可幽棲無此君，層軒高下絕囂塵。", "金聲玉色三千士，雪戟蛇矛丈六身。", "定有霜飆驚長夏，兼疑寒谷近比鄰。", "阿戎風味真難得，好事由來我輩人。"]'),
('013cfb9a-9ac1-466e-bdda-97a56dfbe36c','答張屯田朝退過閣下諸公','劉攽','宋','宋诗','song-poetry','','[]','紫宸歸路接銀臺，複閣重門相望開。',64,'全唐诗/poet.song.35000.json','["紫宸歸路接銀臺，複閣重門相望開。", "浮俗共譏惟寂寞，高賢獨肯少裴回。", "照人珠玉驚塵骨，落筆塤箎寫逸才。", "白日自嫌天上樂，不應滄海隔蓬萊。"]'),
('3aac0632-0c8a-4407-94aa-099c1483ea6c','衰羸','劉攽','宋','宋诗','song-poetry','','[]','衰羸因底病相和，留滯俄然去日多。',64,'全唐诗/poet.song.35000.json','["衰羸因底病相和，留滯俄然去日多。", "却是天憐令壽考，任從人會作風波。", "寬心總與歡欣受，述意無妨慷慨歌。", "更有南華書數紙，鵬聲蝸角奈渠何。"]'),
('6458c187-22a0-4dd8-b559-57c348a4dacc','途次馬上晨起寄章運判','劉攽','宋','宋诗','song-poetry','','[]','去年候客燕趙魏，今歲述職青兖徐。',64,'全唐诗/poet.song.35000.json','["去年候客燕趙魏，今歲述職青兖徐。", "無窮道路不相捨，將老光陰仍暗除。", "官燭鄰雞常曉色，林花巢燕總春餘。", "未知前古才士意，爲底願乘萬乘車。"]'),
('299161d4-4ae9-40dc-892a-e213daf2405e','傷梅聖俞直講都官','劉攽','宋','宋诗','song-poetry','','[]','論兵自負縱橫略，獻賦端從遲暮年。',64,'全唐诗/poet.song.35000.json','["論兵自負縱橫略，獻賦端從遲暮年。", "筐篋成書莫知數，田園生計獨無錢。", "郎官列宿爲時貴，博士三科不待遷。", "已向九原悲蔓草，尚疑吳市有神仙。"]'),
('376b5d32-e7d7-4893-a0c4-3123f299702b','送劉長官桂府掌機宜','劉攽','宋','宋诗','song-poetry','','[]','桂林風物舊宜人，雪片梅花五嶺春。',64,'全唐诗/poet.song.35000.json','["桂林風物舊宜人，雪片梅花五嶺春。", "心喜大江流瘴霧，眼看南極異星辰。", "軍中羽檄時無警，徼外明珠日獻珍。", "酒量問君能幾許，越猿蠻鳥易傷神。"]'),
('5d1c08a8-aca8-42a7-81d5-c37b000c133c','雨後向景亭','劉攽','宋','宋诗','song-poetry','','[]','春泥軟熟步成黏，水外風光一頓添。',64,'全唐诗/poet.song.35000.json','["春泥軟熟步成黏，水外風光一頓添。", "境爲偶來生喜色，情緣久住失憎嫌。", "黄鸝慣習沙鷗野，古木粗疏徑草纖。", "更向樽中得真趣，天然柔旨不因甜。"]'),
('ad9a93a0-f82e-45f2-bd3b-17d75dfb86d2','酬送吳潛朝奉','劉攽','宋','宋诗','song-poetry','','[]','衰翁同歲喜相收，同病同心同白頭。',64,'全唐诗/poet.song.35000.json','["衰翁同歲喜相收，同病同心同白頭。", "委吏除官俱逆旅，瘴烟香草等荒州。", "六千里外拋機略，二十年來謹校讎。", "工拙是非無會處，下陂紅日若爲留。"]'),
('b5ba9314-8daa-4c81-baaf-8896fc3f1e8d','酬送羅朝奉  其一','劉攽','宋','宋诗','song-poetry','','[]','二年流竄逐卑棲，歸奉蓬丘顔向低。',64,'全唐诗/poet.song.35000.json','["二年流竄逐卑棲，歸奉蓬丘顔向低。", "病到鈞天都是夢，老如濛汜已平西。", "兩轓更忝魚符寵，雙鬢誰憐鶴髮齊。", "相愧清詩無以報，回將燕石塞縣黎。"]'),
('4bc168cf-ce06-42e8-8a98-a31033bf388c','酬送羅朝奉  其二','劉攽','宋','宋诗','song-poetry','','[]','老去光陰若電驚，此身已復愧扶行。',64,'全唐诗/poet.song.35000.json','["老去光陰若電驚，此身已復愧扶行。", "歸田悔不如元亮，畢娶猶能似尚平。", "曩歲薦賢終未效，太音從古竟希聲。", "最憐閭里人相語，北部威名動帝城。"]'),
('c88490fa-98ef-4e06-87b9-1b2500acc838','冬至登樓','劉攽','宋','宋诗','song-poetry','','[]','澤國風光早早催，陽生已復似春回。',64,'全唐诗/poet.song.35000.json','["澤國風光早早催，陽生已復似春回。", "不妨野史書雲物，會伴南公進壽杯。", "塵世光陰俱短日，客心冥漠過潛灰。", "此心未厭隆中卧，亦任東風起蟄雷。"]'),
('b3827751-7d43-4b71-8821-9d9cd30aa237','送高士敦成都鈐轄','劉攽','宋','宋诗','song-poetry','','[]','使君出守腰銅虎，東第歸來上濯龍。',64,'全唐诗/poet.song.35000.json','["使君出守腰銅虎，東第歸來上濯龍。", "四姓禮容均馬鄧，三刀形勝夢巴賨。", "軍中樂事隨談笑，徼外威聲待指縱。", "壯歲勳名當自致，舅家恩澤不成封。"]'),
('4987f479-10ed-44b3-ab61-617a44841881','留別蘇安上','劉攽','宋','宋诗','song-poetry','','[]','高閤橫霄梧十尋，回廊曲檻晝陰陰。',64,'全唐诗/poet.song.35000.json','["高閤橫霄梧十尋，回廊曲檻晝陰陰。", "期年不就長楊賦，晚歲空爲梁甫吟。", "童稚相親俱白髮，風波失所更情深。", "滄溟極目雲濤壯，相見胸中快病襟。"]'),
('a19439f2-d2e1-4879-96e4-7cc93072bd0e','與顧子惇同爲秘書少監今年余以病求守汝南子惇亦除河東漕作詩紀事亦用送別','劉攽','宋','宋诗','song-poetry','','[]','蓬萊閣下枕書眠，一日除官不後先。',64,'全唐诗/poet.song.35000.json','["蓬萊閣下枕書眠，一日除官不後先。", "并土山河多馬地，汝南秔稻濯龍淵。", "壯心自喜談兵策，暮齒長慚守乘田。", "別後天中相望處，參旗橫注太行邊。"]'),
('0cd065f5-37cc-4c70-83c3-76a624ae19b1','郡樓望雪','劉攽','宋','宋诗','song-poetry','','[]','繞郭蒼山高復重，東風朔雪曙雲濃。',64,'全唐诗/poet.song.35000.json','["繞郭蒼山高復重，東風朔雪曙雲濃。", "層樓已出紅塵境，到客寧知群玉峰。", "萬樹羽儀翔白鷺，四原鱗甲動真龍。", "玉樽清酒留終夕，更看山明霽後松。"]'),
('c7dc71b0-9185-4fa3-ba40-a4d8057074c3','和通判裴庫部城樓雪後','劉攽','宋','宋诗','song-poetry','','[]','數刻又移半日閒，倚樓朝雪正怡顔。',64,'全唐诗/poet.song.35000.json','["數刻又移半日閒，倚樓朝雪正怡顔。", "委蛇原色蒼龍甲，宛轉城陰玉带環。", "曾是茵憑偕出處，聊於木雁得中間。", "傷春一振曹風陋，不羨淮南大小山。"]'),
('1ea3cb17-d42c-423d-b6b2-c03ff7f66da2','復雪','劉攽','宋','宋诗','song-poetry','','[]','九江舊瘴冬無雪，三峽悲風近有冰。',64,'全唐诗/poet.song.35000.json','["九江舊瘴冬無雪，三峽悲風近有冰。", "山岳出雲寒處處，樓臺倚玉照層層。", "不憂鴻雁飛無力，直畏蛟龍病莫興。", "凍酒一杯還自勸，夜窗飄灑讀書燈。"]'),
('9ccc8f9c-e9c5-42d4-8ab4-1df175fcadc3','次韵宋職方雪','劉攽','宋','宋诗','song-poetry','','[]','梵天銀界談非想，仙府瑶臺恨隔塵。',64,'全唐诗/poet.song.35000.json','["梵天銀界談非想，仙府瑶臺恨隔塵。", "何事同雲移絕境，不知高宴即良因。", "林芳散漫裝珠蕊，粉面光輝照玉人。", "別舉一樽邀老伴，迎春送臘祇三旬。"]'),
('a63dc946-9273-4380-9254-cd7668f2c370','次韵裴庫部雪二首  其一','劉攽','宋','宋诗','song-poetry','','[]','小雨駐雲風借威，回眸千里玉山輝。',64,'全唐诗/poet.song.35000.json','["小雨駐雲風借威，回眸千里玉山輝。", "塗人竟比麻衣色，野老時驚白雁飛。", "梁苑正應延上客，齊宮遥想闢重闈。", "誰云自鄶無譏者，一曲陽春可見微。"]'),
('caee4a15-175e-43cf-a4d2-fa3707e58d9a','次韵裴庫部雪二首  其二','劉攽','宋','宋诗','song-poetry','','[]','似薄凝霜不振威，端凌愛日奪光輝。',64,'全唐诗/poet.song.35000.json','["似薄凝霜不振威，端凌愛日奪光輝。", "變成鹽浦風沙亂，卷起濤江海上飛。", "西望屯雲瞻魏闕，正思鳴佩賀端闈。", "孤城牢落無來客，坐待山明見翠微。"]'),
('0966b7ac-9e7b-4472-b0dd-fbc10265a049','太一宮奉安後得雪','劉攽','宋','宋诗','song-poetry','','[]','八通除道接層霄，五日同雲映泬寥。',64,'全唐诗/poet.song.35000.json','["八通除道接層霄，五日同雲映泬寥。", "靈貺那從天馬下，積陰疑有海神朝。", "潤生塵陌無窮遠，甘入原田不待消。", "陋巷苦寒方晝卧，靜無人迹到瓊瑶。"]'),
('3dc03941-dc8e-4758-a0fa-77971030b88b','雪中呈通判庫部宋職方','劉攽','宋','宋诗','song-poetry','','[]','冬雪并今早兩回，無風韵膩白皚皚。',64,'全唐诗/poet.song.35000.json','["冬雪并今早兩回，無風韵膩白皚皚。", "麥根得潤萌芽綠，瘴氣逢寒霧露開。", "官爲勸農知我喜，心緣愛客望君來。", "城頭甚有登臨境，群玉排峰銀作臺。"]'),
('f9363766-ff61-4387-8879-24719eb9d1e8','錢穆甫楊康功使高麗還爲中書舍人書此爲寄','劉攽','宋','宋诗','song-poetry','','[]','天子邊人二使星，滄波一笑已揚舲。',64,'全唐诗/poet.song.35000.json','["天子邊人二使星，滄波一笑已揚舲。", "大明照海陽烏近，黑霧迎潮水怪腥。", "北貊左肩輸策略，西垣右掖付儀刑。", "授詩三百成專對，更看黄麻似六經。"]'),
('f1f6cedb-29d8-4f08-9799-0fa80b08d738','酬狄奉議','劉攽','宋','宋诗','song-poetry','','[]','病卧湘濱面嶽山，每聽鳴鶴憶蘇仙。',64,'全唐诗/poet.song.35000.json','["病卧湘濱面嶽山，每聽鳴鶴憶蘇仙。", "三苗地闊橫千里，五嶺泉分會一川。", "門有雀羅甘棄置，人今舞袖足迴旋。", "梁公孫子丹青似，傾蓋歡然秀句傳。"]'),
('f8345ebe-0961-42a0-a635-40a21b369cc7','酬張伯常朝議','劉攽','宋','宋诗','song-poetry','','[]','郢人蘭雪有餘風，盡在君家七字中。',64,'全唐诗/poet.song.35000.json','["郢人蘭雪有餘風，盡在君家七字中。", "白髮塵纓深念我，青郊藜杖不如公。", "鄉心正想千年鶴，老計終須一畝宮。", "不諱求田并問舍，景山何必晚爲通。"]'),
('de3d67e7-c295-48b3-bc87-cd22697f048d','酬黄朝議  其一','劉攽','宋','宋诗','song-poetry','','[]','自無籌略預材難，非有文華聚筆端。',64,'全唐诗/poet.song.35000.json','["自無籌略預材難，非有文華聚筆端。", "涉歷羊腸迷坦坦，穿聯魚目愧珊珊。", "嶽猿聽久堪頭白，林實嘗來厭齒酸。", "葵藿傾心由物性，日邊依約見長安。"]'),
('0b51a8fe-8875-4f7f-a76e-be8cea29f619','酬黄朝議  其二','劉攽','宋','宋诗','song-poetry','','[]','蘧公四十九年非，萬事當須向老知。',64,'全唐诗/poet.song.35000.json','["蘧公四十九年非，萬事當須向老知。", "材者不如愚者樂，前人多作後人資。", "羨君黄髮初傾蓋，矜我迷津數贈詩。", "聽話朱陵仙府事，慨然清嘯一伸眉。"]'),
('e776ccae-eaba-4e9c-90d4-f5ed8a384b71','酬魏朝議','劉攽','宋','宋诗','song-poetry','','[]','鶑谷相從列俊英，四朝容許濫虛名。',64,'全唐诗/poet.song.35000.json','["鶑谷相從列俊英，四朝容許濫虛名。", "忍將百老言存沒，乍喜三人咏合并。", "春入芳菲皆意思，酒隨衰朽即心情。", "新詩不怪煩先唱，猶向君前畏後生。"]'),
('9e9c5f4a-2932-49ce-9bf8-14657daebe3b','贈黄朝議','劉攽','宋','宋诗','song-poetry','','[]','黄公八十健精神，遠近推爲五福身。',64,'全唐诗/poet.song.35000.json','["黄公八十健精神，遠近推爲五福身。", "樽酒不曾輕賤士，爐丹時復遇幽人。", "晚夸鄉里拖金紫，早見兒孫列搢紳。", "一事世儒難學處，弟兄歸老樂相親。"]'),
('42e29437-9386-4f58-9f7b-93460f1c8afe','次韵和孔朝議','劉攽','宋','宋诗','song-poetry','','[]','自愧專城無到客，今晨錫宴喜君同。',64,'全唐诗/poet.song.35000.json','["自愧專城無到客，今晨錫宴喜君同。", "詩言泮水始可與，酒勝邯鄲長不空。", "但有葵心傾日下，待看雲瑞起封中。", "高車清興底易盡，怪似林間束緼翁。"]'),
('f7573b7d-cc2e-4c9f-8f9d-20eb3447ece3','和張給事喜雨','劉攽','宋','宋诗','song-poetry','','[]','勿驚四野連宵雨，盡是諸山觸石雲。',64,'全唐诗/poet.song.35000.json','["勿驚四野連宵雨，盡是諸山觸石雲。", "雷響透空如欲墜，電光劃暗總成紋。", "祝官陳信無虛語，梵宇凝香不斷薰。", "帝力由來人莫識，始知延譽屬夫君。"]'),
('5247f7e1-8bc4-43d8-ab6f-d50dc7a3f7ba','次韵韓康公','劉攽','宋','宋诗','song-poetry','','[]','行馬門闌與古同，客車連軫響隆隆。',64,'全唐诗/poet.song.35000.json','["行馬門闌與古同，客車連軫響隆隆。", "定知醉飽能容士，當信康寧盡屬公。", "剽得新聲夸耳性，傳將佳句愈頭風。", "文人桃李多無數，珠玉旁邊愧此翁。"]'),
('5f8f862d-bac9-4c7e-aa72-c0d623313ca2','次韵韓康公二首  其一','劉攽','宋','宋诗','song-poetry','','[]','疊石疏篁淺藥苗，淡雲清雨意寥寥。',64,'全唐诗/poet.song.35000.json','["疊石疏篁淺藥苗，淡雲清雨意寥寥。", "酇侯僻地規摹別，荀令西濠步武遥。", "繞砌芝蘭歡內集，滿蹊桃李慰佳招。", "原情獨恨飛鴻遠，悵望三秋咏采蕭。"]'),
('98ce71e8-2543-4e9e-af50-52ac87c8f3ef','次韵韓康公二首  其二','劉攽','宋','宋诗','song-poetry','','[]','清汝泱泱紫邏深，綠車紅旆付重臨。',64,'全唐诗/poet.song.35000.json','["清汝泱泱紫邏深，綠車紅旆付重臨。", "聖朝不逆原鴒意，達士俱存塞馬心。", "日赤報衙容晏枕，夜蘭留宴縱清斟。", "鳳池何必全勝此，薄暮歸休客萬簪。"]'),
('70ba3a05-0c7b-4d96-abfb-6efedc56bc1f','王史館園','劉攽','宋','宋诗','song-poetry','','[]','鳴泉傍舍水翻車，修竹連雲曲徑斜。',64,'全唐诗/poet.song.35000.json','["鳴泉傍舍水翻車，修竹連雲曲徑斜。", "謝傅東山非獨往，酇侯避地此傳家。", "丹椒紅桂隨時實，綠芰緋薇觸處花。", "到客可能忘外事，斷年相與玩芳華。"]'),
('dc934e33-73f1-4857-9491-ae2306f77005','過柏林院僧吉長老有古殿吳道子畫維摩居士又有斷碑是寶歷年中記義岑禪師住院事','劉攽','宋','宋诗','song-poetry','','[]','靈光歲久獨巋然，峴首遺碑亦未遷。',64,'全唐诗/poet.song.35000.json','["靈光歲久獨巋然，峴首遺碑亦未遷。", "會向三生記前佛，暫從方丈識諸天。", "篆香徐刻黄金印，梵宇時開貝葉篇。", "門外霜風正摇落，庭前翠柏自安禪。"]'),
('892a234c-ea78-4367-91e3-d044bfc6b998','館宿有懷平甫','劉攽','宋','宋诗','song-poetry','','[]','銅壺上水掖門扃，岑寂回廊起獨行。',64,'全唐诗/poet.song.35000.json','["銅壺上水掖門扃，岑寂回廊起獨行。", "日下屋山三面赤，月臨天井四方明。", "校經燈火初無禁，汗簡文書不計程。", "坐憶故人清夜語，淡雲飛去隔層城。"]'),
('f7006581-f780-4fc6-8935-d72457550f57','曲阜宣聖廟夫子手植檜二首  其一','劉攽','宋','宋诗','song-poetry','','[]','秀色拏空四十圍，問年今已倍千斯。',64,'全唐诗/poet.song.35000.json','["秀色拏空四十圍，問年今已倍千斯。", "移根信假杓關力，息蔭寧無煖席時。", "文字魯恭經改觀，履綦鍾意想攀枝。", "季孫亦自譽佳樹，漫負甘棠蔽芾詩。"]'),
('f422b0c3-26dc-445e-ac68-b1675de0c7c2','曲阜宣聖廟夫子手植檜二首  其二','劉攽','宋','宋诗','song-poetry','','[]','伐樹商丘去被圍，似於庭檜特勤斯。',64,'全唐诗/poet.song.35000.json','["伐樹商丘去被圍，似於庭檜特勤斯。", "禹腰堯顙應遺魄，柏葉松身異曩時。", "恭梓二三千學士，愛棠四十六孫枝。", "攝衣下馬低回久，更就清風一誦詩。"]'),
('c15156a2-c8c1-415d-9f40-dba47c59dbeb','城濠泛舟同畢長官','劉攽','宋','宋诗','song-poetry','','[]','綠水環城十二里，茅茨带郭百餘家。',64,'全唐诗/poet.song.35000.json','["綠水環城十二里，茅茨带郭百餘家。", "侵雲柳影不見日，過雨荷香全勝花。", "幽事圍棋翻局勢，清歡煮雪試茶芽。", "眼前景物自蕭散，何必青溪向若邪。"]'),
('18fbf58f-8c90-4575-8be5-ad4609589733','次韵酬姚都官時會堂見寄','劉攽','宋','宋诗','song-poetry','','[]','百里崑岡半草萊，畫梁危棟一朝開。',64,'全唐诗/poet.song.35000.json','["百里崑岡半草萊，畫梁危棟一朝開。", "清川去水縈回渚，喬木濃陰映綠苔。", "子獻人琴俱不幸，武侯營壘信奇才。", "斷鴻牢落情愁絕，聞笛那堪賦七哀。"]'),
('f377f204-371d-4688-bea4-732c28b3fcca','遊船','劉攽','宋','宋诗','song-poetry','','[]','太液滄波北下流，依然清淺可勝舟。',64,'全唐诗/poet.song.35000.json','["太液滄波北下流，依然清淺可勝舟。", "浴鳬鳴鶴輝輝日，折葦衰荷澹澹秋。", "勝境陳前終不厭，機心去盡了無愁。", "宋生善賦登臨興，華髮相從免獨遊。"]'),
('d6e9db38-57f3-4c0c-a5e3-3c3824b2ad91','和晁金部感秋','劉攽','宋','宋诗','song-poetry','','[]','秋來無悶亦無悲，世味年華老遍知。',64,'全唐诗/poet.song.35000.json','["秋來無悶亦無悲，世味年華老遍知。", "黄葉暮蟬携杖處，斷霞鳴雁倚樓時。", "淮陽汲守容多病，水部何郎最解詩。", "咫尺音書那度歲，春風已復柳垂絲。"]'),
('9635033c-3172-4f6b-aecb-640ec58a29b3','雙檜','劉攽','宋','宋诗','song-poetry','','[]','雙檜森森高出檐，憶昨卜鄰逢吉占。',64,'全唐诗/poet.song.35000.json','["雙檜森森高出檐，憶昨卜鄰逢吉占。", "清風似主我爲客，冠蓋相向何凝嚴。", "愛棠不能如召伯，種柳自覺勝陶潛。", "春暉漸永群芳麗，翠影看花一寸添。"]'),
('76f7d2cc-7dd2-4486-b061-a89e6804453b','題王金吾園亭','劉攽','宋','宋诗','song-poetry','','[]','烏衣里巷接城隅，東第名園冠上都。',64,'全唐诗/poet.song.35000.json','["烏衣里巷接城隅，東第名園冠上都。", "家事從前貴公子，宦游當世執金吾。", "舊蹊桃李春相續，滿地芝蘭德不孤。", "故有鼎彝傳盛烈，况聞圖史自爲娛。"]'),
('460d492f-dd5c-4886-975f-1aeec1924b84','負暄','劉攽','宋','宋诗','song-poetry','','[]','聞道帝師仍負暄，遥知愛景滿維垣。',64,'全唐诗/poet.song.35000.json','["聞道帝師仍負暄，遥知愛景滿維垣。", "鷹揚肯顧踆烏逝，龍衮尤憐夸父奔。", "赤舄正宜隨步武，白駒那敢離庭軒。", "野人皆欲獻天子，他日期公助一言。"]'),
('83affb67-2c87-4659-9457-97669497ea40','陳通議園亭','劉攽','宋','宋诗','song-poetry','','[]','聚星休沐事依然，社臘安車不計年。',64,'全唐诗/poet.song.35000.json','["聚星休沐事依然，社臘安車不計年。", "五福何妨兼第宅，一壺元自有神仙。", "種來珍木如人立，移取名花奪地偏。", "聞道都城曾問卜，始知機石不虛傳。"]'),
('87c596cc-7fa6-42f9-9c3d-16be54a61cfb','杜介供奉園亭','劉攽','宋','宋诗','song-poetry','','[]','側徑群芳經荷鋤，小窗明日喜觀書。',64,'全唐诗/poet.song.35000.json','["側徑群芳經荷鋤，小窗明日喜觀書。", "下床便得山居樂，深巷仍多長者車。", "省事即知長脫灑，養生元不待贏餘。", "客來一醉聊相向，莫問經年甔石儲。"]'),
('4e447251-c3f3-4ee6-b28f-f18497137837','酬黄安期推官見寄','劉攽','宋','宋诗','song-poetry','','[]','郴江清澈照毫毛，吹笛平陽舍有蒿。',64,'全唐诗/poet.song.35000.json','["郴江清澈照毫毛，吹笛平陽舍有蒿。", "鄉信不嫌無過雁，宦遊正復長兒曹。", "青楓雨後如人立，南極秋來出地高。", "齊難楚稱何日就，釣竿元自欲連鼇。"]'),
('ab95859f-115c-4161-8d8d-be05bb765840','酬黄推官','劉攽','宋','宋诗','song-poetry','','[]','既將魚目換驪珠，富潤囊箱足賈餘。',64,'全唐诗/poet.song.35000.json','["既將魚目換驪珠，富潤囊箱足賈餘。", "顧我能知天下馬，呼兒藏作篋中書。", "老羞流輩爲千諾，狂守初心付兩如。", "相助飛鳴竟何力，祇宜空手講玄虛。"]'),
('5a38dc4d-b2a5-4946-ae02-85591f387c26','予所居本章丞相舊第他日友人楊彥文爲余道丞相時事因作一篇予楊丞相以郎官始卜此宅不出都門二十餘年遂至台衮故末句及之','劉攽','宋','宋诗','song-poetry','','[]','酇侯常以儉爲師，僻地依然草滿蹊。',64,'全唐诗/poet.song.35000.json','["酇侯常以儉爲師，僻地依然草滿蹊。", "却指舊池曾浴鳳，更攀喬樹憶棲雞。", "清泉惡石皆吾有，樽酒囊書得自携。", "誰道爲郎多白首，已看霖雨出蟠泥。"]'),
('7c3fa621-2f27-4e09-b881-5e27d3c44a85','與成太博九同年會飲成四韵','劉攽','宋','宋诗','song-poetry','','[]','江海分龍不計年，異方傾蓋意歡然。',64,'全唐诗/poet.song.35000.json','["江海分龍不計年，異方傾蓋意歡然。", "壯夫白首驚相問，濁水清塵默自憐。", "萬事過前都是夢，一杯相屬獨非天。", "得朋正復同心士，賦咏能忘垂隴篇。"]'),
('7f808afa-e68c-4125-84b0-c059d4460c17','游玉仙觀寄王四十','劉攽','宋','宋诗','song-poetry','','[]','紫府仙真冰雪顔，丹梯岑寂試來攀。',64,'全唐诗/poet.song.35000.json','["紫府仙真冰雪顔，丹梯岑寂試來攀。", "翠鬟濯玉交團扇，濃霧噴香闇博山。", "不信異人能到此，正憐春意已歸還。", "吹笙化舄知君事，猶恨來游先後間。"]'),
('b271727b-62d2-4314-9afb-a81952dee43a','京北流人','劉攽','宋','宋诗','song-poetry','','[]','嗟爾流人亦可悲，白頭老叟抱中兒。',64,'全唐诗/poet.song.35000.json','["嗟爾流人亦可悲，白頭老叟抱中兒。", "不羞遠作投荒客，自恨生遲外戶時。", "魚失江湖相喣沫，鳥囚籠檻苦啼饑。", "鄉原日日生荆棘，說似旁人猶涕垂。"]'),
('042cbbca-39df-4fd6-a166-1ee35068e7be','觀灌園偶書','劉攽','宋','宋诗','song-poetry','','[]','一叟汲泉摇轆轤，老妻分水亦携鋤。',64,'全唐诗/poet.song.35000.json','["一叟汲泉摇轆轤，老妻分水亦携鋤。", "青青宿草知春入，浥浥蒼苔過雨初。", "勞力不應嗤强勉，養生何必待贏餘。", "白頭當作於陵子，身教兒孫種樹書。"]'),
('4c2c6d96-1c46-4be3-b3a6-9d9cc5a2b85d','和宋次道三館曬書','劉攽','宋','宋诗','song-poetry','','[]','天祿圖書一歲開，五雲遲日近蓬萊。',64,'全唐诗/poet.song.35000.json','["天祿圖書一歲開，五雲遲日近蓬萊。", "後生得見靈蘭策，貴客都傾內外臺。", "不似羽陵殘蠹簡，正如金谷聚英材。", "論詩老去無情思，况是陽春未易陪。"]'),
('ea77746c-6ee1-414b-abf4-c53a9cba05b7','送張器判官','劉攽','宋','宋诗','song-poetry','','[]','平吳舊族仕中朝，湯樂徐馮已寂寥。',64,'全唐诗/poet.song.35000.json','["平吳舊族仕中朝，湯樂徐馮已寂寥。", "吾子白頭趨幕府，同年黄綬亦雲霄。", "著鞭跨馬須爭道，奮臂呼盧更叱梟。", "顔駟馮唐俱晚遇，不妨青紫老垂腰。"]'),
('8861ac04-86c0-4cc6-bf4c-b01fb2e9cc4c','次韵和張舍人北使歸','劉攽','宋','宋诗','song-poetry','','[]','飲冰重見古人心，絕幕仍當暮雪深。',64,'全唐诗/poet.song.35000.json','["飲冰重見古人心，絕幕仍當暮雪深。", "朝出穹廬隨拜日，夜鳴刁斗候橫參。", "胡兒射雁爭娛客，羌女聽笳却走林。", "聞說虜情親博望，一言珍重萬黄金。"]'),
('29e43f23-98a6-4ae6-a127-5d30916bc770','兩府新第','劉攽','宋','宋诗','song-poetry','','[]','聖世諸公起草萊，君恩東第一時開。',64,'全唐诗/poet.song.35000.json','["聖世諸公起草萊，君恩東第一時開。", "排門畫戟交行馬，轉肘沙堤接上臺。", "衛國名亭緣伐叛，平津虛館爲翹材。", "猶分長史待天下，衰老詎能忘儻來。"]'),
('baa73373-1c3e-4a9a-8115-291423ae04c8','乙巳早春再遊玉仙觀贈陳道士','劉攽','宋','宋诗','song-poetry','','[]','十里平郊不值人，解鞍依約記前春。',64,'全唐诗/poet.song.35000.json','["十里平郊不值人，解鞍依約記前春。", "問年已復驚身老，遇境猶能發興新。", "泉漲池冰舒雁爪，霜團庭檜疊龍鱗。", "種桃道士長無恙，自愧劉郎病滯身。"]'),
('17cf12ec-137a-4615-9f6c-96550370b73f','新廣柏悅堂後軒作七言','劉攽','宋','宋诗','song-poetry','','[]','南榮曝日足娛客，北牖來風亦在予。',64,'全唐诗/poet.song.35000.json','["南榮曝日足娛客，北牖來風亦在予。", "聊以維摩開丈室，便知陶令愛吾廬。", "神龜大蔡昂頭際，澤雉名翬矯翼初。", "戲問庭前雙古柏，閱人無算我誰如。"]'),
('2e1f5404-7329-4fad-93da-7f86d5948caa','立春謝賜幡勝口號呈子瞻沖元內翰子開器資舍人','劉攽','宋','宋诗','song-poetry','','[]','立春幡勝紫宸朝，正以金璫插右貂。',64,'全唐诗/poet.song.35000.json','["立春幡勝紫宸朝，正以金璫插右貂。", "便覺陽和生暖律，俱承慶澤下層霄。", "奇零雪片依樓角，容易風威轉柳條。", "七十無能不歸去，强將衰白向顔韶。"]'),
('96604f83-0be2-45da-8b62-32270af76e20','和前韵','劉攽','宋','宋诗','song-poetry','','[]','雪寒常怯月邊朝，乍起東風拂敝貂。',64,'全唐诗/poet.song.35000.json','["雪寒常怯月邊朝，乍起東風拂敝貂。", "銀勝綵幡分節物，宿雲晨霧凝璇霄。", "君爲特達千金璧，我是衰遲百尺條。", "叩缶烏烏聊快耳，寧知報響得咸韶。"]'),
('d6e8b3dd-6251-4d7d-a58e-08b35b20268a','王正仲林子中聯舟西上過睢陽寄書率爾成詩爲報','劉攽','宋','宋诗','song-poetry','','[]','大帆如翼畫江來，鼙鼓聲乾虺虺雷。',64,'全唐诗/poet.song.35000.json','["大帆如翼畫江來，鼙鼓聲乾虺虺雷。", "洛水登仙惟李郭，兔園延客得鄒枚。", "寄書上有加餐飯，傾蓋何時數舉杯。", "想到石渠尋舊境，秋花著子遍庭槐。"]'),
('1568df14-4617-4d2d-b750-89b13c1692e2','呂舍人北使','劉攽','宋','宋诗','song-poetry','','[]','漢德舟車萬里通，赤心持節復平戎。',64,'全唐诗/poet.song.35000.json','["漢德舟車萬里通，赤心持節復平戎。", "空同氣色連窮髮，當戶君臣聚引弓。", "馬酒禦寒朝伴凍，貂裘衝雪晝禁風。", "清蒲固有安邊畫，可待甘陳傅鄭功。"]'),
('ac7c9089-5a4b-481f-96c3-4a3eeb635765','仲馮北使','劉攽','宋','宋诗','song-poetry','','[]','極北空同戴斗星，越疆猶有短長亭。',64,'全唐诗/poet.song.35000.json','["極北空同戴斗星，越疆猶有短長亭。", "漢朝正朔原無外，邊地山河不見經。", "雪擁旃裘綿欲折，冰生湩酪酒初醒。", "我家四世俱持節，送爾皇華却涕零。"]'),
('39d98c0b-f099-4966-b7fa-b5e357ed68e9','王仲至使北','劉攽','宋','宋诗','song-poetry','','[]','朔雪如沙萬里程，幽陰戴斗正嚴凝。',64,'全唐诗/poet.song.35000.json','["朔雪如沙萬里程，幽陰戴斗正嚴凝。", "終軍何必功橫草，沈尹無煩夕飲冰。", "茗粥邇來誇湩酪，氈裘仍自愧綿繒。", "歲寒拜日穹廬外，想見東南瑞氣昇。"]'),
('a7c7ab7e-4073-48c7-8904-63bec175dba9','早春郊外','劉攽','宋','宋诗','song-poetry','','[]','滿城塵土無窮極，出郭風煙頓掃除。',64,'全唐诗/poet.song.35000.json','["滿城塵土無窮極，出郭風煙頓掃除。", "春淺暗泉流脈脈，日長歸雁影疏疏。", "强將拙計仍謀野，等復勞生愧荷鋤。", "安得面山臨水地，種花移竹一茅廬。"]'),
('b4394197-e568-4766-b626-bc97433fa72b','贈楊次公秘丞','劉攽','宋','宋诗','song-poetry','','[]','莫將陽九歸時數，自爲乾封致吉祥。',64,'全唐诗/poet.song.35000.json','["莫將陽九歸時數，自爲乾封致吉祥。", "必若中興待雲漢，枉教流議及桑羊。", "相望冠蓋交馳傳，躬作犧牲屬奉常。", "膚寸崇朝看變化，吾農從此萬斯箱。"]'),
('d2977b74-50ec-432d-a5af-554ea7629676','酬潘及甫同年秘丞','劉攽','宋','宋诗','song-poetry','','[]','困學那知三代英，定交良愧十年兄。',64,'全唐诗/poet.song.35000.json','["困學那知三代英，定交良愧十年兄。", "斷鴻陳迹悲朝露，喬木孤飛念友生。", "樽酒相逢開口笑，風波遠別使人驚。", "海邊春色青青柳，淚落陽關最後聲。"]'),
('f14ae704-23e7-4864-97a5-bbb7a7a0e02e','省宿','劉攽','宋','宋诗','song-poetry','','[]','開旦文書整日勞，漏傳門掩謝諸曹。',64,'全唐诗/poet.song.35000.json','["開旦文書整日勞，漏傳門掩謝諸曹。", "小庭待月久不下，喬木降風空自高。", "舊學荒蕪多夢寐，微官補益抵分毫。", "秋來鬢髮看成雪，不似潘生始二毛。"]'),
('925fedc8-c278-4251-b282-b5eac55171b8','次韵和陳學士八月十六日省宿','劉攽','宋','宋诗','song-poetry','','[]','疏簾珍簟倚通中，落燼飄香墮玉蟲。',64,'全唐诗/poet.song.35000.json','["疏簾珍簟倚通中，落燼飄香墮玉蟲。", "信宿依然十分月，黄昏正爾一番風。", "流螢暗逐星過水，驚鵲時翻葉墮空。", "詩興不禁頭已白，醉鄉祇有面微紅。"]'),
('29ba2122-c7d1-4723-9d34-7f75b06abdfc','次韵和登州張使君','劉攽','宋','宋诗','song-poetry','','[]','層城表海勢嵯峨，車騎雍容樂事多。',64,'全唐诗/poet.song.35000.json','["層城表海勢嵯峨，車騎雍容樂事多。", "八月潮平占候火，三更日上看濤波。", "閒留方士談迂怪，醉聽齊謳起艷歌。", "莫以高材厭留滯，功名從古喻裘蓑。"]'),
('16015f3c-9317-46ed-88df-5840d4d80efc','和陳五祠九宮致齋','劉攽','宋','宋诗','song-poetry','','[]','帝家三正付惟清，岑寂容臺最古廳。',64,'全唐诗/poet.song.35000.json','["帝家三正付惟清，岑寂容臺最古廳。", "長日齋居空旦旦，幾年華髮欲星星。", "霜風洒葉都成赤，籬菊疏花雜間青。", "多少舊溪招隠興，暫因釐事繞林坰。"]'),
('b69f5057-8a68-4f20-a37b-c3623d29db37','題所種梧楸','劉攽','宋','宋诗','song-poetry','','[]','曲檻層檐與樹宜，三年初見綠陰垂。',64,'全唐诗/poet.song.35000.json','["曲檻層檐與樹宜，三年初見綠陰垂。", "聲隨白雨凉生疾，影奪朱炎暑到遲。", "傍倚轆轤看汲井，下留閒客坐圍棋。", "會須百尺參天直，白髮空嗟拱把詩。"]'),
('27f22f05-6153-4d32-94c9-60d068762a08','還家','劉攽','宋','宋诗','song-poetry','','[]','草徑茅廬不遠城，歸來松竹已秋聲。',64,'全唐诗/poet.song.35000.json','["草徑茅廬不遠城，歸來松竹已秋聲。", "鄙人倦客方招隠，弱女非男亦慰情。", "薄願自甘隨老圃，短才無用至名卿。", "閭里相見成幽熟，他日禽魚尚不驚。"]'),
('1c31c15c-303d-453c-88cc-3b7dde2681a5','城上新亭','劉攽','宋','宋诗','song-poetry','','[]','野芳喬木共回環，步到西城五里間。',64,'全唐诗/poet.song.35000.json','["野芳喬木共回環，步到西城五里間。", "值有叢祠休足力，就爲幽境慰心顔。", "鷗聲遠水連晴日，剎影高臺似淺山。", "勝事本來容易集，可憐人自不能閒。"]'),
('0a482cbc-9bac-4747-9a03-abdcede54b9f','次韵王介甫金陵懷古四首  其一','劉攽','宋','宋诗','song-poetry','','[]','虎踞群山带繞江，爲誰爲國爲誰降。',64,'全唐诗/poet.song.35000.json','["虎踞群山带繞江，爲誰爲國爲誰降。", "高臺麋鹿看無數，廢沼鳬鷖去自雙。", "萬里朝雲隨逝水，百年西月過虛窗。", "白門酒美東風快，笑數英雄盡一缸。"]'),
('e5cd93e3-9e63-48f3-8184-b1b8c962c104','次韵王介甫金陵懷古四首  其二','劉攽','宋','宋诗','song-poetry','','[]','樓船西下勢橫江，元帥旌旗就約降。',64,'全唐诗/poet.song.35000.json','["樓船西下勢橫江，元帥旌旗就約降。", "旋報前師覆張悌，亟傳單騎馘王雙。", "燕焚正自當煙突，蟻潰何堪值水窗。", "回首三軍歡奏凱，萬牛行炙酒千缸。"]'),
('cd970e36-e97a-4474-9739-5d63fb44e5b9','次韵王介甫金陵懷古四首  其三','劉攽','宋','宋诗','song-poetry','','[]','楚貢來遲詭問江，漢收群策士心降。',64,'全唐诗/poet.song.35000.json','["楚貢來遲詭問江，漢收群策士心降。", "一言已重黄金百，再見仍蒙白璧雙。", "漂客脫身甘馬革，老儒投筆謝書窗。", "豈知三閣酣詩酒，浩唱庭花倒玉缸。"]'),
('2bab2a73-1a89-4fe7-bfad-67d33021bf69','次韵王介甫金陵懷古四首  其四','劉攽','宋','宋诗','song-poetry','','[]','頹垣落水半平江，喬木風呼不易降。',64,'全唐诗/poet.song.35000.json','["頹垣落水半平江，喬木風呼不易降。", "耕出珠璣時得一，道逢麟鳳不成雙。", "潮聲半夜來寒渚，月色深秋照舊窗。", "唯有魚鹽城下市，檣烏想望集瓶缸。"]'),
('0fb68395-ae8e-4406-98b5-25487b097f5e','送馮當世移金陵','劉攽','宋','宋诗','song-poetry','','[]','滿城携酒駐高軒，楚老沾衣共一言。',64,'全唐诗/poet.song.35000.json','["滿城携酒駐高軒，楚老沾衣共一言。", "何幸期年無吏事，方從歉歲識君恩。", "潮迎綵鷁來瓜步，山映朱旗轉白門。", "早晚使星還北極，溥看霖雨濟乾坤。"]'),
('f103cc95-930c-4af2-9f06-586e71c6f600','李公擇自滑州移知鄂州','劉攽','宋','宋诗','song-poetry','','[]','黄鶴仙人去不留，武昌官柳傍層樓。',64,'全唐诗/poet.song.35000.json','["黄鶴仙人去不留，武昌官柳傍層樓。", "前山欲近滄浪水，芳草遥分鸚鵡洲。", "漁父嘯歌聊自樂，禰衡詞賦若爲謀。", "朱輪皂蓋一身貴，談笑豈知千古愁。"]'),
('a073ffb2-b39e-4f5a-a0e6-3df6f0de1535','得江同州和詩後却寄','劉攽','宋','宋诗','song-poetry','','[]','左輔關河二十城，使車全勝直承明。',64,'全唐诗/poet.song.35000.json','["左輔關河二十城，使車全勝直承明。", "白頭樽酒諳風味，乘興篇章得性情。", "苜蓿空肥天驥老，風霜有意皂鵰橫。", "驚沙急雪迷秦樹，不似山陰一日程。"]'),
('426d8116-0f97-4d5d-93a2-08da8b83465e','次韵和裴潤州見寄','劉攽','宋','宋诗','song-poetry','','[]','江城山翠若連環，城下波濤暗楚關。',64,'全唐诗/poet.song.35000.json','["江城山翠若連環，城下波濤暗楚關。", "去計祇應勞侍從，歸心願復賜清閒。", "百年舊法軒丘外，千里傷懷嬴博間。", "過事惱君堪白首，添歡惟有綵衣斑。"]'),
('931325a8-2306-43c6-9e45-c34f5439a7e5','陸子履知潁州','劉攽','宋','宋诗','song-poetry','','[]','稻白魚肥潁水清，重湖光彩動層城。',64,'全唐诗/poet.song.35000.json','["稻白魚肥潁水清，重湖光彩動層城。", "經爲遊客歡閭里，特羨朱軒擁旆旌。", "整棹鳬鷖橫筆勢，倚樓風雨壯歌聲。", "聚星賢士兼存歿，配社名鄉見遠情。"]'),
('37e05aea-a2d5-4a37-a29e-a64677cdffe3','寄韓慶州','劉攽','宋','宋诗','song-poetry','','[]','萬騎將軍西護羌，邊塵無復近麾幢。',64,'全唐诗/poet.song.35000.json','["萬騎將軍西護羌，邊塵無復近麾幢。", "烽傳列障來遮敵，雪擁層城接受降。", "日暮悲笳還自疊，天寒羈雁少成雙。", "檄書不得從軍樂，覢弩空令候小邦。"]'),
('3239146d-d32c-4ca9-990a-315e5ee7e295','送謝師厚知唐州','劉攽','宋','宋诗','song-poetry','','[]','腰虎憑熊近越鄉，方城南望色蒼蒼。',64,'全唐诗/poet.song.35000.json','["腰虎憑熊近越鄉，方城南望色蒼蒼。", "社人隨處祠桐柏，傳馬來時認肅爽。", "兩國風煙通置吏，百年荆棘勸鋤荒。", "王成勞徠先蒙賞，史起猶應問濁漳。"]'),
('ebad1bf8-2142-4c41-8471-6fd9dd6df2da','送王廣淵郎中知潁州','劉攽','宋','宋诗','song-poetry','','[]','二月潁河春水生，檣烏相望使君行。',64,'全唐诗/poet.song.35000.json','["二月潁河春水生，檣烏相望使君行。", "東風不起驚濤勢，遲日何妨短驛程。", "坐有圖書歡傲吏，靜看魚鳥忘專城。", "漢庭良守誰先賞，會見膠東舉相成。"]'),
('0e3e9eb7-83db-4d5f-acd6-cabac32f5a87','送光祿呂卿知懷州','劉攽','宋','宋诗','song-poetry','','[]','卿秩西來郡組新，東京故事本憂民。',64,'全唐诗/poet.song.35000.json','["卿秩西來郡組新，東京故事本憂民。", "太行形勝連天黨，積石波濤會孟津。", "千里雄風隨坐嘯，百城膏雨待行春。", "期年定有周堪詔，父老無勞借寇恂。"]'),
('3ae807d5-548d-46ce-b6d9-b537b70b525b','送龔鼎臣修撰知兖州','劉攽','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','楚國清名世豈知，郡章新得泰山歸。',64,'全唐诗/poet.song.35000.json','["楚國清名世豈知，郡章新得泰山歸。", "靜思鵰鶚霜天勢，却看蓬瀛客旆飛。", "去國鬢毛休變色，還家傳瑞已生輝。", "翠華早晚東巡守，馳道離宮接帝畿。"]'),
('a4c885db-2702-4d26-b6a9-bfbc978d9e71','送呂郎中知解州','劉攽','宋','宋诗','song-poetry','','[]','南風吹雪暑飛霜，瞬息高車起重裝。',64,'全唐诗/poet.song.35000.json','["南風吹雪暑飛霜，瞬息高車起重裝。", "胡馬邇來充牧苑，漢兵無處不餘糧。", "部丞亟上司農奏，腰組仍夸太守章。", "正頼研桑密心計，晚從王謝識諸郎。"]'),
('0b5ea3ff-7583-4b42-b38f-ea1f70420139','送宋次道知絳州','劉攽','宋','宋诗','song-poetry','','[]','銅鞮宮觀久塵埃，樊守園池亦壯哉。',64,'全唐诗/poet.song.35000.json','["銅鞮宮觀久塵埃，樊守園池亦壯哉。", "屬縣老人書亥字，臨汾神祀問臺駘。", "土風頗記堯遺俗，府吏猶疑楚有材。", "漢史待君成十志，傳車長望北風來。"]'),
('3ac881a0-72b2-4a05-b17f-7670a00fcf91','送韓文饒知均州','劉攽','宋','宋诗','song-poetry','','[]','嶺梅陰下駐旌旟，五月歸更竹使符。',64,'全唐诗/poet.song.35000.json','["嶺梅陰下駐旌旟，五月歸更竹使符。", "漢上川原連夢澤，鄖人風俗語於菟。", "奮髯曹吏知無事，坐嘯雲山得自娛。", "建禮會朝兼夜直，羨君覢弩盛前驅。"]'),
('07a4a3c0-ecfb-4661-a9f9-570cc3366a27','寄孫秦州','劉攽','宋','宋诗','song-poetry','','[]','十年幕府領旌麾，事半前人此復稀。',64,'全唐诗/poet.song.35000.json','["十年幕府領旌麾，事半前人此復稀。", "元帥詩書真用武，小戎車甲豈無衣。", "胡兵候月麒麟鬥，漢馬乘秋苜蓿肥。", "自失陰山常慟哭，更聞消息向金微。"]'),
('687b2931-5c85-4a2a-9c30-06c9d2080b87','次韵和王泰州','劉攽','宋','宋诗','song-poetry','','[]','粒食由來不願餘，雲飛自愧羽翰孤。',64,'全唐诗/poet.song.35000.json','["粒食由來不願餘，雲飛自愧羽翰孤。", "已同白首滯三署，却羨青郊授一夫。", "出守故人猶虎竹，相忘吾道亦江湖。", "秋來卧閣知何事，鈴索生塵獄有蕪。"]'),
('15f97ee4-3b53-4b59-834e-90723a087ef1','送喬左藏自太常博士除知施州','劉攽','宋','宋诗','song-poetry','','[]','志士變衣非變性，丈夫能勇亦能言。',64,'全唐诗/poet.song.35000.json','["志士變衣非變性，丈夫能勇亦能言。", "東郊不顧田二頃，愛子歡然弓兩鞬。", "黔水犀牛群解鴆，峽山猱子躁欺猿。", "蠻溪未足紆長策，會使天驕祭北門。"]'),
('2e299eb2-367c-4846-a819-1aa5189284cc','送王汝州','劉攽','宋','宋诗','song-poetry','','[]','讀易絕編經獲麟，廷臣推汝老成人。',64,'全唐诗/poet.song.35000.json','["讀易絕編經獲麟，廷臣推汝老成人。", "宦遊獨怪烏衣晚，吏隠何妨青綬新。", "風穴不應長嘯虎，湯泉寧復爲煎薪。", "高齋有勝宣城處，三十六峰爲近鄰。"]'),
('da87ec9d-2989-4be1-94c0-112cfa08d236','九月十日趙令園餞送王汝州汝州留詩二篇次韵  其一','劉攽','宋','宋诗','song-poetry','','[]','華髮悲秋復送行，茂林修竹若爲情。',64,'全唐诗/poet.song.35000.json','["華髮悲秋復送行，茂林修竹若爲情。", "菊花節去香猶在，桑落寒來色更清。", "趙魏優賢常不欲，春秋知我亦空名。", "別離何必皆千里，分手如今越與荆。"]'),
('1d96ba0a-f14a-42e2-ad70-23cc6e91a292','九月十日趙令園餞送王汝州汝州留詩二篇次韵  其二','劉攽','宋','宋诗','song-poetry','','[]','五馬來時照路傍，名園秋物自裳裳。',64,'全唐诗/poet.song.35000.json','["五馬來時照路傍，名園秋物自裳裳。", "吹花酒面蟹螯壯，下豉蓴絲魚膾長。", "問事不休推景伯，讀書未見屬黄香。", "窮愁解摘唯須酒，身外浮雲天際翔。"]'),
('b444171c-0cd8-4269-bbd2-8842ed8c6aa5','送韓七文饒郎中再知解州','劉攽','宋','宋诗','song-poetry','','[]','傳瑞生光廄馬閑，使君冠蓋隔年還。',64,'全唐诗/poet.song.35000.json','["傳瑞生光廄馬閑，使君冠蓋隔年還。", "莫嫌屈産齒加長，少有甘棠身再攀。", "白徑嶺前開驛路，哀烏星裏望朝班。", "鹽車過往繁如織，驥耳能忘一顧間。"]'),
('d0be7fe3-3a3a-452e-910c-6e1232293167','送裴郎中知房州','劉攽','宋','宋诗','song-poetry','','[]','好去臺郎應列星，異於遷客向房陵。',64,'全唐诗/poet.song.35000.json','["好去臺郎應列星，異於遷客向房陵。", "且看銀印懸青綬，可在金輿與玉乘。", "柏塢麝臍香不雜，竹崖牛角價無朋。", "清通便是循良術，三最從君數吏能。"]'),
('f1c84f5c-3665-487f-abfb-9d5ffc59bce4','寄王濟州','劉攽','宋','宋诗','song-poetry','','[]','獄市并空俗已和，使君高興足婆娑。',64,'全唐诗/poet.song.35000.json','["獄市并空俗已和，使君高興足婆娑。", "畫成林色重裝洗，鑒作湖光更潔磨。", "歷下軍聲從古盛，濟南名士邇來多。", "小寒漸有北歸雁，話與飛翰同一過。"]'),
('f5ffdd81-fb02-4f22-9c5a-fe95b43a9967','酬王濟州','劉攽','宋','宋诗','song-poetry','','[]','郡印拘人祇看山，簿書無盡且偷閒。',64,'全唐诗/poet.song.35000.json','["郡印拘人祇看山，簿書無盡且偷閒。", "不羞暮景桑榆上，聊寄高情宇宙間。", "頗葺池臺增舊觀，旋栽桃李待堪攀。", "老公此意君知否，未有菟裘未得還。"]'),
('389a28ec-9714-4c51-937e-b8595ddd1ff0','送滿龍圖知襄州','劉攽','宋','宋诗','song-poetry','','[]','鳳林關下七連城，獵獵霜風卷旆旌。',64,'全唐诗/poet.song.35000.json','["鳳林關下七連城，獵獵霜風卷旆旌。", "漢陰抱甕防機械，峴首沈碑認智名。", "季孟中間欲誰與，英賢餘事亦難平。", "習池倒載時一往，却是古今真實情。"]'),
('b82a72c2-3cf6-4c4f-b7ff-d5617bc7aa0b','次韵晁單州詩六首  其一','劉攽','宋','宋诗','song-poetry','','[]','五字酬君詩百篇，知音免負伯牙絃。',64,'全唐诗/poet.song.35000.json','["五字酬君詩百篇，知音免負伯牙絃。", "淹留子賤彈琴地，悵望蘭成射策年。", "術到仙真皆羽化，師無前敵在中權。", "古今風雅人多少，名下聲華不浪傳。"]'),
('3f4314d9-3020-4b73-b2f2-c91c117fbf44','次韵晁單州詩六首  其二','劉攽','宋','宋诗','song-poetry','','[]','材傑知心似合符，不違顔氏亦如愚。',64,'全唐诗/poet.song.35000.json','["材傑知心似合符，不違顔氏亦如愚。", "文章偏我不得力，懷抱與君非有殊。", "龜手但知能澼絖，緯蕭何意得驪珠。", "自携如意樽前舞，曲盡歌長缺酒壺。"]'),
('3f97b38a-67b8-4d2e-a7f8-589544c374b3','次韵晁單州詩六首  其三','劉攽','宋','宋诗','song-poetry','','[]','性僻材疏酷嗜詩，頭童齒缺雪垂頤。',64,'全唐诗/poet.song.35000.json','["性僻材疏酷嗜詩，頭童齒缺雪垂頤。", "五十已過無聞爾，三百雖多奚以爲。", "每向後生知所畏，獨於名士喜同時。", "李陵蘇武俱塵土，豪傑由來自得師。"]'),
('758c2889-56a6-4774-93d6-7404e85dce7d','次韵晁單州詩六首  其四','劉攽','宋','宋诗','song-poetry','','[]','多愛不忍緣愛奇，記人毫髮忘瑕疵。',64,'全唐诗/poet.song.35000.json','["多愛不忍緣愛奇，記人毫髮忘瑕疵。", "垂老此心免愧己，起予它日亟言詩。", "衣冠爲子最青眼，兄弟數君仍白眉。", "瓠葉豈以菲廢禮，鮮首燔炮爲宛脾。"]'),
('502fdb41-3467-4216-b212-260d80d8759f','次韵晁單州詩六首  其五','劉攽','宋','宋诗','song-poetry','','[]','側徑蜂飛忙蔽日，綠陰鶑語靜移時。',64,'全唐诗/poet.song.35000.json','["側徑蜂飛忙蔽日，綠陰鶑語靜移時。", "自疑寂寞揚雄宅，最愛清和謝監詩。", "詞客篇章寫桐葉，飲流籌筯折花枝。", "相望十舍不相就，兩地風光鎮所思。"]'),
('167adf74-562d-4d6f-989a-f13bab27f509','次韵晁單州詩六首  其六','劉攽','宋','宋诗','song-poetry','','[]','貴公門地多陰德，慶事今君大樂生。',64,'全唐诗/poet.song.35000.json','["貴公門地多陰德，慶事今君大樂生。", "愛子桂枝新上第，弄孫蘭茁始書名。", "撥弓試復穿楊葉，負鼎何妨待鵠羹。", "不似淮陽多病守，十年卧閤見交情。"]'),
('df58c07a-c9ec-4f07-9dbc-3cae7dcc1f60','雜諷','劉攽','宋','宋诗','song-poetry','','[]','陽武舊恩惟丙吉，中興同學有嚴遵。',64,'全唐诗/poet.song.35000.json','["陽武舊恩惟丙吉，中興同學有嚴遵。", "封侯會自酬陰德，物色終應訪故人。", "可在介推懷怨望，深疑咎犯亦逡巡。", "剛腸獨有屠羊說，稱義孤高無與鄰。"]'),
('ab9054c4-fd21-4b92-8402-3f362fd1807f','送虞太熙著作知番禺縣','劉攽','宋','宋诗','song-poetry','','[]','遠師猶覺丹青似，大邑知無盤錯憂。',64,'全唐诗/poet.song.35000.json','["遠師猶覺丹青似，大邑知無盤錯憂。", "梅嶺山長因海盡，夜郎江闊傍城流。", "鯨魚浪作傖人鱠，槎客常隨賈舶舟。", "莫爲風帆徑清淺，秘書仍自有蓬丘。"]'),
('b846d4a3-48bb-47f8-9d51-ac153ffb3f6c','送曹輔奉議福建轉運判官  其一','劉攽','宋','宋诗','song-poetry','','[]','馳傳典州名字高，溪山更不厭勤勞。',64,'全唐诗/poet.song.35000.json','["馳傳典州名字高，溪山更不厭勤勞。", "吏逢照膽新磨鏡，事似屠牛已善刀。", "頗說團茶如湩酪，欲將丹荔比葡萄。", "使君詩思過泉湧，爲賦佳篇悟此曹。"]'),
('f742b006-c78b-450a-9e8f-8125d701c190','送曹輔奉議福建轉運判官  其二','劉攽','宋','宋诗','song-poetry','','[]','陳植文華斗石高，景宗詩句復稱豪。',64,'全唐诗/poet.song.35000.json','["陳植文華斗石高，景宗詩句復稱豪。", "數奇不得封龍頟，祿仕無妨似馬曹。", "蠹簡傳將蝌蚪字，銛鋒瑩出鷿鵜膏。", "南州山水能爲助，更看英詞勝廣騷。"]'),
('4d5180e2-a681-4a6c-962a-9e18d7a6caf1','送張遂州','劉攽','宋','宋诗','song-poetry','','[]','九折無艱蜀道通，使君車騎最雍容。',64,'全唐诗/poet.song.35000.json','["九折無艱蜀道通，使君車騎最雍容。", "尚書不復拘三輔，御史仍開給五封。", "接境去思棠樹密，退公歡燕綵衣重。", "治民固有張京兆，坐看巴人益劭農。"]'),
('2a497863-d112-40f5-9fc8-8d9fcfb37fdb','次韵和張宣德合江亭','劉攽','宋','宋诗','song-poetry','','[]','此水此山今昔遊，蒼煙古木又窮秋。',64,'全唐诗/poet.song.35000.json','["此水此山今昔遊，蒼煙古木又窮秋。", "起隨佳士初乘興，忽話離人始欲愁。", "南極早知無到雁，北天那可際歸舟。", "老身學得灰心也，不是灰心淚已流。"]'),
('64b92733-dfbe-4f56-94e6-f63be9740f3f','秋日寄楊十七','劉攽','宋','宋诗','song-poetry','','[]','檐日輝輝過午天，榱風槭槭未霜前。',64,'全唐诗/poet.song.35000.json','["檐日輝輝過午天，榱風槭槭未霜前。", "不甘翠葉無時落，已分黄花特地鮮。", "富貴應須三寸舌，文章不及一囊錢。", "詩翁白髮經秋甚，爲問窮愁有幾篇。"]'),
('019f8e9d-89e1-4459-a0a0-37d9b1e4b590','嶽雲亭  其一','劉攽','宋','宋诗','song-poetry','','[]','山外浮雲橫翠微，海邊初日上朝暉。',64,'全唐诗/poet.song.35000.json','["山外浮雲橫翠微，海邊初日上朝暉。", "我無小魯悠悠志，那欲乘風去去飛。", "上客高吟揮玉麈，佳人半醉舞羅衣。", "昏鴉獨鶴何勞問，合暝投林各有依。"]'),
('b2521382-fddc-4565-a759-f9c9630d7f3f','嶽雲亭  其二','劉攽','宋','宋诗','song-poetry','','[]','檻外連山如合圍，尤憐昏旦變清暉。',64,'全唐诗/poet.song.35000.json','["檻外連山如合圍，尤憐昏旦變清暉。", "雲行驟雨非無事，鳥伴歸鴻即倦飛。", "厭見市朝車馬迹，喜看巖谷薜蘿衣。", "尚平畢娶何蕭散，千載高風自可依。"]'),
('eea0005b-7278-4bc9-aa21-59e4dae9c88a','薄后廟','劉攽','宋','宋诗','song-poetry','','[]','駟家冠虎久騰聲，龍躍中都漢道興。',64,'全唐诗/poet.song.35000.json','["駟家冠虎久騰聲，龍躍中都漢道興。", "人事能無輸織室，母儀終見葬南陵。", "蒼苔複閣連荒草，喬木參雲掛老藤。", "欲學靈均紀天問，古堂丹碧正嚴凝。"]'),
('f05e714c-e6d7-4132-856c-75c327568007','送鄭秘丞知邛州蒲江縣','劉攽','宋','宋诗','song-poetry','','[]','明府之官固有程，巴江繚繞趣君行。',64,'全唐诗/poet.song.35000.json','["明府之官固有程，巴江繚繞趣君行。", "孤帆去遠滄浪色，百丈牽遲灧澦聲。", "火井煮鹽收倍利，山田種芋勸深耕。", "舊來邛竹通西域，邊吏還知健令名。"]'),
('90cfe55a-6cd4-40e7-b17e-b03ae405b2b6','李尚書除少保致仕','劉攽','宋','宋诗','song-poetry','','[]','疏公黄髮欲遺名，詔秩青宮二品榮。',64,'全唐诗/poet.song.35000.json','["疏公黄髮欲遺名，詔秩青宮二品榮。", "自昔爲家皆僻地，更聞題劍得佳城。", "賜金給館君恩重，倚杖看山世累輕。", "試問門風過萬石，白頭賢子已名卿。"]'),
('ea4a0104-75f5-420f-b4fb-fe40b451e029','吳國博未五十致仕歸蘄州','劉攽','宋','宋诗','song-poetry','','[]','名宦於身甚纆徽，白頭青紫莫言歸。',64,'全唐诗/poet.song.35000.json','["名宦於身甚纆徽，白頭青紫莫言歸。", "曼容自以微官去，蘧瑗應知過事非。", "笛竹滿山經夏冷，江魚如玉向秋肥。", "避喧不厭塵紛遠，何况孤城人迹稀。"]'),
('6a4709d6-497c-4afa-8f5d-94e5a677c0ae','與諸公會趙氏園主人加送酒饌既而求詩書五十六字','劉攽','宋','宋诗','song-poetry','','[]','落木稀疏存葉丹，別筵秋興雜悲歡。',64,'全唐诗/poet.song.35000.json','["落木稀疏存葉丹，別筵秋興雜悲歡。", "主人愛客願少駐，老子爲君加一餐。", "蕭相河山餘带礪，謝公子弟悉芝蘭。", "會因休沐觀歌舞，正頼微官謁禁寬。"]'),
('60cbee90-2d87-4709-aca7-c71ae4dd1abf','苦寒早朝','劉攽','宋','宋诗','song-poetry','','[]','漏絕星沈十二門，烈風吹耳萬車奔。',64,'全唐诗/poet.song.35000.json','["漏絕星沈十二門，烈風吹耳萬車奔。", "疾驅不敢行馳道，辨色纔能認掖垣。", "病眼無堪頻唾沫，瘁肌時復强噓溫。", "尚衣仍在青冥外，薄願何當獻負暄。"]'),
('c0b53b11-5d3d-4a2d-8aea-8f7a09afcfe8','次韵和王舍人酬王工部早朝','劉攽','宋','宋诗','song-poetry','','[]','天門金碧照晨光，躍馬鳴珂曉正當。',64,'全唐诗/poet.song.35000.json','["天門金碧照晨光，躍馬鳴珂曉正當。", "人到蓬萊知不夜，地從閶闔敻無傍。", "風移宮漏穿花遠，雲覆爐烟繞禁香。", "望斷雙鳬候飛舄，空傳詩句首東皇。"]'),
('91185921-388f-4f13-bcec-a841ae6ba5f0','雨後早朝','劉攽','宋','宋诗','song-poetry','','[]','雨闋凉生樓閣虛，綠槐花落影蕭疏。',64,'全唐诗/poet.song.35000.json','["雨闋凉生樓閣虛，綠槐花落影蕭疏。", "端門立仗交符後，禁漏傳呼上水初。", "伏閣預聞明詔語，退朝潛誦直臣書。", "愚忠空覺身無補，放去江湖待詔除。"]'),
('56554aff-36fb-49c3-b864-ee07f4d24c38','春雪早朝和沈編校','劉攽','宋','宋诗','song-poetry','','[]','曉寒初怪客衣重，隠約鐘聲長樂宮。',64,'全唐诗/poet.song.35000.json','["曉寒初怪客衣重，隠約鐘聲長樂宮。", "出戶萬家橫雪裏，止車雙闕秀雲中。", "退朝禁柳迎人綠，寓直庭花向日紅。", "縱使著書嘲尚白，會應華髮兆非熊。"]'),
('184cc9d6-f9bb-48cc-8e5a-24fd76cc4f1c','和牟公野館宿早朝','劉攽','宋','宋诗','song-poetry','','[]','夢回仙府豁中扃，未斷塵緣復戰兢。',64,'全唐诗/poet.song.35000.json','["夢回仙府豁中扃，未斷塵緣復戰兢。", "交態出門逢楚越，俗情開口判淄澠。", "夜長鳷鵲偏留月，歲盡天河亦有冰。", "閶闔晨開車馬集，五雲深處望朝昇。"]'),
('89f53ce0-6648-49a5-aee2-6ffb03faa51e','嘉祐中與王丞相吳樞密韓端明王學士會飲騏驥池上去今將二十年王有感事詩見示次韵','劉攽','宋','宋诗','song-poetry','','[]','水色林光照舉觴，陂塘六月起秋凉。',64,'全唐诗/poet.song.35000.json','["水色林光照舉觴，陂塘六月起秋凉。", "壯年過事難重得，末路貧交故未忘。", "注眼階星元近極，叱梟甿采不成王。", "嚴徐未抵馮唐老，猶咏君詩意自卬。"]'),
('70c5c7f0-ec79-4425-8abc-9ca848ce7ece','汾州鄭閎中學士寄蒲萄','劉攽','宋','宋诗','song-poetry','','[]','漢使于闐伐大宛，蒲萄天馬遍長安。',64,'全唐诗/poet.song.35000.json','["漢使于闐伐大宛，蒲萄天馬遍長安。", "絕塵無復千金骨，結實常迎八月寒。", "遠愧故人勤置驛，每逢樽酒爲加餐。", "自身不得凉州牧，何以報君雙玉盤。"]'),
('d7d267c3-fe95-420c-8fe4-d21e571c28bb','與倪秀才酒','劉攽','宋','宋诗','song-poetry','','[]','學子青青佩與衿，湘中携手一傷心。',64,'全唐诗/poet.song.35000.json','["學子青青佩與衿，湘中携手一傷心。", "君爲壯者我白首，家在秦州書萬金。", "失馬頗能如北叟，似鴞那復怪南禽。", "相憐羈旅方無友，齎贈醇醪稍獻斟。"]'),
('cb3a6bc3-d847-4fe4-98a1-908c662e1187','和賈舍人春祠太一壇二首  其一','劉攽','宋','宋诗','song-poetry','','[]','使節春祠太一壇，漢庭儒雅貴兒寬。',64,'全唐诗/poet.song.35000.json','["使節春祠太一壇，漢庭儒雅貴兒寬。", "星河回轉開閶闔，樓觀參差起廣寒。", "月射金盤霜更白，風來宮樹雪猶殘。", "清詩不減高唐頌，萬玉鏘鳴雜珮珊。"]'),
('968e6892-8e94-449a-892a-acf6e5e7b5cf','和賈舍人春祠太一壇二首  其二','劉攽','宋','宋诗','song-poetry','','[]','五城金碧盡樓居，西望屯雲藹太虛。',64,'全唐诗/poet.song.35000.json','["五城金碧盡樓居，西望屯雲藹太虛。", "瑞氣長存春不覺，美光相屬夜如初。", "歸承宣室雍容問，密受神君策畫書。", "力士傳車空杳邈，真遊本自接儲胥。"]'),
('32c6defb-7854-4e62-8aff-6e3e19694ca4','次韵和顧直講','劉攽','宋','宋诗','song-poetry','','[]','故人相語笑家丘，華髮盈簪此滯留。',64,'全唐诗/poet.song.35000.json','["故人相語笑家丘，華髮盈簪此滯留。", "無限風光輕過眼，邇來春色試回頭。", "名園秀木藂幽境，紫府真仙熟舊遊。", "自是山林懷勝賞，非關適野濟吾謀。"]'),
('5489f925-7d76-48a1-8ad2-8b49e3f4fc37','晚歸','劉攽','宋','宋诗','song-poetry','','[]','古木號蟬鴉亂棲，凉風稍稍襲人衣。',64,'全唐诗/poet.song.35000.json','["古木號蟬鴉亂棲，凉風稍稍襲人衣。", "高樓鼓角悲秋意，小市漁樵競夕暉。", "雖有簿書容暇豫，强從賓旅復來歸。", "閉門躍馬俱人事，吾道何能問是非。"]'),
('af9e0c4d-18c8-417f-b540-030bc737ac3e','燈夕都下','劉攽','宋','宋诗','song-poetry','','[]','元夕燈光歲益新，羈遊四十五年春。',64,'全唐诗/poet.song.35000.json','["元夕燈光歲益新，羈遊四十五年春。", "垂髫已識東西事，回首宛如前後身。", "繡轂雕鞍驅不顧，丹臺絳闕到無因。", "清霜著屋風吹面，素月滿庭吾故人。"]'),
('e2ad20db-235f-4943-bd56-b203921cdee9','咏旗','劉攽','宋','宋诗','song-poetry','','[]','玉關歸馬候全師，虎落無塵指列旗。',64,'全唐诗/poet.song.35000.json','["玉關歸馬候全師，虎落無塵指列旗。", "壯士歡聲歌杕杜，降人破膽望槍纍。", "禹功遠近逾千歲，漢德并容過二儀。", "青海遠通青塚地，白羊斜界白狼夷。"]'),
('4604c73d-3564-430f-a9e2-8b7ca386f77a','送張器著作','劉攽','宋','宋诗','song-poetry','','[]','長裾欲敝二毛侵，他日聞君東武吟。',64,'全唐诗/poet.song.35000.json','["長裾欲敝二毛侵，他日聞君東武吟。", "騏驥老成方得路，梧桐焦尾始知音。", "蓬萊著作芸香馥，楚澤絃歌笛竹深。", "七十封侯殊未晚，相看感激壯夫心。"]'),
('d9594742-81aa-49fa-b612-3761d6d87b0c','又次韵酬著作見寄','劉攽','宋','宋诗','song-poetry','','[]','粗了文書過目前，公餘賓宴即歡然。',64,'全唐诗/poet.song.35000.json','["粗了文書過目前，公餘賓宴即歡然。", "臘醅趁熟先春味，官燭供燒合夜煙。", "惡土一番生好木，涸池三面秀紅蓮。", "不知尚有思人否，吟咏來詩幾絕編。"]'),
('a211c82b-b5e2-4513-b44d-30490a3e0e65','次韵王平甫直舍未開梅花','劉攽','宋','宋诗','song-poetry','','[]','複閣深沈人到稀，官梅孤秀及花期。',64,'全唐诗/poet.song.35000.json','["複閣深沈人到稀，官梅孤秀及花期。", "地寒竹柏應爲伴，春近冰霜信有時。", "不恨未開煩久待，正憐將落頼偏遲。", "催人頭白何由奈，可在江南寄一枝。"]'),
('10a7923f-3224-4717-a20f-83f1c41c835b','初夏喜凉','劉攽','宋','宋诗','song-poetry','','[]','季月南州雨過春，雨餘炎氣即經旬。',64,'全唐诗/poet.song.35000.json','["季月南州雨過春，雨餘炎氣即經旬。", "北風一變如秋色，小屋三間喜病身。", "出戶燕兒矜羽化，堆盤梅子薦時新。", "融峰盛夏含冰雪，安得清凉頗借人。"]'),
('f9649790-0145-489f-ae91-5aea50c01046','上巳','劉攽','宋','宋诗','song-poetry','','[]','風光亹亹逼人來，過去清明更不回。',64,'全唐诗/poet.song.35000.json','["風光亹亹逼人來，過去清明更不回。", "巳日家人還祓禊，蜀江清水快流杯。", "關關啼鳥如相和，冉冉殘花欲盡開。", "自笑野心安淡泊，亦能隨衆上春臺。"]'),
('e26e90b6-91f1-4344-aebd-e3e422a76992','南宮鎖宿戲題','劉攽','宋','宋诗','song-poetry','','[]','複閣深沈橫九衢，京塵斷絕閉門居。',64,'全唐诗/poet.song.35000.json','["複閣深沈橫九衢，京塵斷絕閉門居。", "士人應怪跳壺術，漢使曾無繫雁書。", "暝數月華將復缺，春和庭卉已非初。", "東風雷雨知何在，快意青冥看化魚。"]'),
('93b95fe5-7f27-4b9c-8634-e40f6e7f6acb','題禪寺','劉攽','宋','宋诗','song-poetry','','[]','錦帆牙檣四百年，曲池歌榭兩凄然。',64,'全唐诗/poet.song.35000.json','["錦帆牙檣四百年，曲池歌榭兩凄然。", "又從劫火悲前佛，猶有靈光閱逝川。", "何處鳴禽新出谷，幾株喬木上參天。", "春遊不負題詩興，神助仍因夢阿連。"]'),
('7ed8a16a-d6ba-4534-a5e2-c86879bb4b6c','五月望日赴紫宸謁待旦假寐','劉攽','宋','宋诗','song-poetry','','[]','半夜北風凜凜寒，倒衣驚問紫衣班。',64,'全唐诗/poet.song.35000.json','["半夜北風凜凜寒，倒衣驚問紫衣班。", "雲容不辨陰晴際，月色猶迷爽晦間。", "偏喜鳴雞識鐘漏，正憐殘夢失江山。", "濯纓簪筆初無補，空愧紛紛數往還。"]'),
('22c22e45-2766-41df-b1cc-b4521d912290','凝翠堂  其一','劉攽','宋','宋诗','song-poetry','','[]','檐前老竹生無數，座上清風處處來。',64,'全唐诗/poet.song.35000.json','["檐前老竹生無數，座上清風處處來。", "俗客不知看好鳥，紅塵無復污蒼苔。", "兒童戲掃黄金影，茗飲時傾碧玉杯。", "會待秋霜堅草木，簡書羌管倩人裁。"]'),
('2da721f9-6c21-4772-970e-380d6a782f1c','凝翠堂  其二','劉攽','宋','宋诗','song-poetry','','[]','綠竹參差平拂檐，疏陰掩映似重簾。',64,'全唐诗/poet.song.35000.json','["綠竹參差平拂檐，疏陰掩映似重簾。", "留徑人誰識蔣詡，開窗吾擬學陶潛。", "古牆莓苔有石色，長夏江山如火炎。", "避地真宜近幽僻，悠悠笑謝歲華淹。"]'),
('350e149f-ecf6-4d44-9afb-f73f182e884a','劉九經','劉攽','宋','宋诗','song-poetry','','[]','白首儒先困一經，此君年少獨聲名。',64,'全唐诗/poet.song.35000.json','["白首儒先困一經，此君年少獨聲名。", "早知劉氏無蚩者，深信宣尼畏後生。", "賈誼尚爲門下掾，終軍仍許出關行。", "限年選舉今留滯，躍馬贏糧見子情。"]'),
('2e69da3c-230a-465d-baa4-85b141739cc8','送隠直','劉攽','宋','宋诗','song-poetry','','[]','齊楚分飛歲月遷，微官落拓竟依然。',64,'全唐诗/poet.song.35000.json','["齊楚分飛歲月遷，微官落拓竟依然。", "青雲可願已三仕，白首幾何頻十年。", "自昔彈冠深有意，到今同病祇相憐。", "陰風朔雪河梁別，乘興仍思訪戴船。"]'),
('60bcd5a7-0346-4c2d-8469-a75631492c40','送李士寧山人','劉攽','宋','宋诗','song-poetry','','[]','帝城車馬日喧喧，物外相從意爽然。',64,'全唐诗/poet.song.35000.json','["帝城車馬日喧喧，物外相從意爽然。", "自有藥壺容到客，獨摩金狄嘆流年。", "高秋天幕收零雨，清露風林嘒暮蟬。", "曾愧丹砂爲狡獪，更談滄海變桑田。"]'),
('1c4bca00-31a2-444b-9066-5dfe2aaa35de','寄彥猷移鎮錢塘','劉攽','宋','宋诗','song-poetry','','[]','紫垣清切擁鈎陳，閣道分明絕漢津。',64,'全唐诗/poet.song.35000.json','["紫垣清切擁鈎陳，閣道分明絕漢津。", "未怪靈槎滯吳會，祇堪藏劍動星辰。", "懷金紆組臨鄉社，釃酒椎牛宴里人。", "行樂從來多壯觀，秋風莫使鬢華新。"]'),
('cb69936a-e06c-4868-ad50-d15856e6a275','平山堂','劉攽','宋','宋诗','song-poetry','','[]','危棟層軒不易攀，萬峰猶在戶庭間。',64,'全唐诗/poet.song.35000.json','["危棟層軒不易攀，萬峰猶在戶庭間。", "長空未省浮雲礙，積翠如遮去鳥還。", "寡和陽春隨白雪，知音流水與高山。", "吳中辯士嗤枚叟，漫說觀濤可慰顔。"]'),
('f269804d-c929-4f51-a9cc-230fc9cb89f0','次韵和秘書省林舍人校書寓興五首  其一','劉攽','宋','宋诗','song-poetry','','[]','客塵作業通三世，儒墨分流至九家。',64,'全唐诗/poet.song.35000.json','["客塵作業通三世，儒墨分流至九家。", "投閣何妨惟寂寞，起予仍自悅紛華。", "夢緣酒食逢芻狗，兆應錢財屬火花。", "安見高人捐外累，獨超無有躡雲霞。"]'),
('89a8ad3a-0157-4b09-bb72-721b3f0b4c8b','次韵和秘書省林舍人校書寓興五首  其二','劉攽','宋','宋诗','song-poetry','','[]','百緣不信皆前定，千古相矜盡小才。',64,'全唐诗/poet.song.35000.json','["百緣不信皆前定，千古相矜盡小才。", "夢月豫占沙麓襲，建章如待柏梁災。", "朱英强欲希無妄，萇叔空勞射不來。", "聞道蓬萊更清淺，便應滄海起塵埃。"]'),
('4bd5fd97-8b10-485f-b58c-e08b4875c904','次韵和秘書省林舍人校書寓興五首  其三','劉攽','宋','宋诗','song-poetry','','[]','勇夫常作三軍獲，辯士多從五鼎烹。',64,'全唐诗/poet.song.35000.json','["勇夫常作三軍獲，辯士多從五鼎烹。", "到了是非皆妄想，不緣僥倖亦無名。", "小山叢桂容招隠，負郭良田任耦耕。", "倚伏會應齊北叟，朱愚那復問南榮。"]'),
('4fa51b7a-15e9-40b4-a1a6-d12f526ab7b0','次韵和秘書省林舍人校書寓興五首  其四','劉攽','宋','宋诗','song-poetry','','[]','事緣難易始相成，楹直寧當企棟橫。',64,'全唐诗/poet.song.35000.json','["事緣難易始相成，楹直寧當企棟橫。", "坐論巖廊從自貴，退棲林壑未爲輕。", "俗情熠燿陰中火，世路摴蒱馬外坑。", "要使襟懷似雲月，太虛無處不偕行。"]'),
('22779796-5f69-4434-aa24-7f6830e0d51a','次韵和秘書省林舍人校書寓興五首  其五','劉攽','宋','宋诗','song-poetry','','[]','縮手旁觀哂汗顔，未知才與不才間。',64,'全唐诗/poet.song.35000.json','["縮手旁觀哂汗顔，未知才與不才間。", "勞生精衛填東海，多事愚公移北山。", "語道此身甘髮白，息機他日頼心閒。", "良金百煉纔成器，躍冶無如鐵石頑。"]'),
('6daa56e0-fc02-4efd-95f0-518cd1868e2c','黄朝議賜紫','劉攽','宋','宋诗','song-poetry','','[]','長年金紫最相宜，晚達非干入手遲。',64,'全唐诗/poet.song.35000.json','["長年金紫最相宜，晚達非干入手遲。", "白髮閔勞官職事，赤松元作帝王師。", "魚銜印鈕丹鱗舞，鶻勘袍花爛椹垂。", "少似主恩崇舊德，掛車無異立朝時。"]'),
('3801c0bf-b0ce-4ae6-818a-58bf025a1604','回致仕董中允','劉攽','宋','宋诗','song-poetry','','[]','富貴致身良獨難，寄書空復走長安。',64,'全唐诗/poet.song.35000.json','["富貴致身良獨難，寄書空復走長安。", "誰能東郭雙穿履，徑出都門一掛冠。", "家事田廬隨几杖，君恩班序接鵷鸞。", "顔生尚少時無用，長鋏因公慨屢彈。"]'),
('460f2c48-0005-41de-8a22-edd85f676173','次韵酬濮倅李郎中見寄','劉攽','宋','宋诗','song-poetry','','[]','相見無期得寄聲，更憐詩語獨丁寧。',64,'全唐诗/poet.song.35000.json','["相見無期得寄聲，更憐詩語獨丁寧。", "驅之老馬尚知道，行矣泥龜甘不靈。", "半百光陰頭總白，二三朋舊眼偏青。", "芳春樽酒何由共，悵望東郊長短亭。"]'),
('1fdfad64-4628-4f20-86f3-b40463788fea','答仲馮宿興慶池作','劉攽','宋','宋诗','song-poetry','','[]','車馬還城君肯留，通宵歡語破離愁。',64,'全唐诗/poet.song.35000.json','["車馬還城君肯留，通宵歡語破離愁。", "水風楊柳猛消暑，沙雨芰荷潛造秋。", "驚月禽棲時落樹，避燈魚鬣暗衝舟。", "天明紅日驪山道，陳迹依稀似夢遊。"]'),
('e766f63e-16ba-4631-8760-734a1a9b30d9','遊凝祥池飲','劉攽','宋','宋诗','song-poetry','','[]','柳綠蒲新小曲江，洞門岑寂閉仙幢。',64,'全唐诗/poet.song.35000.json','["柳綠蒲新小曲江，洞門岑寂閉仙幢。", "波心殿影遥相况，花底禽聲各自雙。", "薄俸猶能償酒券，老年無事守書窗。", "街頭月色緩歸去，調笑相隨白玉缸。"]'),
('aacb7898-f298-4f0a-8a20-14964e216bc7','同都官遊左山晚歸泛舟城濠呈座客','劉攽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶過西湖上虎丘，雪霜乘興偶來遊。',64,'全唐诗/poet.song.35000.json','["憶過西湖上虎丘，雪霜乘興偶來遊。", "蒼崖古木見僧剎，落日微波迎畫舟。", "從道前塵都妄想，亦逢清境爲淹留。", "座中同是東南客，試說風煙似彼不。"]'),
('8a95f08f-0416-4dcf-9bdb-992fca84817c','初春後園','劉攽','宋','宋诗','song-poetry','','[]','雜樹無行小徑開，新陽留客去頻回。',64,'全唐诗/poet.song.35000.json','["雜樹無行小徑開，新陽留客去頻回。", "梅花著蕊南枝暖，柳带牽絲春事催。", "池面水光如照鏡，城頭山色勝登臺。", "長年慵懶遺詩句，無奈風煙引興來。"]'),
('cb4d7873-b50b-4eb0-958b-f546263cf92d','寄人','劉攽','宋','宋诗','song-poetry','','[]','子雲投閣爲奇字，君山殺身非讖書。',64,'全唐诗/poet.song.35000.json','["子雲投閣爲奇字，君山殺身非讖書。", "埋獄誰能知匣劍，焚城何意禍池魚。", "賜玦應知謝冠佩，杖藜自爾就田廬。", "丈夫蓋棺事乃已，白髮勿羞樵與漁。"]'),
('193b5256-6381-4b7e-b0cf-43e6e0cb8011','重次新字韵寄子瞻公擇','劉攽','宋','宋诗','song-poetry','','[]','古來蘇李有三人，今復齊名事亦新。',64,'全唐诗/poet.song.35000.json','["古來蘇李有三人，今復齊名事亦新。", "秀出文華喧右蜀，指揮能政接東秦。", "定交笑我將迎拙，垂老於君意氣親。", "似向荆山逢玨玉，如從渥水就駢驎。"]'),
('9adeee15-543e-4341-b397-7a502731e5bc','晁美叔前寄知字韵詩別求予詩既已和前篇因復用前韵作一篇寄晁','劉攽','宋','宋诗','song-poetry','','[]','促軫危絃音最悲，傷心那得世人知。',64,'全唐诗/poet.song.35000.json','["促軫危絃音最悲，傷心那得世人知。", "由來入室升堂者，意在高山流水時。", "與子徑爲竹林宴，到今長記角弓詩。", "文昌近極官清貴，不負羔羊及素絲。"]'),
('4953bcff-2881-4a42-a957-ac9cb1c2a3dc','寄熊伯通','劉攽','宋','宋诗','song-poetry','','[]','竄逐衡湘一病翁，望鄉愁對祝融峰。',64,'全唐诗/poet.song.35000.json','["竄逐衡湘一病翁，望鄉愁對祝融峰。", "不同桂管爲元帥，聞道蒼髯益壯容。", "嶺水分流清注北，雪花成片更宜冬。", "丈夫生死論交地，書札寧當向我慵。"]'),
('652ec66c-261b-4eca-b94e-bbabc1a35a89','原父兄近別入都寄此詩','劉攽','宋','宋诗','song-poetry','','[]','水鄉春盡事何如，綠樹陰成穀雨初。',64,'全唐诗/poet.song.35000.json','["水鄉春盡事何如，綠樹陰成穀雨初。", "杯裏尚餘寒食酒，城中已賣鱠殘魚。", "近來慵懶非常甚，別後嬉游益便疏。", "省事只圖千日醉，勞心不讀五車書。"]'),
('a9e059b5-b544-4a01-8af6-09a0e18db356','寄王宗傑','劉攽','宋','宋诗','song-poetry','','[]','謀拙材疏懶是真，豈堪爲吏走風塵。',64,'全唐诗/poet.song.35000.json','["謀拙材疏懶是真，豈堪爲吏走風塵。", "已知富貴非吾望，欲以詩書老此身。", "爲問折腰從斗米，何如白眼看時人。", "聞君高卧辭冠冕，多幸佯狂亦有鄰。"]'),
('a6efc304-5eff-4f7d-848e-0541435dcf0b','寄張四','劉攽','宋','宋诗','song-poetry','','[]','天下風塵日可嘆，豈惟西域與南蠻。',64,'全唐诗/poet.song.35000.json','["天下風塵日可嘆，豈惟西域與南蠻。", "舉世相爭蝸角裏，此身無事馬蹄間。", "力耕可以得飽食，從仕于今真厚顔。", "相勸休官勿待漏，卜居終近虎丘山。"]'),
('630bd59e-b7b7-476b-9399-b52a6cfa5139','嘉祐末予始爲學官同舍六人後二年間錢醇老爲秘閣校理楊之美出判潁州劉隠之姜至之麻仙夫李景真相次爲王宮教授曩游無復留者初秋夜直偶書寄楊之美','劉攽','宋','宋诗','song-poetry','','[]','夷路驅車勢易奔，青冥縱翼自孤騫。',64,'全唐诗/poet.song.35000.json','["夷路驅車勢易奔，青冥縱翼自孤騫。", "求爲散木甘無用，正似靈光幸獨存。", "汗簡老生躋璧府，曳裾賢傅遍王門。", "子雲寂寞經同病，會待庭枝看有孫。"]'),
('b57740e6-8cae-4211-8deb-ca8ac8a5b3c5','寄仲馮','劉攽','宋','宋诗','song-poetry','','[]','終南秋雨色如新，舊國登臨易思人。',64,'全唐诗/poet.song.35000.json','["終南秋雨色如新，舊國登臨易思人。", "廢塞池臺餘氣象，埋藏金玉見精神。", "三公七相空丘壠，萬戶千門盡棘薪。", "安得身隨飛鳥翼，相從談笑折西賓。"]'),
('5558b50a-220e-4f28-82ad-6dd3ca7c9bcb','寄館中僚舊','劉攽','宋','宋诗','song-poetry','','[]','落帆江浦念睽携，遠迹勾吳不自知。',64,'全唐诗/poet.song.35000.json','["落帆江浦念睽携，遠迹勾吳不自知。", "鼠穴祇緣銜窶藪，屬車空羨載鴟夷。", "黄雲海色迷仙境，丹葉秋風感鬢絲。", "爲誦延年五君咏，敢論平子四愁詩。"]'),
('942175f6-a587-4aa5-8407-a22ad75742a9','寄刁景純','劉攽','宋','宋诗','song-poetry','','[]','使君歸老意逍遥，黑髮蒼眉見後凋。',64,'全唐诗/poet.song.35000.json','["使君歸老意逍遥，黑髮蒼眉見後凋。", "自力登山不扶杖，等閒留客亦通宵。", "萬松喬木參雲日，百頃春苗浸海潮。", "徑欲從公十日飲，艷歌清絕舞妖嬈。"]'),
('eb5db1b0-3593-4a03-b841-9084454a7547','寄胡完夫','劉攽','宋','宋诗','song-poetry','','[]','去國那無鬢髮華，白沙猶覺勝長沙。',64,'全唐诗/poet.song.35000.json','["去國那無鬢髮華，白沙猶覺勝長沙。", "晴雲亂眼江楓色，宿雨銷魂野菊花。", "過客誰能問名姓，加餐自不厭魚蝦。", "海陵倉粟年豐熟，吾亦慚爲飽煖家。"]'),
('0b78d236-7a5a-4008-8376-12209481b6d3','寄韓持國','劉攽','宋','宋诗','song-poetry','','[]','承明不許曳朝衫，流落江湖默避讒。',64,'全唐诗/poet.song.35000.json','["承明不許曳朝衫，流落江湖默避讒。", "海氣無時成霧雨，魚租終歲雜腥鹹。", "喜逢晴日聽鳴鶴，却倚津亭數去帆。", "可是絳侯輕賈誼，自無張禹託蕭咸。"]'),
('f3502e2b-5dfd-4550-9ec1-a6e9d4bbfb26','次韵錢虞部九日樂郊有感','劉攽','宋','宋诗','song-poetry','','[]','前日吟君九日詩，名園興盡復傷離。',64,'全唐诗/poet.song.35000.json','["前日吟君九日詩，名園興盡復傷離。", "浮雲色變曾千古，黄菊花開又一時。", "鍾子絕絃誰與聽，羊公墮淚不堪悲。", "孤生長抱吹塤感，何况池塘昔夢思。"]'),
('c842291d-3842-44ef-8b74-72518bca6307','寄王安國時復官大理寺丞監江寧糧料','劉攽','宋','宋诗','song-poetry','','[]','招隠長吟叢桂詩，賜環歡奉璽書歸。',64,'全唐诗/poet.song.35000.json','["招隠長吟叢桂詩，賜環歡奉璽書歸。", "東郊瘦馬驊騮在，南海明珠薏苡非。", "賓客重尋廷尉寺，官曹不遠故山薇。", "須還長孺銀青綬，聊看翁思博士衣。"]'),
('f19b54e3-d138-4a87-bfdb-201673e0eeeb','酬王定國','劉攽','宋','宋诗','song-poetry','','[]','卧讀群言起欲行，壯夫爲不負平生。',64,'全唐诗/poet.song.35000.json','["卧讀群言起欲行，壯夫爲不負平生。", "上書略數三千牘，掉鞅何煩七十城。", "築室曾同老農計，寄詩猶見故人情。", "病軀懶厭金門步，長愧彤廷午漏聲。"]'),
('e16fff67-7137-4f73-a75e-78d6fa94d291','酬晁美叔','劉攽','宋','宋诗','song-poetry','','[]','此身敢與世崢嶸，禿髮衰顔太醜生。',64,'全唐诗/poet.song.35000.json','["此身敢與世崢嶸，禿髮衰顔太醜生。", "長愧使君心匪石，每因佳句贈連城。", "病來筋力惟求卧，老去文章不近名。", "酒量消除百無一，未嘗酣暢若爲酲。"]'),
('55a79c5d-8618-41a9-b999-d89966966a33','酬章質夫','劉攽','宋','宋诗','song-poetry','','[]','晚悟頭陀塵不侵，何妨居士著朝簪。',64,'全唐诗/poet.song.35000.json','["晚悟頭陀塵不侵，何妨居士著朝簪。", "故人自是相忘者，秀句依然莫逆心。", "翠柏高松存茂悅，潛鱗羈羽任飛沈。", "萬緣起滅空花喻，可向空花擬重尋。"]'),
('ab5f459d-c440-44c3-ae04-1ca79dfbc1de','次韵酬韓三相公見寄','劉攽','宋','宋诗','song-poetry','','[]','自昔羊公峴首遊，譙渦開府祇千秋。',64,'全唐诗/poet.song.35000.json','["自昔羊公峴首遊，譙渦開府祇千秋。", "韋平繼相聞詩禮，魯衛提衡絕輩流。", "功與榮名逾響捷，福隨陽報似言酬。", "孤生承乏曾何數，玉鉉龍文顧瓦甌。"]'),
('8bc23c8a-5b63-4c63-9a9c-96d3717b69c8','酬王平甫','劉攽','宋','宋诗','song-poetry','','[]','黯澹流雲索莫風，曉瞻雙闕望蒼龍。',64,'全唐诗/poet.song.35000.json','["黯澹流雲索莫風，曉瞻雙闕望蒼龍。", "秋還鷹隼非無意，凉入楓槐不變容。", "寓直鬢毛悲騎省，讎書編簡待陳農。", "黄花黄葉催時節，倩問誰家酒最醲。"]'),
('a60d403e-0e30-4c3b-8a67-2ca1dd26ebaa','次韵酬孫少述見寄','劉攽','宋','宋诗','song-poetry','','[]','退尺無緣復枉尋，信書那免不通今。',64,'全唐诗/poet.song.35000.json','["退尺無緣復枉尋，信書那免不通今。", "爭評玉價應輸厚，能爲魚謀豈厭深。", "待得散人如散木，敢論機械有機心。", "子荆詩筆興公賦，萬事慚君早息陰。"]'),
('b5c7a27a-6a5b-4f67-a9da-9611e9e50b2e','次韵酬顧子敦見寄','劉攽','宋','宋诗','song-poetry','','[]','丹砂未化不成仙，白髮衰容五十年。',64,'全唐诗/poet.song.35000.json','["丹砂未化不成仙，白髮衰容五十年。", "已自灰心當世事，更能回首大夫賢。", "對棋可待矜無敵，讀易聊須記絕編。", "寄語山陰顧元嘆，人今同病始相憐。"]'),
('9c22dfe0-5a97-4e72-8113-21dfa42caae2','次韵酬曹極司法','劉攽','宋','宋诗','song-poetry','','[]','越紙題詩寄我來，君家八斗定多才。',64,'全唐诗/poet.song.35000.json','["越紙題詩寄我來，君家八斗定多才。", "冰清玉潤高風舊，白雪陽春病眼開。", "長見夔龍參濬哲，不聞徐樂避雄猜。", "自緣衰老無能解，戰勝方當去剪萊。"]'),
('ba14fd17-6395-4b3f-8ab6-5fc7d7631dd5','次韵酬孫少述','劉攽','宋','宋诗','song-poetry','','[]','使節皆窮濁水源，降羌係踵慕稱藩。',64,'全唐诗/poet.song.35000.json','["使節皆窮濁水源，降羌係踵慕稱藩。", "强顔假守真無補，取笑高人不憚煩。", "豈有天池容斥鷃，莫將溝斷比犧樽。", "南山若許堪歸老，二頃平田十畝園。"]'),
('826bbe2b-df97-45df-8a9a-900a91c46a3a','酬韓相公','劉攽','宋','宋诗','song-poetry','','[]','病卧湘山念所親，惟公長記可憐人。',64,'全唐诗/poet.song.35000.json','["病卧湘山念所親，惟公長記可憐人。", "寄書不啻從容語，問舍仍慚消息真。", "半死孤松函徵羽，戀軒瘦馬强精神。", "祁奚鮑叔寧欺我，三入今看總四鄰。"]'),
('b272b698-d0e2-41f2-ba29-da7ee399a9d2','酬劉宜甫','劉攽','宋','宋诗','song-poetry','','[]','萬價睢盱倚市平，百工紛糺待宮成。',64,'全唐诗/poet.song.35000.json','["萬價睢盱倚市平，百工紛糺待宮成。", "神仙亦有丹臺籍，壯士當爲猛虎行。", "畢娶幸能同尚子，敝衣終不效唐生。", "洞天欲到先能說，十二樓前列五城。"]'),
('3c968513-b293-40a5-9a21-00b79be90a48','酬王定國五首  其一','劉攽','宋','宋诗','song-poetry','','["\u8861\u5c71"]','放逐朝恩本自優，衡山猶是古荆州。',64,'全唐诗/poet.song.35000.json','["放逐朝恩本自優，衡山猶是古荆州。", "百年生計羞蝸角，九品人情看馬頭。", "炎瘴還歸君不恙，風波別去我離憂。", "柔姬一唱陽關曲，獨任剛腸亦淚流。"]'),
('2e10e37b-4dbc-4ef6-9e18-48188c0473af','酬王定國五首  其二','劉攽','宋','宋诗','song-poetry','','[]','豈有多方書五車，爾來留意就丹砂。',64,'全唐诗/poet.song.35000.json','["豈有多方書五車，爾來留意就丹砂。", "誰將飽食倉中鼠，換取紅蓮火裏花。", "三顧祇能矜彼善，萬鍾多不悟堪嗟。", "蟠桃結實何難俟，况值安期棗似瓜。"]'),
('93ab18e2-518f-45d2-9b7f-f6221b002bce','酬王定國五首  其三','劉攽','宋','宋诗','song-poetry','','[]','貴公孫子族關西，失路青冥翅羽垂。',64,'全唐诗/poet.song.35000.json','["貴公孫子族關西，失路青冥翅羽垂。", "當世朋游皆父行，古人方略足肩隨。", "薄材老去歡傾蓋，直氣交新喜盡規。", "滿目江山屢回首，白雲流水付心期。"]'),
('74c76f2d-1090-4778-9d80-5c72a5a893e5','酬王定國五首  其四','劉攽','宋','宋诗','song-poetry','','[]','江岸青楓連白蘋，片帆如箭射千鈞。',64,'全唐诗/poet.song.35000.json','["江岸青楓連白蘋，片帆如箭射千鈞。", "風煙何處喧噓市，簫鼓誰家賽水神。", "雁鶩陂湖爭就暖，杉松廬舍不知貧。", "滯淫何必多離恨，譬似生爲澤國人。"]'),
('221bcdea-04c8-40c5-a1e9-a1c6d478e4dc','酬王定國五首  其五','劉攽','宋','宋诗','song-poetry','','[]','願賜支離不肖身，幅巾田野任天真。',64,'全唐诗/poet.song.35000.json','["願賜支離不肖身，幅巾田野任天真。", "我行三徑一廛地，君即東阡南陌人。", "晏卧自輕車結駟，食薇從使甑生塵。", "漳濱卓犖桓公健，盛德由來必有鄰。"]'),
('b19ab964-2847-44f5-a0cc-5c3f99caed01','承天寺翠景亭  其一','劉攽','宋','宋诗','song-poetry','','[]','一山篁竹間松杉，伏虎猶存居士庵。',64,'全唐诗/poet.song.35000.json','["一山篁竹間松杉，伏虎猶存居士庵。", "鐘磬有時聞絕壁，漁樵將晚會平潭。", "薄雲未解成春雨，返照偏能破夕嵐。", "我所思人桂林外，憑高惆悵贈雙南。"]'),
('f9f100a2-ae45-419f-80e1-1a9e00a2dc75','承天寺翠景亭  其二','劉攽','宋','宋诗','song-poetry','','[]','松有喬林桂有叢，石梯苔壁興無窮。',64,'全唐诗/poet.song.35000.json','["松有喬林桂有叢，石梯苔壁興無窮。", "快心疊嶂雲如掃，會意澄波日正中。", "修竹緣崖高竦竦，早梅飄雪細瓏瓏。", "狂吟大叫青冥外，驚看漁郎下釣筒。"]'),
('9e27d5f6-91f9-49ca-a404-8b31ede27669','遣懷','劉攽','宋','宋诗','song-poetry','','[]','六年長病每愁予，末疾風淫豈易除。',64,'全唐诗/poet.song.35000.json','["六年長病每愁予，末疾風淫豈易除。", "彳亍何曾暫忘屨，拮据空恨不能書。", "苦遭白髮無他術，常得中醫亦自如。", "欲向明廷乞骸骨，角巾藜杖整柴車。"]'),
('fef5981f-e336-4176-bbbb-cfe0b787abee','種竹重寄子瞻','劉攽','宋','宋诗','song-poetry','','[]','官曹何獨異吾廬，修竹成林手種初。',64,'全唐诗/poet.song.35000.json','["官曹何獨異吾廬，修竹成林手種初。", "未必七賢皆縱逸，因從三昧得無餘。", "風聲似水還成韵，日影填金尚覺疏。", "舊事喜君能記憶，興來當復埽牆書。"]'),
('94d110f1-0735-4427-b912-e0ed53e72f1b','周橦兄弟得解寄王教授察推','劉攽','宋','宋诗','song-poetry','','[]','今秋鄉里薦賢書，年少周郎智有餘。',64,'全唐诗/poet.song.35000.json','["今秋鄉里薦賢書，年少周郎智有餘。", "全得鳳毛增意氣，正聯鴻翼上空虛。", "汝南月旦評無愧，諸老先生謝不如。", "衰白慚居丈人行，長風猶欲助吹噓。"]'),
('9f793be2-871e-4045-93f9-5deea8b9167a','濟陰縣新成官廨贈知縣著作','劉攽','宋','宋诗','song-poetry','','[]','鼠牙雀角穿垣屋，墨綬銅章愧吏民。',64,'全唐诗/poet.song.35000.json','["鼠牙雀角穿垣屋，墨綬銅章愧吏民。", "製錦可無容膝地，戴星親作執柯人。", "奮飛翬雉檐雙翼，積疊魚龍瓦萬鱗。", "若比治蒲增四善，種花仍欲笑安仁。"]'),
('0ea80e8c-d698-47bd-aaab-53e46d2e4f24','送學正李秀才歸蜀','劉攽','宋','宋诗','song-poetry','','[]','金馬書來信不違，相如獨授七經歸。',64,'全唐诗/poet.song.35000.json','["金馬書來信不違，相如獨授七經歸。", "郡迎徐孺知懸榻，家望蘇秦想下機。", "峽底奔雷江亂湧，嶺頭如雨石交飛。", "丙魚郫酒歡閭里，悔殺京塵化素衣。"]'),
('37268081-0961-4830-862b-4ba7e5b69406','清門  其一','劉攽','宋','宋诗','song-poetry','','[]','清門早日素風傳，正在圖書翰墨間。',64,'全唐诗/poet.song.35000.json','["清門早日素風傳，正在圖書翰墨間。", "惠子應輸五車富，相如才授七經還。", "朱欄碧瓦森華屋，喬木浮雲滿舊山。", "渥水丹丘遠千里，鳳雛神驥落人寰。"]'),
('d87cba7f-464b-4b18-8c19-75fd561cebc1','清門  其二','劉攽','宋','宋诗','song-poetry','','[]','蜀山漠漠水溶溶，高閣經營得我公。',64,'全唐诗/poet.song.35000.json','["蜀山漠漠水溶溶，高閣經營得我公。", "萬軸鉛黄無脫簡，千尋清白有遺風。", "地留神苑逍遥外，天占仙壺縹緲中。", "公是蓬萊真學士，故應乘此問鴻蒙。"]'),
('64935325-4cee-4525-8a03-7cfb1b063eb1','西省種竹偶書呈同省諸公并寄鄧蘇二翰林','劉攽','宋','宋诗','song-poetry','','[]','五月十三竹迷日，今年仍自晏陰初。',64,'全唐诗/poet.song.35000.json','["五月十三竹迷日，今年仍自晏陰初。", "分將池籞千竿翠，就得楓槐一雨餘。", "紅葉蒼苔相映带，南榮北戶頓蕭疏。", "欲爲林下諸君咏，便是濤戎亦盡書。"]'),
('a1d6ae3b-44a0-480c-a5b0-703a13864adf','長安城南','劉攽','宋','宋诗','song-poetry','','[]','三百離宮何處尋，秦山相向晝陰陰。',64,'全唐诗/poet.song.35000.json','["三百離宮何處尋，秦山相向晝陰陰。", "城南地去天尺五，杜曲田皆畝一金。", "源發清泉隨種稻，穭生脩竹自成林。", "老年欲爲五陵客，射獵往來長縱心。"]'),
('c79d8ef1-9c6b-433f-94a1-799222e6a2e6','送陳成伯出牧陝府','劉攽','宋','宋诗','song-poetry','','[]','陳公六十丐朱輪，豪氣誰憐亦爲貧。',64,'全唐诗/poet.song.35000.json','["陳公六十丐朱輪，豪氣誰憐亦爲貧。", "原上鶺鴒深涕淚，櫪間騏驥發精神。", "山違折坂皆夷路，河透釃渠即要津。", "千歲海棠死鐵色，因君光彩會如新。"]'),
('6d2759de-0423-4e81-b88c-f886f71145a3','次韵蘇子瞻觀范景仁新樂','劉攽','宋','宋诗','song-poetry','','[]','大儒高論本升堂，物外光陰更不忙。',64,'全唐诗/poet.song.35000.json','["大儒高論本升堂，物外光陰更不忙。", "樂預請觀同季子，書雖未見屬黄香。", "正聲仍許三人和，古尺應無一黍長。", "鶴舞鳳儀時莫識，勾陳武帳省中央。"]'),
('38852a1d-5a3f-4b0e-8701-2cfbee0300dc','觀范公樂有感','劉攽','宋','宋诗','song-poetry','','[]','蜀公精思古人爲，論樂成書八十時。',64,'全唐诗/poet.song.35000.json','["蜀公精思古人爲，論樂成書八十時。", "那有伯牙爲聽者，空令一足尚傳疑。", "羊山鉅黍知無用，牛鐸遺音自不欺。", "便欲祠君從樂祖，出門陳迹奈深悲。"]'),
('844f8a1e-d20f-414e-aa71-80e194a3f198','贈黄知錄','劉攽','宋','宋诗','song-poetry','','[]','此身羈宦閉門居，里巷蕭條到客疏。',64,'全唐诗/poet.song.35000.json','["此身羈宦閉門居，里巷蕭條到客疏。", "道舊瀟湘與誰可，無雙江夏即君歟。", "塢中吹笛無留事，悵望何人得異書。", "翠羽明珠生海潏，更知名下不應虛。"]'),
('7185b3ad-9512-40ad-a9fc-22ba665dbcbb','題朱陵閣','劉攽','宋','宋诗','song-poetry','','[]','蒼煙漠漠石粼粼，坐倚山顛瞰水濱。',64,'全唐诗/poet.song.35000.json','["蒼煙漠漠石粼粼，坐倚山顛瞰水濱。", "開闔波濤專閱世，春秋風月不愁人。", "未知孤鳥歸飛意，聊問長松老大身。", "信有朱陵仙府在，玉樓珠殿闕爲銀。"]'),
('8a38adbe-dcec-429f-9e8d-a3aaf05e9cf6','步瀛閣','劉攽','宋','宋诗','song-poetry','','[]','方塘十畝水幽幽，魚自潛深鳥自浮。',64,'全唐诗/poet.song.35000.json','["方塘十畝水幽幽，魚自潛深鳥自浮。", "爲有風光陶永日，故題亭榭擬滄洲。", "旋移修竹看停雪，未落垂楊正奈秋。", "客到便留同一醉，山公不問習池遊。"]'),
('3501bd28-50d1-4920-856d-328f7af56242','水閣雨中','劉攽','宋','宋诗','song-poetry','','[]','雨濯苔衣水鏡明，風摇荷扇露珠傾。',64,'全唐诗/poet.song.35000.json','["雨濯苔衣水鏡明，風摇荷扇露珠傾。", "空堂送暑蕭蕭意，高樹吟秋惻惻聲。", "笑以稻粱邀鶴舞，莫將鐘鼓使魚驚。", "煙雲岑寂埃塵絕，頗愛孤舟盡日橫。"]'),
('d9fce82a-c128-490e-9c0a-8222ff81bebc','中秋望月','劉攽','宋','宋诗','song-poetry','','[]','中秋自昔賞金波，爽氣初凝暑頓過。',64,'全唐诗/poet.song.35000.json','["中秋自昔賞金波，爽氣初凝暑頓過。", "風雨定時看有數，樓臺高處得偏多。", "正憐白髮宜相照，不爲衰顔惜暫酡。", "願假長繩留玉兔，望舒能與倩夸娥。"]'),
('4a085458-f5a0-4ff4-9925-11f238bc8712','同諸公登秘閣','劉攽','宋','宋诗','song-poetry','','[]','複閣橫雲不易登，宮煙漠漠柳層層。',64,'全唐诗/poet.song.35000.json','["複閣橫雲不易登，宮煙漠漠柳層層。", "始知奇獸名天祿，遍見群書蠹羽陵。", "此去杳冥無幾許，向來游集類多能。", "秋風撩亂吹蓬鬢，老愧諸公話得朋。"]'),
('ff78550f-b796-4b75-952b-fbd9fb410f50','東園新種雜樹','劉攽','宋','宋诗','song-poetry','','[]','青苔翠竹吾人好，穿徑誅茅野老家。',64,'全唐诗/poet.song.35000.json','["青苔翠竹吾人好，穿徑誅茅野老家。", "豈爲素封增橘樹，還知避世種桃花。", "會因叢桂留騷客，却憶安榴逐漢槎。", "已有風光催物色，定甘羈旅待年華。"]'),
('4695a62f-e8b5-434f-8994-b185a2e20c5e','題深甫新種樹','劉攽','宋','宋诗','song-poetry','','[]','壽張樹梓待成器，方朔種桃因著花。',64,'全唐诗/poet.song.35000.json','["壽張樹梓待成器，方朔種桃因著花。", "古人既信十年計，野老今知五柳家。", "幽鳥鳴春能信宿，翠陰向暑會交加。", "甘棠不忘角弓賦，與子相好情無涯。"]'),
('734a3f18-39a7-453d-95d1-ec1c2f88efb3','長城逢周鼎','劉攽','宋','宋诗','song-poetry','','[]','田家秋收朝不歸，客子到門休馬蹄。',64,'全唐诗/poet.song.35000.json','["田家秋收朝不歸，客子到門休馬蹄。", "偶倩樵兒遠相問，倏乘黄犢仍有携。", "白頭蕭颯映紗帽，薄酒清泠將臛雞。", "幽興每於山野盡，爲君一醉判如泥。"]'),
('c670c114-ebdb-417e-a90c-0e670f678c53','臘月十九日雨後','劉攽','宋','宋诗','song-poetry','','[]','常年過臘雪猶繁，澤國春光已可憐。',64,'全唐诗/poet.song.35000.json','["常年過臘雪猶繁，澤國春光已可憐。", "初怪醉魂迷甲子，稍知客路斷山川。", "柳條著雨看成綠，花蕊融冰乍欲燃。", "避地早辭車馬迹，杖藜猶有里中賢。"]'),
('358a5253-9f97-4823-bdb8-f64016f99c2a','冬至偶作','劉攽','宋','宋诗','song-poetry','','[]','郡南百里即群舒，留滯頻驚歲月除。',64,'全唐诗/poet.song.35000.json','["郡南百里即群舒，留滯頻驚歲月除。", "閒過著慵思運甓，老來多忘却抄書。", "水鄉鳴雁寒無數，山路幽芳冷自如。", "晝坐偏知日南極，十分紅影在吾廬。"]'),
('b133d86a-9f01-4b9e-bef6-40f552b55b09','國子監御書閣觀雨同張主簿','劉攽','宋','宋诗','song-poetry','','[]','閣外凉風得憑欄，陰晴相望一城間。',64,'全唐诗/poet.song.35000.json','["閣外凉風得憑欄，陰晴相望一城間。", "過雲快雨噴濃墨，收水長虹墮缺環。", "斜直樓臺經灑濯，空無燕雀自飛還。", "聖朝百吏都勤事，優借儒官到老閒。"]'),
('d3ffc817-d880-4f18-9764-05054fd66ac8','重題間字韵','劉攽','宋','宋诗','song-poetry','','[]','棟宇雲生覆畫欄，御風身在杳冥間。',64,'全唐诗/poet.song.35000.json','["棟宇雲生覆畫欄，御風身在杳冥間。", "露頭不覺吹烏帽，熱手猶須握冷環。", "欲斷嘶蟬仍自續，倦飛孤鳥亦知還。", "君看老驥驚秋意，日暮凉生十二閑。"]'),
('9cee6d61-59ef-4bb0-9eed-9dba63c07852','雲水','劉攽','宋','宋诗','song-poetry','','[]','雲水東南萬里來，宦情羈思兩悠哉。',64,'全唐诗/poet.song.35000.json','["雲水東南萬里來，宦情羈思兩悠哉。", "舊交備禮矜垂老，晚輩多端謗不材。", "匠石頗知幾死木，火爐容有復然灰。", "過梅收潦秋風起，待得鴻飛燕子回。"]'),
('2c788787-da7f-40e4-a74a-a572e283a602','和王仲至錢塘','劉攽','宋','宋诗','song-poetry','','[]','胥山樓閣半空虛，春雨秋風興有餘。',64,'全唐诗/poet.song.35000.json','["胥山樓閣半空虛，春雨秋風興有餘。", "溪女載花浮水艦，潮兒戴火棹雷車。", "君尋故事應如夢，我得新詩欲信書。", "正是霜天向摇落，拂衣猶自及鱸魚。"]'),
('8cfde199-d076-4954-a2f1-7fe4ff5a6387','賀王丞相賜玉带','劉攽','宋','宋诗','song-poetry','','[]','捷書吉語報安西，辨色彤廷喜氣齊。',64,'全唐诗/poet.song.35000.json','["捷書吉語報安西，辨色彤廷喜氣齊。", "蕭相論功非汗馬，晉公成事有通犀。", "尚方製作皆金玉，委佩光華想虹蜺。", "欲問九環加賜衮，何如判白授封圭。"]'),
('e5e508bb-fa0a-4f9e-bfb2-6716c81cab7f','鳳凰臺','劉攽','宋','宋诗','song-poetry','','[]','江水中分白鷺飛，鍾山秀出衆山微。',64,'全唐诗/poet.song.35000.json','["江水中分白鷺飛，鍾山秀出衆山微。", "鳳凰去後高臺在，麋鹿遊來舊國非。", "萬里孤帆長在目，夕陽游子憺忘歸。", "六朝人物都荒草，但有寒潮信不違。"]'),
('f6f314b5-1c8e-4001-8111-881e8fd2f214','郡齋即事','劉攽','宋','宋诗','song-poetry','','[]','鶴髮霜髯新復新，爲郎補吏兩因循。',64,'全唐诗/poet.song.35000.json','["鶴髮霜髯新復新，爲郎補吏兩因循。", "爭先不及三千客，顧後猶容五十人。", "絕學捐書從佚老，曲肱飲水會忘貧。", "江湖極目連天白，照影知無纓上塵。"]'),
('7740c7a4-a74f-4365-81a6-cf28711771f2','與宋次道舍人同在殿中覆考進士次道子姪同就御試贈次道二首  其一','劉攽','宋','宋诗','song-poetry','','[]','池上君今得鳳毛，階庭蘭玉見兒曹。',64,'全唐诗/poet.song.35000.json','["池上君今得鳳毛，階庭蘭玉見兒曹。", "橫參氣象開衡石，丹桂芬香近赭袍。", "冀北群空經相馬，海濱人去復連鼇。", "西亳里第烏衣巷，賀客無辭應接勞。"]'),
('01dfa18f-c618-4f03-b7b5-71ae0fa7180f','與宋次道舍人同在殿中覆考進士次道子姪同就御試贈次道二首  其二','劉攽','宋','宋诗','song-poetry','','[]','不恨郎潛有二毛，喜從仙禁接官曹。',64,'全唐诗/poet.song.35000.json','["不恨郎潛有二毛，喜從仙禁接官曹。", "重吟紫殿森珠網，縱觀諸郎奪錦袍。", "汗血來時皆驥子，神仙不動倚靈鼇。", "明堂梁棟掄材盡，世上那知伐斫勞。"]'),
('4101bc11-bf41-47ef-951d-a63479519b05','燕子來馬上作','劉攽','宋','宋诗','song-poetry','','[]','馬上春寒透客衣，半晴天氣燕飛飛。',64,'全唐诗/poet.song.35000.json','["馬上春寒透客衣，半晴天氣燕飛飛。", "不知社日明朝是，轉憶吾廬共爾歸。", "風外輕輕雙翼疾，沙邊款款數聲微。", "畏人自習人間世，何事江鷗浪見機。"]'),
('cf22762d-75bb-406b-905b-d120ae72c4c7','酬章朝散  其一','劉攽','宋','宋诗','song-poetry','','[]','本無材畫備驅馳，豈有文章結主知。',64,'全唐诗/poet.song.35000.json','["本無材畫備驅馳，豈有文章結主知。", "廟鼎陳前羞瓠落，井泉方潔懼瓶羸。", "晚交賢傑真難得，辱在泥塗祇自嗤。", "澧有芳蘭沅有茝，夢魂無日不相思。"]'),
('57e244a4-d6da-4287-b4ed-bd2cdfd5aca2','酬章朝散  其二','劉攽','宋','宋诗','song-poetry','','[]','事無機變即無疑，此意唯當靜者知。',64,'全唐诗/poet.song.35000.json','["事無機變即無疑，此意唯當靜者知。", "末路風波成失所，歲寒霜雪正同時。", "勞生毫髮差千里，醉眼須臾已萬期。", "江上鯉魚天上雁，寄書嫌少不嫌遲。"]'),
('9d1c78de-0ec7-4622-98b0-d350380751e5','出汜水關','劉攽','宋','宋诗','song-poetry','','[]','洛河嚴鼓夜方中，上馬西郊滿面風。',64,'全唐诗/poet.song.35000.json','["洛河嚴鼓夜方中，上馬西郊滿面風。", "照野月華鋪水白，轉山銀燭列星紅。", "視祠太一觀爟火，從獵長楊賦射熊。", "壯觀已隨陵谷變，龍旌摇颺倚秋空。"]'),
('d660acb9-ceb2-4963-bae0-4108cf163598','齊州史君學士有游山詩學官諸生咸和史君又有詩二章贈之以刻石摹本示予因次韵  其一','劉攽','宋','宋诗','song-poetry','','[]','辨如流輠解連環，稷下諸生大小山。',64,'全唐诗/poet.song.35000.json','["辨如流輠解連環，稷下諸生大小山。", "幕府名聲收藉甚，雲泉氣味屬偷閒。", "茂林深壑逢迎際，細草穠花次序間。", "值有羽人招隠士，想君乘興不知還。"]'),
('ae25b16e-3f44-4f03-a288-a2b2664ecc30','齊州史君學士有游山詩學官諸生咸和史君又有詩二章贈之以刻石摹本示予因次韵  其二','劉攽','宋','宋诗','song-poetry','','[]','終日塵勞駷轡還，乍臨清濟看群山。',64,'全唐诗/poet.song.35000.json','["終日塵勞駷轡還，乍臨清濟看群山。", "飛來獨鶴應知倦，過去長雲本自閒。", "開國東西誇十二，待賢季孟哂中間。", "吟君詩句心蕭散，舊觀神明覺頓還。"]'),
('b3a9ca89-7c1d-4992-9d68-d9f99a68bc3d','還王平甫秀才詩稿','劉攽','宋','宋诗','song-poetry','','[]','王子能詩古不如，壯心豪氣未應除。',64,'全唐诗/poet.song.35000.json','["王子能詩古不如，壯心豪氣未應除。", "百年總付人間世，一腹都容天下書。", "白雪關山來騕褭，綠萍池沼秀芙蕖。", "窮愁已作無聞老，相愧臨濠一問漁。"]'),
('3a3e5f36-4e37-44dc-9224-98be4ffae6df','見蘇子瞻所作小詩因寄','劉攽','宋','宋诗','song-poetry','','[]','千里相思無見期，喜聞樂府短長詩。',64,'全唐诗/poet.song.35000.json','["千里相思無見期，喜聞樂府短長詩。", "靈均此秘未曾睹，郢客探高空自欺。", "不怪少年爲狡獪，定應師法授微辭。", "吳娃齊女聲如玉，遥想明眸嚬黛時。"]'),
('c569e991-6f8f-4b28-aa68-80d1ea79c88b','得奉世寄詩','劉攽','宋','宋诗','song-poetry','','[]','江城花柳復殘春，每上高樓望所親。',64,'全唐诗/poet.song.35000.json','["江城花柳復殘春，每上高樓望所親。", "身滯蠻舒誰與語，書來子弟爾成人。", "老侵鬚鬢莖莖白，情在篇章字字新。", "幸有竹林堪縱傲，罷官真作自由身。"]'),
('9e49b8f8-39a2-443f-80b4-63bebf66948c','偶題','劉攽','宋','宋诗','song-poetry','','[]','人間變化亦何常，不在他生與彼方。',64,'全唐诗/poet.song.35000.json','["人間變化亦何常，不在他生與彼方。", "病後公羊哀作虎，顧時司馬懿爲狼。", "龍眠頓長參天木，龜老猶搘病叟床。", "又有此曹惟奈久，非干天地日偏長。"]'),
('6dac5054-84ce-4eab-a465-0e66d47f7c6b','次韵和通判庫部會棋','劉攽','宋','宋诗','song-poetry','','[]','三百縱橫事不平，古今仙俗判昏明。',64,'全唐诗/poet.song.35000.json','["三百縱橫事不平，古今仙俗判昏明。", "已居勝勢誰前敵，獨暗機先誤必爭。", "寥落寒星天欲曉，稀疏過雁雨初晴。", "南陽畫諾庭無訟，正頼君詩得此聲。"]'),
('3b523a72-3c0b-4e69-80ed-22ec3fb9bb7e','叔父寄李氏庶子泉銘','劉攽','宋','宋诗','song-poetry','','[]','翠壁清泉庶子銘，文工境絕兩知名。',64,'全唐诗/poet.song.35000.json','["翠壁清泉庶子銘，文工境絕兩知名。", "埋藏雲外山神護，流落人間俗眼驚。", "恨不陪遊如阮籍，遠憐模寫到蠻荆。", "古書豈獨記名姓，自恐疏慵學不成。"]'),
('2f116e15-cc9e-404b-af46-cb5567b3e29f','章武殿','劉攽','宋','宋诗','song-poetry','','[]','歷數歸真主，乾坤仗義兵。',192,'全唐诗/poet.song.35000.json','["歷數歸真主，乾坤仗義兵。", "南夷長後服，下國怨西征。", "麋鹿荒吳苑，梯航聚易京。", "春螽那恃力，朝菌欲長生。", "雷雨隨金鼓，鷹鸇起旆旌。", "靈旗穊牛斗，白羽射欃槍。", "散地人誰保，連甍火徹明。", "晨門迎短箠，死骨斷長鯨。", "父老前流涕，農夫未釋耕。", "將軍薦牛酒，愷樂會韶韺。", "虢滅虞何恃，崇亡紂亦傾。", "一戎終薄伐，再駕就昇平。", "舊邑更脩武，行宮即顧成。", "奎芒垂篆刻，天質望氛清。", "羽衛嚴丹極，潮音接化城。", "欲回江海水，都作頌歌聲。"]'),
('3a66ad66-260d-4d4f-b2f2-424ac095d12c','溪上','劉攽','宋','宋诗','song-poetry','','[]','窄地穿茨拙，高城晚日斜。',72,'全唐诗/poet.song.35000.json','["窄地穿茨拙，高城晚日斜。", "竹籬侵水面，溪女浣汀沙。", "老樹垂朱實，懸藤結白花。", "綠萍浮碎點，芳杜上新芽。", "一邑過千室，十金無數家。", "魚蝦與菰米，惆悵此生涯。"]'),
('313ddb11-0c46-4644-a13a-00dc05bf1b01','和裴庫部十二韵','劉攽','宋','宋诗','song-poetry','','[]','懷人存蔽芾，招隠賦窅窊。',144,'全唐诗/poet.song.35000.json','["懷人存蔽芾，招隠賦窅窊。", "賢傑多能事，音徽自不瑕。", "偶然新樸斫，一笑爲歡呀。", "夏屋已隆棟，清池非漚麻。", "望賒隨朔雁，坐久至昏鴉。", "好事逢諸彥，佳聲播四遐。", "燕遊安以樂，詩語正而葩。", "霜應豐山石，灰飛河內葭。", "凉秋將落帽，斜漢挹浮槎。", "老木圍岑寂，蒼苔積鬖髿。", "瑶光天不遠，圭影日無差。", "莫怪長吟苦，良金出汰沙。"]'),
('c5c94c1d-574e-43e4-8cfd-aad5908edf6a','南征二首  其一','劉攽','宋','宋诗','song-poetry','','[]','漢皇開五嶺，虞帝事三苗。',120,'全唐诗/poet.song.35000.json','["漢皇開五嶺，虞帝事三苗。", "定有南征問，遥知用武朝。", "前籌皆廟略，選士𠙆風飆。", "潦水江湖大，雲山故國遥。", "天陰凝殺氣，師老聽哀謠。", "猿鶴愁君子，黿鼉憶架橋。", "繡衣方責戰，虎節竟乘軺。", "白骨不歸葬，冤魂誰爲招。", "猶傳發閭左，願得聽簫韶。", "旅泊時流動，何由問九霄。"]'),
('721376ff-94ac-4b09-971b-5bd3a378c81d','南征二首  其二','劉攽','宋','宋诗','song-poetry','','[]','揚越舊秦兵，苗頒尚禹征。',144,'全唐诗/poet.song.35000.json','["揚越舊秦兵，苗頒尚禹征。", "初驚一使任，那用萬人行。", "友戶凝昏祲，滄波觸駭鯨。", "越裳無信息，銅柱定將傾。", "服嶺東南尉，戈船萬里程。", "江通夜郎道，秋入伏波營。", "插羽頻封檄，馳軺屢請纓。", "介鱗悲物色，猿鶴悵民生。", "幾日封京觀，歸時捲旆旌。", "休聞七科戍，無用五陽兵。", "海國犀牛遠，南琛紫貝輕。", "平生一長劍，歲暮望欃槍。"]'),
('b87d919e-7678-432f-998e-7531481a6b5c','寄橙與獻臣','劉攽','宋','宋诗','song-poetry','','[]','清霜夜漠漠，佳實曉纍纍。',72,'全唐诗/poet.song.35000.json','["清霜夜漠漠，佳實曉纍纍。", "鵠鷇攢修幹，金華耀夙曦。", "狂酲香處析，痏渴味餘衰。", "採摘悲凡口，漂零恐後時。", "頌聲騷客誤，錫貢禹書遺。", "惆悵生南國，煩君品藻詞。"]'),
('7418b3e2-7628-4faf-ba90-d89b88b9719c','酬臨濮劉推官','劉攽','宋','宋诗','song-poetry','','[]','治民非己長，那得士心降。',120,'全唐诗/poet.song.35000.json','["治民非己長，那得士心降。", "爲問來鳴鳳，何如止吠厖。", "壺餐慚鼎食，鉛割謝矛鏦。", "辯士更持節，佳兵正上瀧。", "薄田桑十畝，小市釀千缸。", "自喜庭無訟，寧論智少雙。", "陪京開左輔，振鐸服中邦。", "禁臠分留印，天枝涖建幢。", "孤生老將至，壹意信猶矼。", "頼倚絃歌化，餘風勉政龐。"]'),
('3e4dc323-4320-4a76-8d03-664b69db15bb','送賈士彥延平知光化縣','劉攽','宋','宋诗','song-poetry','','[]','名家千里駒，富學五車書。',96,'全唐诗/poet.song.35000.json','["名家千里駒，富學五車書。", "柱史文無害，絃歌智有餘。", "素風存翰墨，陰德在門閭。", "江漢子男邑，穀城桑柘墟。", "曾爲都尉治，今亦萬家居。", "安穩飛鳬舄，新鮮縮項魚。", "繡衣夸里父，壽酒薦親輿。", "不作期年別，看君就詔除。"]'),
('9659d76d-bff4-4a63-9dd7-ee30fd86d670','送高麗使','劉攽','宋','宋诗','song-poetry','','[]','絕域求通使，皇華益藉才。',120,'全唐诗/poet.song.35000.json','["絕域求通使，皇華益藉才。", "男兒萬里志，笑語片帆開。", "積鹵生陰火，奔濤起晝雷。", "曝鱗成島嶼，吐氣誤樓臺。", "城邑東迎日，居人學用杯。", "詩書自天性，冠带及家陪。", "歲月如勤止，登臨亦壯哉。", "威聲逾肅慎，仙事指蓬萊。", "鵬向南溟近，槎常八月來。", "言瞻析津次，遥見二星回。"]'),
('79ba15db-048d-4c52-929a-1a86d568d0fa','次韵和宋職方北樓','劉攽','宋','宋诗','song-poetry','','[]','勝事略就手，茲樓無復加。',144,'全唐诗/poet.song.35000.json','["勝事略就手，茲樓無復加。", "棟梁宏可愛，丹碧麗非華。", "風月登臨最，川原眺望賒。", "斗城知日近，瀛海自雲遮。", "杖屨歡乘興，文移謹報衙。", "晝閒禽語靜，歲熟市聲譁。", "柳影重重幕，蓮香處處霞。", "舳艫隨渚遠，睥睨向人斜。", "話聽游童樂，詩煩上客誇。", "國風麟趾應，賓宴鹿鳴嘉。", "鵰鶚無餘力，騏驎不待撾。", "衰遲竟何補，襆被念還家。"]'),
('5d375a82-e8d3-42f9-aa09-0c69b88da11b','復次前韵','劉攽','宋','宋诗','song-poetry','','[]','仙游欺緬邈，古事厭增加。',144,'全唐诗/poet.song.35000.json','["仙游欺緬邈，古事厭增加。", "自我新形勝，因之翫物華。", "不勞工子勸，無價境天賒。", "雲構森如畫，翬飛勢莫遮。", "靜看梁燕賀，閒聽野蜂衙。", "曹事初無壅，軍聲信不譁。", "倚欄歌白雪，爲客進流霞。", "快意凉風起，餘歡素月斜。", "吳趨應有始，齊難詎爲誇。", "夏日思王粲，名流得孟嘉。", "優游琴八疊，悲壯鼓三撾。", "遍看題詩語，飄然自一家。"]'),
('4f060e27-4825-40eb-8235-2c0d2f046d47','既和宋君佳篇因取加字韵中所未用者別爲十二韵','劉攽','宋','宋诗','song-poetry','','[]','板築廢已久，樓居仍可嗟。',144,'全唐诗/poet.song.35000.json','["板築廢已久，樓居仍可嗟。", "敢辭才不逮，何說智無涯。", "史例同新作，民謠異刺奢。", "棟梁虹夭矯，軒檻獸盤拏。", "萬室瞻華宇，千兵擁建牙。", "浮雲生柱礎，杲日透窗紗。", "明滅穿林水，稠重覆塹花。", "長空指去鷺，過雨亂鳴蛙。", "屢獲詩人賦，時紆長者車。", "薦觴凝縹白，諧語繆壺齟。", "隠吏容攀桂，終更遽及瓜。", "多慚雙鬢雪，蕭颯對文緺。"]'),
('b3d55212-7572-4a8f-9239-4260397891ea','合加字韵兩篇二十四字成一章更互次之咏曹之土風并敘出處寄呈司年職方','劉攽','宋','宋诗','song-poetry','','[]','漢郡王封寵，周宗伯命加。',288,'全唐诗/poet.song.35000.json','["漢郡王封寵，周宗伯命加。", "犬牙基自若，麟趾嘆于嗟。", "陵谷隨人世，春秋積歲華。", "洩雲餘薈蔚，浮濟變津涯。", "端木倦游學，朱公精貸賒。", "於今富而麗，遺俗儉寧奢。", "使轍常交錯，京藩倚扞遮。", "鋤鉤非盜用，簫勺換兵拏。", "樸直叨三組，工夫盡兩衙。", "戎容剖符虎，士氣肅旗牙。", "圜土幾無訟，虛庭不禁譁。", "對棋銷白晝，清嘯岸烏紗。", "池館澄潮水，樓譙冠暝霞。", "綠梢檐外柳，紅朵砌前花。", "徙倚危欄峻，行來繚徑斜。", "巢林安短翼，擅壑愧跳蛙。", "夙昔未更事，游談多自誇。", "奏盈方朔牘，書過惠施車。", "臧室初縻迹，連城晚拜嘉。", "華顛看欲落，病齒不勝齟。", "珠琲輕魚目，桐絲陋馬撾。", "敢論雞似鳳，願食棗如瓜。", "臺妙前辭滿，安輿久卧家。", "最容高尚志，那肯待青緺。"]'),
('a3433570-d675-4cf6-b916-0623aa1336b9','又十二韵','劉攽','宋','宋诗','song-poetry','','[]','絕境可遺老，清心仍去邪。',144,'全唐诗/poet.song.35000.json','["絕境可遺老，清心仍去邪。", "樓頭喧燕雀，川面動龍蛇。", "碧瓦浮煙素，朱甍麗日赮。", "倚風時坐嘯，乘月更吹笳。", "庭樾交傾蓋，池房雜舞髽。", "凉秋乘爽塏，吉歲驗汙邪。", "厨釀全欺魯，兒歌習陋巴。", "林珍餉桃李，溪飯列魚蝦。", "勝賞須神會，浮名祇盜夸。", "誰能貪課最，本自學禪迦。", "羈旅枝栖鵲，田園舍負蝸。", "蕭條看白鬢，早晚得丹砂。"]'),
('ead40c94-1362-401c-b7e5-89caaea36dbf','酬范判官喜雨','劉攽','宋','宋诗','song-poetry','','[]','一旬天再雨，惠澤夜來深。',120,'全唐诗/poet.song.35000.json','["一旬天再雨，惠澤夜來深。", "震發雷霆事，榮華卉木心。", "問年如隔併，閱日屢辛壬。", "安水江千里，良田畝一金。", "劭農非有術，望歲忽爲霖。", "雊雉依青隴，跳魚出廢涔。", "夢成池上作，喜見洛生吟。", "破敵聯飛鏃，高張信雅琴。", "緒風開晝色，遲日媚花陰。", "更有資清興，連峰映碧潯。"]'),
('221254f1-98d1-4990-a891-fc6662fc2061','赴官京東同舍諸公觀音院見餞有贈并簡不至者','劉攽','宋','宋诗','song-poetry','','[]','今日承人乏，東州假傳車。',96,'全唐诗/poet.song.35000.json','["今日承人乏，東州假傳車。", "勞生復去國，垂老欲捐書。", "斗酒相爲樂，諸家食有魚。", "華燈續光景，鳴笛問吹噓。", "即事已陳迹，懷人方跂予。", "要官多謁禁，數子莫情疏。", "啼鳥春猶淺，高花日勝初。", "朝回應見念，會語殿中廬。"]'),
('a78ced86-795a-4c70-a2d1-f6948151f5e7','景德寺河沙院餞蘇安上知泰州劉元忠河北都運分題得無字','劉攽','宋','宋诗','song-poetry','','[]','今朝一樽酒，聊與故人俱。',72,'全唐诗/poet.song.35000.json','["今朝一樽酒，聊與故人俱。", "非復少年日，深驚別意殊。", "燕雲低朔漠，楚水向江湖。", "報國不一事，出門成異塗。", "騰鱗安浩蕩，雋翼就虛無。", "應笑白頭老，閉關方據梧。"]'),
('79ef9e60-2095-4944-bd18-0c9a6364baca','過太康縣此路入亳州云是先帝昔東幸時馳道也馬上口占行二十里成三十韵','劉攽','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','維昔東巡狩，天王景宅朝。',292,'全唐诗/poet.song.35000.json','["維昔東巡狩，天王景宅朝。", "金椎隠馳道，象載下招摇。", "呂應青雲近，關迎紫氣遥。", "旄頭前詔羿，陪乘後征僑。", "奉引三司肅，中堅萬馬調。", "旂常亂辰象，劍佩雜瓊瑶。", "多士和相讓，諸侯貴不驕。", "海神來積雪，仙馭會祥飆。", "象帝初觀妙，猶龍此見譙。", "强名大樸著，將隠德音昭。", "上善泉仍潔，知常檜後凋。", "虛心明左契，聞道首參寥。", "絳節賓閒館，璇宮盛綺寮。", "洞天留白日，書法祕青霄。", "瑄玉嚴禋祀，歌童采夜謠。", "衆神如向座，佳氣鬰通宵。", "隴麥聞重秀，房芝搴紫苗。", "醴泉甘愈疾，舞鳳樂儀韶。", "舉翼王喬{血／与}，排雲子晉簫。", "頌釐知簡簡，奏賦欲飄飄。", "麗澤驚雷雨，鴻恩霈蓼蕭。", "百年皆就見，比屋幸寬徭。", "牧馬猶如隗，封人預祝堯。", "歡聲喧望幸，舊里不崇朝。"]'),
('755c8c9d-bc9b-4d88-8056-9837469e1e35','次韵和石曼卿泰山','劉攽','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','步至東山表，纔知嶽鎮尊。',144,'全唐诗/poet.song.35000.json','["步至東山表，纔知嶽鎮尊。", "百川趨渤碣，一柱際乾坤。", "託始無懷氏，談更洛誦孫。", "後王崇檢玉，方士說天門。", "巖石居凝命，群峰遠駿奔。", "陰陽殊雨霽，朝夕異凉溫。", "學者譏秦事，功臣誓漢恩。", "氣連滄海碧，影變濁河渾。", "候日來丁夜，捫星待合昏。", "仙真疑史闕，宮殿謹司存。", "落水雷穿谷，危松珀擁根。", "更尋宣父志，雅意屬崦崑。"]'),
('4044f385-3b5a-40fb-9688-057fd1cb5382','將至洛中先寄宋次道諸幕府','劉攽','宋','宋诗','song-poetry','','[]','頻年洛陽道，秋月照征車。',96,'全唐诗/poet.song.35000.json','["頻年洛陽道，秋月照征車。", "關口朝煙上，伊川曉日初。", "艤船看飲馬，投策數游魚。", "蟬嘒隨林靜，鐘鳴應谷虛。", "夙齡懷勝尚，吏役久愁予。", "及此娛山水，翻知喜簡書。", "名都士淵藪，盛德世璠璵。", "羈旅如傾蓋，詹言興有餘。"]'),
('08e6b6d7-5f9f-4906-95cc-1af714329e8a','錢子高舉賢良中科寄賀子飛','劉攽','宋','宋诗','song-poetry','','[]','當世英雄彀，連年伯仲賢。',168,'全唐诗/poet.song.35000.json','["當世英雄彀，連年伯仲賢。", "友于聲競爽，敵萬智無前。", "讜議天人際，馳辭日月邊。", "會驚文得鳳，真謂筆如椽。", "萬乘親前席，諸生敢比肩。", "晚成無近器，妙選悉青錢。", "濟美高陽舊，傳經韋氏專。", "公侯將必復，廊廟定誰先。", "步武青雲接，官曹畫省聯。", "軼群看赤驥，洵直想朱絃。", "德賞今誰擬，才難古亦然。", "從容照棣萼，聞望已陶甄。", "夏屋方隆棟，雲檣穩濟川。", "那令得賢頌，祇貴漢王淵。"]'),
('353612a3-7a9d-4ebb-b948-634f3dccdd3c','送裴二知蘇州','劉攽','宋','宋诗','song-poetry','','[]','著書玄尚白，送客鬼揶揄。',72,'全唐诗/poet.song.35000.json','["著書玄尚白，送客鬼揶揄。", "積水望江海，秋風吹軸轤。", "貴人千騎長，紫綬左魚符。", "遺愛留南國，歡聲接舊吳。", "曉霜繁橘柚，過雨熟菰蒲。", "安得如王子，從君飛隻鳬。"]'),
('d9e604ff-2248-4754-b107-c02e34ad3b60','和原父同江鄰幾過浄土院觀古殿吳道子畫楊惠之塑像及顯僧傳當世貴人形骨仁僧鼓琴作','劉攽','宋','宋诗','song-poetry','','[]','真賞非俗嗜，雅游知勝緣。',120,'全唐诗/poet.song.35000.json','["真賞非俗嗜，雅游知勝緣。", "百身化前佛，方丈納諸天。", "工以智自表，名由高益傳。", "吳生擅粉繪，楊氏妙鈞埏。", "能事古未盡，希聲今亦然。", "伻圖觀肖像，撫㢩置鳴絃。", "理會均聞見，神交遺後先。", "衣冠若對面，山水欲忘年。", "子墨臺中妙，仙翁樹下賢。", "新詩俱絕唱，塵土更餘妍。"]'),
('e5d7015b-0727-4b43-b82f-1511abefb017','同徐監簿作水始冰','劉攽','宋','宋诗','song-poetry','','[]','霜落歲將晏，風生水始冰。',72,'全唐诗/poet.song.35000.json','["霜落歲將晏，風生水始冰。", "猶殘夏蟲怪，初比玉壺凝。", "氣襲璇源潔，光摇寶鑑澄。", "涵虛同凜凜，履薄乍兢兢。", "魚鱉悲潛伏，江湖息沸騰。", "淩陰如獻納，會是却炎蒸。"]'),
('927fa725-47ec-4910-8ba3-3a12cd77c5a8','送韓子華奉使安撫江南','劉攽','宋','宋诗','song-poetry','','[]','漢庭重八使，同日出東都。',72,'全唐诗/poet.song.35000.json','["漢庭重八使，同日出東都。", "仗節年仍少，埋輪氣不孤。", "詔書敦直指，懸弩肅前驅。", "宣布君恩被，周爰楚澤紆。", "秋風捲旌旆，桂楫上江湖。", "遊子故鄉在，相思天一隅。"]'),
('581e9f39-c8e6-42b3-8f4f-cf8679dfcf11','送張益宣州法曹','劉攽','宋','宋诗','song-poetry','','[]','掾曹仁恕用，郎選孝廉爲。',72,'全唐诗/poet.song.35000.json','["掾曹仁恕用，郎選孝廉爲。", "之子文無害，居廷敢决疑。", "一王除制作，三尺著毫釐。", "過眼皆成誦，讎書自所宜。", "察廉時爾貴，治道吏爲師。", "去去弦歌化，當如別後思。"]'),
('6ec27a08-0d1a-4f11-966f-dcf669f516bf','郊祀慶成詩','劉攽','宋','宋诗','song-poetry','','[]','聖瑞歸文子，珍符屬孝孫。',288,'全唐诗/poet.song.35000.json','["聖瑞歸文子，珍符屬孝孫。", "儲精凝景命，端拱輯群臣。", "禮樂成中典，人神定一尊。", "亮章新物睹，咸秩備司存。", "成德兼明察，彌文付討論。", "積高參斗極，因吉際乾坤。", "候景迎長日，萌芽發舊根。", "律風乘廣莫，卦氣起昆侖。", "閶闔開黄道，星辰拱紫垣。", "奉瑄嚴太一，推策本軒轅。", "八廟森重構，諸侯盛駿奔。", "薦馨光裸玉，告嘏逮歸弔。", "旄纛羅千乘，旂旛徑九門。", "龍蛇影摇動，鵝鸛勢飛翻。", "士勇歡鳬藻，天晴候晏溫。", "幔城橫象魏，玉果會春園。", "嚴警連宵鼜，周廬次屬鞬。", "望雲舒錦石，揖月上金盆。", "廣樂歡來格，升煙續載燔。", "頌釐如響答，終事寂無喧。", "輦路祥飆轉，端門旭日暾。", "天雞還自舞，仙鶴爲孤騫。", "河漢驚垂象，雷霆浹厚恩。", "畫衣期不犯，肺石更何冤。"]'),
('577e9d96-ba76-48d5-8bd3-f39cba2c826d','次韵和王正仲熙寧郊祀二十韵','劉攽','宋','宋诗','song-poetry','','[]','駿命膺長發，鴻圖本慎徽。',240,'全唐诗/poet.song.35000.json','["駿命膺長發，鴻圖本慎徽。", "八方星拱極，四海日升暉。", "舊典增咸秩，彌文示表微。", "聖時均玉燭，天統正璿璣。", "南極迎陽復，陰泉候氣歸。", "積高常眷顧，昭孝每毋違。", "羽衛來雙闕，和鑾並六飛。", "風霆齊命令，龍虎會旗旂。", "帳殿層城暮，金波列宿稀。", "嚴更虛夜鼜，雕輦下彤闈。", "廣樂千人唱，升煙萬目睎。", "衆神知受記，象物競來依。", "陟降兼明察，圓方比範圍。", "送音仍鬻鬻，畀福想霏霏。", "霈澤蘇群動，春陽暢墐扉。", "慶深周揭厲，感極至歔欷。", "多士參鳴玉，微生厠皂衣。", "肅雍瞻帝武，奉引近天威。", "儒館鵷鸞舊，長謠錦繡輝。", "因知子雲賦，何足頌巍巍。"]'),
('ac3e60d0-f700-4dee-b035-dbcfa3d9ba63','聞蜀中大水寄閬中諸弟','劉攽','宋','宋诗','song-poetry','','[]','蜀嶺參天近，巴江向海迂。',120,'全唐诗/poet.song.35000.json','["蜀嶺參天近，巴江向海迂。", "百城同暗谷，獨鳥視前途。", "六月蒸雲甚，長風驟雨俱。", "漏天疇得補，深峽不時輸。", "回首蛇蛟鬭，傷心虎豹呼。", "劍關愁斷棧，天漢逼乘桴。", "臂飲通殊俗，巢居自一隅。", "遺黎待螺蚌，小邑斷樵蘇。", "絕域飛黄鵠，仙人用隻鳬。", "清秋已收潦，問爾麗泥塗。"]'),
('34c0e1d4-7603-49dd-b520-bab1c3082cb5','馮當世生日  其一','劉攽','宋','宋诗','song-poetry','','[]','申甫維崧嶽，東方本歲星。',192,'全唐诗/poet.song.35000.json','["申甫維崧嶽，東方本歲星。", "舊書容盡信，成事况親聆。", "南紀浮江漢，青煒變頊冥。", "氣和方毓粹，地勝已儲靈。", "德宇何寥廓，斯文實典刑。", "龍駒來汗血，霜刃脫青萍。", "智略聯三捷，規模壯六經。", "羽翰驚海運，辰象屬天扃。", "回首煙霄近，橫雲漢閣青。", "河圖開祕奧，龍節付儀形。", "萬里風聲肅，三年楚俗寧。", "里甿羞螮蝀，鄉校謹螟蛉。", "聖主思霖雨，群生望大庭。", "指期調鼎實，洗眼頌椿齡。", "授易嘗占晉，論詩竊次駉。", "莫言狂簡士，足記景鐘銘。"]'),
('688ef2bf-5ac8-4297-95ff-ab5cade8f825','馮當世生日  其二','劉攽','宋','宋诗','song-poetry','','[]','陽月方開旦，商行接素秋。',168,'全唐诗/poet.song.35000.json','["陽月方開旦，商行接素秋。", "聲華臨盛際，勳業動前修。", "舊物詩兼禮，公望礪與舟。", "諫行扶廟算，威克弊邦讎。", "翻欲危晁氏，皆能苦絳侯。", "孤城雖莫可，具美亦誰侜。", "北關虛前事，南冠記昔遊。", "客惟論藥餌，書不號窮愁。", "迥有閒中趣，高於物外求。", "賓朋依白傅，潤澤借裴休。", "跂也身方族，時哉歲欲遒。", "愁無縮地術，頼有置書郵。", "理楫王猷拙，稱觴小陸優。", "傾心日夜急，滾滾大江流。"]'),
('6c8b0ded-3694-422d-b5ab-880fb55bb930','送子惇出使河北','劉攽','宋','宋诗','song-poetry','','[]','禹積基壺口，堯仁被冀方。',240,'全唐诗/poet.song.35000.json','["禹積基壺口，堯仁被冀方。", "官迎赤車使，詔選瑣闈郎。", "力學推元稹，高才屬長康。", "壯懷來慷慨，得志自軒昂。", "愛直容知默，中和異吐剛。", "一臺傳駮議，二府見分章。", "前效平原淺，嚴威夏日長。", "居常祇逢掖，試躍即干將。", "雲漢昭回地，鵷鸞八九行。", "穹廬休夕拜，覢弩備晨裝。", "洚水成滔陸，流庸頗異鄉。", "挂冠勞畚鍤，佩犢問耕桑。", "哺乳增襵粥，完膚滌痏瘡。", "朴忠將漕最，惇厚訓兵强。", "冀馬羅馳傳，河魚飽食魴。", "細書夸睇視，淳酎沃煩腸。", "肯作田園計，寧嫌鬢髮蒼。", "能令老者奮，直與大鵬翔。", "處世當何語，懷君豈易忘。", "哂由終所畏，與點自知狂。"]'),
('cddb73ce-ef11-4876-bb5d-22e34aa6de3b','卜居書懷','劉攽','宋','宋诗','song-poetry','','[]','漆雕未能信，陽甫免歸居。',168,'全唐诗/poet.song.35000.json','["漆雕未能信，陽甫免歸居。", "理以逍遥得，材由濩落疏。", "狹才輕勢利，小隠幸林廬。", "藿食由來事，茅茨不願餘。", "南檐容曝日，側徑喜携鋤。", "筋力吾如此，功名世有諸。", "憶初干萬乘，徒步謁公車。", "投射東堂策，歸來北闕書。", "先鳴煩指日，弱羽愧吹噓。", "雲雨非人力，泥塗亦詔除。", "江湖輕乘雁，鐘鼓陋鶢鶋。", "有道翻羞卷，迷津幸遂初。", "幽棲謝車馬，至樂狎樵漁。", "述作稱狂簡，誰能問起予。"]'),
('7b96b5f5-ac63-468a-855e-63c235e8c195','渭水','劉攽','宋','宋诗','song-poetry','','[]','鳥鼠流清渭，岍岐導衆山。',144,'全唐诗/poet.song.35000.json','["鳥鼠流清渭，岍岐導衆山。", "懸車循暗谷，斷棧出重關。", "長路去未已，連峰深更艱。", "秋高木落外，天夐鳥飛間。", "日出看群動，煙收認百蠻。", "別腸逾九絕，愁淚獨長潸。", "立志薄軒冕，隠居宜草菅。", "自甘家食薄，還愛綵衣斑。", "從吏負夙願，辭親何厚顔。", "簡書今可畏，幕府尚餘閒。", "猨叫無勞思，鴻冥不易攀。", "歸來城闕望，但見白雲還。"]'),
('8d9205ca-3cd3-4344-8601-fa2ff6fc2353','致齋中太一宮見屏風有唐賢和常舍人詩因次韵寄子瞻內翰子由侍郎子開舍人穆父待制數公皆嘗祠太一也','劉攽','宋','宋诗','song-poetry','','[]','禁掖下祠宮，青槐輦道通。',144,'全唐诗/poet.song.35000.json','["禁掖下祠宮，青槐輦道通。", "薄雲收霽雨，初夏接薰風。", "將旦群陰伏，齋居百慮空。", "夢遊如有遇，反聽更能聰。", "秘祝寧神外，多儀拜貺中。", "佐靈猶五帝，執事本三宮。", "象海鼇山峻，翻階藥秀紅。", "守儒嚴講幄，起草麗談叢。", "夙昔嬉遊並，神仙步武同。", "吹藜驚爝火，抱法想江楓。", "已老仍書癖，懷賢愧易東。", "君王問無擇，留意屬溪工。"]'),
('40690cca-a173-487c-8e94-7a4b98fbf255','羽林通孝經','劉攽','宋','宋诗','song-poetry','','[]','聖治周方域，儒風暨羽林。',72,'全唐诗/poet.song.35000.json','["聖治周方域，儒風暨羽林。", "一經嚴授業，五孝得潛心。", "騎獵宸遊簡，嚴廬禁掖深。", "披文知行在，即事亦官箴。", "訓勇寧慚晉，專門詎屬參。", "從茲六郡俗，不羨滿籯金。"]'),
('9ce21989-dddd-4062-8f7b-244d431baeac','寄杭州通判蘇子瞻海州使君孫巨源','劉攽','宋','宋诗','song-poetry','','[]','淛水三江外，朐山百郡東。',288,'全唐诗/poet.song.35000.json','["淛水三江外，朐山百郡東。", "專城須聞望，半刺亦才雄。", "浪海元無際，吳潮近峽中。", "茵憑那獨異，翰墨自兼工。", "追昔賢良舉，殊時步武同。", "百篇傳冠古，半策已全功。", "咫尺騰霄使，回旋著籍通。", "龍媒流汗血，鳳羽雜鳬翁。", "烈士猶難進，清朝各願忠。", "伏蒲寧曲學，鳴鼓尚深攻。", "物理安圓鑿，人倫陋發蒙。", "俟河愁敝箄，破膽忤豐隆。", "力擠膠西相，廉欺第五公。", "絕絃迷促軫，折翼創虛弓。", "卧閣寧多病，治中有舊風。", "從容付丞史，咻噢及兒童。", "使者誅求急，王人禮數崇。", "湯年偏一溉，稷御不終窮。", "高宴延仙伯，閒遊歷梵宮。", "怒濤翻練白，浴日上霞紅。", "沙鮚能藏蟹，江鳬不慕鴻。", "五雲瞻碣石，七澤望青楓。", "瓜戍留麋巀，茅心憶桂叢。", "賜環聊衮衮，遺楪漫忡忡。"]'),
('f2b7cb00-8f61-4c2c-864e-676ec4f9b56b','寄梅聖俞江鄰幾韓持國','劉攽','宋','宋诗','song-poetry','','[]','直諒多聞友，衣冠領袖賢。',144,'全唐诗/poet.song.35000.json','["直諒多聞友，衣冠領袖賢。", "平生三徑樂，少別四時遷。", "曲策春山秘，絃歌璧水圜。", "吳門真養性，委吏故依然。", "杖履兼閭里，詩文孰後先。", "風雲多變態，鞭弭屢周旋。", "清汝流無極，維嵩地少偏。", "微官非擇取，勝事偶陳前。", "遲日消棋局，殘春頼醉眠。", "時從謝客咏，不廢遠公禪。", "吏課輕涓露，官箴恨纆牽。", "裹糧嗟不遂，回首鎮幽捐。"]'),
('94280ba5-68b8-4312-9f7e-61649a7927e4','寄王子直謝師宰','劉攽','宋','宋诗','song-poetry','','[]','自昔東南美，由來王謝郎。',72,'全唐诗/poet.song.35000.json','["自昔東南美，由來王謝郎。", "提衡俱射策，繼踵事專場。", "凡馬驚騏驥，群蜚下鳳凰。", "同時冠後進，舉國誦成章。", "賈子諸王服，蕭生舊友光。", "青冥看咫尺，雲路更翱翔。"]'),
('fa1bd65d-e58c-41c3-b197-9a7ba9f6cf57','游東寺','劉攽','宋','宋诗','song-poetry','','[]','籃輿出乘興，佳客不相遺。',72,'全唐诗/poet.song.35000.json','["籃輿出乘興，佳客不相遺。", "水色鳴騶外，林光倚蓋時。", "寒餘草初變，風煦柳先知。", "複閣披襟久，迴廊步屧遲。", "招提應不厭，幽熟重前期。", "會待花如霰，壺觴約自隨。"]'),
('9a152834-a239-485c-912f-93afd3f611d9','江漢','劉攽','宋','宋诗','song-poetry','','[]','江漢繄常武，苗民傒舞階。',240,'全唐诗/poet.song.35000.json','["江漢繄常武，苗民傒舞階。", "百蠻時暴桀，終古事威懷。", "壤穴深潛蟻，山林盛鬥豺。", "墮鳶愁瘴霧，吹蠱厭昏霾。", "淫毒皆沙蜮，跳梁自井蛙。", "幾成分服嶺，垂欲罷朱崖。", "元帥全軍出，天王太室齋。", "鑿門資感奮，負羽必誰差。", "壯氣隨霆擊，先聲甚雨偕。", "遊魂蚩爾輩，賈勇洎吾儕。", "略野窮飛鳥，圍城盡析骸。", "饑啼兒宛轉，怨哭鬼歐哇。", "破竹餘銛刃，焚原只亂稭。", "鯨掀才足膾，狸搰可須埋。", "王略過銅柱，天威暢藁街。", "斗牛光更潤，溟海靜無涯。", "賈舶盈珠琲，宮娥賤玳釵。", "拜侯金篆斗，犒士酒如淮。", "神武千齡協，歡娛萬國諧。", "告成方歷吉，名嶽望禋柴。"]'),
('0a3a9e73-a2af-4909-8f88-eb64c1e35ae1','溫湯和王法曹','劉攽','宋','宋诗','song-poetry','','[]','火井傳夷檄，炎洲記海隅。',120,'全唐诗/poet.song.35000.json','["火井傳夷檄，炎洲記海隅。", "仙遊空詣絕，方志每多誣。", "泛濫浮清沼，淵源自奧區。", "洪鈞從鼓橐，一氣審爲爐。", "烈焰方焚澤，騰波盛濺珠。", "沃焦難與並，執熱諒誰須。", "鼇抃終當釣，鯨掀會學屠。", "此中勝鼎鼐，不復待樵蘇。", "池館他年貴，衣冠萬乘俱。", "廢興仍在目，惆悵指平蕪。"]'),
('fb39061a-ea82-46fa-904b-556a43c60750','蔡州城枕汝水寒日水涸清淺可愛原父與郡守泛舟川上甚有佳境以書垂報緬想勝遊因形短什','劉攽','宋','宋诗','song-poetry','','[]','積水寒收潦，深淵浄見沙。',144,'全唐诗/poet.song.35000.json','["積水寒收潦，深淵浄見沙。", "冷光憐玉潔，清鑒絕毫差。", "鷗鳥居相樂，漁樵近有家。", "濟川新剡木，載石去乘槎。", "樹影魚鱗密，城陰瓠子斜。", "夤緣忘向背，頃刻變烟霞。", "練白翻雲葉，金鎔蕩日華。", "照心同不隠，滌慮愛無邪。", "客醉風吹酒，歸迷斗轉車。", "林宗昔無暇，范蠡去空賒。", "鳬雁晴餘喜，波瀾雪後佳。", "謝塘芳草夢，依約向無涯。"]'),
('4f0bbd69-68b4-455c-98ff-79f4c1a03725','登東山小魯','劉攽','宋','宋诗','song-poetry','','[]','惟昔宣尼氏，登山俯大東。',72,'全唐诗/poet.song.35000.json','["惟昔宣尼氏，登山俯大東。", "隘然輕魯國，不復夢周公。", "洙泗秋毫外，龜蒙聚米中。", "浮埃殊擾擾，鬥蟻竟匆匆。", "遊觀情應類，臨河事不同。", "豈將千乘富，一換舞雩風。"]'),
('c2e96028-f31a-4771-8f66-b3d6f91d17b5','賀玉汝殿中御史','劉攽','宋','宋诗','song-poetry','','[]','世許忠臣子，仍爲憲府官。',72,'全唐诗/poet.song.35000.json','["世許忠臣子，仍爲憲府官。", "自宜棠棣萼，復正觸邪冠。", "霜肅臺中柏，香餘省署蘭。", "鷹鸇與秋勁，冰玉瑩心寒。", "去路鄰霄漢，無人怨鏌干。", "流傳廟廊語，聳激壯夫肝。"]'),
('64046d3b-32af-454a-947b-d78c41fc67c0','佚老堂爲馬給事題','劉攽','宋','宋诗','song-poetry','','[]','膂力期方壯，功名付衆才。',144,'全唐诗/poet.song.35000.json','["膂力期方壯，功名付衆才。", "朝廷不能出，軒冕儻時來。", "賢者皆知此，勞生亦念哉。", "暮年均暇逸，末路忍低回。", "延閣通雲漢，東垣接上臺。", "老成宜鶴髮，絕足信龍媒。", "脫落經綸際，從容里地開。", "圖書收舊素，池籞就穿栽。", "松竹依陶令，兒童戲老萊。", "尚知南郡富，肯使少游哀。", "詎有東家問，端思齒杖陪。", "會爲三徑客，幽屏謝塵埃。"]'),
('2c86e335-d3e1-4fa6-98d6-a240524ec75d','灞涘望長安','劉攽','宋','宋诗','song-poetry','','[]','去國一回首，憑高因肆觀。',72,'全唐诗/poet.song.35000.json','["去國一回首，憑高因肆觀。", "清川會灞涘，白日麗長安。", "魏闕中天直，南山並海寒。", "樓居雲縹緲，城象斗闌干。", "即事感能賦，有情知永嘆。", "不勞歌倚瑟，悽愴指邯鄲。"]'),
('31ffe764-bfa8-43a0-893d-42682afcc40d','集英殿觀先帝御容','劉攽','宋','宋诗','song-poetry','','[]','墮淚不能禁，彤庭北望深。',72,'全唐诗/poet.song.35000.json','["墮淚不能禁，彤庭北望深。", "壽觴疑在眼，宮漏獨驚心。", "繪事應神助，天光想下臨。", "秋毫分萬一，玉色辨侵尋。", "未悟攀髯遠，如聞棄屣音。", "當時萬年木，風動亦蕭森。"]'),
('c6efbdf0-f7e5-4c91-93ed-ef66552426e3','王四十監鴻慶宮','劉攽','宋','宋诗','song-poetry','','[]','沛邑祠原廟，明年啟壽宮。',96,'全唐诗/poet.song.35000.json','["沛邑祠原廟，明年啟壽宮。", "真遊追柱史，吏隠即冥鴻。", "苑路連修竹，兒歌習大風。", "海鳬隨步武，笙鶴下虛空。", "司馬官園令，千秋擢寢中。", "書成大人賦，夢識白頭翁。", "北闕縻徐樂，丹砂愧葛洪。", "帝鄉那可問，相望五雲東。"]'),
('97f6ff10-a9bd-43ab-b0af-7e75a2884085','代魏秀才和','劉攽','宋','宋诗','song-poetry','','[]','明府敏爲政，經綸功已深。',120,'全唐诗/poet.song.35000.json','["明府敏爲政，經綸功已深。", "無欺禮神意，不擾愛民心。", "直道容多梗，良時避孔壬。", "未成宣室召，空賜潁川金。", "茲日量天聽，方春報雨霖。", "望蜺舒黯黯，笑電趣涔涔。", "耒耜歡南畝，歌謠變越吟。", "和應光爇戶，潤足俟薰琴。", "久客羞王粲，忘饑學漢陰。", "鹿門那忍去，留釣此江潯。"]'),
('6aa14a71-32fe-49bf-8b2e-622ed53e3e2e','又和魏秀才','劉攽','宋','宋诗','song-poetry','','[]','川原惟漢廣，雷雨向春深。',120,'全唐诗/poet.song.35000.json','["川原惟漢廣，雷雨向春深。", "望望三農事，悠悠一歲心。", "月離初候畢，龍見亦推壬。", "向夕風翻海，中天電爍金。", "農占不騎晦，史例足書霖。", "至治無饑穰，元和蔑旱涔。", "遷鸚殊自喜，倦客獨悲吟。", "未必魚生釜，聊因酒貰琴。", "奮身從嫖姚，走馬過雕陰。", "辜負封侯骨，棲遲沔水潯。"]'),
('1a0ca909-b044-422e-8a4c-a73921e98ea6','答吳侍郎寄陝府','劉攽','宋','宋诗','song-poetry','','[]','天王相有三，分陝按殽函。',72,'全唐诗/poet.song.35000.json','["天王相有三，分陝按殽函。", "列國依明德，西人盛美談。", "甘棠元聽訟，綵服自調甘。", "餘力斯文貴，珍詞萬象含。", "氣清融渤澥，材絕聳楩柟。", "請誦詩三百，先知學召南。"]'),
('62314ad3-bbb5-449b-b101-6a1b16dae811','次韵和韓持國雪二十韵','劉攽','宋','宋诗','song-poetry','','[]','層雲升蒼莽，密雪亂高低。',216,'全唐诗/poet.song.35000.json','["層雲升蒼莽，密雪亂高低。", "巧緻欺工倕，繁多感計倪。", "因高宜嶽鎮，善下及塗泥。", "海變方朝若，天通憶命黎。", "懸檐垂齟齬，投隙置刀圭。", "冥頊豪無頼，娥舒弱易迷。", "清心還自照，正色故思齊。", "報曙端成誤，驚春妄問奚。", "林珍翔鷺鵠，玉氣墮虹蜺。", "獵野甘燔兔，登川快臛蠵。", "風回飄柳絮，日暝亂醯雞。", "蟲篆初難辨，庖羔久未刲。", "冥鴻愁徑度，饑雀愴單棲。", "律驗知陽復，天旋測氣躋。", "浮生共羈旅，外境本筌蹄。", "置酒容高會，論文慰解携。", "詩從載塗唱，賦爲騁妍題。", "數聽波濤辨，滔滔百仞溪。"]'),
('6d4c7eb5-2b86-4806-987d-261097be9513','咏雪','劉攽','宋','宋诗','song-poetry','','[]','朔雪三冬暮，同雲萬里間。',288,'全唐诗/poet.song.35000.json','["朔雪三冬暮，同雲萬里間。", "昊天還質素，長路失幽艱。", "舞急低仍舉，吹多去復還。", "增高元稍稍，投隙故閒閒。", "積鹵輸鹽浦，飄沙聚玉關。", "怒濤狂振海，疊巘坐移山。", "喜厚猶多積，憎繁詎得刪。", "旗旛高卷野，塵壒密通闤。", "點綴林芳亂，裝褫石蘚斑。", "戶斜遺尺劍，窗缺置連環。", "圭璧衣裳會，閭閻米粟頒。", "折篁終不屈，喬樹頓堪攀。", "紈潔裁歌扇，珈明聳髻鬟。", "運籌思巧歷，語異叱神奸。", "凍筆無由捉，强弓不易彎。", "雁號隨雀瞀，龍蟄並魚鰥。", "坎辟威權厲，陽芽勢力孱。", "晦冥愁運促，溫燠愴時慳。", "畛域通三壤，塗泥洎百蠻。", "暝鷄矜喔喔，宵犬事籋籋。", "踠足傷騏驥，迷群失鷺鷳。", "製書思籀頡，議巧謝倕般。", "蚊翼騰空曲，芝英擢野菅。", "藩籬容月魄，軒陛絕人寰。"]'),
('3383b30e-bcbd-460f-902f-75bf88d1cd0b','駕幸開寶寺福聖院新閣','劉攽','宋','宋诗','song-poetry','','[]','帝圖天不極，覺苑日融輝。',96,'全唐诗/poet.song.35000.json','["帝圖天不極，覺苑日融輝。", "減劫寧無待，直乘必應機。", "化城非樸斫，檀施自依歸。", "香象開馳道，珠瓔接尚衣。", "梵音潮海會，阿閣鳳凰飛。", "清蹕通長樂，齋居護却非。", "雨花交霰雪，燎桂雜煙霏。", "默冀南山壽，賢公已見幾。"]'),
('2e500deb-d464-4a7b-962d-69ae308c3320','原父舍人爰自春坊遷職史氏未更晦望旋有新命增秩諫省躋榮綸閣斐然成篇以伸歡賀','劉攽','宋','宋诗','song-poetry','','[]','近署銅龍貴，仙山策府遥。',168,'全唐诗/poet.song.35000.json','["近署銅龍貴，仙山策府遥。", "由來稱國士，自致必雲霄。", "太史題凡例，彤庭奉日朝。", "除書新翰墨，受賜接晨朝。", "池水通翔鳳，星垣直建杓。", "泛槎輕濟海，逸御捷凌飆。", "獻納當宸扆，絲綸聳具寮。", "直詞明黼黻，大冊粲瓊瑶。", "拜舞腰金重，歸來廐馬調。", "泥書開鵠板，法駕從雞翹。", "高興吟紅藥，珍辭賦洞簫。", "宮花香永晝，禁漏靜通宵。", "枝鵲聲何喜，原鴒意自饒。", "寄言江漢客，無事老漁樵。"]'),
('5bd89ec6-a5a0-4f2d-aaf5-ce940ebac7a9','和秘閣趙光祿學士臘月夜閣宿見寄','劉攽','宋','宋诗','song-poetry','','[]','秘宇聳嚴凝，名卿壽作朋。',72,'全唐诗/poet.song.35000.json','["秘宇聳嚴凝，名卿壽作朋。", "臘殘琪樹雪，夜寂瑣窗燈。", "交意嘗投漆，高談亟引繩。", "正憐湖海別，况復歲華增。", "詩勇堅無敵，材全問不能。", "龍淵方出匣，持以喻韓稜。"]'),
('a78691be-ef9c-45c7-8c46-dcf263b3a7c3','分題河决東郡','劉攽','宋','宋诗','song-poetry','','[]','漢郡金堤北，黄河落日東。',72,'全唐诗/poet.song.35000.json','["漢郡金堤北，黄河落日東。", "波濤凝沴氣，翻浪蹙長空。", "鉅野鮫人室，魚山水伯宮。", "坐嗟山海變，心恐地天通。", "未就宣防築，深懷夏禹功。", "何當開嶺首，西注出湖中。"]'),
('5e099a66-d079-478c-b76b-aa55aa64cd62','陪馬守蜀山禱雨','劉攽','宋','宋诗','song-poetry','','[]','丘禱亦以久，齋居先筮從。',72,'全唐诗/poet.song.35000.json','["丘禱亦以久，齋居先筮從。", "鳴騶趁殘夜，觸石會前峰。", "簫鼓終椒奠，風霆起蟄龍。", "化工輕瞬息，幽貺振舂容。", "灑濯埃塵絕，虛凉灝氣逢。", "小人思學稼，即事喜年豐。"]'),
('5b2cc5c2-101e-4e65-b4c8-da8aa77ab025','送王相公','劉攽','宋','宋诗','song-poetry','','[]','白麻詔出鳳凰池，金節銅符副錫珪。',192,'全唐诗/poet.song.35000.json','["白麻詔出鳳凰池，金節銅符副錫珪。", "故事周公不之魯，是行山甫亦徂齊。", "百年禮樂更檮杌，萬國車書載狄鞮。", "開闔乾坤容海運，斡回樞極寄杓携。", "故都形勝餘龍虎，開府文章盛壁奎。", "列坐諸生親絳帳，縱談禪伯得金篦。", "四山嵐氣連松梓，二水波濤亂鼓鼙。", "里老傍車看畫鹿，江靈低首避燃犀。", "鴻河带地長餘潤，蟠木開花亦有蹊。", "躍冶空慚折鉤喙，在鈞仍似落巢泥。", "苦心刻鵠纔成鶩，卑意函牛祇洎鷄。", "早晚重開丞相閣，爲公羸馬踏沙堤。"]'),
('d7a8fb4f-9bb5-46a1-97c9-14277fb30340','和楊褒早春二首  其一','劉攽','宋','宋诗','song-poetry','','[]','雪色留寒風弄和，新陽淺淺故陰多。',96,'全唐诗/poet.song.35000.json','["雪色留寒風弄和，新陽淺淺故陰多。", "池冰漸盡泉初潔，徑草猶微菊未莎。", "歸雁聲音矜久客，晴雲意態似妖娥。", "杖藜窮巷貧非憊，隠几衡門嘯也歌。", "身外閒愁從撥棄，眼前詩景得遮羅。", "亦知白髮非春事，老伴相尋奈我何。"]'),
('27b997d1-1b8e-4443-9d03-aec3802f6a79','和楊褒早春二首  其二','劉攽','宋','宋诗','song-poetry','','[]','少年意氣屬時和，春入青門樂事多。',96,'全唐诗/poet.song.35000.json','["少年意氣屬時和，春入青門樂事多。", "試著青衫迎暖日，閒騎駿馬踏青莎。", "御風直欲從仙子，奔月猶能及素娥。", "雁鶩陂前來膾鯉，芙蓉園裏去聽歌。", "舞狂相屬揮如意，醉起馳歸擲叵羅。", "寄語子雲天祿閣，新書尚白竟如何。"]'),
('dc617ade-9bb2-4050-82e3-7ee9f7db3026','寄齊州李學士并呈蘇密州','劉攽','宋','宋诗','song-poetry','','[]','濟水由來徹海清，兩州偕得水南名。',96,'全唐诗/poet.song.35000.json','["濟水由來徹海清，兩州偕得水南名。", "遺人頗記睢陽曲，說士猶談歷下兵。", "碧落羽翰俱失路，白頭章綬偶專城。", "東秦表海知君重，左輔陪京莫我輕。", "賓客此邦多長者，詩書前古聚諸生。", "不知高密何如彼，試仗西風問子卿。"]'),
('9fa8e054-02e1-4cae-8126-b9cc930e4e67','送王兖州','劉攽','宋','宋诗','song-poetry','','[]','卧閣偏州獨老夫，三年化盡白髭鬚。',160,'全唐诗/poet.song.35000.json','["卧閣偏州獨老夫，三年化盡白髭鬚。", "故人始得班荆語，督府相觀剖竹符。", "舊學翰林君子澤，雄文策府列仙儒。", "蛟龍莫作池中物，老驥幾爲轅下駒。", "腰底印章馳傳乘，道傍冠蓋棄關繻。", "黄金上冢家相樂，文弩迎官吏疾驅。", "甲子可憐同步武，光陰稍覺近桑榆。", "掛車正爾思前路，畢娶由來異壯圖。", "笑謔會須矜此酒，分飛何必待長塗。", "側身東望艱梁甫，猶冀君家有隻鳬。"]'),
('f3066326-7e07-44ab-9e9f-8f044ec9e595','次韵宋職方新脩廳事','劉攽','宋','宋诗','song-poetry','','[]','事從梁棟拯隳頹，民有餘工庫有財。',128,'全唐诗/poet.song.35000.json','["事從梁棟拯隳頹，民有餘工庫有財。", "不待公輸洎玉繭，肯論新甫與徂徠。", "經營結構無遺巧，壯麗宏深要必該。", "廣砌水平鋪淡碧，應門風過絕纖埃。", "雲山噴墨文屏合，金獸銜環洞戶開。", "勢似名翬飛夭矯，喜知巢燕到裴徊。", "陳平社宰非無意，薛惠郵亭信不才。", "會道曹風如魯衛，輔州元作帝京陪。"]'),
('a1ff10f3-304e-4aa0-9a83-5f3fcfc50d0c','再和宋職方','劉攽','宋','宋诗','song-poetry','','[]','萬緣冥數有興頹，不爲勞民與費財。',128,'全唐诗/poet.song.35000.json','["萬緣冥數有興頹，不爲勞民與費財。", "常怪丘淵猶改舊，足令蓍蔡可知來。", "黄圖左輔今仍重，甲令名藩此正該。", "過去英賢聯踵武，幾多能事悉塵埃。", "僝工匠石三農隙，唾手公堂一旦開。", "妙選棟梁虹宛轉，觸新廊廡雁徘徊。", "落成幸有羔羊酒，能賦欣逢錦繪才。", "衰老專城無異術，祇將勤拙任家陪。"]'),
('a0c1b8da-f61c-4b7d-9893-1730266b40b8','次韵酬李推官','劉攽','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','少無風力致雲霄，老寄東藩愧節旄。',128,'全唐诗/poet.song.35000.json','["少無風力致雲霄，老寄東藩愧節旄。", "涉境已憐清濟涸，開門猶喜岱山高。", "智微黑蟻穿珠竅，術異游魚出鼎膏。", "思古循良深自嘆，視身尸素欲何逃。", "流光去去車馳轂，過事新新海駕濤。", "屈指家聲歡上客，愜心風什幸詩豪。", "青春小圃饒佳卉，遲日芳樽付濁醪。", "傾蓋强君留一醉，相看前路釣連鼇。"]'),
('31afbd01-7156-4578-9027-cbde84169286','答鄭秘丞見寄長韵','劉攽','宋','宋诗','song-poetry','','[]','鄭公真率故難攀，夙昔相期季孟間。',224,'全唐诗/poet.song.35000.json','["鄭公真率故難攀，夙昔相期季孟間。", "晝錦鄉閭嗤拓落，藉糟官局壓清閒。", "飲腸縱逸巵無當，詩句清新玉作環。", "屢舞自矜能舉袖，少歌誰復顧酡顔。", "南金不足償棋進，魯酒頻聞輸罰鍰。", "豪忤里儒連束矢，狂侵醉尉欲翹關。", "婢勤織衽幾無欲，男飽詩書僅有鰥。", "疲馬踏泥如得絆，弱弓支肘不成彎。", "權材未恨原中秘，領邑那知寄百蠻。", "說將正憐胡越異，問津空復鬢毛斑。", "江連楚蜀無窮水，路繞巴渝不盡山。", "青嶂叫猿寒寂寂，亂泉衝石暝潺潺。", "有生誰得辭羈旅，良苦遥知冒險艱。", "高興由來向人盡，尺書仍喜不吾慳。"]'),
('cb20848b-c02a-4c2f-9c34-e0f1459a5f0c','雨後小園','劉攽','宋','宋诗','song-poetry','','[]','雨多三徑似荒郊，處處秋陰紫翠交。',96,'全唐诗/poet.song.35000.json','["雨多三徑似荒郊，處處秋陰紫翠交。", "照水白蓮霜雪朵，倚天喬木夕陽梢。", "池光俯見游魚窟，樓角遥臨宿羽巢。", "倚杖移時看蟻鬥，操舟繚岸試杯膠。", "牆陰靜色憐甘菊，垣上懸藤識苦匏。", "老圃不須譏抱甕，野人無事伴誅茅。"]'),
('d69f497b-0ecd-42c8-922f-644b3ce6ce5c','終南山','劉攽','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','終南際滄海，千里張屏風。',24,'全唐诗/poet.song.35000.json','["終南際滄海，千里張屏風。", "落月沈山西，朝陽生嶺東。"]'),
('df636be7-8a3c-4a4d-8969-e82f299d3c8e','火浣壇','劉攽','宋','宋诗','song-poetry','','[]','天游神不虛，火解形復見。',24,'全唐诗/poet.song.35000.json','["天游神不虛，火解形復見。", "明明學道心，不與劫火變。"]'),
('7ee7fcf3-94de-4176-bc92-7722febc25e4','許真君祠','劉攽','宋','宋诗','song-poetry','','[]','舊怪神仙事，燕齊得浪傳。',24,'全唐诗/poet.song.35000.json','["舊怪神仙事，燕齊得浪傳。", "丹青此堂上，想像爲依然。"]'),
('ec5bea3c-a650-4afd-9035-f0cf9e91a247','酒舫','劉攽','宋','宋诗','song-poetry','','[]','美酒留人飲，乘風縱客槎。',24,'全唐诗/poet.song.35000.json','["美酒留人飲，乘風縱客槎。", "秋潭夜深月，春嶼雨餘花。"]'),
('01f8d20b-41be-41c1-87bd-0b98ee29aa5e','竹岡','劉攽','宋','宋诗','song-poetry','','[]','夤緣映層阜，蒼翠復春苔。',24,'全唐诗/poet.song.35000.json','["夤緣映層阜，蒼翠復春苔。", "君知愛霜雪，若个是龍材。"]'),
('41c7b320-a297-4aa1-9474-1d7f28600f8a','寒食後聞雁','劉攽','宋','宋诗','song-poetry','','[]','後雁來何暮，春風萬里情。',24,'全唐诗/poet.song.35000.json','["後雁來何暮，春風萬里情。", "江南多燕子，無處覓同聲。"]'),
('7e3954ba-05d9-4513-8646-bd8a620ca7ab','丹井','劉攽','宋','宋诗','song-poetry','','[]','古井玄泉色，仙人玉鏡寒。',24,'全唐诗/poet.song.35000.json','["古井玄泉色，仙人玉鏡寒。", "照來知骨相，作意就金丹。"]'),
('bf15894e-8cb9-487c-bc5d-351a1b1ae12d','初夜','劉攽','宋','宋诗','song-poetry','','[]','栖雞已登屋，宿羽復歸林。',24,'全唐诗/poet.song.35000.json','["栖雞已登屋，宿羽復歸林。", "不語聽鐘坐，默默千里心。"]'),
('61353285-3834-49bf-98d4-c68ae843bd0d','郡樓晚坐同陳掾','劉攽','宋','宋诗','song-poetry','','[]','雲來湖外雨，樓倚樹梢風。',24,'全唐诗/poet.song.35000.json','["雲來湖外雨，樓倚樹梢風。", "不惜清凉意，持將與子同。"]'),
('251e4df2-bc60-471d-9c1c-05c7f06d48b6','人日立春','劉攽','宋','宋诗','song-poetry','','[]','花勝已宜春，剪綵更爲人。',24,'全唐诗/poet.song.35000.json','["花勝已宜春，剪綵更爲人。", "風光今日好，顔貌一時新。"]'),
('08c1b39a-9623-4762-b827-6def898a995a','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其一','劉攽','宋','宋诗','song-poetry','','[]','赤驥脫馵羈，軒然視瑶池。',24,'全唐诗/poet.song.35000.json','["赤驥脫馵羈，軒然視瑶池。", "公持漢使節，不減豸冠時。"]'),
('2d39467d-6702-4ce3-ab5a-d879e6a762d3','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其二','劉攽','宋','宋诗','song-poetry','','[]','三江互東南，波浪浮日光。',24,'全唐诗/poet.song.35000.json','["三江互東南，波浪浮日光。", "峽中起奔濤，積錢僅成塘。"]'),
('34e8e08d-d017-48ab-9aeb-578b33ee04cf','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其三','劉攽','宋','宋诗','song-poetry','','[]','吳帆若飛鴻，千里長風生。',24,'全唐诗/poet.song.35000.json','["吳帆若飛鴻，千里長風生。", "組練白玉粒，一月來上京。"]'),
('b8042adf-fab6-4bb4-9eac-03eafe329095','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其四','劉攽','宋','宋诗','song-poetry','','[]','利術析秋毫，心計遊無垠。',24,'全唐诗/poet.song.35000.json','["利術析秋毫，心計遊無垠。", "亦有甘棠蔭，蔽芾如舊春。"]'),
('f077faaf-cd71-4791-8af7-e29f556c249c','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其五','劉攽','宋','宋诗','song-poetry','','[]','忽爲嚴霜誅，慘戚動秋草。',24,'全唐诗/poet.song.35000.json','["忽爲嚴霜誅，慘戚動秋草。", "狐狸不足問，豺狼詎橫道。"]'),
('25d0dfc1-0614-4cac-85c4-3ad9600e675c','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其六','劉攽','宋','宋诗','song-poetry','','[]','諸公惜分手，置酒倚名園。',24,'全唐诗/poet.song.35000.json','["諸公惜分手，置酒倚名園。", "長廊蔽修景，晝無車馬喧。"]'),
('4f0f834c-bf56-4b39-b694-89f8d0861c52','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其七','劉攽','宋','宋诗','song-poetry','','[]','露光洗高花，風力曳垂柳。',24,'全唐诗/poet.song.35000.json','["露光洗高花，風力曳垂柳。", "上客請賦詩，主人起爲壽。"]'),
('1876eb14-c80f-409e-82c9-35c742455a3e','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其八','劉攽','宋','宋诗','song-poetry','','[]','春濃芳菲雜，日夕境氣變。',24,'全唐诗/poet.song.35000.json','["春濃芳菲雜，日夕境氣變。", "望望檣上烏，去去令人羨。"]'),
('93e2c344-ee3c-49ed-8c92-1a807764a721','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其九','劉攽','宋','宋诗','song-poetry','','[]','壯年吳會遊，常有懷遠情。',24,'全唐诗/poet.song.35000.json','["壯年吳會遊，常有懷遠情。", "想見瓜步南，草長鶑亂鳴。"]'),
('782bbda1-7f1b-45c3-add1-3323ed3c7d51','送韓玉汝司封奉使兩浙聞諸公先分題用池塘生春草園柳變鳴禽字合爲十章四句  其一○','劉攽','宋','宋诗','song-poetry','','[]','驛騎傳梅花，書帖封來禽。',24,'全唐诗/poet.song.35000.json','["驛騎傳梅花，書帖封來禽。", "何以慰別愁，遲此瑶華音。"]'),
('4c817f21-19d8-4b1a-b7d3-5a73713c0ef4','花嶼','劉攽','宋','宋诗','song-poetry','','[]','孤絕池心嶼，高低水面花。',24,'全唐诗/poet.song.35000.json','["孤絕池心嶼，高低水面花。", "若無舟楫到，應似隔仙家。"]'),
('8015ace1-69eb-4356-ab35-3647c52e102e','池上','劉攽','宋','宋诗','song-poetry','','[]','罷客棋仍在，留書卷未終。',24,'全唐诗/poet.song.35000.json','["罷客棋仍在，留書卷未終。", "荷喧知過雨，萍聚見來風。"]'),
('0e1b40f9-e13e-4259-8a5f-7f1624d9e7fb','嘯臺','劉攽','宋','宋诗','song-poetry','','[]','高臺見百里，長嘯海風生。',24,'全唐诗/poet.song.35000.json','["高臺見百里，長嘯海風生。", "爲問塵埃耳，能聞鸞鶴聲。"]'),
('db7be65c-dfc0-4a6d-8587-18d62ef2b339','鼎池','劉攽','宋','宋诗','song-poetry','','[]','仙去遺金鼎，年深認劫灰。',24,'全唐诗/poet.song.35000.json','["仙去遺金鼎，年深認劫灰。", "懷人何限意，時向鼎池來。"]'),
('24ba6198-5509-4838-9149-62999c914010','故人謝師厚刻唐賢淳于先生墓詩于善謔驛系語其後刻石後二年師厚去世明年余過善謔驛讀詩悲之因作淳于墓詩又題二韵追悼師厚平生忘形善謔莫逆惟師厚爲然也','劉攽','宋','宋诗','song-poetry','','[]','故人墳宿草，翰墨想遺風。',24,'全唐诗/poet.song.35000.json','["故人墳宿草，翰墨想遺風。", "善謔知君意，何傷睿武公。"]');
